export const GeneratorsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 The Problem: Eager vs Lazy</div>
      <p style={c.prose}>Normal functions run to completion and return once. But what if you need to produce values <strong style={{ color: '#eab308' }}>one at a time</strong>, only when asked? That's what generators solve — they're <strong style={{ color: '#00ff88' }}>lazy sequences</strong>.</p>
    </RevealCard>
    <AnalogyCard emoji="🍣" title="A sushi conveyor belt" analogy="Instead of preparing all 100 dishes at once and putting them on the table (eager), a conveyor belt brings one dish at a time as customers take them. If nobody takes a dish, it's never made. Generators work the same way — values are produced only when requested." connection="Each call to next() is like a customer taking a dish — the generator produces the next value on demand, pausing until the next request." />
    <StorySteps steps={[
      { title: 'Declare with function*', color: '#eab308', desc: 'The asterisk signals this is a generator function. Calling it returns a generator object — nothing executes yet.', code: `function* myGen() { yield 1; yield 2; }\nconst gen = myGen(); // no execution yet!` },
      { title: 'yield pauses and emits', color: '#4facfe', desc: 'Calling next() runs until the next yield, returns that value, and pauses.', code: `gen.next(); // {value: 1, done: false}\ngen.next(); // {value: 2, done: false}` },
      { title: 'done: true ends the sequence', color: '#00ff88', desc: 'After the last yield or a return statement, done becomes true.', code: `gen.next(); // {value: undefined, done: true}` },
      { title: 'Use with for...of', color: '#a855f7', desc: 'Generators implement the iteration protocol — they work anywhere iterables work.', code: `for (const val of myGen()) console.log(val); // 1, 2\n[...myGen()]; // [1, 2]` },
    ]} />
    <InlinePoll question="What does calling a generator function return?" options={["The first yielded value", "A generator iterator object", "undefined", "A Promise"]} correct={1} explanation="Calling a generator function doesn't execute any code — it returns a generator object. Execution only starts when you call .next() for the first time." />
    <CommonMistake mistake="'I called the generator function but nothing happened'" fix="Calling myGenerator() just creates the iterator object. You need to call .next() to start execution. Think of it as: the function defines the sequence, the object controls traversal." />
    <DidYouKnow fact="Generators were the original way to implement async/await patterns in JavaScript (via co library and yield). async/await was designed as syntactic sugar for this pattern." color="#eab308" />
    <InterviewMeter topics={[{ topic: 'What is a generator and what does yield do?', freq: 70 }, { topic: 'Making objects iterable with Symbol.iterator + generator', freq: 65 }, { topic: 'Infinite sequences with generators', freq: 55 }, { topic: 'Two-way communication via next(value)', freq: 45 }]} />
  </div>
);

export const TypeScriptLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Why TypeScript?</div>
      <p style={c.prose}>TypeScript catches entire categories of bugs <strong style={{ color: '#4facfe' }}>before your code runs</strong>. No more "Cannot read property 'x' of undefined" at 2am in production — the compiler catches it when you write the code.</p>
    </RevealCard>
    <AnalogyCard emoji="🔧" title="A spell checker for code logic" analogy="Just as a spell checker catches typos before you send an email, TypeScript catches type errors before you ship code. It doesn't prevent all bugs — but it eliminates an entire class of the most common ones." connection="TypeScript's static analysis runs at compile time. It knows that user.naem is a typo of user.name before you even save the file." />
    <StorySteps steps={[
      { title: 'interface vs type — the core difference', color: '#4facfe', desc: 'Interfaces can be merged (declaration merging); types cannot. Types support unions; interfaces do not.', code: `interface User { name: string; }\ninterface User { age: number; } // merged! ✓\n\ntype ID = string | number; // union — only with type ✓` },
      { title: 'Generics — reusable with any type', color: '#00ff88', desc: 'Generics let you write type-safe code that works for any type.', code: `function first<T>(arr: T[]): T | undefined {\n  return arr[0];\n}\nfirst([1, 2, 3]); // number\nfirst(['a']); // string` },
      { title: 'Utility types — transform existing types', color: '#a855f7', desc: 'Pick, Omit, Partial, Required — derive new types from existing ones.', code: `type SafeUser = Omit<User, 'password'>;\ntype UpdateUser = Partial<User>;\ntype UserForm = Pick<User, 'name' | 'email'>;` },
    ]} />
    <InlinePoll question="When should you use type instead of interface?" options={["Always — type is more powerful", "For union types, primitives, and complex computed types", "Never — interface is always better", "Only for function types"]} correct={1} explanation="type is required for union types (string | number), mapped types, conditional types, and tuples. interface is better for object shapes and public APIs that might need declaration merging." />
    <CommonMistake mistake="Using 'any' to silence TypeScript errors" fix="any disables type checking entirely for that value. Use unknown for values of unknown type (forces you to narrow before use), or find the proper type. 'any' is an escape hatch that defeats the purpose of TypeScript." />
    <InterviewMeter topics={[{ topic: 'interface vs type differences', freq: 80 }, { topic: 'Generics with constraints', freq: 75 }, { topic: 'Utility types (Partial, Omit, Pick)', freq: 70 }, { topic: 'any vs unknown vs never', freq: 65 }]} />
  </div>
);

export const StateManagementLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 State Has Types — Match the Tool to the Type</div>
      <p style={c.prose}>The #1 state management mistake: <strong style={{ color: '#ef4444' }}>putting everything in one place</strong>. Server data, UI state, form state, and URL state are fundamentally different problems requiring different tools.</p>
    </RevealCard>
    <AnalogyCard emoji="🗂" title="Different drawers for different things" analogy="You wouldn't put your kitchen utensils, car keys, medical records, and shopping receipts all in the same drawer. Each type of information belongs in the right storage: utensils in kitchen drawer, keys on hook, records in filing cabinet." connection="Server state → React Query. UI state → useState/Zustand. Forms → React Hook Form. URL state → router params. Each tool designed for its specific problem." />
    <StorySteps steps={[
      { title: 'Identify the state type first', color: '#4facfe', desc: 'Before choosing a library, classify the state.', code: `// Server state — from APIs\nconst { data } = useQuery(['users'], fetchUsers);\n// Client state — UI only\nconst [open, setOpen] = useState(false);\n// Form state\nconst { register } = useForm();\n// URL state\nconst [search] = useSearchParams();` },
      { title: 'Colocate state as low as possible', color: '#00ff88', desc: 'State should live in the closest common ancestor of components that use it — not always at the top.', code: `// ❌ Lifting everything to App\nfunction App() { const [modalOpen, setModalOpen] = useState(false); }\n// ✅ Keep it local\nfunction Header() { const [modalOpen, setModalOpen] = useState(false); }` },
      { title: 'Server state is different — use React Query', color: '#a855f7', desc: 'API data has unique needs: caching, revalidation, loading states. React Query handles all of them.', code: `// useState approach — manual, error-prone\nconst [users, setUsers] = useState([]);\nconst [loading, setLoading] = useState(true);\nuseEffect(() => { fetchUsers().then(setUsers).finally(...) }, []);\n\n// React Query — handles everything\nconst { data, isLoading, error } = useQuery(['users'], fetchUsers);` },
    ]} />
    <InlinePoll question="You have a list of users fetched from an API used in 5 different components. Where should you store this data?" options={["Global Redux store", "Local useState in each component (refetch per component)", "React Query — handles caching and deduplication automatically", "Context with manually managed loading states"]} correct={2} explanation="React Query caches the data under the ['users'] key. All 5 components call useQuery(['users']) but only ONE network request fires. The data is shared, cached, and automatically revalidated." />
    <CommonMistake mistake="Putting fetched API data in Redux store with manual loading/error/caching logic" fix="Redux is for client-side state (UI state, user preferences). API data needs: caching, deduplication, background revalidation, stale handling. React Query handles all of these — Redux requires you to build it all manually." />
    <InterviewMeter topics={[{ topic: 'Difference between server and client state', freq: 80 }, { topic: 'When to use useReducer vs useState', freq: 70 }, { topic: 'React Query vs Redux for async data', freq: 75 }, { topic: 'Context performance issues and solutions', freq: 65 }]} />
  </div>
);

export const TestingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Tests Are About Confidence, Not Coverage</div>
      <p style={c.prose}>100% code coverage doesn't mean your app works. Tests should answer: <strong style={{ color: '#00ff88' }}>"If this passes, am I confident this feature works for users?"</strong></p>
    </RevealCard>
    <AnalogyCard emoji="🏥" title="Medical tests, not security theater" analogy="A good medical test gives you actionable information — positive means you have the condition, negative means you don't. A bad test (too sensitive or too specific) wastes time and creates false alarms. Tests should tell you something meaningful." connection="Testing implementation details is like taking a blood pressure reading to diagnose a broken arm. Test behavior (what the component DOES) not implementation (how it works internally)." />
    <StorySteps steps={[
      { title: 'Unit tests — pure logic', color: '#4facfe', desc: 'Fast, isolated tests for pure functions, utilities, reducers. No DOM needed.', code: `test('add returns sum', () => {\n  expect(add(2, 3)).toBe(5);\n});\ntest('formatDate formats correctly', () => {\n  expect(formatDate('2024-01-15')).toBe('Jan 15, 2024');\n});` },
      { title: 'Integration tests — components + interactions', color: '#00ff88', desc: 'Render component, interact like a user, assert what they see. The highest-value test type for UI.', code: `test('login form submits correctly', async () => {\n  render(<LoginForm onSubmit={mockSubmit} />);\n  await userEvent.type(screen.getByLabelText('Email'), 'user@example.com');\n  await userEvent.click(screen.getByRole('button', { name: 'Sign In' }));\n  expect(mockSubmit).toHaveBeenCalledWith({ email: 'user@example.com' });\n});` },
      { title: 'Query by role — accessible queries', color: '#a855f7', desc: 'RTL prefers queries that users (and screen readers) would use.', code: `// ✅ Preferred — tests accessibility too\nscreen.getByRole('button', { name: 'Submit' });\nscreen.getByLabelText('Email address');\nscreen.getByText('Welcome back');\n\n// ❌ Avoid — brittle implementation details\nscreen.getByTestId('submit-btn');\ncontainer.querySelector('.btn-primary');` },
    ]} />
    <InlinePoll question="A test breaks after you rename a CSS class from 'btn-primary' to 'button-primary'. What type of test was this?" options={["A good test — it caught a change", "A brittle test coupled to implementation details", "A visual regression test", "An accessibility test"]} correct={1} explanation="Tests querying by class names test implementation details. Renaming a class is a refactor — behavior didn't change. Good tests query by role, text, or label — things users and screen readers see, not CSS class names." />
    <CommonMistake mistake="Aiming for 100% test coverage as the goal" fix="Coverage measures which lines ran, not whether behavior is correct. A test that calls a function but makes no assertions gets 100% coverage with zero confidence. Focus on testing critical user paths and edge cases thoroughly." />
    <InterviewMeter topics={[{ topic: 'Unit vs integration vs E2E differences', freq: 80 }, { topic: 'RTL philosophy — test behavior not implementation', freq: 75 }, { topic: 'What should NOT be tested', freq: 65 }, { topic: 'Mocking strategies (MSW vs jest.mock)', freq: 70 }]} />
  </div>
);

export const DebounceLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 The Problem: Too Many Calls</div>
      <p style={c.prose}>A search input firing an API call on every keystroke would make hundreds of requests as the user types. Debounce waits for the user to <strong style={{ color: '#00ff88' }}>pause</strong> before acting. Throttle fires at a <strong style={{ color: '#4facfe' }}>maximum rate</strong> regardless of how often it's called.</p>
    </RevealCard>

    <AnalogyCard
      emoji="🔔"
      title="An elevator door"
      analogy="An elevator doesn't close immediately when you press the button — it waits a few seconds in case someone else wants to get in. Each new person pressing the button resets the wait timer. Only when nobody presses for N seconds does the door finally close."
      connection="Each keystroke resets the debounce timer. Only when the user stops typing for N ms does the function fire — resulting in one API call instead of dozens."
    />

    <StorySteps steps={[
      {
        title: 'Every call resets the timer',
        color: '#4facfe',
        desc: 'Debounce clears the previous timer and sets a new one on every call. Only the final call after silence actually fires.',
        code: `function debounce(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);          // cancel previous
    timer = setTimeout(() => {    // schedule new
      fn.apply(this, args);
    }, delay);
  };
}`,
      },
      {
        title: 'Throttle fires immediately then waits',
        color: '#a855f7',
        desc: 'Throttle fires on the first call, then ignores subsequent calls until the limit period has passed.',
        code: `function throttle(fn, limit) {
  let lastRun = 0;
  return function(...args) {
    const now = Date.now();
    if (now - lastRun >= limit) {
      lastRun = now;
      fn.apply(this, args);
    }
  };
}`,
      },
      {
        title: 'When to use which',
        color: '#00ff88',
        desc: 'The choice depends on whether you want to react to the end of activity (debounce) or limit frequency during continuous activity (throttle).',
        code: `// Debounce: wait for pause
const onSearch = debounce(fetchResults, 300);
input.addEventListener('input', onSearch);
// → fires once after user stops typing

// Throttle: max once per interval
const onScroll = throttle(updateHeader, 100);
window.addEventListener('scroll', onScroll);
// → fires at most every 100ms during scroll`,
      },
    ]} />

    <InlinePoll
      question="User types 'r', 'e', 'a', 'c', 't' quickly (each 50ms apart) with debounce(fn, 300ms). How many times does fn fire?"
      options={['5 times — once per keystroke', '1 time — after 300ms of silence', '0 times', '2 times']}
      correct={1}
      explanation="Each keystroke resets the 300ms timer. Since keystrokes are 50ms apart, the timer never completes mid-sequence. Only after the last keystroke ('t') plus 300ms of silence does fn fire once."
    />

    <CommonMistake
      mistake="Using debounce for a scroll handler: 'I debounced my scroll event so it performs better.'"
      fix="Debounce waits for activity to STOP before firing — your scroll handler would never fire during scrolling! Use throttle for scroll (fires continuously at a limited rate). Debounce = react to end of activity. Throttle = limit frequency during activity."
    />

    <DidYouKnow
      fact="Lodash's debounce has 'leading' and 'trailing' edge options. Leading fires immediately on first call AND after silence. This is how search suggestions work — show results immediately, then again after typing stops."
      color="#00ff88"
    />

    <InterviewMeter topics={[
      { topic: 'Implement debounce from scratch', freq: 85 },
      { topic: 'Debounce vs throttle — which for search vs scroll', freq: 80 },
      { topic: 'Add cancel() method to debounce', freq: 50 },
      { topic: 'Leading vs trailing edge options', freq: 45 },
    ]} />
  </div>
);

export const RapidFireLearn = ({ item }) => {
  const answers = {
    'rf-null-undefined': {
      answer: 'undefined = declared but not assigned (JS default). null = intentionally absent (developer set it). typeof null === "object" is a famous bug.',
      code: `let a;              // undefined (not assigned)
const u = null;     // null (intentional)
null == undefined   // true  (loose equality)
null === undefined  // false (strict equality)
typeof null         // 'object' ← famous JS bug`,
    },
    'rf-debounce-throttle': {
      answer: 'Debounce: waits for pause in calls, then fires once. Throttle: fires at most once per interval. Debounce = search input. Throttle = scroll handler.',
      code: `debounce(fn, 300) // fires after 300ms of silence
throttle(fn, 300) // fires at most every 300ms`,
    },
    'rf-event-loop-1min': {
      answer: 'JS is single-threaded. Async ops go to Web APIs. Callbacks queue up: Promises → microtask queue (high priority), setTimeout → macrotask queue (lower). Loop: drain ALL microtasks → one macrotask → repeat.',
      code: `console.log('A');
setTimeout(() => console.log('B'), 0);
Promise.resolve().then(() => console.log('C'));
console.log('D');
// Output: A, D, C, B`,
    },
    'rf-closure': {
      answer: 'A function that remembers variables from its outer scope even after that scope has finished executing. Holds a live reference, not a copy.',
      code: `function createCounter() {
  let count = 0;           // private
  return () => ++count;    // closes over count
}
const inc = createCounter();
inc(); // 1
inc(); // 2`,
    },
    'rf-hoisting': {
      answer: 'Declarations are moved to the top of their scope before execution. var → hoisted + undefined. function declarations → fully hoisted. let/const → hoisted but TDZ (ReferenceError if accessed early).',
      code: `console.log(x); // undefined (var hoisted)
var x = 5;

console.log(y); // ReferenceError (TDZ)
let y = 5;

greet(); // works! (function declaration hoisted)
function greet() { return 'hi'; }`,
    },
    'rf-map-foreach': {
      answer: 'map returns a NEW array with transformed values. forEach returns undefined — side effects only. Use map when you need the result.',
      code: `[1,2,3].map(x => x * 2)      // [2,4,6] ← new array
[1,2,3].forEach(x => x * 2)  // undefined ← no return`,
    },
    'rf-memoization': {
      answer: 'Caching the result of a function for given inputs. Same inputs → return cached result without recomputing. Only works for pure functions.',
      code: `const cache = {};
function memoFib(n) {
  if (cache[n] !== undefined) return cache[n];
  if (n <= 1) return n;
  return cache[n] = memoFib(n-1) + memoFib(n-2);
}`,
    },
    'rf-hydration': {
      answer: 'React attaching event listeners and state to server-rendered HTML, making it interactive. The HTML already exists — React "wakes it up" rather than rebuilding it.',
      code: `// Server sends static HTML
// <div id="root"><button>Click me</button></div>

// React hydrates — attaches onClick without rebuilding DOM
ReactDOM.hydrateRoot(document.getElementById('root'), <App />);`,
    },
    'rf-reconciliation': {
      answer: "React's diffing algorithm that compares the new virtual DOM tree with the previous one to find the minimal set of real DOM changes needed.",
      code: `// React compares old vs new virtual DOM tree
// Same element type → update props only
// Different type → destroy and recreate
// Lists → use key prop to track items`,
    },
    'rf-lazy-loading': {
      answer: 'Deferring loading of resources until they are needed. Images below the fold load when scrolled into view. Components load only when rendered.',
      code: `// Images
<img loading="lazy" src="photo.jpg" />

// React components
const Dashboard = lazy(() => import('./Dashboard'));
<Suspense fallback={<Spinner />}>
  <Dashboard />
</Suspense>`,
    },
    'rf-tree-shaking': {
      answer: 'Dead code elimination by the bundler. Unused exports are removed from the final bundle. Requires ES module static syntax (import/export) — not possible with CommonJS require().',
      code: `// utils.js
export const used = () => 'I am included';
export const unused = () => 'I am removed'; // tree-shaken!

// main.js
import { used } from './utils'; // only 'used' in bundle`,
    },
    'rf-ssr': {
      answer: 'HTML generated on the server per request. Good for SEO and fast First Contentful Paint. Server sends fully rendered HTML — browser displays it before JavaScript loads.',
      code: `// Next.js SSR — runs on server each request
async function Page() {
  const data = await db.getUsers(); // server-only!
  return <UserList users={data} />;
}`,
    },
    'rf-csr': {
      answer: 'HTML built in the browser via JavaScript. Fast after initial load, slow first paint. Server sends empty HTML shell, JS downloads and renders everything client-side.',
      code: `// CSR — browser receives:
// <div id="root"></div>
// Then JS runs and fills it in

ReactDOM.createRoot(document.getElementById('root'))
  .render(<App />);`,
    },
    'rf-auth-authz': {
      answer: 'Authentication = who are you (identity). Authorization = what are you allowed to do (permissions). Auth first, then authz.',
      code: `// Authentication — verify identity
const user = await verifyJWT(token); // who are you?

// Authorization — check permissions
if (!user.roles.includes('admin')) {
  throw new Error('Forbidden'); // what can you do?
}`,
    },
    'rf-cors': {
      answer: "Cross-Origin Resource Sharing. Browser security policy that blocks cross-origin requests unless the server explicitly allows them via headers. Only browsers enforce it — curl and Postman are not affected.",
      code: `// Server must send:
Access-Control-Allow-Origin: https://myapp.com
Access-Control-Allow-Methods: GET, POST

// Preflight for non-simple requests:
// Browser sends OPTIONS first, checks headers, then real request`,
    },
    'rf-xss': {
      answer: 'Cross-Site Scripting. Attacker injects malicious scripts into your page that run in other users\' browsers. Fix: textContent not innerHTML, CSP headers, sanitize user input.',
      code: `// ❌ Vulnerable
element.innerHTML = userInput; // executes scripts!

// ✅ Safe
element.textContent = userInput; // always literal text

// ✅ React JSX escapes by default
<div>{userInput}</div> // safe`,
    },
    'rf-csrf': {
      answer: 'Cross-Site Request Forgery. Tricks authenticated users into making unintended requests. Fix: SameSite cookies, CSRF tokens, check Origin header.',
      code: `// Fix: SameSite cookie
Set-Cookie: session=abc; SameSite=Strict; HttpOnly

// Fix: CSRF token in header
headers: { 'X-CSRF-Token': csrfToken }`,
    },
    'rf-optimistic-ui': {
      answer: 'Update UI immediately before server confirms, assuming success. Roll back on failure. Creates instant-feeling interactions.',
      code: `// Optimistic like
function handleLike(postId) {
  setLiked(true);      // immediate UI update
  setCount(c => c+1);  // assume success
  api.like(postId).catch(() => {
    setLiked(false);   // rollback on error
    setCount(c => c-1);
  });
}`,
    },
    'rf-virtualization': {
      answer: 'Only rendering DOM nodes for visible list items. A list of 100,000 items only has ~20-30 DOM nodes at any time. Libraries: TanStack Virtual, react-window.',
      code: `// Without virtualization: 100k DOM nodes
items.map(item => <div key={item.id}>{item.name}</div>)

// With virtualization: only ~20 DOM nodes
const virtualizer = useVirtualizer({
  count: items.length,
  getScrollElement: () => parentRef.current,
  estimateSize: () => 48,
});`,
    },
    'rf-code-splitting': {
      answer: 'Breaking the JS bundle into chunks loaded on demand. Only download code for the current page/feature. Reduces initial load time dramatically.',
      code: `// Route-based splitting
const Dashboard = lazy(() => import('./Dashboard'));
const Settings  = lazy(() => import('./Settings'));

// Component-based splitting
const HeavyChart = lazy(() => import('./HeavyChart'));
{showChart && (
  <Suspense fallback={<Spinner />}>
    <HeavyChart />
  </Suspense>
)}`,
    },
  };

  const content = item?.id ? answers[item.id] : null;

  return (
    <div style={c.wrap}>
      <RevealCard color='#ef444440' delay={0}>
        <div style={c.title('#ef4444')}>⚡ Rapid Fire Practice</div>
        <p style={c.prose}>
          In rapid-fire interview rounds, you need <strong style={{ color: '#ef4444' }}>crisp answers in under 30 seconds</strong>. Practice saying these out loud until they're automatic.
        </p>
      </RevealCard>

      {content ? (
        <>
          <div style={c.card('#eab30840', '#1a1000')}>
            <div style={c.title('#eab308')}>📝 ONE-LINER ANSWER</div>
            <p style={{ ...c.prose, fontSize: 14, fontWeight: 600, lineHeight: 1.8 }}>
              {content.answer}
            </p>
          </div>

          {content.code && (
            <div style={c.card()}>
              <div style={c.title('#4facfe')}>💻 CODE EXAMPLE</div>
              <div style={c.code}>{content.code}</div>
            </div>
          )}
        </>
      ) : (
        <div style={c.card('#2a3f5f40', '#0d1829')}>
          <div style={{ ...c.muted, textAlign: 'center', padding: 16 }}>
            Quick answer for <strong style={{ color: '#e2e8f0' }}>{item?.title}</strong>:<br /><br />
            Study the explanation above, then practice explaining it in one sentence.
          </div>
        </div>
      )}

      <div style={c.card('#052210', '#0a4420')}>
        <div style={c.title('#00ff88')}>🎯 HOW TO ANSWER IN 30 SECONDS</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {[
            '1. Give the one-line definition first',
            '2. State the key difference from similar concepts',
            '3. Give a one-line real-world example',
            '4. Stop — don\'t over-explain in rapid-fire',
          ].map((tip, i) => (
            <div key={i} style={{ fontSize: 13, color: '#9ca3af', display: 'flex', gap: 8 }}>
              <span style={{ color: '#00ff88', flexShrink: 0 }}>→</span>
              <span>{tip}</span>
            </div>
          ))}
        </div>
      </div>

      <InterviewMeter topics={[
        { topic: 'Speed of answer (under 30 seconds)', freq: 95 },
        { topic: 'Definition given immediately without hesitation', freq: 90 },
        { topic: 'Code example if asked', freq: 70 },
        { topic: 'Difference from similar concept mentioned', freq: 75 },
      ]} />
    </div>
  );
};

export const ObservablesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 The Problem With Promises</div>
      <p style={c.prose}>
        Promises are great — but they only give you <strong style={{ color: '#ef4444' }}>one value, one time</strong>. What if you need to handle a stream of events — user clicks, WebSocket messages, search input changes — over time? That's where Observables come in.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="📺"
      title="Promise = movie rental, Observable = live TV channel"
      analogy="A Promise is like renting a movie — you get one thing, it plays once, it's done. An Observable is like a live TV channel — it streams continuously, you can tune in (subscribe) and tune out (unsubscribe) whenever you want, and the same channel can have multiple viewers."
      connection="Promise resolves once with one value. Observable emits 0 to N values over time, only starts when subscribed, and can be cancelled."
    />

    <StorySteps steps={[
      {
        title: 'Promise — one value, starts immediately',
        color: '#ef4444',
        desc: 'A Promise starts executing the moment it is created (eager). It settles exactly once — either fulfilled or rejected. You cannot cancel it.',
        code: `const promise = fetch('/api/data'); // starts NOW
// Can only resolve once
// Cannot be cancelled
// No way to emit multiple values
promise.then(res => res.json()).then(data => {
  console.log(data); // fires exactly once
});`,
      },
      {
        title: 'Observable — stream, starts only when subscribed',
        color: '#06b6d4',
        desc: 'An Observable is lazy — nothing happens until subscribe() is called. It can emit multiple values over time and can be cancelled by unsubscribing.',
        code: `import { fromEvent } from 'rxjs';

// Nothing happens yet — just defining the stream
const clicks$ = fromEvent(button, 'click');

// NOW it starts — subscribing activates it
const sub = clicks$.subscribe(event => {
  console.log('clicked!', event); // fires on EVERY click
});

// Cancel anytime — cleans up the event listener
sub.unsubscribe();`,
      },
      {
        title: 'Operators — transform streams',
        color: '#a855f7',
        desc: 'RxJS operators like map, filter, debounceTime, switchMap transform streams in a pipeline. This is where Observables truly shine over Promises.',
        code: `import { fromEvent } from 'rxjs';
import { map, debounceTime, switchMap } from 'rxjs/operators';

// Search as you type — all handled in one pipeline
const search$ = fromEvent(input, 'input').pipe(
  map(e => e.target.value),        // extract value
  debounceTime(300),               // wait for pause
  switchMap(q =>                   // cancel previous, fetch new
    fetch('/api/search?q=' + q).then(r => r.json())
  )
);
search$.subscribe(results => renderResults(results));`,
      },
      {
        title: 'Cold vs Hot Observables',
        color: '#00ff88',
        desc: 'Cold: each subscriber gets its own independent execution (like a Netflix movie). Hot: all subscribers share one execution (like a live stream).',
        code: `import { interval, share } from 'rxjs';

// Cold — each subscriber gets own timer starting from 0
const cold$ = interval(1000);
cold$.subscribe(n => console.log('A:', n)); // 0, 1, 2...
cold$.subscribe(n => console.log('B:', n)); // also 0, 1, 2...

// Hot — all subscribers share one timer
const hot$ = cold$.pipe(share());
hot$.subscribe(n => console.log('A:', n)); // 0, 1, 2...
hot$.subscribe(n => console.log('B:', n)); // joins mid-stream`,
      },
    ]} />

    <InlinePoll
      question="You're building a search-as-you-type feature. User types quickly and each keystroke fires a request. Which RxJS operator prevents stale results from overwriting fresh ones?"
      options={[
        'mergeMap — keeps all requests running',
        'switchMap — cancels the previous request when a new one starts',
        'concatMap — queues all requests in order',
        'exhaustMap — ignores new requests while one is running',
      ]}
      correct={1}
      explanation="switchMap subscribes to the new inner observable and cancels/unsubscribes from the previous one. Each new keystroke cancels the previous in-flight request — only the latest request can update the UI."
    />

    <CommonMistake
      mistake="'Observables are just Promises with more features — I can always use async/await instead.'"
      fix="Observables and Promises solve different problems. Promises are for single async values. Observables are for streams — multiple values over time (user events, WebSockets, timers, real-time data). You can't model a click stream or WebSocket with a Promise."
    />

    <DidYouKnow
      fact="Angular uses Observables everywhere (HttpClient returns Observables, not Promises). The Angular team chose RxJS because Angular apps are inherently event-driven — forms, routing, HTTP all emit streams of events over time."
      color="#06b6d4"
    />

    <InterviewMeter topics={[
      { topic: 'Promise vs Observable — key differences', freq: 75 },
      { topic: 'Cold vs Hot Observables', freq: 60 },
      { topic: 'switchMap vs mergeMap use cases', freq: 65 },
      { topic: 'When to use Observable vs Promise', freq: 70 },
    ]} />
  </div>
);

export const WebWorkersLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 The Problem: JavaScript is Single-Threaded</div>
      <p style={c.prose}>
        JavaScript runs on <strong style={{ color: '#ef4444' }}>one thread</strong>. If you run a heavy computation — sorting 1 million items, image processing, complex calculations — the entire UI <strong style={{ color: '#ef4444' }}>freezes</strong>. No scrolling, no clicks, no animations. Web Workers solve this by moving work to a background thread.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="👷"
      title="A restaurant kitchen with a prep cook"
      analogy="The head chef (main thread) takes orders, plates food, and talks to customers — everything the customer sees. The prep cook (Web Worker) works in the back chopping vegetables, making stocks — heavy background work. They communicate via a pass-through window (postMessage). The head chef never freezes because the prep work happens separately."
      connection="Main thread handles UI, events, and rendering. Web Worker handles heavy computation in background. They communicate only via postMessage — no shared access."
    />

    <StorySteps steps={[
      {
        title: 'Without Web Workers — UI freezes',
        color: '#ef4444',
        desc: 'Heavy synchronous code blocks the main thread. The browser cannot paint, respond to clicks, or run animations until it finishes.',
        code: `// ❌ This freezes the browser for ~1 second
function heavyCalc(n) {
  let result = 0;
  for (let i = 0; i < n * 1000000; i++) result += i;
  return result;
}

button.onclick = () => {
  const result = heavyCalc(100); // UI FROZEN during this
  display.textContent = result;  // user sees nothing until done
};`,
      },
      {
        title: 'Create a Worker — separate thread',
        color: '#a855f7',
        desc: 'Move the heavy work to a worker file. The main thread sends a message, continues running, and receives the result when ready.',
        code: `// worker.js (separate file)
self.onmessage = (e) => {
  let result = 0;
  for (let i = 0; i < e.data * 1000000; i++) result += i;
  self.postMessage(result); // send result back
};

// main.js
const worker = new Worker('./worker.js');

button.onclick = () => {
  worker.postMessage(100);   // send work to background
  // UI stays responsive here!
};

worker.onmessage = (e) => {
  display.textContent = e.data; // receive result
};`,
      },
      {
        title: 'Inline Worker — no separate file needed',
        color: '#4facfe',
        desc: 'Create the worker from a Blob URL — useful when you want to keep everything in one file or are working with a bundler.',
        code: `const workerCode = \`
  self.onmessage = (e) => {
    // fibonacci — intentionally slow
    function fib(n) {
      if (n <= 1) return n;
      return fib(n-1) + fib(n-2);
    }
    self.postMessage(fib(e.data));
  };
\`;

const blob = new Blob([workerCode], { type: 'application/javascript' });
const worker = new Worker(URL.createObjectURL(blob));

worker.postMessage(42);
worker.onmessage = e => console.log(e.data); // result
worker.terminate(); // clean up when done`,
      },
      {
        title: 'Transferable Objects — zero copy',
        color: '#00ff88',
        desc: 'postMessage copies data by default. For large buffers, transfer ownership instead — zero copy, much faster. The original becomes unusable after transfer.',
        code: `// ❌ Default — copies the entire 100MB buffer
const buffer = new ArrayBuffer(100 * 1024 * 1024);
worker.postMessage({ buffer }); // slow copy

// ✅ Transfer — zero copy, ownership moves to worker
worker.postMessage({ buffer }, [buffer]);
// buffer is now detached in main thread
// buffer.byteLength === 0

// SharedArrayBuffer — true shared memory
const shared = new SharedArrayBuffer(4);
const view = new Int32Array(shared);
Atomics.store(view, 0, 42);
worker.postMessage({ shared }); // SAME memory, no copy
// Changes in worker are instantly visible in main thread`,
      },
    ]} />

    <InlinePoll
      question="What is the key limitation of Web Workers compared to the main thread?"
      options={[
        'They are much slower',
        'They cannot access the DOM, window, or document — communication only via postMessage',
        'They only work in Chrome',
        'They cannot use async/await',
      ]}
      correct={1}
      explanation="Web Workers run in complete isolation from the main thread. No DOM access, no window, no document. They can only communicate via postMessage(). This isolation is intentional — it prevents race conditions on shared DOM state."
    />

    <CommonMistake
      mistake="'I'll use a Web Worker to speed up every function in my app.'"
      fix="Web Workers have overhead — creating the worker, serializing/deserializing messages (postMessage copies data). They only help for genuinely heavy computations (>50ms). For light work, the overhead costs more than the benefit. Profile first."
    />

    <DidYouKnow
      fact="SharedArrayBuffer was disabled in all browsers in 2018 after the Spectre CPU vulnerability was discovered — it enabled timing attacks. It was re-enabled in 2020 but now requires two security headers: Cross-Origin-Opener-Policy: same-origin and Cross-Origin-Embedder-Policy: require-corp."
      color="#a855f7"
    />

    <InterviewMeter topics={[
      { topic: 'What Web Workers solve and their limitations', freq: 70 },
      { topic: 'postMessage and the structured clone algorithm', freq: 60 },
      { topic: 'Transferable objects vs copying', freq: 55 },
      { topic: 'SharedArrayBuffer and Atomics', freq: 45 },
      { topic: 'Service Worker vs Dedicated Worker differences', freq: 65 },
    ]} />
  </div>
);

export const ModulePatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 The Problem: Everything Was Global</div>
      <p style={c.prose}>
        Before ES modules, every JavaScript file shared the <strong style={{ color: '#ef4444' }}>same global scope</strong>. Include 3 libraries and they all dump variables onto <code style={{ color: '#ef4444' }}>window</code>. Name collisions, accidental overwrites, impossible to maintain. The Module Pattern was the solution.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🏪"
      title="A shop with a front counter and a back room"
      analogy="A shop has a back room (private — staff only, inventory, cash register) and a front counter (public — what customers can see and interact with). Customers can buy items and ask questions, but they can't walk into the back room and change prices directly."
      connection="The module pattern creates a private scope (back room) using closures, and returns a public API (front counter) — the only way to interact with the private state."
    />

    <StorySteps steps={[
      {
        title: 'The problem — global scope pollution',
        color: '#ef4444',
        desc: 'Without modules, every variable and function is global. Multiple scripts conflict with each other.',
        code: `// script1.js
var count = 0;
function increment() { count++; }

// script2.js (loaded after)
var count = 'hello'; // accidentally overwrites!
increment();
console.log(count); // 'hello' — broken!`,
      },
      {
        title: 'IIFE — create a private scope',
        color: '#eab308',
        desc: 'An Immediately Invoked Function Expression runs instantly and creates its own scope. Variables inside are private.',
        code: `// IIFE syntax — function that runs immediately
(function() {
  var count = 0;        // private to this scope
  function increment() { count++; }
  window.myCounter = { increment, getCount: () => count };
})(); // ← the () invokes it immediately

// count is not accessible outside
console.log(typeof count); // 'undefined' — private!
myCounter.increment();
myCounter.getCount(); // 1`,
      },
      {
        title: 'Revealing Module Pattern',
        color: '#4facfe',
        desc: 'Define everything privately, then explicitly return only what should be public. The cleanest pre-ES6 encapsulation pattern.',
        code: `const UserModule = (function() {
  // Private
  let _users = [];
  let _currentUser = null;

  function _validate(user) {
    return user.name && user.email;
  }

  // Public API — only these are revealed
  return {
    add(user) {
      if (_validate(user)) _users.push(user);
    },
    login(email) {
      _currentUser = _users.find(u => u.email === email);
    },
    getCurrent: () => _currentUser,
    count: () => _users.length,
  };
})();

UserModule.add({ name: 'Alice', email: 'a@a.com' });
UserModule._users; // undefined — truly private`,
      },
      {
        title: 'ES Modules — the modern standard',
        color: '#00ff88',
        desc: 'ES6 modules give us true module scope without IIFEs. Each file is its own scope. Static imports enable tree shaking.',
        code: `// utils.js — module scope, nothing leaks to global
const _private = 'hidden';
export const add = (a, b) => a + b;
export default class Calculator { /* ... */ }

// main.js
import Calculator, { add } from './utils.js';

// Dynamic import — lazy loading / code splitting
const { add: lazyAdd } = await import('./utils.js');

// Named exports for tree shaking
import { add } from './math.js'; // bundler removes unused exports`,
      },
    ]} />

    <InlinePoll
      question="What is the key difference between CommonJS (require) and ES Modules (import)?"
      options={[
        'CommonJS is newer',
        'CommonJS is dynamic and resolved at runtime; ES Modules are static and analyzed at build time — enabling tree shaking',
        'ES Modules only work in browsers',
        'They are identical in behavior',
      ]}
      correct={1}
      explanation="ES Modules use static syntax — you can't conditionally import. This lets bundlers analyze the dependency graph at build time and remove unused exports (tree shaking). CommonJS require() can be called conditionally anywhere — impossible to statically analyze."
    />

    <CommonMistake
      mistake="Using var inside an IIFE and thinking it's block-scoped: (function() { if(true) { var x = 1; } console.log(x); // 1 — not block scoped! })()"
      fix="var is function-scoped, not block-scoped. Even inside an IIFE, var leaks to the function scope. Use let/const for true block scoping. This is one reason ES modules + let/const replaced the IIFE pattern entirely."
    />

    <DidYouKnow
      fact="The jQuery library ($) is one big IIFE: (function(global) { /* entire jQuery */ })(window). This is why jQuery doesn't pollute the global scope except for the single $ variable it explicitly assigns. Every popular pre-ES6 library used this pattern."
      color="#eab308"
    />

    <InterviewMeter topics={[
      { topic: 'What is an IIFE and why was it used', freq: 65 },
      { topic: 'Revealing module pattern explanation', freq: 60 },
      { topic: 'CommonJS vs ES Modules differences', freq: 75 },
      { topic: 'Why ES Modules enable tree shaking', freq: 70 },
      { topic: 'Dynamic import() and code splitting', freq: 65 },
    ]} />
  </div>
);

export const ExecutionContextLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 What Happens Before Your Code Runs?</div>
      <p style={c.prose}>
        Before JavaScript executes a single line, it does a <strong style={{ color: '#4facfe' }}>preparation pass</strong> — scanning your code, registering variables and functions, setting up scope. This is why you can call a function before it's defined. Understanding this separates junior from senior developers.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🎭"
      title="A theatre before the show"
      analogy="Before the play starts, stagehands set up the stage — place props, arrange furniture, position lights. The audience sees nothing yet. Then the curtain rises and the play runs. JavaScript's creation phase is the stagehands setting up. The execution phase is the play."
      connection="Creation phase: JS scans code, allocates memory for variables (var=undefined, let/const=TDZ) and fully hoists function declarations. Execution phase: code runs line by line."
    />

    <StorySteps steps={[
      {
        title: 'Global Execution Context is created first',
        color: '#4facfe',
        desc: 'When your script loads, one Global EC is created. It has a Variable Environment, Lexical Environment, and this binding (= window in browsers).',
        code: `// Global EC created:
// - Variable Environment: { x: undefined, greet: fn }
// - this: window (browser) / global (Node)

var x = 10;
function greet() { return 'hello'; }

// After creation phase runs, execution begins:
console.log(x);    // undefined (creation phase set it)
x = 10;            // now assigned
console.log(x);    // 10`,
      },
      {
        title: 'Each function call creates a new EC',
        color: '#a855f7',
        desc: 'Every function call pushes a new Execution Context onto the Call Stack. It has its own variables, arguments, and this binding.',
        code: `function outer() {
  let a = 1;        // outer EC's variable
  function inner() {
    let b = 2;      // inner EC's variable
    console.log(a); // found via scope chain → 1
    console.log(b); // local → 2
  }
  inner(); // inner EC pushed to call stack
}          // inner EC popped when it returns
outer();   // outer EC pushed, then popped`,
      },
      {
        title: 'Call Stack — LIFO order',
        color: '#eab308',
        desc: 'The call stack tracks which context is currently executing. Last In, First Out. Stack overflow = too many nested calls.',
        code: `function a() { b(); }
function b() { c(); }
function c() {
  console.trace();
  // Call stack: c → b → a → anonymous (global)
}
a();

// Stack overflow example:
function infinite() { infinite(); } // RangeError!
// Each call pushes a new EC — stack runs out of space`,
      },
      {
        title: 'Scope chain — how variables are found',
        color: '#00ff88',
        desc: 'Each EC has a reference to its outer EC\'s lexical environment. JS walks this chain to find variables — local first, then outer, then global.',
        code: `let global = 'G';

function outer() {
  let outerVar = 'O';

  function inner() {
    let innerVar = 'I';
    // Scope chain lookup order:
    console.log(innerVar);  // 1. local ✓
    console.log(outerVar);  // 2. outer scope ✓
    console.log(global);    // 3. global scope ✓
    console.log(missing);   // 4. not found → ReferenceError
  }
  inner();
}`,
      },
    ]} />

    <InlinePoll
      question="What happens during the 'creation phase' of an execution context?"
      options={[
        'Code executes line by line',
        'Variables are allocated in memory: var gets undefined, let/const enter TDZ, function declarations are fully hoisted',
        'The DOM is constructed',
        'Event listeners are registered',
      ]}
      correct={1}
      explanation="The creation phase happens BEFORE any code runs. The engine scans the scope, allocates memory for var (sets to undefined), registers function declarations fully, and places let/const in the Temporal Dead Zone. Only then does execution begin."
    />

    <CommonMistake
      mistake="'let and const are not hoisted' — this is incomplete and technically wrong."
      fix="let and const ARE hoisted during the creation phase — the engine registers them. But unlike var, they are NOT initialized. They exist in the Temporal Dead Zone (TDZ) until their declaration line. Accessing them before that line throws ReferenceError — not because they don't exist, but because they're uninitialized."
    />

    <DidYouKnow
      fact="Every closure is tied to its outer execution context's Lexical Environment object. When a function returns but inner functions still reference its variables, the Lexical Environment object is kept alive in memory — this is the mechanical reason closures work."
      color="#4facfe"
    />

    <InterviewMeter topics={[
      { topic: 'Creation phase vs execution phase', freq: 70 },
      { topic: 'Call stack explanation and stack overflow', freq: 75 },
      { topic: 'Scope chain and variable lookup order', freq: 65 },
      { topic: 'How closures relate to execution contexts', freq: 60 },
    ]} />
  </div>
);

export const DeepCloningLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 The Problem: Shared References</div>
      <p style={c.prose}>
        In JavaScript, objects are stored by <strong style={{ color: '#ef4444' }}>reference</strong>. Copying an object with <code style={{ color: '#ef4444' }}>= </code> or spread just copies the pointer. Modify the copy and you modify the original. Deep cloning creates a truly independent copy.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="📄"
      title="Photocopy vs carbon copy"
      analogy="A shallow copy is like a carbon copy — if you write on the original, the copy changes too because they share the same underlying paper. A deep copy is like a full photocopy — completely independent, changes to one don't affect the other at any level."
      connection="Shallow copy: top-level properties are independent, but nested objects are still the same reference. Deep copy: every nested object is independently copied."
    />

    <StorySteps steps={[
      {
        title: 'The problem — shallow copy gotcha',
        color: '#ef4444',
        desc: 'Spread and Object.assign only copy the top level. Nested objects are still shared references.',
        code: `const original = { name: 'Alice', address: { city: 'NY' } };

const shallow = { ...original }; // spread — shallow copy
shallow.name = 'Bob';            // ✓ independent
shallow.address.city = 'LA';     // ❌ mutates original!

console.log(original.address.city); // 'LA' — oops!
console.log(original.name);         // 'Alice' — ok`,
      },
      {
        title: 'JSON method — simple but limited',
        color: '#eab308',
        desc: 'JSON.parse(JSON.stringify()) works for simple objects but silently corrupts or drops many types.',
        code: `const obj = {
  name: 'Alice',
  date: new Date(),       // → becomes string!
  fn: () => 'hello',      // → dropped silently!
  undef: undefined,       // → dropped silently!
  map: new Map([[1, 2]]), // → becomes {}!
};

const clone = JSON.parse(JSON.stringify(obj));
// clone.date is STRING not Date
// clone.fn is undefined
// clone.map is {}
// ❌ Never use for objects with special types`,
      },
      {
        title: 'structuredClone — modern best practice',
        color: '#00ff88',
        desc: 'Built-in since Node 17 and modern browsers. Handles most types correctly including Date, Map, Set, ArrayBuffer, and circular references.',
        code: `const obj = {
  date: new Date(),
  map: new Map([[1, 'a']]),
  set: new Set([1, 2, 3]),
  buffer: new ArrayBuffer(8),
  nested: { deep: { value: 42 } },
};

const clone = structuredClone(obj);
clone.date instanceof Date; // true ✓
clone.map instanceof Map;   // true ✓
clone.nested.deep.value = 99;
obj.nested.deep.value;      // still 42 ✓

// Also handles circular references:
const circular = {};
circular.self = circular;
structuredClone(circular); // works! ✓`,
      },
      {
        title: 'Custom recursive clone — handles everything',
        color: '#a855f7',
        desc: 'For maximum control — handles class instances, prototype chains, functions. Use WeakMap for circular reference detection.',
        code: `function deepClone(value, seen = new WeakMap()) {
  if (value === null || typeof value !== 'object') return value;
  if (seen.has(value)) return seen.get(value); // circular ref
  if (value instanceof Date) return new Date(value);
  if (value instanceof RegExp) return new RegExp(value);
  if (value instanceof Map)
    return new Map([...value].map(([k,v]) =>
      [deepClone(k, seen), deepClone(v, seen)]));
  if (value instanceof Set)
    return new Set([...value].map(v => deepClone(v, seen)));

  const clone = Array.isArray(value) ? [] :
    Object.create(Object.getPrototypeOf(value));
  seen.set(value, clone);
  for (const key of Reflect.ownKeys(value)) {
    clone[key] = deepClone(value[key], seen);
  }
  return clone;
}`,
      },
    ]} />

    <InlinePoll
      question="Which method handles circular references AND preserves Date objects correctly?"
      options={[
        'JSON.parse(JSON.stringify())',
        'Object.assign({}, obj)',
        'structuredClone()',
        'Spread operator {...obj}',
      ]}
      correct={2}
      explanation="structuredClone() is the modern standard. It handles circular references, Date, Map, Set, ArrayBuffer, and typed arrays. JSON.parse/stringify throws on circular refs and converts Date to string. Spread and Object.assign are shallow only."
    />

    <CommonMistake
      mistake="Using JSON.parse(JSON.stringify(obj)) for all deep cloning needs in production code."
      fix="It silently drops functions, undefined, and Symbol properties, converts Date to string, converts Map/Set to {}, and throws on circular references. Use structuredClone() for modern code. If you need to clone class instances with methods, use a recursive custom clone or lodash cloneDeep."
    />

    <DidYouKnow
      fact="Immer.js takes a different approach entirely — instead of cloning, it uses Proxy to let you write 'mutating' code that actually produces an immutable copy. produce(state, draft => { draft.count++ }) returns a new state without mutating the original. This is how Redux Toolkit works internally."
      color="#06b6d4"
    />

    <InterviewMeter topics={[
      { topic: 'Shallow vs deep copy difference', freq: 80 },
      { topic: 'JSON method limitations', freq: 75 },
      { topic: 'structuredClone usage and limitations', freq: 65 },
      { topic: 'Implementing recursive deep clone', freq: 60 },
    ]} />
  </div>
);

export const ProxyReflectLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Intercepting JavaScript's Core Operations</div>
      <p style={c.prose}>
        What if you could intercept every property access, assignment, function call, and <code>in</code> check on an object — and run your own code in response? That's exactly what <strong style={{ color: '#00ff88' }}>Proxy</strong> does. It's how Vue 3's reactivity system works.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🔐"
      title="A building security desk"
      analogy="When someone tries to enter a building, security intercepts them first — checks their ID, logs their visit, allows or denies entry, then either lets them through or redirects them. Proxy is the security desk for JavaScript objects — every operation is intercepted before reaching the real object."
      connection="Every get, set, delete, or has operation on a Proxied object goes through your handler traps first. You decide what happens — validate, log, transform, or just pass through."
    />

    <StorySteps steps={[
      {
        title: 'Basic Proxy — intercept get and set',
        color: '#00ff88',
        desc: 'Wrap an object with a Proxy and define traps. get intercepts property reads, set intercepts property writes.',
        code: `const handler = {
  get(target, key, receiver) {
    console.log('Reading:', key);
    return Reflect.get(target, key, receiver); // pass through
  },
  set(target, key, value, receiver) {
    console.log('Writing:', key, '=', value);
    return Reflect.set(target, key, value, receiver);
  },
};

const obj = new Proxy({ name: 'Alice' }, handler);
obj.name;         // logs: "Reading: name"
obj.age = 30;     // logs: "Writing: age = 30"`,
      },
      {
        title: 'Validation Proxy',
        color: '#4facfe',
        desc: 'Reject invalid values before they reach the object. Throw meaningful errors instead of silent corruption.',
        code: `function createValidated(target, rules) {
  return new Proxy(target, {
    set(target, key, value, receiver) {
      if (rules[key]) {
        const error = rules[key](value);
        if (error) throw new TypeError(\`\${key}: \${error}\`);
      }
      return Reflect.set(target, key, value, receiver);
    }
  });
}

const user = createValidated({}, {
  age:   v => v < 0    ? 'Cannot be negative'   : null,
  email: v => !v.includes('@') ? 'Invalid email' : null,
});

user.age = 25;            // ✓
user.age = -1;            // TypeError: age: Cannot be negative
user.email = 'notvalid';  // TypeError: email: Invalid email`,
      },
      {
        title: 'Reactive Proxy — Vue 3 internals',
        color: '#a855f7',
        desc: 'Track which properties components read (dependency tracking), then trigger re-renders when those properties change.',
        code: `function reactive(obj) {
  return new Proxy(obj, {
    get(target, key, receiver) {
      track(key);  // record: "this component uses key"
      return Reflect.get(target, key, receiver);
    },
    set(target, key, value, receiver) {
      const result = Reflect.set(target, key, value, receiver);
      trigger(key); // notify: "key changed, re-render!"
      return result;
    }
  });
}

const state = reactive({ count: 0, name: 'Alice' });
// Component reads state.count → tracked
state.count++; // → triggers re-render for count subscribers`,
      },
      {
        title: 'Why use Reflect inside traps?',
        color: '#eab308',
        desc: 'Always use Reflect methods inside traps — they correctly handle prototype chains, setters, and return the right boolean value.',
        code: `// ❌ Direct target access — wrong
set(target, key, value) {
  target[key] = value; // misses prototype setters!
  return true;         // must manually return true
}

// ✅ Reflect — correct
set(target, key, value, receiver) {
  return Reflect.set(target, key, value, receiver);
  // handles prototype chain ✓
  // handles setters correctly ✓
  // returns false if assignment fails ✓
}`,
      },
    ]} />

    <InlinePoll
      question="Which JavaScript framework's reactivity system (reactive(), ref()) is built entirely on Proxy?"
      options={[
        'React — useState uses Proxy internally',
        'Vue 3 — reactive() wraps objects in Proxy to track and trigger updates',
        'Angular — uses Zone.js with Proxy',
        'Svelte — compiles to Proxy calls',
      ]}
      correct={1}
      explanation="Vue 3 completely rewrote its reactivity system in Vue 3 using Proxy (replacing Vue 2's Object.defineProperty). The get trap tracks dependencies, the set trap triggers updates. This is why Vue 3 reactivity works on new properties added after creation — Proxy intercepts all operations."
    />

    <CommonMistake
      mistake="Using target[key] = value directly inside a set trap instead of Reflect.set()."
      fix="Direct assignment in a proxy trap bypasses the prototype chain and doesn't handle setters correctly. Always use Reflect.set(target, key, value, receiver) — it behaves identically to normal assignment but is correct in all edge cases and returns the proper boolean indicating success or failure."
    />

    <DidYouKnow
      fact="Proxy cannot be polyfilled — it's a fundamental language feature that requires engine support. This is why Vue 3 dropped support for IE11 (no Proxy support). Vue 2 used Object.defineProperty which could be polyfilled but had limitations: couldn't detect property addition or array index changes."
      color="#00ff88"
    />

    <InterviewMeter topics={[
      { topic: 'What Proxy does and basic trap examples', freq: 65 },
      { topic: 'Why use Reflect inside traps', freq: 55 },
      { topic: 'Vue 3 reactivity uses Proxy', freq: 60 },
      { topic: 'Validation and logging use cases', freq: 60 },
    ]} />
  </div>
);

export const GeneratorsAsyncLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Generators: Pauseable Functions</div>
      <p style={c.prose}>
        Normal functions run to completion and return once. Generators can <strong style={{ color: '#eab308' }}>pause mid-execution</strong>, yield a value, and resume later. They're the foundation of async/await and enable powerful lazy evaluation patterns.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="⏸️"
      title="A music player with pause/resume"
      analogy="A normal function is like a song that plays from start to finish with no way to pause. A generator is like a music player — you can pause at any point, hand control back to the listener, and resume exactly where you left off when they press play again."
      connection="yield is the pause button. next() is the play button. The generator remembers exactly where it paused — all local variables are preserved between calls."
    />

    <StorySteps steps={[
      {
        title: 'Basic generator — yield pauses execution',
        color: '#eab308',
        desc: 'function* declares a generator. yield pauses and returns a value. next() resumes from where it paused.',
        code: `function* sequence() {
  console.log('start');
  yield 1;              // pause, return 1
  console.log('middle');
  yield 2;              // pause, return 2
  console.log('end');
  return 3;             // done: true
}

const gen = sequence();  // nothing runs yet
gen.next(); // logs 'start', returns {value:1, done:false}
gen.next(); // logs 'middle', returns {value:2, done:false}
gen.next(); // logs 'end', returns {value:3, done:true}
gen.next(); // {value:undefined, done:true}`,
      },
      {
        title: 'Generators implement iterables',
        color: '#4facfe',
        desc: 'Generators automatically implement the iterator protocol. They work with for...of, spread, and destructuring.',
        code: `function* range(start, end, step = 1) {
  for (let i = start; i < end; i += step) {
    yield i;
  }
}

// Works with for...of
for (const n of range(0, 5)) console.log(n); // 0,1,2,3,4

// Works with spread
[...range(0, 5)];         // [0, 1, 2, 3, 4]

// Infinite sequence — only computes on demand
function* naturals() {
  let n = 1;
  while (true) yield n++;
}
const [first, second, third] = naturals(); // 1, 2, 3
// Never infinite-loops — stops when destructuring is done`,
      },
      {
        title: 'Two-way communication with next(value)',
        color: '#a855f7',
        desc: 'You can send values INTO a generator via next(value). The value becomes the result of the yield expression.',
        code: `function* calculator() {
  let total = 0;
  while (true) {
    const input = yield total; // receive value, send total
    if (input === null) return total;
    total += input;
  }
}

const calc = calculator();
calc.next();    // start, {value:0}
calc.next(10);  // send 10, {value:10}
calc.next(5);   // send 5,  {value:15}
calc.next(3);   // send 3,  {value:18}
calc.next(null);// end,     {value:18, done:true}`,
      },
      {
        title: 'Async generators — async iteration',
        color: '#00ff88',
        desc: 'Combine async/await with generators for streaming async data. Use for await...of to consume.',
        code: `// Async generator — yields Promises
async function* fetchPages(url) {
  let page = 1;
  while (true) {
    const res = await fetch(\`\${url}?page=\${page}\`);
    const data = await res.json();
    if (data.items.length === 0) return;
    yield data.items; // yield each page
    page++;
  }
}

// Consume with for await...of
for await (const items of fetchPages('/api/products')) {
  console.log('Got page:', items);
  renderItems(items);
  // automatically handles pagination!
}`,
      },
    ]} />

    <InlinePoll
      question="What does calling a generator function return?"
      options={[
        'The first yielded value',
        'A generator iterator object — nothing executes until you call .next()',
        'A Promise',
        'undefined',
      ]}
      correct={1}
      explanation="Calling a generator function does NOT execute any code. It returns a generator object (iterator). Code only starts running when you call .next() for the first time — generators are completely lazy."
    />

    <CommonMistake
      mistake="Thinking async/await and generators are different things entirely."
      fix="async/await is syntactic sugar for generators + Promises. Under the hood, async function compiles to a generator that yields Promises. The JS runtime's async scheduler is essentially doing what libraries like co.js did manually before async/await existed."
    />

    <DidYouKnow
      fact="Before async/await existed (pre-ES2017), developers used generators + the co library to write async code that looked synchronous: co(function*() { const data = yield fetch('/api'); }). This was so popular that TC39 standardized async/await as cleaner syntax for the same pattern."
      color="#eab308"
    />

    <InterviewMeter topics={[
      { topic: 'What generators are and how yield works', freq: 65 },
      { topic: 'Making objects iterable with generator Symbol.iterator', freq: 60 },
      { topic: 'Async generators for streaming data', freq: 50 },
      { topic: 'Relationship between generators and async/await', freq: 55 },
    ]} />
  </div>
);

export const WeakRefsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 The Problem: Memory Leaks From Caches</div>
      <p style={c.prose}>
        Caches are great for performance — but a cache that holds strong references to objects <strong style={{ color: '#ef4444' }}>prevents garbage collection</strong>. Your cache grows forever and leaks memory. WeakMap, WeakSet, and WeakRef solve this by holding <strong style={{ color: '#06b6d4' }}>weak references</strong> that don't prevent GC.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🪁"
      title="A sticky note vs a locked safe"
      analogy="A strong reference is like locking an object in a safe — it cannot be removed as long as the safe exists. A weak reference is like a sticky note pointing to an object — if the object is moved or thrown away, the sticky note just becomes invalid. The sticky note doesn't KEEP the object alive."
      connection="WeakMap keys are weak references. If the key object is garbage collected, the WeakMap entry automatically disappears — the cache cleans itself up."
    />

    <StorySteps steps={[
      {
        title: 'Map cache — leaks memory',
        color: '#ef4444',
        desc: 'A regular Map keeps strong references to its keys. Even if the key object is no longer used anywhere else, the Map prevents it from being garbage collected.',
        code: `const cache = new Map();

function processUser(user) {
  if (cache.has(user)) return cache.get(user);
  const result = expensiveCompute(user);
  cache.set(user, result);
  return result;
}

// Problem: even after user is "done", cache keeps it alive
// The Map holds a strong reference — GC can't collect it
// cache grows forever → memory leak!`,
      },
      {
        title: 'WeakMap cache — auto-cleanup',
        color: '#06b6d4',
        desc: 'WeakMap keys are weakly held. When the key object is GC\'d, the entry disappears automatically.',
        code: `const cache = new WeakMap(); // keys are weak references

function processUser(user) {
  if (cache.has(user)) return cache.get(user);
  const result = expensiveCompute(user);
  cache.set(user, result);
  return result;
}

// When user object is no longer referenced elsewhere,
// GC can collect it AND the cache entry disappears
// Zero memory leak, zero manual cleanup needed ✓

// Also perfect for private data:
const _private = new WeakMap();
class Person {
  constructor(name, ssn) {
    _private.set(this, { ssn }); // private, freed with instance
    this.name = name;
  }
  getSSN() { return _private.get(this).ssn; }
}`,
      },
      {
        title: 'WeakSet — track without preventing GC',
        color: '#a855f7',
        desc: 'WeakSet stores objects weakly. Perfect for tracking which objects have been processed without preventing their collection.',
        code: `const processed = new WeakSet();

function processOnce(item) {
  if (processed.has(item)) {
    console.log('Already processed');
    return;
  }
  doProcess(item);
  processed.add(item); // tracked, but weakly held
}

// When item is GC'd, WeakSet entry disappears too
// No manual cleanup needed

// Real use case: tracking visited DOM nodes
const visitedNodes = new WeakSet();
function markVisited(node) { visitedNodes.add(node); }
function isVisited(node)   { return visitedNodes.has(node); }
// When DOM node is removed, WeakSet cleans itself up`,
      },
      {
        title: 'WeakRef + FinalizationRegistry',
        color: '#00ff88',
        desc: 'WeakRef wraps an object with a weak reference. FinalizationRegistry runs cleanup when the object is collected.',
        code: `// WeakRef — holds weak reference, object may be GC'd
let bigObject = { data: new Array(1000000).fill('x') };
const ref = new WeakRef(bigObject);

// Access the object if still alive:
const obj = ref.deref();
if (obj) {
  console.log(obj.data.length); // 1000000
} else {
  console.log('Already garbage collected');
}

// FinalizationRegistry — cleanup callback after GC
const registry = new FinalizationRegistry((key) => {
  console.log(\`\${key} was garbage collected — cleaning up\`);
  cleanupExternalResource(key);
});

registry.register(bigObject, 'bigObject');
bigObject = null; // eligible for GC
// Later: "bigObject was garbage collected — cleaning up"`,
      },
    ]} />

    <InlinePoll
      question="Why can't you iterate over a WeakMap or check its size?"
      options={[
        "It's a bug that will be fixed",
        'Entries can disappear at any time due to GC — iteration would be non-deterministic and give inconsistent results',
        'For security reasons',
        'WeakMap is too new to support iteration',
      ]}
      correct={1}
      explanation="The GC can remove WeakMap entries between any two JavaScript instructions. If iteration were allowed, you might start iterating 5 entries and end with 3 because GC ran mid-iteration. The non-iterability is intentional — it's a consequence of weak references, not a limitation."
    />

    <CommonMistake
      mistake="Using WeakMap when you need to iterate over entries or know the cache size."
      fix="WeakMap is intentionally non-iterable with no .size property. If you need to iterate, count, or list entries — use a regular Map. Use WeakMap only when: keys are objects you don't own, you want auto-cleanup, and you don't need to enumerate entries."
    />

    <DidYouKnow
      fact="React uses WeakMap internally to store fiber data associated with DOM nodes. When a DOM node is removed, the associated fiber data is automatically garbage collected — no manual cleanup needed. This is WeakMap's auto-cleanup in production at scale."
      color="#06b6d4"
    />

    <InterviewMeter topics={[
      { topic: 'WeakMap vs Map for caching — memory implications', freq: 70 },
      { topic: 'Why WeakMap is non-iterable', freq: 60 },
      { topic: 'WeakRef.deref() usage pattern', freq: 50 },
      { topic: 'FinalizationRegistry for cleanup', freq: 45 },
    ]} />
  </div>
);

export const CurryingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Functions That Return Functions</div>
      <p style={c.prose}>
        Currying transforms a function that takes multiple arguments into a chain of functions each taking <strong style={{ color: '#f97316' }}>one argument at a time</strong>. It sounds academic, but it enables powerful patterns: reusable specialized functions, clean data pipelines, and point-free programming.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🍕"
      title="Customizing a pizza order step by step"
      analogy="Instead of ordering a pizza all at once ('large, pepperoni, thin crust'), you make one decision at a time: first choose size, get back a function for toppings, choose pepperoni, get back a function for crust. Each step returns a more specialized order function."
      connection="curry(pizza)('large')('pepperoni')('thin') — each call takes one argument and returns the next function in the chain. Partial application: orderLargePizza = pizza('large') — reuse this for all large pizzas."
    />

    <StorySteps steps={[
      {
        title: 'Manual currying — functions returning functions',
        color: '#f97316',
        desc: 'Transform a multi-argument function into a chain of single-argument functions using arrow function nesting.',
        code: `// Regular function
const add = (a, b) => a + b;
add(3, 4); // 7

// Curried version
const curriedAdd = a => b => a + b;
curriedAdd(3)(4); // 7

// Power: partial application — create specialized functions
const add10 = curriedAdd(10);  // partially applied
const add5  = curriedAdd(5);

add10(3);  // 13
add10(20); // 30
add5(3);   // 8`,
      },
      {
        title: 'Auto-curry utility',
        color: '#4facfe',
        desc: 'A curry() function that automatically curries any function based on its arity (number of parameters).',
        code: `function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn.apply(this, args); // enough args — call fn
    }
    return function(...more) {     // not enough — collect more
      return curried.apply(this, args.concat(more));
    };
  };
}

const multiply = curry((a, b, c) => a * b * c);
multiply(2)(3)(4);   // 24
multiply(2, 3)(4);   // 24 — partial groups work too
multiply(2)(3, 4);   // 24

const double = multiply(2);   // partially applied
const triple = multiply(3);
double(5);   // 10
triple(5);   // 15`,
      },
      {
        title: 'Real-world: reusable data transforms',
        color: '#00ff88',
        desc: 'Curried functions with pipe/compose create readable, reusable data transformation pipelines.',
        code: `const pipe = (...fns) => x => fns.reduce((v, f) => f(v), x);

// Curried utilities
const filter = pred => arr => arr.filter(pred);
const map    = fn   => arr => arr.map(fn);
const sortBy = key  => arr => [...arr].sort((a,b) => a[key] > b[key] ? 1 : -1);

// Compose into a pipeline
const getActiveUserNames = pipe(
  filter(u => u.active),      // keep active users
  map(u => u.name),           // extract names
  sortBy('name'),             // sort alphabetically
);

getActiveUserNames(users); // clean, readable, reusable`,
      },
      {
        title: 'Partial application vs currying',
        color: '#a855f7',
        desc: 'Currying always creates unary (one-arg) functions. Partial application fixes some arguments — not necessarily one at a time.',
        code: `// Currying — always unary (one arg at a time)
const curried = a => b => c => a + b + c;
curried(1)(2)(3); // 6

// Partial application — fix any number of args
function partial(fn, ...preset) {
  return (...later) => fn(...preset, ...later);
}

const add = (a, b, c) => a + b + c;
const add1and2 = partial(add, 1, 2); // fix first TWO args
add1and2(3); // 6 — only needs the last arg

// Built-in partial application:
const log = console.log.bind(console, '[INFO]');
log('message'); // "[INFO] message"`,
      },
    ]} />

    <InlinePoll
      question="What does add(3) return if add is defined as: const add = a => b => a + b?"
      options={[
        '3',
        'A new function b => 3 + b, waiting for the second argument',
        'NaN',
        'undefined',
      ]}
      correct={1}
      explanation="add(3) partially applies 3 as a. It returns the inner function b => 3 + b — a specialized 'add 3 to anything' function. add(3)(4) would give 7. This is the essence of currying: call with fewer arguments to get a specialized function."
    />

    <CommonMistake
      mistake="Using rest parameters in curried functions: const fn = curry((...args) => ...) — this breaks auto-curry."
      fix="Auto-curry implementations use fn.length to determine arity. Rest parameters (...args) have length === 0, so the curry function can't know how many arguments are expected. Always use explicit named parameters for functions you want to auto-curry."
    />

    <DidYouKnow
      fact="Currying is named after mathematician Haskell Curry — yes, the same person the Haskell programming language is named after. In Haskell, ALL functions are automatically curried — every function takes exactly one argument. JavaScript requires explicit currying."
      color="#f97316"
    />

    <InterviewMeter topics={[
      { topic: 'What currying is and manual implementation', freq: 70 },
      { topic: 'Currying vs partial application difference', freq: 65 },
      { topic: 'pipe() and compose() with curried functions', freq: 60 },
      { topic: 'Implement curry() from scratch', freq: 65 },
    ]} />
  </div>
);

export const SymbolsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 The Problem: Property Name Collisions</div>
      <p style={c.prose}>
        String property keys can collide — two libraries adding a <code style={{ color: '#ef4444' }}>id</code> property to the same object will overwrite each other. Symbols solve this: every <code style={{ color: '#a855f7' }}>Symbol()</code> is <strong style={{ color: '#a855f7' }}>completely unique</strong>, even if they have the same description.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🔑"
      title="A fingerprint vs a name tag"
      analogy="Two people can have the same name tag ('John') and you can't tell them apart. But fingerprints are biologically unique — even identical twins have different fingerprints. Symbol() is like a fingerprint for property keys — each one is unique even if they have the same description."
      connection="Symbol('id') === Symbol('id') is false — even same description, completely different symbols. This guarantees no collisions between libraries or modules adding properties to the same object."
    />

    <StorySteps steps={[
      {
        title: 'Symbols are always unique',
        color: '#a855f7',
        desc: 'Every Symbol() call produces a unique value. Descriptions are just for debugging — they don\'t affect uniqueness.',
        code: `const s1 = Symbol('id');
const s2 = Symbol('id');

s1 === s2;        // false — always unique
typeof s1;        // 'symbol'
s1.toString();    // 'Symbol(id)'
s1.description;   // 'id' (description, not the value)

// Use as object keys — guaranteed no collision
const LIB_A_ID = Symbol('id');
const LIB_B_ID = Symbol('id');

const obj = {};
obj[LIB_A_ID] = 'library A data';
obj[LIB_B_ID] = 'library B data';
// Both exist without collision ✓`,
      },
      {
        title: 'Symbols are hidden from common operations',
        color: '#4facfe',
        desc: 'Symbol keys don\'t appear in for...in, Object.keys(), or JSON.stringify() — useful for metadata that shouldn\'t be serialized.',
        code: `const SECRET = Symbol('secret');
const user = {
  name: 'Alice',
  email: 'alice@example.com',
  [SECRET]: 'internal-session-token',
};

Object.keys(user);      // ['name', 'email'] — no Symbol
JSON.stringify(user);   // '{"name":"Alice","email":"..."}' — no Symbol
for (const key in user) { /* name, email — no Symbol */ }

// Access symbol property directly:
user[SECRET];           // 'internal-session-token' ✓

// Get all symbol keys:
Object.getOwnPropertySymbols(user); // [Symbol(secret)]`,
      },
      {
        title: 'Symbol.iterator — make anything iterable',
        color: '#00ff88',
        desc: 'Well-known symbols let you customize built-in JavaScript behavior. Symbol.iterator is the most important — make any object work with for...of.',
        code: `class Range {
  constructor(from, to) {
    this.from = from;
    this.to = to;
  }

  [Symbol.iterator]() {    // implement iteration protocol
    let current = this.from;
    const to = this.to;
    return {
      next() {
        if (current <= to) return { value: current++, done: false };
        return { value: undefined, done: true };
      }
    };
  }
}

const range = new Range(1, 5);
[...range];                      // [1, 2, 3, 4, 5]
for (const n of range) { ... }  // 1, 2, 3, 4, 5
const [first, second] = range;  // destructuring works too`,
      },
      {
        title: 'Symbol.for — global registry',
        color: '#eab308',
        desc: 'Symbol.for() creates symbols in a global registry. Same key always returns the same symbol — useful for cross-module coordination.',
        code: `// Symbol() — always unique, local
const local1 = Symbol('app.id');
const local2 = Symbol('app.id');
local1 === local2; // false

// Symbol.for() — global registry
const global1 = Symbol.for('app.id');
const global2 = Symbol.for('app.id');
global1 === global2; // true — same symbol!

// Use case: cross-module type checking
// auth-module.js
export const USER_TOKEN = Symbol.for('auth.userToken');

// api-module.js
import { USER_TOKEN } from './auth-module';
// or use Symbol.for directly — same symbol
const token = Symbol.for('auth.userToken'); // same as USER_TOKEN`,
      },
    ]} />

    <InlinePoll
      question="What does [Symbol.iterator]() need to return for the iteration protocol to work?"
      options={[
        'An array of values',
        'An iterator object with a next() method that returns {value, done}',
        'A generator function',
        'A Promise',
      ]}
      correct={1}
      explanation="The iteration protocol requires [Symbol.iterator]() to return an iterator object with a next() method. next() must return {value: currentValue, done: false} for each item, then {value: undefined, done: true} when finished."
    />

    <CommonMistake
      mistake="Using Symbol.for() everywhere thinking it's 'better' than Symbol()."
      fix="Symbol.for('key') uses a global registry — the same string key always returns the same symbol from ANYWHERE in your program, including third-party code. This can cause unintended collisions. Use Symbol() for local unique keys, Symbol.for() only when you intentionally want to share a symbol across modules."
    />

    <DidYouKnow
      fact="React uses Symbol.for('react.element') to tag React elements internally. When React receives an object, it checks for this symbol to verify it's a genuine React element and not a plain object. This prevents XSS attacks — an attacker's JSON response can't accidentally be treated as a React element because JSON.stringify drops Symbol properties."
      color="#a855f7"
    />

    <InterviewMeter topics={[
      { topic: 'Symbol uniqueness and use cases', freq: 60 },
      { topic: 'Symbol.iterator to make objects iterable', freq: 65 },
      { topic: 'Symbol() vs Symbol.for() difference', freq: 55 },
      { topic: 'Well-known symbols overview', freq: 50 },
    ]} />
  </div>
);

export const RaceConditionsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 When Timing Breaks Your UI</div>
      <p style={c.prose}>
        Race conditions happen when the <strong style={{ color: '#ef4444' }}>outcome depends on timing</strong> of async operations. The classic: user types "react", triggering 4 search requests. If the "reac" response arrives AFTER "react", the UI shows wrong results — even though the user typed "react".
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🏁"
      title="Multiple horses, wrong photo finish"
      analogy="You bet on horse #4 (the latest search term). But the race officials (browser) might declare horse #2 (an older response) the winner if it crosses the line last — even if it left the gate first. You expected horse #4 but got horse #2's results."
      connection="The search result that arrives LAST wins — regardless of which query was most recent. Without cancellation, older responses can overwrite newer ones."
    />

    <StorySteps steps={[
      {
        title: 'The bug — stale responses overwrite fresh',
        color: '#ef4444',
        desc: 'Each keystroke fires a request. Responses arrive out of order. The last response to arrive "wins" — even if it\'s for an old query.',
        code: `// ❌ Race condition — classic mistake
function SearchBox() {
  const [results, setResults] = useState([]);

  const handleInput = async (query) => {
    const data = await searchAPI(query); // may resolve out of order!
    setResults(data); // stale response can overwrite fresh!
  };

  // User types: 'r' → 're' → 'rea' → 'reac' → 'react'
  // 5 requests fire, any can win
  // 'rea' response might arrive after 'react' response
  // UI shows 'rea' results even though user typed 'react'
}`,
      },
      {
        title: 'Fix 1 — AbortController (best solution)',
        color: '#00ff88',
        desc: 'Cancel the previous request when a new one starts. Only the latest request can complete.',
        code: `function SearchBox() {
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (!query) return;
    const controller = new AbortController();

    fetch(\`/api/search?q=\${query}\`, {
      signal: controller.signal  // attach abort signal
    })
      .then(r => r.json())
      .then(data => setResults(data))
      .catch(e => {
        if (e.name !== 'AbortError') console.error(e);
        // AbortError is expected — not a real error
      });

    return () => controller.abort(); // cancel on next render
  }, [query]); // runs on every query change
}`,
      },
      {
        title: 'Fix 2 — Request ID check',
        color: '#4facfe',
        desc: 'Track the latest request ID. Ignore any response that isn\'t from the most recent request.',
        code: `let latestRequestId = 0;

async function search(query) {
  const myId = ++latestRequestId; // claim this ID

  const data = await searchAPI(query);

  if (myId !== latestRequestId) {
    return; // a newer request was made — ignore this result
  }

  setResults(data); // only the latest request updates state
}`,
      },
      {
        title: 'Fix 3 — Libraries handle it automatically',
        color: '#a855f7',
        desc: 'React Query, SWR, and RTK Query all handle race conditions automatically — you get the right behavior for free.',
        code: `// React Query — race conditions handled automatically
const { data } = useQuery({
  queryKey: ['search', query],
  queryFn: () => searchAPI(query),
  // automatically cancels stale requests ✓
  // only updates UI with latest data ✓
  // deduplicates simultaneous same-key requests ✓
});

// Or with debounce to reduce requests:
const debouncedQuery = useDebounce(query, 300);
const { data } = useQuery({
  queryKey: ['search', debouncedQuery],
  queryFn: () => searchAPI(debouncedQuery),
  enabled: debouncedQuery.length > 0,
});`,
      },
    ]} />

    <InlinePoll
      question="Does checking 'if (isMounted)' before setState fix a race condition?"
      options={[
        'Yes — it prevents all stale updates',
        'No — it only prevents setState on unmounted components. Stale responses can still overwrite correct results while the component is mounted',
        'Yes — but only in React 18',
        'Yes — combined with useEffect cleanup',
      ]}
      correct={1}
      explanation="isMounted prevents 'setState on unmounted component' warnings but doesn't fix race conditions. If request #1 (for 'reac') completes after request #2 (for 'react'), it still overwrites the correct results — even though the component is mounted. Use AbortController or request ID tracking."
    />

    <CommonMistake
      mistake="Using debounce alone to prevent race conditions: 'I debounced search so only one request fires.'"
      fix="Debounce reduces the NUMBER of requests but doesn't eliminate race conditions. If the user pauses twice, two requests fire. If the first response arrives after the second, you still get stale results. Debounce + AbortController together is the complete solution."
    />

    <DidYouKnow
      fact="Race conditions in frontend are one of the most common sources of subtle bugs that are hard to reproduce — they depend on network timing which varies by connection speed, server load, and geographic location. They often only appear in production on slow connections and are nearly impossible to reproduce locally."
      color="#ef4444"
    />

    <InterviewMeter topics={[
      { topic: 'What is a race condition with a concrete example', freq: 75 },
      { topic: 'AbortController solution', freq: 70 },
      { topic: 'Does isMounted fix race conditions?', freq: 65 },
      { topic: 'React Query automatic handling', freq: 60 },
    ]} />
  </div>
);

export const InterfaceVsTypeLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 The Most Common TypeScript Interview Question</div>
      <p style={c.prose}>
        "What's the difference between interface and type?" — asked in nearly every senior TypeScript interview. Most developers say <strong style={{ color: '#ef4444' }}>"they're basically the same"</strong> which is partially true but misses the critical differences that matter in real codebases.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="📋"
      title="A template vs a blueprint"
      analogy="An interface is like a legal contract template — you can add amendments (declaration merging) and other contracts can extend it. A type alias is like a blueprint — more flexible in what it can describe (unions, intersections, primitives) but fixed once created, no merging allowed."
      connection="interface: mergeable, extendable, object shapes only. type: unions, intersections, primitives, computed types — more powerful but no merging."
    />

    <StorySteps steps={[
      {
        title: 'Declaration merging — only interfaces can do this',
        color: '#4facfe',
        desc: 'Declaring the same interface twice merges them. This is how @types packages augment third-party libraries.',
        code: `// interface — merges automatically
interface User { name: string; }
interface User { age: number; }
// User is now: { name: string; age: number; } ✓

// type — error if declared twice
type User = { name: string; };
type User = { age: number; }; // ❌ Error: Duplicate identifier

// Real use case — augmenting Express types
declare module 'express' {
  interface Request {
    user?: AuthUser; // add user to every Request object
  }
}`,
      },
      {
        title: 'Union types — only type can do this',
        color: '#00ff88',
        desc: 'type can describe unions, intersections, primitives, and tuples. interface cannot.',
        code: `// type — unions ✓
type ID = string | number;
type Result = 'success' | 'error' | 'pending';
type Nullable<T> = T | null;
type Pair = [string, number]; // tuple

// interface — cannot express unions ❌
interface ID = string | number; // SyntaxError!

// Both can describe objects:
interface UserI { name: string; age: number; }
type UserT = { name: string; age: number; };
// ← these are functionally identical`,
      },
      {
        title: 'Extending — different syntax, same result',
        color: '#a855f7',
        desc: 'Both support extension but with different syntax. interfaces use extends, types use & intersection.',
        code: `// Interface extending interface
interface Animal { name: string; }
interface Dog extends Animal { breed: string; }

// Interface extending type
type HasAge = { age: number; };
interface Person extends HasAge { name: string; }

// Type intersection (equivalent to extends)
type Animal = { name: string; };
type Dog = Animal & { breed: string; };

// Type extending interface
interface Named { name: string; }
type Employee = Named & { salary: number; };`,
      },
      {
        title: 'When to use which — the rule of thumb',
        color: '#eab308',
        desc: 'Use interface for public APIs and objects. Use type for unions, utilities, and complex computed types.',
        code: `// ✅ interface for component props (public API)
interface ButtonProps {
  label: string;
  onClick: () => void;
  variant?: 'primary' | 'secondary';
}

// ✅ type for union types (only option)
type Status = 'loading' | 'success' | 'error';

// ✅ type for utility/computed types
type ReadonlyUser = Readonly<User>;
type UserKeys = keyof User;

// ✅ interface for anything that might be extended
interface Config { timeout: number; }
// Later in another file:
interface Config { retries: number; } // merged ✓`,
      },
    ]} />

    <InlinePoll
      question="Which one supports declaration merging?"
      options={[
        'type — it\'s more flexible',
        'interface — declaring same name twice merges the definitions',
        'Both support it',
        'Neither — it\'s a TypeScript error',
      ]}
      correct={1}
      explanation="Only interface supports declaration merging. This is used by @types packages to augment third-party libraries — for example, extending Express's Request interface to add a user property without modifying the library source."
    />

    <CommonMistake
      mistake="Using type for everything because 'it's more powerful' — never using interface."
      fix="interface and type are not competing — they're complementary. interface is better for object shapes, especially public APIs that consumers might need to extend. type is better for unions, mapped types, and computed types. Use both where appropriate."
    />

    <DidYouKnow
      fact="The TypeScript team's official guidance (in their handbook) recommends using interface for object types when possible, and type for everything else. The main practical reason: interface errors are often more readable for object types because TypeScript can name them in error messages."
      color="#4facfe"
    />

    <InterviewMeter topics={[
      { topic: 'Declaration merging — interface only', freq: 85 },
      { topic: 'Union types — type only', freq: 80 },
      { topic: 'When to use each in practice', freq: 75 },
      { topic: 'Module augmentation with interface', freq: 60 },
    ]} />
  </div>
);

export const GenericsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Write Once, Work for Any Type</div>
      <p style={c.prose}>
        Without generics, you write <code style={{ color: '#ef4444' }}>getFirstNumber</code>, <code style={{ color: '#ef4444' }}>getFirstString</code>, <code style={{ color: '#ef4444' }}>getFirstUser</code>... or you use <code style={{ color: '#ef4444' }}>any</code> and lose all type safety. Generics let you write <strong style={{ color: '#00ff88' }}>one function that works for ALL types</strong> while keeping full type safety.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="📦"
      title="A shipping box that fits anything"
      analogy="A shipping company doesn't make separate boxes for phones, books, and toys. They make one box design that works for anything — the content type is specified when you pack it. Generics are the same: define the structure once, specify the content type when you use it."
      connection="function identity<T>(value: T): T — T is the 'box type'. When you call identity(42), TypeScript infers T = number. When you call identity('hello'), T = string. One function, infinite types."
    />

    <StorySteps steps={[
      {
        title: 'The problem generics solve',
        color: '#ef4444',
        desc: 'Without generics: duplicate functions or lose type safety with any.',
        code: `// ❌ Without generics — duplicate code
function firstNumber(arr: number[]): number { return arr[0]; }
function firstString(arr: string[]): string { return arr[0]; }
// Need a new function for every type!

// ❌ Using any — no type safety
function first(arr: any[]): any { return arr[0]; }
const result = first([1, 2, 3]);
result.toUpperCase(); // no error — but crashes at runtime!

// ✅ Generic — one function, full type safety
function first<T>(arr: T[]): T | undefined { return arr[0]; }
const num = first([1, 2, 3]);      // TypeScript knows: number
const str = first(['a', 'b']);     // TypeScript knows: string
str.toUpperCase();                 // ✓ TypeScript allows this
num.toUpperCase();                 // ✗ Error: not on number`,
      },
      {
        title: 'Generic constraints — limit what T can be',
        color: '#4facfe',
        desc: 'extends constrains T to types that have certain properties. Without it you can only use properties all types share.',
        code: `// Without constraint — T could be anything
function getLength<T>(arg: T): number {
  return arg.length; // ❌ Error: T might not have length
}

// With constraint — T must have length property
function getLength<T extends { length: number }>(arg: T): number {
  return arg.length; // ✓ guaranteed to exist
}
getLength('hello');   // 5 — string has length ✓
getLength([1,2,3]);   // 3 — array has length ✓
getLength(42);        // ❌ Error: number has no length

// keyof constraint — key must exist on the object
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}
const user = { name: 'Alice', age: 30 };
getProperty(user, 'name'); // string ✓
getProperty(user, 'xyz');  // ❌ Error: not a key of user`,
      },
      {
        title: 'Generic classes and interfaces',
        color: '#a855f7',
        desc: 'Classes and interfaces can be generic too — typed containers, repositories, and data structures.',
        code: `// Generic Stack
class Stack<T> {
  private items: T[] = [];
  push(item: T): void { this.items.push(item); }
  pop(): T | undefined { return this.items.pop(); }
  peek(): T | undefined { return this.items[this.items.length - 1]; }
  isEmpty(): boolean { return this.items.length === 0; }
}

const numStack = new Stack<number>();
numStack.push(1);
numStack.push('hello'); // ❌ Error: string not assignable to number

const strStack = new Stack<string>();
strStack.push('hello'); // ✓

// Generic API response wrapper
interface ApiResponse<T> {
  data: T;
  status: number;
  message: string;
}
type UserResponse = ApiResponse<User>;
type ListResponse = ApiResponse<User[]>;`,
      },
      {
        title: 'Conditional types and infer',
        color: '#eab308',
        desc: 'The most advanced generic feature — extract types from other types using conditional logic.',
        code: `// Conditional types
type IsArray<T> = T extends any[] ? true : false;
type IsArray<string[]>; // true
type IsArray<string>;   // false

// infer — extract types
type ReturnType<T> = T extends (...args: any[]) => infer R ? R : never;
type Unwrap<T> = T extends Promise<infer U> ? U : T;

type FnReturn = ReturnType<() => number>;      // number
type PromiseValue = Unwrap<Promise<string>>;   // string

// Real use: make all functions async
type Asyncify<T> = T extends (...args: infer A) => infer R
  ? (...args: A) => Promise<R>
  : never;`,
      },
    ]} />

    <InlinePoll
      question="What does <T extends object> mean in a generic function?"
      options={[
        'T must be an instance of Object class',
        'T is constrained — only types that are objects (not primitives) can be passed',
        'T extends the object prototype',
        'T must have an extends method',
      ]}
      correct={1}
      explanation="extends in generics means 'T must be assignable to object'. It constrains what types can be used. <T extends object> rejects primitives (string, number, boolean). <T extends {name: string}> requires T to have at least a name string property."
    />

    <CommonMistake
      mistake="Using any instead of generics: function wrap(value: any) { return { value }; } — loses all type information."
      fix="function wrap<T>(value: T): { value: T } { return { value }; } — TypeScript infers T from the argument. wrap(42).value is number, wrap('hello').value is string. The return type is correctly typed without any explicit annotation needed."
    />

    <DidYouKnow
      fact="TypeScript's entire utility type library (Partial, Required, Pick, Omit, ReturnType, etc.) is implemented using generics, mapped types, and conditional types — no special compiler magic. You can implement all of them yourself: type MyPartial<T> = { [K in keyof T]?: T[K] }."
      color="#00ff88"
    />

    <InterviewMeter topics={[
      { topic: 'Basic generic functions with type inference', freq: 80 },
      { topic: 'Generic constraints with extends and keyof', freq: 75 },
      { topic: 'Generic classes and interfaces', freq: 65 },
      { topic: 'Conditional types and infer keyword', freq: 60 },
    ]} />
  </div>
);

export const UtilityTypesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Stop Duplicating Types</div>
      <p style={c.prose}>
        You have a <code style={{ color: '#a855f7' }}>User</code> type with 10 fields. Your form needs all fields optional. Your API response should never expose password. Your update endpoint only needs some fields. Without utility types, you'd write 4 nearly-identical types. Utility types <strong style={{ color: '#a855f7' }}>derive new types from existing ones</strong>.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="✂️"
      title="Cookie cutters for types"
      analogy="You have a ball of dough (your base type). Utility types are cookie cutters — Partial makes everything optional, Pick selects specific fields, Omit removes fields, Readonly freezes everything. One base type, many derived shapes, no duplication."
      connection="type SafeUser = Omit<User, 'password'> — derived from User, automatically stays in sync when User changes. No manual duplication."
    />

    <StorySteps steps={[
      {
        title: 'Partial and Required — toggle optionality',
        color: '#4facfe',
        desc: 'Partial makes all properties optional. Required makes all properties required. Both create new types without modifying the original.',
        code: `interface User {
  id: number;
  name: string;
  email: string;
  age: number;
}

// Partial — all optional (perfect for update endpoints)
type UpdateUser = Partial<User>;
// { id?: number; name?: string; email?: string; age?: number; }

function updateUser(id: number, data: UpdateUser) {
  // data can have any subset of User fields
}
updateUser(1, { name: 'Bob' }); // ✓ only name provided

// Required — opposite of Partial
type StrictConfig = Required<Partial<Config>>;
// ensures all fields present even if Config had optional ones`,
      },
      {
        title: 'Pick and Omit — select or remove fields',
        color: '#00ff88',
        desc: 'Pick keeps only specified fields. Omit removes specified fields. Most commonly used utility types in real codebases.',
        code: `interface User {
  id: number;
  name: string;
  email: string;
  password: string;
  createdAt: Date;
}

// Pick — keep only these fields
type UserProfile = Pick<User, 'id' | 'name' | 'email'>;
// { id: number; name: string; email: string; }

// Omit — remove these fields (never expose password)
type SafeUser = Omit<User, 'password'>;
// { id: number; name: string; email: string; createdAt: Date; }

// Real-world: derive form types from API types
type CreateUserForm = Omit<User, 'id' | 'createdAt'>; // no auto fields
type LoginForm = Pick<User, 'email' | 'password'>;`,
      },
      {
        title: 'Record, Exclude, Extract, NonNullable',
        color: '#a855f7',
        desc: 'Record creates typed dictionaries. Exclude/Extract filter union types. NonNullable removes null and undefined.',
        code: `// Record — typed dictionary/map
type Roles = 'admin' | 'user' | 'guest';
type Permissions = Record<Roles, string[]>;
// { admin: string[]; user: string[]; guest: string[]; }

// Exclude — remove from union
type NonBoolean = Exclude<string | number | boolean, boolean>;
// string | number

// Extract — keep from union
type OnlyStrings = Extract<string | number | boolean, string>;
// string

// NonNullable — remove null and undefined
type DefinitelyString = NonNullable<string | null | undefined>;
// string`,
      },
      {
        title: 'ReturnType, Parameters, Awaited',
        color: '#eab308',
        desc: 'Extract type information from functions and Promises — without duplicating the type manually.',
        code: `// ReturnType — extract return type of a function
function fetchUser(id: number): Promise<User> { /* ... */ }
type FetchResult = ReturnType<typeof fetchUser>; // Promise<User>

// Parameters — extract parameter types as tuple
type FetchParams = Parameters<typeof fetchUser>; // [number]

// Awaited — unwrap Promise type
type UserData = Awaited<ReturnType<typeof fetchUser>>; // User

// Real use: mock function with same signature
function mockFetch(...args: Parameters<typeof fetchUser>):
  ReturnType<typeof fetchUser> {
  return Promise.resolve(testUser);
}
// Automatically stays in sync if fetchUser signature changes!`,
      },
    ]} />

    <InlinePoll
      question="You have a User type with 10 fields including 'password'. What's the cleanest way to create a SafeUser type that excludes the password?"
      options={[
        'Manually rewrite all 9 fields',
        'type SafeUser = Omit<User, "password"> — derives from User automatically',
        'type SafeUser = Pick<User, "password"> — selects what to keep',
        'Use interface SafeUser extends User without password',
      ]}
      correct={1}
      explanation="Omit<User, 'password'> creates a type with all User fields except password. It automatically stays in sync — if you add fields to User, SafeUser gets them too (unless you Omit them). Manually rewriting creates maintenance burden and sync bugs."
    />

    <CommonMistake
      mistake="Deep Partial: type DeepPartial<T> = Partial<T> makes all fields optional — but nested objects still have required fields."
      fix="Partial<T> is shallow — it only makes top-level properties optional. For deep partial, use a recursive type: type DeepPartial<T> = T extends object ? { [K in keyof T]?: DeepPartial<T[K]> } : T. TypeScript doesn't include this built-in — you need to define it yourself."
    />

    <DidYouKnow
      fact="All TypeScript utility types are implemented using the same generic features available to you. Partial<T> is literally: { [K in keyof T]?: T[K] }. You can read the TypeScript source code to see all built-in utility types — they're in lib.es5.d.ts and are just type aliases, nothing special."
      color="#a855f7"
    />

    <InterviewMeter topics={[
      { topic: 'Partial vs Required use cases', freq: 75 },
      { topic: 'Pick vs Omit — which removes, which keeps', freq: 80 },
      { topic: 'Record for typed dictionaries', freq: 65 },
      { topic: 'ReturnType and Parameters for function types', freq: 70 },
    ]} />
  </div>
);

export const AnyUnknownNeverLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 TypeScript's Type Hierarchy</div>
      <p style={c.prose}>
        TypeScript has a type hierarchy. At the top is <strong style={{ color: '#4facfe' }}>unknown</strong> — every type is assignable to it. At the bottom is <strong style={{ color: '#00ff88' }}>never</strong> — nothing is assignable to it. And then there's <strong style={{ color: '#ef4444' }}>any</strong> — which breaks the entire hierarchy and disables type checking.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🗂️"
      title="A filing system"
      analogy="unknown is like an unlabeled inbox — anything can go in, but you can't use it until you open it and check what's inside. any is like a magic folder that accepts everything AND lets you use everything without checking — useful but dangerous. never is an impossible inbox that can never receive anything."
      connection="unknown: accept anything, use nothing until narrowed. any: accept anything, use anything (no checks). never: can't assign to it, signals impossible states."
    />

    <StorySteps steps={[
      {
        title: 'any — the escape hatch (use sparingly)',
        color: '#ef4444',
        desc: 'any disables type checking entirely for that value. It\'s contagious — it spreads to everything it touches.',
        code: `let x: any = 'hello';
x.toUpperCase();     // ok
x.doesNotExist();    // ok — no error! (runtime crash)
x.foo.bar.baz;       // ok — TypeScript trusts you completely
x = 42;             // ok
x = {};             // ok

// Contagious — spreads to other variables
const y = x;        // y is also any
const z = x.name;   // z is also any

// ❌ Common mistake — using any to silence errors
function process(data: any) {  // avoid this
  return data.value;           // no type safety!
}`,
      },
      {
        title: 'unknown — type-safe any',
        color: '#4facfe',
        desc: 'unknown accepts any value like any, but forces you to narrow the type before using it. Much safer.',
        code: `let x: unknown = 'hello';
x.toUpperCase(); // ❌ Error: Object is of type 'unknown'
// Must narrow first:

if (typeof x === 'string') {
  x.toUpperCase(); // ✓ narrowed to string
}
if (x instanceof Date) {
  x.toISOString(); // ✓ narrowed to Date
}

// ✅ Use unknown for: error handlers, API responses, user input
try {
  riskyOperation();
} catch (e: unknown) {               // e is unknown
  if (e instanceof Error) {
    console.error(e.message);        // ✓ safe
  }
}

async function fetchUser(): Promise<unknown> {
  const data = await fetch('/api/user').then(r => r.json());
  return data; // caller must validate before using
}`,
      },
      {
        title: 'never — the impossible type',
        color: '#00ff88',
        desc: 'never represents values that never exist. Functions that never return, unreachable code, and exhaustive checks.',
        code: `// Function that never returns
function throwError(msg: string): never {
  throw new Error(msg);
}
function infiniteLoop(): never {
  while (true) {}
}

// Exhaustive check — never is the safety net
type Shape = 'circle' | 'square' | 'triangle';
function area(shape: Shape): number {
  switch (shape) {
    case 'circle':   return Math.PI * 5 * 5;
    case 'square':   return 25;
    case 'triangle': return 12.5;
    default:
      // If you add 'pentagon' to Shape without handling it,
      // TypeScript errors HERE — shape would be 'pentagon'
      // but it's being assigned to never
      const exhaustive: never = shape; // ← compile error!
      return exhaustive;
  }
}`,
      },
      {
        title: 'The type hierarchy',
        color: '#a855f7',
        desc: 'Understanding the hierarchy explains assignment compatibility rules.',
        code: `// unknown is the TOP type — anything is assignable to it
const u: unknown = 'hello';    // ✓ string → unknown
const u2: unknown = 42;        // ✓ number → unknown
const u3: unknown = null;      // ✓ null → unknown

// never is the BOTTOM type — nothing is assignable to it
const n: never = 'hello';      // ❌ string is not never
const n2: never = 42;          // ❌ number is not never
// Only never is assignable to never

// any breaks the hierarchy in BOTH directions
const a: any = 'hello';        // ✓ anything → any
const s: string = a;           // ✓ any → anything (dangerous!)

// Summary:
// never → (is assignable to) → everything
// everything → (is assignable to) → unknown
// any ↔ everything (breaks rules both ways)`,
      },
    ]} />

    <InlinePoll
      question="You're writing a catch block and need to access the error message. What type should you use for e?"
      options={[
        'any — so you can access .message without errors',
        'unknown — forces you to check it\'s an Error before accessing .message',
        'Error — all errors are Error instances',
        'string — errors are always strings',
      ]}
      correct={1}
      explanation="catch (e: unknown) is the safe choice. Not all thrown values are Error instances — someone might throw a string, number, or object. Using unknown forces you to check: if (e instanceof Error) { e.message } — which is correct. Using any lets you access .message on a thrown string, crashing at runtime."
    />

    <CommonMistake
      mistake="Adding 'as any' everywhere to silence TypeScript errors: const user = (await fetchUser()) as any"
      fix="as any is a red flag — you're discarding all type safety. Use unknown and write a type guard: function isUser(val: unknown): val is User { return typeof val === 'object' && val !== null && 'name' in val; }. Or use a validation library like Zod that gives you runtime + compile-time safety."
    />

    <DidYouKnow
      fact="TypeScript's noImplicitAny compiler option makes the compiler error when it would infer any. The strict mode enables this automatically. Many TypeScript teams also use the 'unknown' rule from @typescript-eslint to prevent explicit any usage — making their codebases fully type-safe."
      color="#ef4444"
    />

    <InterviewMeter topics={[
      { topic: 'Difference between any, unknown, and never', freq: 85 },
      { topic: 'Why unknown is safer than any', freq: 80 },
      { topic: 'never for exhaustive switch checks', freq: 65 },
      { topic: 'Type hierarchy — top and bottom types', freq: 60 },
    ]} />
  </div>
);

export const TypeGuardsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Narrowing — From Broad to Specific</div>
      <p style={c.prose}>
        TypeScript starts with a broad type like <code style={{ color: '#eab308' }}>string | number | null</code>. Type guards narrow it down to the specific type you need. Without narrowing, TypeScript won't let you call string methods on <code style={{ color: '#ef4444' }}>string | number</code>.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🔍"
      title="A detective narrowing suspects"
      analogy="A detective starts with 'anyone in the city could be the culprit' (broad type). Each clue narrows it down: 'must be over 6ft' (type guard 1), 'was in London that day' (type guard 2), 'knows the victim' (type guard 3). Eventually: one suspect. TypeScript does the same — each check narrows the type."
      connection="TypeScript tracks your checks. After if (typeof x === 'string'), TypeScript knows x is string inside that block — it's narrowed. Outside the block, it's still string | number."
    />

    <StorySteps steps={[
      {
        title: 'Built-in type guards',
        color: '#eab308',
        desc: 'typeof, instanceof, and in checks automatically narrow types.',
        code: `function process(value: string | number | Date | null) {
  if (value === null) {
    // TypeScript knows: value is null
    return 'null value';
  }
  if (typeof value === 'string') {
    // TypeScript knows: value is string
    return value.toUpperCase();
  }
  if (typeof value === 'number') {
    // TypeScript knows: value is number
    return value.toFixed(2);
  }
  if (value instanceof Date) {
    // TypeScript knows: value is Date
    return value.toISOString();
  }
}`,
      },
      {
        title: 'User-defined type guards',
        color: '#4facfe',
        desc: 'Functions that return "value is Type" — explicitly tell TypeScript what type something is after a custom check.',
        code: `interface Cat { meow(): void; type: 'cat'; }
interface Dog { bark(): void; type: 'dog'; }

// User-defined type guard — return type is "value is Type"
function isCat(animal: Cat | Dog): animal is Cat {
  return animal.type === 'cat';
}

function makeSound(animal: Cat | Dog) {
  if (isCat(animal)) {
    animal.meow(); // ✓ TypeScript knows it's Cat
  } else {
    animal.bark(); // ✓ TypeScript knows it's Dog
  }
}

// Practical: API response validation
function isUser(val: unknown): val is User {
  return (
    typeof val === 'object' && val !== null &&
    'id' in val && typeof (val as any).id === 'number' &&
    'name' in val && typeof (val as any).name === 'string'
  );
}`,
      },
      {
        title: 'Discriminated unions — the best pattern',
        color: '#00ff88',
        desc: 'Objects with a shared literal field — TypeScript narrows automatically based on that field.',
        code: `// Discriminated union — 'type' field is the discriminant
type Action =
  | { type: 'INCREMENT'; amount: number }
  | { type: 'DECREMENT'; amount: number }
  | { type: 'RESET' }
  | { type: 'SET'; value: number };

function reducer(state: number, action: Action): number {
  switch (action.type) {
    case 'INCREMENT':
      return state + action.amount; // ✓ action.amount available
    case 'RESET':
      return 0;                     // ✓ action.value NOT available
    case 'SET':
      return action.value;          // ✓ action.value available
    case 'DECREMENT':
      return state - action.amount;
  }
}`,
      },
      {
        title: 'Assertion functions',
        color: '#a855f7',
        desc: 'Functions that assert a condition — TypeScript narrows based on the assertion surviving.',
        code: `// Assertion function — asserts value is not null
function assertDefined<T>(val: T | null | undefined, msg: string):
  asserts val is T {
  if (val == null) throw new Error(msg);
}

// assert condition
function assert(condition: boolean, msg: string):
  asserts condition {
  if (!condition) throw new Error(msg);
}

// Usage:
let user: User | null = getUser();
assertDefined(user, 'User must be logged in');
user.name; // ✓ TypeScript knows user is User (not null)

const count = getValue();
assert(typeof count === 'number', 'Expected number');
count.toFixed(2); // ✓ TypeScript knows count is number`,
      },
    ]} />

    <InlinePoll
      question="What is a discriminated union and why is it TypeScript's preferred narrowing pattern?"
      options={[
        'A union where all types are different',
        'A union where members share a common literal property — TypeScript narrows automatically based on checking that property',
        'A union that can\'t be used with generics',
        'A special TypeScript syntax for switch statements',
      ]}
      correct={1}
      explanation="Discriminated unions (also called tagged unions) have a shared literal property like type: 'circle' | 'square'. Checking action.type === 'circle' tells TypeScript exactly which union member you have. It's the most readable pattern and works perfectly with switch statements."
    />

    <CommonMistake
      mistake="Using type assertions (as SomeType) as a substitute for type guards."
      fix="as SomeType is a lie to the compiler — it doesn't verify anything at runtime. If you're wrong, you get a runtime crash with no TypeScript warning. Type guards (typeof, instanceof, user-defined) actually CHECK the type at runtime AND tell TypeScript. Use guards, not assertions."
    />

    <DidYouKnow
      fact="TypeScript's type narrowing is 'flow-based analysis' — it tracks what each branch of your code proves about the type. After 'if (x === null) return', TypeScript knows x is not null for the rest of the function. This is why TypeScript can narrow complex chains of conditions automatically without any extra syntax."
      color="#eab308"
    />

    <InterviewMeter topics={[
      { topic: 'typeof and instanceof type guards', freq: 80 },
      { topic: 'User-defined type guards with "is" keyword', freq: 70 },
      { topic: 'Discriminated unions for complex types', freq: 75 },
      { topic: 'Assertion functions', freq: 55 },
    ]} />
  </div>
);

export const MappedConditionalLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Types That Transform Other Types</div>
      <p style={c.prose}>
        Mapped and conditional types are TypeScript's most powerful feature — they let you <strong style={{ color: '#a855f7' }}>compute new types from existing types</strong> programmatically. This is how all built-in utility types are implemented, and how you build truly DRY type systems.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🏭"
      title="A type factory"
      analogy="A car factory takes a blueprint (input type) and applies a process (mapped/conditional logic) to produce a new blueprint (output type). Partial<User> is a factory: input=User blueprint, process='make all fields optional', output=partial User blueprint."
      connection="Mapped types iterate over keys. Conditional types branch on type relationships. Together they implement all TypeScript utility types."
    />

    <StorySteps steps={[
      {
        title: 'Mapped types — iterate over keys',
        color: '#a855f7',
        desc: '[K in keyof T] iterates over all keys of T, letting you transform each property.',
        code: `// Implement Partial from scratch
type MyPartial<T> = {
  [K in keyof T]?: T[K]; // ? makes each property optional
};

// Implement Readonly from scratch
type MyReadonly<T> = {
  readonly [K in keyof T]: T[K]; // readonly modifier
};

// Remove modifiers with -
type Mutable<T> = {
  -readonly [K in keyof T]: T[K]; // remove readonly
};
type Required<T> = {
  [K in keyof T]-?: T[K]; // remove optional (-)
};

// Transform values
type Stringify<T> = {
  [K in keyof T]: string; // all values become string
};`,
      },
      {
        title: 'Key remapping with as',
        color: '#4facfe',
        desc: 'Remap keys while mapping — rename or filter properties.',
        code: `// Rename all keys with prefix
type Getters<T> = {
  [K in keyof T as \`get\${Capitalize<string & K>}\`]: () => T[K]
};
// Getters<{name: string}> = { getName: () => string }

// Filter keys by type
type StringKeys<T> = {
  [K in keyof T as T[K] extends string ? K : never]: T[K]
};
// StringKeys<{name:string, age:number}> = {name: string}

// Event handlers from interface
type EventHandlers<T> = {
  [K in keyof T as \`on\${Capitalize<string & K>}\`]?: (val: T[K]) => void
};`,
      },
      {
        title: 'Conditional types — if/else for types',
        color: '#00ff88',
        desc: 'T extends U ? X : Y — if T is assignable to U, use X, otherwise Y.',
        code: `type IsString<T> = T extends string ? true : false;
type A = IsString<string>;  // true
type B = IsString<number>;  // false

// Unwrap Promise
type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T;
type R = Awaited<Promise<Promise<string>>>; // string

// NonNullable — remove null and undefined
type NonNullable<T> = T extends null | undefined ? never : T;
type N = NonNullable<string | null | undefined>; // string

// Distributive conditional types
type ToArray<T> = T extends any ? T[] : never;
type R = ToArray<string | number>; // string[] | number[]
// (distributes over each union member)`,
      },
      {
        title: 'infer — extract types',
        color: '#eab308',
        desc: 'infer introduces a type variable inside a conditional type to extract a part of the matched type.',
        code: `// Extract return type
type ReturnType<T> =
  T extends (...args: any[]) => infer R ? R : never;
type Fn = () => Promise<User[]>;
type R = ReturnType<Fn>; // Promise<User[]>

// Extract first element of tuple
type Head<T extends any[]> =
  T extends [infer First, ...any[]] ? First : never;
type H = Head<[string, number, boolean]>; // string

// Extract Promise value
type UnwrapPromise<T> =
  T extends Promise<infer Value> ? Value : T;
type V = UnwrapPromise<Promise<string>>; // string
type V2 = UnwrapPromise<string>;         // string (not a promise)

// Deep: unwrap nested promises
type DeepAwaited<T> =
  T extends Promise<infer U> ? DeepAwaited<U> : T;`,
      },
    ]} />

    <InlinePoll
      question="What does [K in keyof T]-? do in a mapped type?"
      options={[
        'Removes the key K from the type',
        'Removes the optional modifier — makes all properties required (opposite of Partial)',
        'Makes all properties negative numbers',
        'Filters out null values',
      ]}
      correct={1}
      explanation="The - prefix removes a modifier. -? removes the optional modifier (?), making properties required. -readonly removes the readonly modifier. This is how Required<T> is implemented: { [K in keyof T]-?: T[K] } — removes optional from every property."
    />

    <CommonMistake
      mistake="Circular conditional types: type Circular<T> = T extends object ? Circular<T> : T — causes TypeScript to error or give 'any'."
      fix="Recursive conditional types need a base case to terminate. Use depth limiting or restructure to avoid deep recursion. TypeScript has a recursion limit to prevent infinite type computation. For deep recursive types, consider using interfaces with extends instead."
    />

    <DidYouKnow
      fact="Template literal types (introduced in TypeScript 4.1) combined with mapped types let you generate entire sets of related types. type EventMap = { [K in 'click'|'focus'|'blur' as `on${Capitalize<K>}`]: (e: Event) => void } automatically generates onClick, onFocus, onBlur — the basis of React's event prop types."
      color="#a855f7"
    />

    <InterviewMeter topics={[
      { topic: 'Mapped types — iterating over keyof T', freq: 70 },
      { topic: 'Conditional types syntax and use cases', freq: 65 },
      { topic: 'infer keyword to extract types', freq: 60 },
      { topic: 'Implementing utility types from scratch', freq: 55 },
    ]} />
  </div>
);

export const TestingPyramidLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Tests Are About Confidence, Not Coverage</div>
      <p style={c.prose}>
        100% code coverage doesn't mean your app works. A test that calls every line but makes no assertions is worthless. Tests should answer one question: <strong style={{ color: '#00ff88' }}>"If all tests pass, am I confident this feature works for real users?"</strong>
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🏗️"
      title="Building inspections at different levels"
      analogy="A building inspector checks individual bricks (unit tests — fast, many), then checks how rooms connect (integration tests — medium), then checks the whole building is liveable (E2E tests — slow, few). You need all three levels but in different proportions — most checks at the brick level, fewest at the whole-building level."
      connection="Unit tests: fast, cheap, many — test pure logic. Integration tests: medium — test components working together. E2E tests: slow, expensive, few — test critical user journeys."
    />

    <StorySteps steps={[
      {
        title: 'Unit tests — pure logic only',
        color: '#4facfe',
        desc: 'Test functions, utilities, reducers in complete isolation. No DOM, no network, no React. Fastest possible tests.',
        code: `// ✅ Great for unit tests
test('formatCurrency formats correctly', () => {
  expect(formatCurrency(1234.5, 'USD')).toBe('$1,234.50');
  expect(formatCurrency(0, 'EUR')).toBe('€0.00');
});

test('validateEmail rejects invalid emails', () => {
  expect(validateEmail('notanemail')).toBe(false);
  expect(validateEmail('user@example.com')).toBe(true);
});

test('cartReducer adds items correctly', () => {
  const state = cartReducer([], { type: 'ADD', item: { id: 1 } });
  expect(state).toHaveLength(1);
  expect(state[0].id).toBe(1);
});`,
      },
      {
        title: 'Integration tests — the highest ROI for frontend',
        color: '#00ff88',
        desc: 'Render a component, interact with it like a real user, assert what they see. This is the sweet spot for frontend testing.',
        code: `// ✅ Integration test — component + interactions
test('login form shows error on wrong password', async () => {
  server.use(
    rest.post('/api/login', (req, res, ctx) =>
      res(ctx.status(401), ctx.json({ error: 'Invalid credentials' }))
    )
  );

  render(<LoginForm />);

  await userEvent.type(
    screen.getByLabelText('Email'), 'user@test.com'
  );
  await userEvent.type(
    screen.getByLabelText('Password'), 'wrongpass'
  );
  await userEvent.click(
    screen.getByRole('button', { name: 'Sign In' })
  );

  expect(await screen.findByText('Invalid credentials'))
    .toBeInTheDocument();
});`,
      },
      {
        title: 'E2E tests — critical paths only',
        color: '#a855f7',
        desc: 'Real browser, real server, real database. Slow and expensive — use only for the flows that absolutely must work.',
        code: `// ✅ E2E with Playwright — checkout flow
test('user can complete checkout', async ({ page }) => {
  await page.goto('/products');
  await page.click('[data-testid="product-1"]');
  await page.click('text=Add to Cart');
  await page.click('text=Checkout');

  await page.fill('[name="cardNumber"]', '4242424242424242');
  await page.fill('[name="expiry"]', '12/25');
  await page.fill('[name="cvv"]', '123');

  await page.click('text=Place Order');

  await expect(page.locator('text=Order confirmed'))
    .toBeVisible();
});

// Use E2E for: checkout, login, signup, critical business flows
// NOT for: every component variant, styling, happy paths already covered`,
      },
      {
        title: 'The Testing Trophy — frontend reality',
        color: '#eab308',
        desc: 'Kent C. Dodds\' Testing Trophy inverts the pyramid for frontend: emphasize integration tests most.',
        code: `// Testing Trophy distribution for frontend:

// 1. Static analysis (TypeScript, ESLint) — free!
//    Catches type errors, undefined variables, bad patterns

// 2. Unit tests — some
//    Pure functions, utilities, complex algorithms, reducers

// 3. Integration tests — MOST
//    Component + user interactions + API mocking
//    Best confidence-to-cost ratio for UI

// 4. E2E tests — few
//    Login flow, checkout, critical user journeys

// The question for every test:
// "Does this test give me confidence the feature works for users?"
// If yes — write it. If no (testing CSS class names) — skip it.`,
      },
    ]} />

    <InlinePoll
      question="A test breaks after you rename a CSS class from 'btn-primary' to 'button-primary'. What does this tell you?"
      options={[
        'The test caught a real regression',
        'The test was testing implementation details — brittle, low value',
        'CSS class names should never change',
        'The test needs to be updated every time',
      ]}
      correct={1}
      explanation="Renaming a CSS class is a refactor — behavior didn't change. If a test breaks, it was testing implementation (class names) not behavior (button works when clicked). Good tests use getByRole, getByText, getByLabelText — things users actually see."
    />

    <CommonMistake
      mistake="Aiming for 100% code coverage as the primary testing goal."
      fix="Coverage measures which lines were executed — not whether behavior is correct. A test can call every line while making zero assertions and still get 100% coverage. Focus on covering user-critical paths thoroughly, not on hitting an arbitrary line coverage number."
    />

    <DidYouKnow
      fact="Google's internal testing guidelines found that the ideal test split for most software is roughly 70% unit, 20% integration, 10% E2E. But for frontend UI code, the Testing Trophy suggests inverting this — more integration tests because components only make sense when interacting with users."
      color="#00ff88"
    />

    <InterviewMeter topics={[
      { topic: 'Unit vs integration vs E2E differences', freq: 85 },
      { topic: 'Testing pyramid vs testing trophy', freq: 65 },
      { topic: 'When to write each type of test', freq: 75 },
      { topic: 'What NOT to test (implementation details)', freq: 70 },
    ]} />
  </div>
);

export const ReactTestingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Test Like a User, Not Like a Developer</div>
      <p style={c.prose}>
        The golden rule of React Testing Library: <strong style={{ color: '#4facfe' }}>"The more your tests resemble the way your software is used, the more confidence they give you."</strong> Query elements the way users find them — by text, label, and role — not by class names or component internals.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="👤"
      title="Testing from the user's perspective"
      analogy="A usability tester doesn't look at the HTML source code — they look at the screen, read the text, and click buttons. React Testing Library forces you to test the same way: find elements by what's visible and meaningful to users, not by internal implementation details."
      connection="getByRole('button', {name:'Submit'}) finds what the user sees. getByTestId('submit-btn') tests what the developer wrote. One breaks on refactor, the other only breaks when behavior changes."
    />

    <StorySteps steps={[
      {
        title: 'Query priority — most to least preferred',
        color: '#4facfe',
        desc: 'RTL provides queries in priority order. Accessible queries (role, label) are preferred because they test accessibility too.',
        code: `// ✅ Preferred — accessible queries
screen.getByRole('button', { name: 'Submit' });
screen.getByRole('textbox', { name: 'Email' });
screen.getByLabelText('Password');
screen.getByText('Welcome back');
screen.getByPlaceholderText('Search...');

// ⚠️ Acceptable — test IDs (last resort)
screen.getByTestId('submit-button');

// ❌ Avoid — implementation details
container.querySelector('.btn-primary');
wrapper.find(Button); // Enzyme style — avoid
screen.getByClassName('submit-btn'); // doesn't exist in RTL for a reason`,
      },
      {
        title: 'userEvent vs fireEvent',
        color: '#00ff88',
        desc: 'userEvent simulates real user behavior with full event sequences. fireEvent dispatches single DOM events.',
        code: `import userEvent from '@testing-library/user-event';

test('search input filters results', async () => {
  const user = userEvent.setup();
  render(<SearchBox />);

  // ✅ userEvent.type — simulates real typing
  // fires: focus, keydown, keypress, input, keyup per character
  await user.type(screen.getByRole('textbox'), 'react');

  // ✅ userEvent.click — mousedown, mouseup, click, focus
  await user.click(screen.getByRole('button', { name: 'Search' }));

  // ❌ fireEvent — only dispatches ONE event
  // fireEvent.change(input, { target: { value: 'react' } })
  // Doesn't simulate typing character by character
  // Misses many real browser interactions
});`,
      },
      {
        title: 'Async testing — waitFor and findBy',
        color: '#a855f7',
        desc: 'For async operations, use findBy queries (return Promises) or waitFor to wait for assertions to pass.',
        code: `test('loads and displays users', async () => {
  render(<UserList />);

  // Component shows loading state first
  expect(screen.getByText('Loading...')).toBeInTheDocument();

  // findBy* — waits up to 1000ms for element to appear
  const users = await screen.findByRole('list');
  expect(users).toBeInTheDocument();

  // waitFor — retry assertion until it passes
  await waitFor(() => {
    expect(screen.getAllByRole('listitem')).toHaveLength(3);
  });

  // ❌ Don't use getBy for async content — throws immediately
  // screen.getByText('Alice'); // fails before data loads
});`,
      },
      {
        title: 'What NOT to test',
        color: '#eab308',
        desc: 'Testing the wrong things creates brittle tests that break on harmless refactors.',
        code: `// ❌ Don't test implementation details
test('sets isLoading to true when fetching', () => {
  const { result } = renderHook(() => useUsers());
  expect(result.current.isLoading).toBe(true);
  // Changing the state variable name breaks this test
});

// ✅ Test observable behavior instead
test('shows loading spinner while fetching', async () => {
  render(<Users />);
  expect(screen.getByRole('progressbar')).toBeInTheDocument();
  await waitFor(() =>
    expect(screen.queryByRole('progressbar')).not.toBeInTheDocument()
  );
});

// ❌ Don't test library internals
// Don't test that useState was called
// Don't test that useEffect ran
// Don't test component prop types`,
      },
    ]} />

    <InlinePoll
      question="Why does React Testing Library not provide a getByClassName query?"
      options={[
        'It was forgotten — it will be added later',
        'Class names are implementation details — they can change without user-visible behavior changing',
        'Performance reasons',
        'CSS classes are not accessible',
      ]}
      correct={1}
      explanation="This is intentional. Class names are implementation details — renaming .btn-primary to .button-primary doesn't change what the user sees or how the button works. Tests querying by class name break on harmless refactors. RTL forces you to query by what users actually see."
    />

    <CommonMistake
      mistake="Using act() manually everywhere: 'I wrap everything in act() to prevent warnings.'"
      fix="RTL wraps most operations in act() automatically. Only wrap manually when: triggering state updates outside of RTL utilities (raw DOM events, custom async operations). Wrapping everything in act() is a sign you're fighting the library — use userEvent and waitFor instead."
    />

    <DidYouKnow
      fact="React Testing Library was created by Kent C. Dodds in 2018 as a reaction to Enzyme — the dominant testing library at the time. Enzyme encouraged testing implementation details (component state, instance methods). RTL's philosophy was so compelling it became the React team's official recommendation and Enzyme was eventually deprecated."
      color="#4facfe"
    />

    <InterviewMeter topics={[
      { topic: 'RTL philosophy — test behavior not implementation', freq: 85 },
      { topic: 'Query priority (getByRole over getByTestId)', freq: 75 },
      { topic: 'userEvent vs fireEvent difference', freq: 70 },
      { topic: 'findBy vs getBy for async content', freq: 65 },
    ]} />
  </div>
);

export const MockingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Isolating What You're Testing</div>
      <p style={c.prose}>
        Tests should be <strong style={{ color: '#eab308' }}>fast, reliable, and isolated</strong>. Real API calls are slow, flaky, and depend on external servers. Mocking replaces real dependencies with controlled fakes — so you can test your code's behavior without the unpredictability of the real world.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🎭"
      title="A flight simulator vs a real plane"
      analogy="Pilots train in simulators — they behave like real planes but in a controlled environment. You can simulate engine failures, bad weather, and emergencies safely. Mocks are simulators for your code's dependencies — they behave like real APIs but return controlled responses you define."
      connection="Mock the API call to return exactly the data you need for the test. Test your component's behavior for success, loading, error states — without needing a real server."
    />

    <StorySteps steps={[
      {
        title: 'Spy vs Stub vs Mock — the differences',
        color: '#eab308',
        desc: 'Three types of test doubles, each with a specific purpose.',
        code: `// SPY — wraps real implementation, records calls
const spy = jest.spyOn(console, 'log');
doSomething(); // console.log still works
expect(spy).toHaveBeenCalledWith('expected message');
spy.mockRestore(); // restore original

// STUB — replaces implementation with fixed return value
jest.spyOn(userService, 'getUser')
  .mockResolvedValue({ id: 1, name: 'Alice' });
// getUser() now returns Alice without hitting the DB

// MOCK — pre-programmed with expectations
const mockCallback = jest.fn();
button.click(); // triggers mockCallback
expect(mockCallback).toHaveBeenCalledTimes(1);
expect(mockCallback).toHaveBeenCalledWith({ type: 'click' });`,
      },
      {
        title: 'jest.mock — module-level mocking',
        color: '#4facfe',
        desc: 'Replace entire modules with mocked versions. Useful for mocking third-party libraries and internal modules.',
        code: `// Mock entire module
jest.mock('./userService');
import { getUser } from './userService'; // auto-mocked

// Set return values per test
(getUser as jest.Mock).mockResolvedValue({ id: 1, name: 'Alice' });

test('renders user name', async () => {
  render(<UserProfile userId={1} />);
  expect(await screen.findByText('Alice')).toBeInTheDocument();
});

// Mock with factory function
jest.mock('./analytics', () => ({
  track: jest.fn(),
  identify: jest.fn(),
}));

// Partial mock — keep some real implementations
jest.mock('./utils', () => ({
  ...jest.requireActual('./utils'), // keep real implementations
  formatDate: jest.fn(() => 'Jan 1, 2024'), // mock just this one
}));`,
      },
      {
        title: 'MSW — Mock Service Worker (best practice)',
        color: '#00ff88',
        desc: 'Intercept HTTP requests at the network level. Same handlers work in tests AND in the browser for development.',
        code: `// handlers.js — shared between tests and browser dev
import { rest } from 'msw';

export const handlers = [
  rest.get('/api/users', (req, res, ctx) => {
    return res(ctx.json([{ id: 1, name: 'Alice' }]));
  }),
  rest.post('/api/login', (req, res, ctx) => {
    const { email } = req.body;
    if (email === 'wrong@test.com') {
      return res(ctx.status(401), ctx.json({ error: 'Unauthorized' }));
    }
    return res(ctx.json({ token: 'abc123' }));
  }),
];

// test setup
import { setupServer } from 'msw/node';
const server = setupServer(...handlers);
beforeAll(() => server.listen());
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

// Override per test
test('shows error on login failure', () => {
  server.use(
    rest.post('/api/login', (req, res, ctx) =>
      res(ctx.status(401))
    )
  );
});`,
      },
      {
        title: 'What should NOT be mocked',
        color: '#a855f7',
        desc: 'Over-mocking creates tests that pass but don\'t test anything real.',
        code: `// ❌ Over-mocking — testing nothing real
jest.mock('./useUserData'); // mock the entire hook
jest.mock('./UserCard');    // mock the child component
jest.mock('./utils');       // mock all utilities

test('UserProfile renders', () => {
  render(<UserProfile />);
  // This test passes even if UserProfile is completely broken
  // because everything is mocked!
});

// ✅ Mock only external/slow things
// Mock: HTTP requests (use MSW), timers (jest.useFakeTimers),
//       third-party SDKs, file system, environment variables

// Don't mock: your own utilities, pure functions,
//             child components you control, React hooks you wrote`,
      },
    ]} />

    <InlinePoll
      question="What is the key advantage of Mock Service Worker (MSW) over jest.mock for API mocking?"
      options={[
        'MSW is faster',
        'MSW intercepts at the network level — the same handlers work in tests, browser development, and Storybook without changing application code',
        'MSW requires less setup',
        'MSW works only in Node.js',
      ]}
      correct={1}
      explanation="MSW intercepts actual HTTP requests at the service worker / node level — your application code makes real fetch() calls, they just get intercepted. This means: same mocking code for Jest tests, browser dev mode, and Storybook. No need to change application code for testing."
    />

    <CommonMistake
      mistake="Mocking everything including your own components and utilities — creating tests that always pass regardless of bugs."
      fix="Only mock what you don't control or what makes tests slow/flaky: HTTP requests (use MSW), browser APIs (localStorage), timers, third-party SDKs. Keep your own utilities, components, and logic real — that's the code you're actually testing."
    />

    <DidYouKnow
      fact="MSW was created by Artem Zakharchenko after he was frustrated by the fragility of jest.mock for API testing. The key insight was using service workers (the same technology that powers PWAs) to intercept network requests — making mocks work at the network layer rather than the JavaScript import layer."
      color="#eab308"
    />

    <InterviewMeter topics={[
      { topic: 'Spy vs stub vs mock differences', freq: 75 },
      { topic: 'jest.mock usage and partial mocking', freq: 70 },
      { topic: 'MSW for network-level mocking', freq: 65 },
      { topic: 'What should and shouldn\'t be mocked', freq: 70 },
    ]} />
  </div>
);

export const ReduxLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Why Redux Exists</div>
      <p style={c.prose}>
        As apps grow, state scattered across components becomes impossible to debug. You can't answer: <strong style={{ color: '#ef4444' }}>"What changed? When? Why?"</strong> Redux solves this with a <strong style={{ color: '#a855f7' }}>single source of truth</strong> and a strict unidirectional data flow that makes every state change traceable.
      </p>
    </RevealCard>

    <AnalogyCard
      emoji="🏦"
      title="A bank with an audit trail"
      analogy="A bank doesn't let you directly reach into the vault and change your balance. Every transaction goes through a teller (action), is recorded in the ledger (reducer), and the balance (store) updates accordingly. Every change is traceable — you can see exactly what happened and when."
      connection="dispatch(action) → reducer computes new state → store updates → UI re-renders. Every state change is an explicit, logged action. Time-travel debugging becomes possible."
    />

    <StorySteps steps={[
      {
        title: 'The three principles of Redux',
        color: '#a855f7',
        desc: 'Single source of truth, state is read-only, changes are pure functions. These constraints make state predictable.',
        code: `// 1. Single source of truth
const store = createStore(rootReducer);
// ONE store for the entire app

// 2. State is read-only — only actions change it
store.dispatch({ type: 'INCREMENT' }); // ✓
store.getState().count = 5;            // ❌ never mutate directly

// 3. Changes are pure functions (reducers)
function reducer(state = 0, action) {
  switch (action.type) {
    case 'INCREMENT': return state + 1; // pure, no mutation
    case 'DECREMENT': return state - 1;
    default: return state;
  }
}`,
      },
      {
        title: 'Redux Toolkit — modern Redux',
        color: '#4facfe',
        desc: 'RTK eliminates all the boilerplate. createSlice generates actions and reducers together. Uses Immer under the hood so you can "mutate" safely.',
        code: `import { createSlice, configureStore } from '@reduxjs/toolkit';

const counterSlice = createSlice({
  name: 'counter',
  initialState: { value: 0, status: 'idle' },
  reducers: {
    increment: state => { state.value += 1; }, // Immer handles immutability
    decrement: state => { state.value -= 1; },
    incrementByAmount: (state, action) => {
      state.value += action.payload;
    },
  },
});

export const { increment, decrement, incrementByAmount } = counterSlice.actions;

const store = configureStore({
  reducer: { counter: counterSlice.reducer },
});`,
      },
      {
        title: 'Async with createAsyncThunk',
        color: '#00ff88',
        desc: 'RTK\'s createAsyncThunk handles async operations with automatic pending/fulfilled/rejected action types.',
        code: `import { createAsyncThunk, createSlice } from '@reduxjs/toolkit';

// Creates 3 actions: fetchUsers/pending, /fulfilled, /rejected
export const fetchUsers = createAsyncThunk(
  'users/fetchAll',
  async (_, { rejectWithValue }) => {
    try {
      const res = await fetch('/api/users');
      return await res.json();
    } catch (err) {
      return rejectWithValue(err.message);
    }
  }
);

const usersSlice = createSlice({
  name: 'users',
  initialState: { list: [], loading: false, error: null },
  extraReducers: (builder) => {
    builder
      .addCase(fetchUsers.pending, state => { state.loading = true; })
      .addCase(fetchUsers.fulfilled, (state, action) => {
        state.loading = false;
        state.list = action.payload;
      })
      .addCase(fetchUsers.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });
  },
});`,
      },
      {
        title: 'Selectors — read state efficiently',
        color: '#eab308',
        desc: 'useSelector subscribes a component to a slice of state. Only re-renders when that slice changes. Use reselect for computed/memoized selectors.',
        code: `import { useSelector, useDispatch } from 'react-redux';
import { createSelector } from '@reduxjs/toolkit';

// Basic selector
const count = useSelector(state => state.counter.value);

// ❌ New object every call — always re-renders
const bad = useSelector(state => ({
  count: state.counter.value,
  name: state.user.name,
}));

// ✅ Memoized selector with createSelector
const selectActiveUsers = createSelector(
  state => state.users.list,
  users => users.filter(u => u.active) // only recomputes when list changes
);

function UserList() {
  const dispatch = useDispatch();
  const activeUsers = useSelector(selectActiveUsers);
  return (
    <div>
      {activeUsers.map(u => <div key={u.id}>{u.name}</div>)}
      <button onClick={() => dispatch(fetchUsers())}>Refresh</button>
    </div>
  );
}`,
      },
    ]} />

    <InlinePoll
      question="What does createSlice from Redux Toolkit automatically generate?"
      options={[
        'Only the reducer function',
        'Action creators, action type strings, AND the reducer — all from one definition',
        'Only the action creators',
        'A complete Redux store with DevTools',
      ]}
      correct={1}
      explanation="createSlice generates: the reducer function, action creator functions for each case (slice.actions.increment), and action type strings ('counter/increment'). This eliminates the boilerplate of writing separate action types, action creators, and reducers."
    />

    <CommonMistake
      mistake="Using Redux for ALL state — including local UI state like modal open/close, form inputs, and component-level toggles."
      fix="Redux is for global state that multiple components need: auth, user preferences, cached API data. Local UI state belongs in useState. A good rule: if only one component uses it, keep it local. Server data belongs in React Query, not Redux."
    />

    <DidYouKnow
      fact="Redux was inspired by Facebook's Flux architecture and the Elm programming language. Dan Abramov created it in 2015 while preparing a conference talk about hot reloading. He didn't expect it to become the dominant state management solution — he thought it was too simple to be interesting."
      color="#a855f7"
    />

    <InterviewMeter topics={[
      { topic: 'Redux unidirectional data flow', freq: 80 },
      { topic: 'createSlice and Redux Toolkit basics', freq: 75 },
      { topic: 'createAsyncThunk for async operations', freq: 65 },
      { topic: 'Selectors and re-render optimization', freq: 70 },
      { topic: 'When to use Redux vs local state', freq: 75 },
    ]} />
  </div>
);
export const RenderCycleLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 How React Decides When to Update the Screen</div>
      <p style={c.prose}>
        React doesn't update the DOM on every setState call. It <strong style={{ color: '#4facfe' }}>batches</strong> updates together, runs reconciliation, and commits only the minimal DOM changes needed. Understanding this cycle is the key to writing performant React code.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🖨️" title="A smart printer with a queue" analogy="A smart printer doesn't print every document the moment you click print — it queues all print jobs, batches them efficiently, and prints in one pass. React's batching works the same way — queue all state updates, process once, render once." connection="Multiple setState calls in the same event are queued and processed together in one render pass. React 18 extended this to async contexts like setTimeout and Promises." />
    <StorySteps steps={[
      {
        title: 'Render phase — building the new tree', color: '#4facfe', desc: 'React calls your component functions and builds a new fiber tree. This phase is pure and interruptible in Concurrent Mode.', code: `// Render phase: React calls these functions
function App() { return <div><Counter /><Name /></div>; }
function Counter() { return <span>{count}</span>; }
// Nothing changed in real DOM yet — just virtual tree
// This phase CAN be interrupted by higher-priority work` },
      {
        title: 'Commit phase — updating the real DOM', color: '#00ff88', desc: 'React applies the minimal set of changes to the real DOM. Always synchronous — runs to completion.', code: `// Commit sub-phases:
// 1. Before mutation — reads DOM before changes
// 2. Mutation      — makes DOM changes
// 3. Layout        — runs useLayoutEffect sync
// After commit: useEffect runs asynchronously` },
      {
        title: 'Automatic batching — React 18', color: '#a855f7', desc: 'React 18 batches ALL state updates everywhere — including setTimeout, Promises, and native events.', code: `// React 17 — 3 separate re-renders in setTimeout
setTimeout(() => {
  setCount(c => c + 1); // re-render 1
  setName('Bob');        // re-render 2
  setFlag(true);         // re-render 3
});

// React 18 — ONE render, all three batched ✓
setTimeout(() => {
  setCount(c => c + 1);
  setName('Bob');
  setFlag(true); // only ONE re-render!
});

// Opt out when needed:
import { flushSync } from 'react-dom';
flushSync(() => setCount(c => c + 1)); // renders NOW` },
      {
        title: 'useTransition — urgent vs non-urgent', color: '#eab308', desc: 'Mark some updates as non-urgent. React prioritizes urgent work (typing) over transitions (search results).', code: `const [isPending, startTransition] = useTransition();

const handleChange = (e) => {
  setQuery(e.target.value); // URGENT — always immediate

  startTransition(() => {
    setResults(filterItems(items, e.target.value)); // NON-URGENT
  });
};

// isPending = true while transition is computing
<div style={{ opacity: isPending ? 0.5 : 1 }}>
  {results.map(r => <Result key={r.id} item={r} />)}
</div>` },
    ]} />
    <InlinePoll question="You call setCount(), setName(), setFlag() inside Promise.then() in React 18. How many re-renders happen?" options={['3 re-renders — one per setState', '1 re-render — React 18 batches all three automatically', '2 re-renders', 'Depends on component structure']} correct={1} explanation="React 18 automatic batching groups all setState calls — even in async contexts like Promise.then, setTimeout, and native events — into a single re-render." />
    <CommonMistake mistake="Calling flushSync inside a React event handler unnecessarily to 'ensure state is updated'." fix="React already batches and flushes state updates before the next browser paint in event handlers. flushSync is only needed when you need to read the DOM synchronously WITHIN the same function after a state update." />
    <DidYouKnow fact="React's Concurrent Mode makes the render phase interruptible. If you're rendering a 500-item list and the user starts typing, React can pause the list render, handle the keystroke, then resume. This is powered by the Fiber architecture." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'React 18 automatic batching explanation', freq: 80 }, { topic: 'Render phase vs commit phase difference', freq: 70 }, { topic: 'useTransition and isPending usage', freq: 65 }, { topic: 'flushSync — when and why to use it', freq: 60 }]} />
  </div>
);

export const ContextPerfLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 Context Re-renders: The Hidden Performance Trap</div>
      <p style={c.prose}>
        Context looks simple — but it has a critical trap: <strong style={{ color: '#ef4444' }}>every consumer re-renders whenever the context value changes</strong>, even if the component only uses a tiny part of the value.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📢" title="A company-wide announcement for a desk change" analogy="Imagine ANY announcement goes to ALL 500 employees. Someone moved their desk? Every employee stops work to listen. Context works the same way — changing notifications re-renders auth, header, and footer components even though they don't care about notifications." connection="Context broadcasts changes to ALL subscribers. Unlike Zustand where components subscribe to specific slices, Context has no granularity." />
    <StorySteps steps={[
      {
        title: 'The problem — one context, too many re-renders', color: '#ef4444', desc: 'A large context object means any update re-renders all consumers.', code: `// ❌ One big context — any change re-renders EVERYTHING
const AppContext = createContext({});
function AppProvider({ children }) {
  const [user, setUser] = useState(null);
  const [theme, setTheme] = useState('dark');
  const [notifications, setNotifications] = useState([]);

  // Adding a notification re-renders Header (uses user),
  // Sidebar (uses theme), NotifBell — ALL re-render!
  return (
    <AppContext.Provider
      value={{ user, theme, notifications, setNotifications }}
    >
      {children}
    </AppContext.Provider>
  );
}` },
      {
        title: 'Fix 1 — split context by concern', color: '#00ff88', desc: 'Separate contexts for separate concerns. Components only subscribe to what they actually use.', code: `// ✅ Split by update frequency
const UserContext  = createContext(null);
const ThemeContext = createContext('dark');
const NotifContext = createContext([]);

// Now: updating notifications ONLY re-renders NotifBell
// Header (uses UserContext)  — not affected ✓
// Sidebar (uses ThemeContext) — not affected ✓` },
      {
        title: 'Fix 2 — memoize the context value', color: '#4facfe', desc: 'useMemo prevents creating a new object reference on every render.', code: `// ❌ New object every render — re-renders all consumers
<UserContext.Provider value={{ user, setUser }}>

// ✅ Stable reference — only new object when user changes
function UserProvider({ children }) {
  const [user, setUser] = useState(null);
  const value = useMemo(
    () => ({ user, setUser }),
    [user] // only new object when user changes
  );
  return <UserContext.Provider value={value}>{children}</UserContext.Provider>;
}` },
      {
        title: 'Fix 3 — children as props pattern', color: '#a855f7', desc: 'Pass expensive components as children so they are owned by a parent that doesn\'t re-render on state change.', code: `// ✅ ExpensiveChild owned by App — doesn't re-render on count
function App() {
  return (
    <Counter>
      <ExpensiveChild /> {/* App doesn't re-render on count change */}
    </Counter>
  );
}
function Counter({ children }) {
  const [count, setCount] = useState(0);
  return (
    <div>
      <button onClick={() => setCount(c => c+1)}>{count}</button>
      {children} {/* same element reference — no re-render ✓ */}
    </div>
  );
}` },
    ]} />
    <InlinePoll question="Why does <Context.Provider value={{ user, login }}> cause all consumers to re-render on every parent render?" options={['Context always re-renders consumers', '{ user, login } creates a new object reference on every render — React sees a different reference even though the values are identical', 'login function causes the issue', 'ThemeContext needs separate memoization']} correct={1} explanation="{ user, login } is an object literal — a brand new object on every parent render. Even though user and login haven't changed, the new reference triggers all consumers. Fix: useMemo(() => ({ user, login }), [user])." />
    <CommonMistake mistake="Putting frequently updating state (counter, live data, form values) in a Context consumed by many components." fix="Context is ideal for low-frequency updates: auth, theme, locale. For frequently changing state shared across many components, use Zustand or Jotai — their selective subscriptions only re-render components whose specific slice changed." />
    <DidYouKnow fact="The React team considered adding a context selector API (like Redux useSelector) to the core library but decided against it. The recommendation is to split contexts. Libraries like use-context-selector and Jotai fill this gap." color="#ef4444" />
    <InterviewMeter topics={[{ topic: 'Why context causes re-renders — object reference issue', freq: 85 }, { topic: 'Split context by concern solution', freq: 75 }, { topic: 'useMemo for stable context value', freq: 70 }, { topic: 'Zustand vs Context for frequently updating state', freq: 70 }]} />
  </div>
);

export const CustomHooksLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Extract Logic, Not Just UI</div>
      <p style={c.prose}>
        Custom hooks let you extract <strong style={{ color: '#00ff88' }}>stateful logic</strong> from components into reusable functions. The same data fetching, debouncing, or subscription logic used in 5 components becomes one hook — tested once, used everywhere.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🔌" title="Electrical outlets — standardized interfaces" analogy="Every outlet in your house has the same interface. Your phone charger, lamp, and toaster all plug into the same standard. Custom hooks are the same — a standardized interface for reusable logic. useDebounce, useFetch, useLocalStorage all follow the same 'use' convention." connection="Any function starting with 'use' that calls other hooks. Components consume the interface without caring about the implementation." />
    <StorySteps steps={[
      {
        title: 'useFetch — data fetching with cleanup', color: '#4facfe', desc: 'The most common custom hook. Handles loading, error, data states plus AbortController cleanup.', code: `function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);
    fetch(url, { signal: controller.signal })
      .then(r => { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(d => { setData(d); setLoading(false); })
      .catch(e => { if (e.name !== 'AbortError') { setError(e.message); setLoading(false); } });
    return () => controller.abort(); // cleanup on url change/unmount
  }, [url]);

  return { data, loading, error };
}` },
      {
        title: 'useDebounce — delay value updates', color: '#a855f7', desc: 'Delays updating a value until N ms of silence. Use for search inputs.', code: `function useDebounce(value, delay = 300) {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer); // cleanup on each change
  }, [value, delay]);

  return debounced;
}

// Usage — search only fires after user stops typing
function SearchPage() {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebounce(query, 300);

  const { data } = useFetch(\`/api/search?q=\${debouncedQuery}\`);
}` },
      {
        title: 'useLocalStorage — synced persistence', color: '#eab308', desc: 'useState that persists to localStorage and stays in sync across tabs.', code: `function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch { return initialValue; }
  });

  const set = useCallback((newValue) => {
    setValue(newValue);
    localStorage.setItem(key, JSON.stringify(newValue));
  }, [key]);

  return [value, set];
}

const [theme, setTheme] = useLocalStorage('theme', 'dark');` },
      {
        title: 'useIntersectionObserver — visibility detection', color: '#00ff88', desc: 'Detect when an element enters the viewport. Used for infinite scroll, lazy loading, animations.', code: `function useIntersectionObserver(ref, options = {}) {
  const [isIntersecting, setIsIntersecting] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => setIsIntersecting(entry.isIntersecting),
      options
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [ref, options.threshold, options.rootMargin]);

  return isIntersecting;
}

// Infinite scroll trigger
const triggerRef = useRef(null);
const isVisible = useIntersectionObserver(triggerRef, { threshold: 0.1 });
useEffect(() => { if (isVisible) loadMore(); }, [isVisible]);` },
    ]} />
    <InlinePoll question="What is the key benefit of custom hooks over regular utility functions?" options={['Custom hooks are faster', 'Custom hooks can contain React state and effects — regular functions cannot use hooks', 'Custom hooks have better TypeScript support', 'Custom hooks are tree-shakable']} correct={1} explanation="Regular utility functions can't use useState, useEffect, etc. Custom hooks can contain any hook logic — making them perfect for encapsulating complex stateful behavior like data fetching, subscriptions, or browser API integration." />
    <CommonMistake mistake="Not memoizing returned callbacks from custom hooks — causing consumers to get new function references every render." fix="If your hook returns functions and consumers put them in dependency arrays, memoize them with useCallback. Otherwise consumers get infinite loops or incorrect memoization. Stable references from hooks are a contract with consumers." />
    <DidYouKnow fact="The React team almost didn't add the 'use' naming convention requirement. It was added because the ESLint plugin needs a way to know which functions must follow the rules of hooks. Without the convention, linting would be impossible." color="#00ff88" />
    <InterviewMeter topics={[{ topic: 'What custom hooks are and why use them', freq: 80 }, { topic: 'useFetch implementation with cleanup', freq: 75 }, { topic: 'useDebounce pattern', freq: 65 }, { topic: 'Returning stable references from hooks', freq: 60 }]} />
  </div>
);

export const HOCLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Components That Enhance Components</div>
      <p style={c.prose}>
        A Higher-Order Component is a <strong style={{ color: '#eab308' }}>function that takes a component and returns an enhanced version</strong>. It's the component equivalent of higher-order functions like map and filter — same pattern, applied to UI.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🎁" title="Gift wrapping" analogy="A gift wrap service takes any item (component) and wraps it beautifully (HOC). The gift inside hasn't changed — it's the same product. But now it has extra packaging: a bow (loading state), gift tag (auth check), bubble wrap (error boundary). The wrapper adds behavior without modifying the original." connection="withAuth(ProfilePage) returns a new component. ProfilePage is unchanged. The wrapper adds auth checking logic around it." />
    <StorySteps steps={[
      {
        title: 'Basic HOC structure', color: '#eab308', desc: 'A function that takes a Component and returns a new Component with added behavior.', code: `// HOC signature: Component → EnhancedComponent
function withLoading(WrappedComponent) {
  return function WithLoadingComponent({ isLoading, ...props }) {
    if (isLoading) return <div>Loading...</div>;
    return <WrappedComponent {...props} />;
    //                       ↑ always spread props through!
  };
}

// Usage
const UserListWithLoading = withLoading(UserList);
<UserListWithLoading isLoading={loading} users={users} />` },
      {
        title: 'withAuth — protect routes', color: '#4facfe', desc: 'Classic HOC use case — wrap any component with authentication checking.', code: `function withAuth(WrappedComponent) {
  return function AuthenticatedComponent(props) {
    const { user } = useAuth();

    if (!user) {
      return <Navigate to="/login" replace />;
    }

    return <WrappedComponent {...props} user={user} />;
  };
}

// Set displayName for React DevTools
withAuth.displayName = \`withAuth(\${WrappedComponent.displayName})\`;

const ProtectedDashboard = withAuth(Dashboard);` },
      {
        title: 'Compose multiple HOCs', color: '#a855f7', desc: 'HOCs compose — wrap with multiple to add multiple behaviors.', code: `const compose = (...fns) => x => fns.reduceRight((v, f) => f(v), x);

// Apply multiple HOCs
const EnhancedComponent = compose(
  withAuth,        // checks authentication
  withLogging,     // logs renders
  withErrorBoundary // catches errors
)(MyComponent);

// Without compose (harder to read):
const EnhancedComponent = withAuth(withLogging(withErrorBoundary(MyComponent)));` },
      {
        title: 'Why hooks replaced most HOCs', color: '#00ff88', desc: 'The same logic with no wrapper component in the tree. Easier to debug, no prop collisions.', code: `// ❌ HOC approach — adds wrapper to component tree
const UserListWithData = withData(withLogging(withAuth(UserList)));
// DevTools shows: WithAuth > WithLogging > WithData > UserList

// ✅ Hooks approach — flat, no wrappers
function UserList() {
  const { user } = useAuth();       // same logic
  useLogging('UserList');           // same logic
  const { data } = useFetch('/api/users'); // same logic
  // No extra component layers in the tree
}` },
    ]} />
    <InlinePoll question="What must a HOC always do with props?" options={['Filter out all props', 'Spread all received props to the wrapped component — {...props}', 'Only pass explicit props', 'Convert props to state']} correct={1} explanation="A HOC wraps a component — it should be transparent. Always spread props: <WrappedComponent {...props} />. The HOC may intercept specific props (like isLoading) but must pass everything else through so the wrapped component receives what it expects." />
    <CommonMistake mistake="Forgetting to set displayName on the HOC — the wrapped component shows as 'Component' in React DevTools." fix="Set displayName explicitly: WithLoading.displayName = `withLoading(${WrappedComponent.displayName || WrappedComponent.name || 'Component'})`. This makes debugging much easier — you'll see 'withLoading(UserList)' instead of just 'Component'." />
    <DidYouKnow fact="React.memo is itself a Higher-Order Component — it takes a component and returns a memoized version. So is React.forwardRef. The HOC pattern is built into React itself, even though hooks have replaced most custom HOC use cases." color="#eab308" />
    <InterviewMeter topics={[{ topic: 'What a HOC is and basic example', freq: 75 }, { topic: 'HOC vs custom hooks — when to use each', freq: 70 }, { topic: 'Props spreading and displayName best practices', freq: 60 }, { topic: 'Composing multiple HOCs', freq: 55 }]} />
  </div>
);

export const RenderPropsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Sharing Logic Via Function Props</div>
      <p style={c.prose}>
        The render props pattern shares logic by passing a <strong style={{ color: '#06b6d4' }}>function as a prop</strong> that a component calls to know what to render. The logic lives in the component, the rendering decision lives in the function you pass.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🎨" title="A picture frame vs a painting" analogy="A picture frame (render props component) provides the structure — hanging mechanism, border, glass. You provide the painting (render function) — what actually displays. The frame doesn't care what painting you put in. You can put any painting in any frame." connection="<DataFetcher render={data => <Chart data={data} />} /> — DataFetcher handles fetching logic, you decide how to render the data." />
    <StorySteps steps={[
      {
        title: 'Basic render props pattern', color: '#06b6d4', desc: 'Component accepts a function prop. It calls that function with data. You decide what to render with that data.', code: `// DataFetcher handles logic, you handle rendering
function DataFetcher({ url, render }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(url).then(r => r.json())
      .then(d => { setData(d); setLoading(false); });
  }, [url]);

  return render({ data, loading }); // call your function!
}

// Usage — you control the rendering
<DataFetcher
  url="/api/users"
  render={({ data, loading }) =>
    loading ? <Spinner /> : <UserList users={data} />
  }
/>` },
      {
        title: 'Children as function — most common form', color: '#a855f7', desc: 'Use children as the render function — cleaner JSX syntax.', code: `function Mouse({ children }) {
  const [pos, setPos] = useState({ x: 0, y: 0 });

  return (
    <div onMouseMove={e => setPos({ x: e.clientX, y: e.clientY })}>
      {children(pos)} {/* call children as a function */}
    </div>
  );
}

// Usage
<Mouse>
  {({ x, y }) => (
    <div>
      Mouse at {x}, {y}
      <img src="cat.png" style={{ position: 'fixed', left: x, top: y }} />
    </div>
  )}
</Mouse>` },
      {
        title: 'Performance gotcha', color: '#ef4444', desc: 'Inline render functions create new references every parent render — breaks PureComponent optimization.', code: `// ❌ Inline function — new reference every render
<Mouse render={({ x, y }) => <Cat x={x} y={y} />} />

// ✅ Define outside or use useCallback
const renderCat = useCallback(
  ({ x, y }) => <Cat x={x} y={y} />,
  []
);
<Mouse render={renderCat} />` },
      {
        title: 'Why hooks replaced render props', color: '#00ff88', desc: 'Same logic, simpler API, no JSX nesting.', code: `// ❌ Render props — JSX nesting
<Mouse>
  {pos => (
    <WindowSize>
      {size => (
        <DataFetcher url="/api">
          {data => <MyComponent pos={pos} size={size} data={data} />}
        </DataFetcher>
      )}
    </WindowSize>
  )}
</Mouse>

// ✅ Hooks — flat and clean
function MyComponent() {
  const pos  = useMouse();
  const size = useWindowSize();
  const data = useFetch('/api');
  return <div>{/* use all three */}</div>;
}` },
    ]} />
    <InlinePoll question="What is the 'children as function' pattern?" options={['Passing children as a string', '<Comp>{(data) => <div>{data}</div>}</Comp> — using children as the render function', 'Rendering child components dynamically', 'Using React.Children API']} correct={1} explanation="Instead of a named render prop, use children as the function: <Mouse>{pos => <div>{pos.x}</div>}</Mouse>. The component calls this.props.children(data). Same pattern — different prop name. It's the most common form of render props." />
    <CommonMistake mistake="Creating inline render functions that break memoization: <DataFetcher render={() => <Child />} /> — new function every render." fix="The render prop is a new function reference on every parent render. If DataFetcher is a PureComponent, it still re-renders because the prop looks different. Define the render function with useCallback or outside the component." />
    <DidYouKnow fact="The render props pattern was popularized by Michael Jackson (not the singer) in 2017 with his 'Use a Render Prop!' article. Ironically, he later co-created React Router v6 which uses hooks instead of render props — hooks made the pattern largely obsolete." color="#06b6d4" />
    <InterviewMeter topics={[{ topic: 'What render props pattern is', freq: 65 }, { topic: 'Children as function variant', freq: 60 }, { topic: 'Render props vs hooks — when still useful', freq: 60 }, { topic: 'Performance issue with inline render functions', freq: 55 }]} />
  </div>
);

export const CompoundComponentsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Components That Work Together</div>
      <p style={c.prose}>
        Compound components are a group of components designed to <strong style={{ color: '#a855f7' }}>work together as a unit</strong>, sharing implicit state via Context. Think of HTML's <code>&lt;select&gt;</code> and <code>&lt;option&gt;</code> — they're separate elements but deeply connected.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🍔" title="A burger and its ingredients" analogy="A burger (Tabs) is made of specific parts: bun (Tab), patty (TabPanel), lettuce (TabList). Each part makes no sense alone. Together they form a complete meal. The 'restaurant' (parent component) manages how they fit together — the ingredients just know their role." connection="<Tabs> manages active state via Context. <Tab> reads it to show active style. <TabPanel> reads it to show/hide content. No prop drilling — just implicit shared state." />
    <StorySteps steps={[
      {
        title: 'The problem with prop-heavy APIs', color: '#ef4444', desc: 'Without compound components, everything becomes a prop — hard to use and inflexible.', code: `// ❌ Prop-heavy — hard to customize, inflexible
<Tabs
  tabs={['Home', 'Profile', 'Settings']}
  panels={[<Home />, <Profile />, <Settings />]}
  activeTab={0}
  onTabChange={setActive}
  tabClassName="tab"
  panelClassName="panel"
  // 20 more props for every customization...
/>

// ✅ Compound — flexible, expressive
<Tabs>
  <TabList>
    <Tab>Home</Tab>
    <Tab>Profile</Tab>
  </TabList>
  <TabPanel><Home /></TabPanel>
  <TabPanel><Profile /></TabPanel>
</Tabs>` },
      {
        title: 'Parent provides state via Context', color: '#a855f7', desc: 'The parent manages shared state and provides it via Context. Children consume it implicitly.', code: `const TabsContext = createContext(null);

function Tabs({ children, defaultIndex = 0 }) {
  const [activeIndex, setActiveIndex] = useState(defaultIndex);

  const value = useMemo(
    () => ({ activeIndex, setActiveIndex }),
    [activeIndex]
  );

  return (
    <TabsContext.Provider value={value}>
      <div className="tabs">{children}</div>
    </TabsContext.Provider>
  );
}

function useTabsContext() {
  const ctx = useContext(TabsContext);
  if (!ctx) throw new Error('Must be used inside <Tabs>');
  return ctx;
}` },
      {
        title: 'Children consume shared state', color: '#4facfe', desc: 'Each child component reads from Context — no props needed from parent to child.', code: `function TabList({ children }) {
  return <div role="tablist">{children}</div>;
}

function Tab({ children, index }) {
  const { activeIndex, setActiveIndex } = useTabsContext();
  const isActive = index === activeIndex;
  return (
    <button
      role="tab"
      aria-selected={isActive}
      onClick={() => setActiveIndex(index)}
      style={{ fontWeight: isActive ? 700 : 400 }}
    >
      {children}
    </button>
  );
}

function TabPanel({ children, index }) {
  const { activeIndex } = useTabsContext();
  if (index !== activeIndex) return null;
  return <div role="tabpanel">{children}</div>;
}` },
      {
        title: 'Dot notation — signal compound relationship', color: '#eab308', desc: 'Attach child components as properties on the parent using dot notation.', code: `// Attach children to parent
Tabs.List  = TabList;
Tabs.Tab   = Tab;
Tabs.Panel = TabPanel;

// Usage is self-documenting
<Tabs>
  <Tabs.List>
    <Tabs.Tab index={0}>Home</Tabs.Tab>
    <Tabs.Tab index={1}>Profile</Tabs.Tab>
  </Tabs.List>
  <Tabs.Panel index={0}><Home /></Tabs.Panel>
  <Tabs.Panel index={1}><Profile /></Tabs.Panel>
</Tabs>` },
    ]} />
    <InlinePoll question="How do compound components share state between parent and children without prop drilling?" options={['Redux store', 'Via React Context — parent provides state, children consume it via useContext', 'Through the DOM', 'Via global variables']} correct={1} explanation="The parent creates a Context with its state and provides it. Each child component calls useContext to access the shared state. No props need to be explicitly passed — children just consume what the parent provides." />
    <CommonMistake mistake="Using compound components when a simple prop-based API would be cleaner — over-engineering small components." fix="Compound components shine for complex, flexible UIs: Tabs, Accordion, Select, Modal, Menu. For simple components with 2-3 variants, a props-based API is cleaner. Use compound components when consumers need layout control or want to reorder/omit parts." />
    <DidYouKnow fact="Material UI, Radix UI, and Headless UI all use the compound components pattern extensively. Radix UI's Accordion, Dialog, and Select are all compound components — they separate structure from styling, making fully custom designs possible while keeping accessibility built in." color="#a855f7" />
    <InterviewMeter topics={[{ topic: 'What compound components are and why', freq: 65 }, { topic: 'Context for implicit state sharing', freq: 60 }, { topic: 'Dot notation convention', freq: 55 }, { topic: 'When to use vs avoid compound components', freq: 55 }]} />
  </div>
);

export const ControlledUncontrolledLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Who Owns the Form State?</div>
      <p style={c.prose}>
        The fundamental question in React forms: <strong style={{ color: '#4facfe' }}>does React control the input value, or does the DOM?</strong> Controlled components give React full control. Uncontrolled components let the DOM manage itself.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🎮" title="Controlled vs autopilot" analogy="A controlled component is like manually flying a plane — you control every movement, you always know the exact position. An uncontrolled component is like autopilot — the plane manages itself, you only check the position when you need to land (submit)." connection="Controlled: value={state} — React knows the value every keystroke. Uncontrolled: ref={inputRef} — React only reads it when needed." />
    <StorySteps steps={[
      {
        title: 'Controlled — React owns the value', color: '#4facfe', desc: 'value prop makes React the single source of truth. Every keystroke updates state, which updates the input.', code: `function ControlledForm() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  // React always knows the current value
  // Can validate on every keystroke
  // Can format/transform input in real time

  const handleSubmit = (e) => {
    e.preventDefault();
    submitData({ name, email }); // already have the values
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        value={name}         // ← React controls this
        onChange={e => setName(e.target.value)}
      />
      {name.length < 2 && <span>Name too short</span>}
    </form>
  );
}` },
      {
        title: 'Uncontrolled — DOM owns the value', color: '#a855f7', desc: 'No value prop. Use ref to read the value when needed (like on submit).', code: `function UncontrolledForm() {
  const nameRef = useRef(null);
  const emailRef = useRef(null);

  // React doesn't know the value until you read it
  // No re-renders on every keystroke!
  // Simpler for basic forms

  const handleSubmit = (e) => {
    e.preventDefault();
    submitData({
      name: nameRef.current.value,   // read on submit
      email: emailRef.current.value,
    });
  };

  return (
    <form onSubmit={handleSubmit}>
      <input ref={nameRef} defaultValue="" />
      <input ref={emailRef} type="email" />
      <button type="submit">Submit</button>
    </form>
  );
}` },
      {
        title: 'defaultValue vs value', color: '#eab308', desc: 'defaultValue sets the initial value for uncontrolled. value creates a controlled input.', code: `// Controlled — React manages value
<input value={state} onChange={setState} />
// React re-renders on every keystroke

// Uncontrolled — DOM manages value
<input defaultValue="initial" ref={ref} />
// No re-renders, just read ref on submit

// ❌ Common mistake: value without onChange
<input value="fixed" /> // read-only! can't type
// React warns: "provide onChange or use defaultValue"

// ✅ File inputs are ALWAYS uncontrolled
<input type="file" ref={fileRef} />
// Can never set value programmatically` },
      {
        title: 'React Hook Form — best of both worlds', color: '#00ff88', desc: 'RHF uses uncontrolled inputs (no re-renders) but gives you controlled-like validation and values.', code: `import { useForm } from 'react-hook-form';

function Form() {
  const { register, handleSubmit, formState: { errors } } = useForm();

  return (
    <form onSubmit={handleSubmit(data => console.log(data))}>
      <input
        {...register('name', {
          required: 'Name is required',
          minLength: { value: 2, message: 'Too short' }
        })}
      />
      {errors.name && <span>{errors.name.message}</span>}
      <button type="submit">Submit</button>
    </form>
  );
  // Zero re-renders during typing!
  // Full validation + values on submit
}` },
    ]} />
    <InlinePoll question="What happens if you set value={x} on an input without an onChange handler?" options={['The input works normally', 'The input becomes read-only — you can\'t type. React warns you to add onChange or use defaultValue', 'React throws an error', 'The value is ignored']} correct={1} explanation="value without onChange creates a read-only input. React sets the value but without onChange, there's no way to update state when the user types — so the input rejects all keystrokes. Use defaultValue for uncontrolled, or value + onChange for controlled." />
    <CommonMistake mistake="Using controlled inputs for every form field — causing re-renders on every single keystroke in a large form." fix="For large forms, uncontrolled inputs (React Hook Form, Formik with refs) cause zero re-renders during typing. Only validate/submit triggers work. This can be a significant performance improvement for complex forms with 20+ fields." />
    <DidYouKnow fact="File inputs (<input type='file'>) are the one input type that can NEVER be controlled in React. You cannot programmatically set their value for security reasons — browsers don't allow scripts to pre-populate file inputs. They are always uncontrolled." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'Controlled vs uncontrolled difference', freq: 80 }, { topic: 'defaultValue vs value distinction', freq: 75 }, { topic: 'When to use each approach', freq: 65 }, { topic: 'File inputs are always uncontrolled', freq: 55 }]} />
  </div>
);

export const ErrorBoundariesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 Catching UI Crashes Gracefully</div>
      <p style={c.prose}>
        Without error boundaries, a JavaScript error in any component crashes the <strong style={{ color: '#ef4444' }}>entire React tree</strong> — the user sees a blank screen. Error boundaries catch rendering errors and display a fallback UI instead.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🔌" title="A circuit breaker" analogy="A circuit breaker protects your home — when one circuit overloads, it trips and cuts that circuit without taking down the whole house. Error boundaries are circuit breakers for your component tree. One broken component trips the boundary, shows fallback UI, but the rest of the app keeps running." connection="Wrap risky sections in ErrorBoundary. If they crash, the boundary catches the error, logs it, and shows a fallback — the rest of your app is unaffected." />
    <StorySteps steps={[
      {
        title: 'What error boundaries catch', color: '#ef4444', desc: 'Catches errors during rendering, lifecycle methods, and constructors of child components.', code: `// ✅ Error boundaries CATCH these:
// - Errors during render
// - Errors in constructor
// - Errors in lifecycle methods (componentDidMount, etc)
// - Errors in useEffect? NO — only class lifecycle methods

// ❌ Error boundaries DO NOT catch:
// - Event handlers (use try/catch)
// - Async code (setTimeout, fetch)
// - Errors in the boundary itself
// - Server-side rendering errors` },
      {
        title: 'Class component implementation', color: '#4facfe', desc: 'Error boundaries must be class components. getDerivedStateFromError renders fallback. componentDidCatch logs the error.', code: `class ErrorBoundary extends React.Component {
  state = { hasError: false, error: null };

  static getDerivedStateFromError(error) {
    // Called during render — update state to show fallback
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // Called after render — log to error service
    logToSentry(error, errorInfo.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div>
          <h2>Something went wrong</h2>
          <button onClick={() => this.setState({ hasError: false })}>
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}` },
      {
        title: 'react-error-boundary library', color: '#00ff88', desc: 'The recommended library — adds hooks support and a simpler API.', code: `import { ErrorBoundary, useErrorBoundary } from 'react-error-boundary';

// Declarative fallback component
function FallbackComponent({ error, resetErrorBoundary }) {
  return (
    <div role="alert">
      <p>Error: {error.message}</p>
      <button onClick={resetErrorBoundary}>Try again</button>
    </div>
  );
}

// Usage
<ErrorBoundary
  FallbackComponent={FallbackComponent}
  onError={(error, info) => logToService(error, info)}
  onReset={() => window.location.reload()}
>
  <RiskyComponent />
</ErrorBoundary>` },
      {
        title: 'Strategic placement', color: '#eab308', desc: 'Place boundaries at the right granularity — protect sections without hiding too much.', code: `// ✅ Good — protect each section independently
function App() {
  return (
    <div>
      <ErrorBoundary fallback={<HeaderFallback />}>
        <Header />
      </ErrorBoundary>

      <ErrorBoundary fallback={<p>Feed unavailable</p>}>
        <NewsFeed />     {/* crash here doesn't affect sidebar */}
      </ErrorBoundary>

      <ErrorBoundary fallback={<p>Sidebar error</p>}>
        <Sidebar />      {/* crash here doesn't affect feed */}
      </ErrorBoundary>
    </div>
  );
}` },
    ]} />
    <InlinePoll question="Why can't error boundaries catch errors in event handlers?" options={['React decided not to support it', 'Event handlers run outside the render cycle — errors there don\'t affect rendering, so use regular try/catch', 'It\'s technically impossible', 'Event handler errors crash the entire app']} correct={1} explanation="Error boundaries catch rendering errors because React needs to unmount and show fallback UI when rendering fails. Event handlers run outside the render cycle — their errors don't break rendering. Use regular try/catch in event handlers." />
    <CommonMistake mistake="Putting one error boundary at the root of the app to 'catch everything' — showing a blank page for any error." fix="Granular boundaries give better UX. Wrap each major section (navigation, main content, sidebar, each widget) in its own boundary. A broken widget shows a small fallback; the rest of the app keeps working." />
    <DidYouKnow fact="Before React 16, errors during rendering would leave React in a corrupted state — the component tree was broken but nothing caught it. React 16 introduced error boundaries specifically to fix this. The React team said 'it is worse to leave a corrupted UI in place than to completely remove it.'" color="#ef4444" />
    <InterviewMeter topics={[{ topic: 'What error boundaries catch and don\'t catch', freq: 80 }, { topic: 'Class component implementation', freq: 65 }, { topic: 'Strategic placement in component tree', freq: 65 }, { topic: 'react-error-boundary library', freq: 60 }]} />
  </div>
);

export const PortalsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Escape the DOM Hierarchy</div>
      <p style={c.prose}>
        Normally, a component renders inside its parent's DOM node. Portals let you render a component's children into a <strong style={{ color: '#4facfe' }}>completely different DOM node</strong> — while keeping it in the same React tree.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🌀" title="A teleporter" analogy="Imagine you're on the 5th floor of a building (deep in a nested component) but you need to put a sign in the lobby (document.body). Normally you'd have to carry it through every floor. A portal is a teleporter — you can place content anywhere in the building regardless of where you are." connection="ReactDOM.createPortal(children, document.body) renders children at document.body while the component that renders them is still nested deeply in the React tree." />
    <StorySteps steps={[
      {
        title: 'The problem portals solve', color: '#ef4444', desc: 'Modals inside overflow:hidden parents get clipped. z-index battles become impossible.', code: `// ❌ Problem: Modal inside overflow:hidden container
<div style={{ overflow: 'hidden', position: 'relative' }}>
  {/* Everything renders here */}
  <Modal /> {/* clipped by overflow:hidden! */}
</div>

// ✅ Solution: portal to document.body
// Modal teleports out of overflow:hidden parent
// Renders above everything else in the DOM` },
      {
        title: 'createPortal — basic usage', color: '#4facfe', desc: 'ReactDOM.createPortal(children, domNode) renders children into domNode.', code: `import { createPortal } from 'react-dom';

function Modal({ isOpen, onClose, children }) {
  if (!isOpen) return null;

  return createPortal(
    // This JSX renders into document.body
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={e => e.stopPropagation()}>
        {children}
      </div>
    </div>,
    document.body  // ← DOM node to render into
  );
}

// In index.html, add a separate div:
// <div id="modal-root"></div>
// Then: document.getElementById('modal-root')` },
      {
        title: 'Events still bubble through React tree', color: '#00ff88', desc: 'Despite different DOM location, events bubble through the React component tree — not the DOM tree.', code: `function App() {
  const [clicked, setClicked] = useState(false);

  return (
    // This onClick catches events from the Modal
    // even though Modal renders in document.body!
    <div onClick={() => setClicked(true)}>
      <Modal>
        <button>Click me</button>
        {/* Click bubbles up through React tree to App */}
        {/* Even though in DOM, it's at document.body */}
      </Modal>
    </div>
  );
}` },
      {
        title: 'Portal container setup', color: '#eab308', desc: 'Create a dedicated portal container in HTML for clean separation.', code: `// index.html
<body>
  <div id="root"></div>
  <div id="portal-root"></div>  {/* dedicated portal target */}
</body>

// Reusable Portal component
function Portal({ children }) {
  const portalRoot = document.getElementById('portal-root');
  return createPortal(children, portalRoot);
}

// Usage
<Portal>
  <Tooltip position={pos}>Hover content</Tooltip>
</Portal>` },
    ]} />
    <InlinePoll question="A click inside a Portal modal — does it bubble up to the parent component that rendered the portal?" options={['No — events stop at the portal boundary', 'Yes — events bubble through the React component tree, not the DOM tree', 'Only click events bubble', 'Events must be handled at document level']} correct={1} explanation="Events bubble through the React component tree regardless of DOM position. A click inside a portal modal will bubble up to the parent component that rendered the portal. This is intentional — it makes event handling predictable from React's perspective." />
    <CommonMistake mistake="Forgetting to handle focus trapping in modals — screen readers and keyboard users can tab out of the modal." fix="A11y-compliant modals need focus trapping: when the modal opens, focus moves inside it; Tab key cycles through focusable elements inside the modal only; Esc closes it. Use @radix-ui/react-dialog or focus-trap-react to handle this automatically." />
    <DidYouKnow fact="Before portals were added in React 16, developers used workarounds like mounting modals directly to document.body with ReactDOM.render(), or building elaborate z-index stacking contexts. Portals made these workarounds obsolete and made modals first-class React citizens." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'What portals are and the problem they solve', freq: 70 }, { topic: 'createPortal syntax', freq: 65 }, { topic: 'Event bubbling through React tree (not DOM)', freq: 65 }, { topic: 'Modal accessibility with portals', freq: 55 }]} />
  </div>
);

export const SuspenseLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Declarative Loading States</div>
      <p style={c.prose}>
        Suspense lets you <strong style={{ color: '#a855f7' }}>declaratively specify loading states</strong> for parts of your component tree. Instead of checking isLoading flags everywhere, wrap lazy content in Suspense and define the fallback once.
      </p>
    </RevealCard>
    <AnalogyCard emoji="⏳" title="A restaurant reservation system" analogy="When you reserve a table (Suspense boundary), the host gives you a pager (fallback). You wait in the bar (loading state). When your table is ready (component loaded), the pager buzzes and you're seated (component renders). The rest of the restaurant keeps running normally — other tables aren't affected." connection="<Suspense fallback={<Spinner />}> — Suspense holds the fallback until all children are ready. Other parts of the UI continue rendering normally." />
    <StorySteps steps={[
      {
        title: 'Code splitting with React.lazy', color: '#a855f7', desc: 'React.lazy dynamically imports a component. Suspense shows the fallback while the chunk loads.', code: `import { lazy, Suspense } from 'react';

// Lazy load — only downloads when first rendered
const Dashboard = lazy(() => import('./Dashboard'));
const Settings  = lazy(() => import('./Settings'));

// Suspense catches the "suspended" components
function App() {
  return (
    <Router>
      <Suspense fallback={<PageSkeleton />}>
        <Routes>
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/settings"  element={<Settings />} />
        </Routes>
      </Suspense>
    </Router>
  );
}` },
      {
        title: 'Nested Suspense boundaries', color: '#4facfe', desc: 'Different parts of the UI can have different loading states at different granularities.', code: `function ProductPage() {
  return (
    <div>
      {/* Shows immediately — no suspense */}
      <ProductHeader />

      {/* Show skeleton for the image */}
      <Suspense fallback={<ImageSkeleton />}>
        <ProductImage />
      </Suspense>

      {/* Different skeleton for reviews */}
      <Suspense fallback={<ReviewsSkeleton />}>
        <Reviews />
      </Suspense>
      {/* Each section loads independently! */}
    </div>
  );
}` },
      {
        title: 'useDeferredValue — stale-while-updating', color: '#eab308', desc: 'Show stale content while new content loads. Keeps UI responsive during updates.', code: `function SearchResults({ query }) {
  const deferredQuery = useDeferredValue(query);
  const isStale = deferredQuery !== query;

  return (
    <div style={{ opacity: isStale ? 0.5 : 1 }}>
      {/* Shows old results while new ones load */}
      {/* Dims to indicate loading */}
      <Suspense fallback={<Spinner />}>
        <Results query={deferredQuery} />
      </Suspense>
    </div>
  );
}` },
      {
        title: 'Prefetch on hover', color: '#00ff88', desc: 'Start loading chunks before the user navigates — zero wait time on click.', code: `function NavLink({ to, children }) {
  const prefetch = () => {
    // Start downloading the chunk on hover
    // By the time user clicks, it's already loaded!
    if (to === '/dashboard') import('./Dashboard');
    if (to === '/settings')  import('./Settings');
  };

  return (
    <Link to={to} onMouseEnter={prefetch}>
      {children}
    </Link>
  );
}` },
    ]} />
    <InlinePoll question="What does React.lazy(() => import('./Component')) do?" options={['Renders Component lazily after scroll', 'Creates a lazy component that only downloads its code when first rendered, wrapped in Suspense', 'Defers Component rendering to next tick', 'Memoizes Component forever']} correct={1} explanation="React.lazy creates a lazy component. The bundle for that component isn't downloaded until it's first rendered. Wrap in <Suspense fallback={<Loading />}> to handle the loading state while the bundle downloads." />
    <CommonMistake mistake="Putting Suspense too high in the tree — showing a full-page spinner for a small widget that's loading." fix="Place Suspense boundaries close to the components that might suspend. This gives granular loading UX — a small skeleton for each section rather than a full-page spinner that hides all content." />
    <DidYouKnow fact="Suspense for data fetching (not just code splitting) was announced in 2018 but took until React 18 to become production-ready. It required a complete rewrite of React's rendering model (Concurrent Mode) to work correctly. The 4-year journey shows how complex the problem is." color="#a855f7" />
    <InterviewMeter topics={[{ topic: 'React.lazy + Suspense for code splitting', freq: 80 }, { topic: 'Placement strategy for Suspense boundaries', freq: 65 }, { topic: 'useDeferredValue for stale-while-updating', freq: 55 }, { topic: 'Prefetch on hover pattern', freq: 55 }]} />
  </div>
);

export const ForwardRefLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Passing Refs Through Components</div>
      <p style={c.prose}>
        In React, <code>ref</code> is special — it's not passed as a prop. <strong style={{ color: '#00ff88' }}>forwardRef</strong> lets a component explicitly receive a ref from its parent and pass it to a DOM element or child component.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📬" title="A mail forwarding service" analogy="When you move, you set up mail forwarding — letters addressed to your old address get forwarded to your new one. forwardRef does the same: a ref 'addressed' to a component gets forwarded to the actual DOM element inside it." connection="ref={inputRef} on a custom Input component — without forwardRef, inputRef points to nothing. With forwardRef, inputRef points to the actual <input> DOM element." />
    <StorySteps steps={[
      {
        title: 'The problem — refs don\'t pass through', color: '#ef4444', desc: 'Without forwardRef, ref on a custom component points to null — it doesn\'t reach the DOM element inside.', code: `// ❌ Without forwardRef
function Input({ placeholder }) {
  return <input placeholder={placeholder} />;
}

const inputRef = useRef(null);
<Input ref={inputRef} placeholder="Type here..." />
// inputRef.current === null! ref didn't reach the <input>
// React warns: "Function components cannot be given refs"` },
      {
        title: 'forwardRef — pass ref to DOM element', color: '#00ff88', desc: 'Wrap the component in forwardRef. Ref is passed as the second argument.', code: `const Input = React.forwardRef(function Input(props, ref) {
  return (
    <div className="input-wrapper">
      <input ref={ref} {...props} /> {/* forward ref here */}
    </div>
  );
});

// Now ref works!
const inputRef = useRef(null);
<Input ref={inputRef} placeholder="Type here..." />

// Parent can control the input:
inputRef.current.focus();
inputRef.current.select();
inputRef.current.value;` },
      {
        title: 'useImperativeHandle — custom ref API', color: '#4facfe', desc: 'Instead of exposing the raw DOM node, expose only specific methods. Creates a clean API for the parent.', code: `const FancyInput = forwardRef(function FancyInput(props, ref) {
  const inputRef = useRef(null);

  // Expose only what the parent should control
  useImperativeHandle(ref, () => ({
    focus: () => inputRef.current.focus(),
    clear: () => { inputRef.current.value = ''; },
    getValue: () => inputRef.current.value,
    // Raw DOM node NOT exposed — parent can't break internals
  }));

  return <input ref={inputRef} {...props} />;
});

// Parent usage:
fancyRef.current.focus();     // ✓ exposed
fancyRef.current.clear();     // ✓ exposed
fancyRef.current.click();     // ✗ not exposed — protected!` },
      {
        title: 'TypeScript typing for forwardRef', color: '#eab308', desc: 'Generic forwardRef needs explicit type parameters for ref type and props type.', code: `interface InputProps {
  placeholder?: string;
  onSearch: (value: string) => void;
}

const SearchInput = forwardRef<HTMLInputElement, InputProps>(
  function SearchInput({ placeholder, onSearch }, ref) {
    return (
      <input
        ref={ref}
        placeholder={placeholder}
        onChange={e => onSearch(e.target.value)}
      />
    );
  }
);

// ref is correctly typed as RefObject<HTMLInputElement>
const ref = useRef<HTMLInputElement>(null);
<SearchInput ref={ref} onSearch={handleSearch} />` },
    ]} />
    <InlinePoll question="When should you use useImperativeHandle instead of just forwarding the DOM ref directly?" options={['Always — it\'s more secure', 'When you want to limit what the parent can do — expose specific methods without giving full DOM access', 'Never — just forward the DOM ref', 'Only in TypeScript']} correct={1} explanation="Exposing raw DOM nodes gives parents too much power and couples them to your implementation details. useImperativeHandle creates a stable API: expose focus(), clear() — later you can change the DOM structure without breaking parent code." />
    <CommonMistake mistake="Using forwardRef for every component by default — adding unnecessary complexity." fix="Only use forwardRef when a parent genuinely needs to imperatively control a child's DOM element (focus, scroll, measure). For 95% of component communication, props and callbacks are the right approach. forwardRef is an escape hatch for DOM imperative operations." />
    <DidYouKnow fact="In React 19, forwardRef is no longer needed — ref is passed as a regular prop. You can write function Input({ ref, ...props }) directly. This is a breaking change that simplifies component authoring significantly, removing one of the more confusing React APIs." color="#00ff88" />
    <InterviewMeter topics={[{ topic: 'Why forwardRef is needed', freq: 75 }, { topic: 'forwardRef basic implementation', freq: 70 }, { topic: 'useImperativeHandle to expose custom API', freq: 60 }, { topic: 'React 19 changes to ref handling', freq: 50 }]} />
  </div>
);

export const MemoLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 When to Stop Re-rendering</div>
      <p style={c.prose}>
        By default, React re-renders a component every time its parent re-renders — even if props haven't changed. <strong style={{ color: '#eab308' }}>React.memo</strong> opts a component out: it only re-renders when its props actually change.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📸" title="A photograph vs a live camera feed" analogy="A regular component is like a live camera — it updates every second regardless of whether anything changed. React.memo is like taking a photograph — it only updates when you explicitly tell it something changed. If props are the same, use the cached image." connection="React.memo does a shallow comparison of props. If all props are the same reference, it skips the render and reuses the last output." />
    <StorySteps steps={[
      {
        title: 'React.memo — skip renders when props unchanged', color: '#eab308', desc: 'Wraps a component so it only re-renders when props change (shallow comparison).', code: `// ❌ Without memo — re-renders on every parent render
function ExpensiveList({ items }) {
  // renders even if items didn't change
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// ✅ With memo — skips render if items reference is same
const ExpensiveList = React.memo(function ExpensiveList({ items }) {
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
});

// Custom comparison for deep equality:
const MemoList = React.memo(ExpensiveList, (prev, next) => {
  return prev.items.length === next.items.length;
  // true = props are equal, skip render
  // false = props changed, re-render
});` },
      {
        title: 'useMemo — memoize computed values', color: '#4facfe', desc: 'Cache expensive calculations. Recomputes only when dependencies change.', code: `function ProductList({ products, category }) {
  // ❌ Recomputes on every render — even if products/category didn't change
  const filtered = products.filter(p => p.category === category);

  // ✅ Only recomputes when products or category changes
  const filtered = useMemo(
    () => products.filter(p => p.category === category),
    [products, category]
  );

  // ❌ Too simple to memoize — overhead > benefit
  const doubled = useMemo(() => count * 2, [count]);
  // Just write: const doubled = count * 2;

  return <ul>{filtered.map(p => <Product key={p.id} item={p} />)}</ul>;
}` },
      {
        title: 'useCallback — stable function references', color: '#a855f7', desc: 'Returns a memoized function reference. Required when passing callbacks to memoized children.', code: `function Parent() {
  const [count, setCount] = useState(0);

  // ❌ New function reference every render
  // MemoChild always re-renders despite React.memo!
  const handleClick = () => console.log('clicked');

  // ✅ Stable reference — MemoChild skips re-render
  const handleClick = useCallback(
    () => console.log('clicked'),
    [] // no dependencies — function never changes
  );

  return (
    <div>
      <button onClick={() => setCount(c => c+1)}>{count}</button>
      <MemoChild onClick={handleClick} /> {/* won't re-render ✓ */}
    </div>
  );
}` },
      {
        title: 'When NOT to memoize', color: '#ef4444', desc: 'Memoization has overhead. Don\'t add it everywhere without profiling.', code: `// ❌ Over-memoization — adds complexity without benefit
const add = useCallback((a, b) => a + b, []); // trivial
const doubled = useMemo(() => count * 2, [count]); // trivial
const SimpleComponent = React.memo(({ text }) => <p>{text}</p>); // cheap

// ✅ Worth memoizing:
// - Expensive calculations (sorting, filtering large arrays)
// - Callbacks passed to memoized child components
// - Objects/arrays passed as props to memoized children
// - Reference equality checks in useEffect deps

// Rule: profile first (React DevTools Profiler),
// then optimize based on actual data` },
    ]} />
    <InlinePoll question="A component wrapped in React.memo still re-renders on every parent render. Most likely cause?" options={['React.memo is broken', 'A prop is a new object/function reference created inline each render (e.g., config={{}} or onClick={()=>{}})', 'The component has internal state', 'React 18 changed React.memo behavior']} correct={1} explanation="React.memo does shallow comparison. Inline objects/functions create new references every render — memo sees them as different and allows re-render. Fix: useMemo for objects, useCallback for functions passed as props." />
    <CommonMistake mistake="Adding React.memo, useMemo, and useCallback to every component and function 'just in case'." fix="Memoization adds overhead (comparison cost, closure allocation, cognitive complexity). Add it only when profiling shows a real performance issue. The React DevTools Profiler shows which components re-rendered and why — start there." />
    <DidYouKnow fact="useCallback(fn, deps) is literally identical to useMemo(() => fn, deps). They're the same hook internally — useCallback is just a convenience wrapper for the specific case of memoizing functions. React chose to add useCallback because memoizing functions is so common it deserved a dedicated API." color="#eab308" />
    <InterviewMeter topics={[{ topic: 'What React.memo does and when it fails', freq: 85 }, { topic: 'useMemo vs useCallback difference', freq: 80 }, { topic: 'When NOT to memoize', freq: 70 }, { topic: 'React DevTools Profiler to find real issues', freq: 65 }]} />
  </div>
);

export const ReRenderCausesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 Why Is My Component Re-rendering?</div>
      <p style={c.prose}>
        Understanding exactly what causes re-renders is the foundation of React performance optimization. There are <strong style={{ color: '#ef4444' }}>exactly 4 causes</strong> — once you know them, you can fix any re-render issue.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🔔" title="A notification system" analogy="Your phone buzzes when: YOU get a message (own state), SOMEONE TEXTS you (prop changes), THE GROUP CHAT gets a message (parent re-renders), or YOU'RE SUBSCRIBED to a channel that posts (context changes). Exactly 4 sources. Same for React components." connection="State change, prop change, parent re-render, context change. Know which one is causing the issue and you know exactly how to fix it." />
    <StorySteps steps={[
      {
        title: 'Cause 1 — own state changes', color: '#4facfe', desc: 'Any setState call re-renders the component. This is intentional — state changes should update the UI.', code: `function Counter() {
  const [count, setCount] = useState(0);
  // clicking button → setCount → re-render (correct!)
  return <button onClick={() => setCount(c => c+1)}>{count}</button>;
}` },
      {
        title: 'Cause 2 — props change (new reference)', color: '#a855f7', desc: 'Props compared by reference. New object/function/array reference = re-render even if values are identical.', code: `// ❌ These create new references every parent render:
<Child config={{ theme: 'dark' }} />  // new object {}
<Child onClick={() => submit()} />    // new function
<Child items={[...todos]} />          // new array

// ✅ Stable references:
const config   = useMemo(() => ({ theme: 'dark' }), []);
const onClick  = useCallback(() => submit(), []);
// items from state — only new reference when state changes` },
      {
        title: 'Cause 3 — parent re-renders', color: '#eab308', desc: 'When a parent re-renders, ALL children re-render by default — even if their props didn\'t change.', code: `function Parent() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <button onClick={() => setCount(c => c+1)}>{count}</button>
      <Child />  {/* re-renders on every count change! */}
                 {/* even though Child has no props */}
    </div>
  );
}

// Fix: React.memo or children-as-props pattern
const Child = React.memo(() => <div>Static content</div>);` },
      {
        title: 'Cause 4 — context changes', color: '#ef4444', desc: 'Any consumer re-renders when context value changes — even if the specific data they use didn\'t change.', code: `// ❌ Context value changes → ALL consumers re-render
const ThemeContext = createContext({});
function App() {
  const [user, setUser] = useState(null);
  const [theme, setTheme] = useState('dark');

  return (
    // When user changes, theme consumers also re-render!
    <ThemeContext.Provider value={{ theme, user }}>
      <ThemedButton /> {/* only uses theme, but re-renders for user! */}
    </ThemeContext.Provider>
  );
}

// Fix: split contexts
const UserContext  = createContext(null);
const ThemeContext = createContext('dark');` },
    ]} />
    <InlinePoll question="How do you identify what caused a specific re-render in React?" options={['Add console.log to every component', 'React DevTools Profiler → record → click component → see "Why did this render?"', 'Use Chrome Performance panel', 'Check network requests']} correct={1} explanation="React DevTools Profiler shows a flame chart of renders. Click any rendered component to see 'Why did this render?' — it shows exactly which prop, state, or context changed. This is the fastest way to debug re-render issues." />
    <CommonMistake mistake="Adding React.memo to every component without first profiling to find the actual bottleneck." fix="React.memo has overhead (comparison cost). Profile first with React DevTools Profiler — find which components actually re-render unnecessarily and why. Then apply the specific fix: useCallback for unstable callbacks, useMemo for unstable objects, split contexts for context issues." />
    <DidYouKnow fact="The why-did-you-render library by Welldone Software patches React to automatically log re-renders and their cause to the console. Add MyComponent.whyDidYouRender = true to any component to track it. Much faster than manual profiling for finding unexpected re-renders." color="#ef4444" />
    <InterviewMeter topics={[{ topic: '4 causes of re-renders — can list all', freq: 90 }, { topic: 'New reference problem with inline objects/functions', freq: 85 }, { topic: 'React DevTools Profiler usage', freq: 70 }, { topic: 'Fixes for each cause', freq: 75 }]} />
  </div>
);

export const StateBatchingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Multiple setStates, One Render</div>
      <p style={c.prose}>
        When you call setState multiple times, React doesn't re-render after each one. It <strong style={{ color: '#4facfe' }}>batches</strong> them together and renders once. React 18 extended this to work everywhere — including async code.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🚌" title="A bus schedule" analogy="A bus doesn't leave the moment one passenger boards — it waits until the scheduled departure time to collect all passengers. React batching works the same: it waits until all synchronous state updates are collected, then renders once with the final state." connection="setCount(); setName(); setFlag() — React waits for all three, then renders once with the updated values of all three." />
    <StorySteps steps={[
      {
        title: 'React 17 — partial batching', color: '#ef4444', desc: 'React 17 only batched inside React event handlers. Async code caused separate renders.', code: `// React 17: batched ✓
function handleClick() {
  setCount(c => c + 1); // batched
  setName('Bob');        // batched
  // → 1 render
}

// React 17: NOT batched ❌
setTimeout(() => {
  setCount(c => c + 1); // render 1
  setName('Bob');        // render 2
  // → 2 separate renders!
}, 1000);` },
      {
        title: 'React 18 — automatic batching everywhere', color: '#00ff88', desc: 'React 18 batches ALL setState calls everywhere automatically — setTimeout, Promises, native events.', code: `// React 18: ALL of these are batched ✓
setTimeout(() => {
  setCount(c => c + 1);
  setName('Bob');
  setFlag(true);
  // → 1 render (automatically batched!)
}, 1000);

fetch('/api').then(() => {
  setData(response);
  setLoading(false);
  // → 1 render (automatically batched!)
});

element.addEventListener('click', () => {
  setX(1); setY(2);
  // → 1 render (automatically batched!)
});` },
      {
        title: 'flushSync — opt out of batching', color: '#eab308', desc: 'Force synchronous rendering for cases where you need to read the DOM after a state update.', code: `import { flushSync } from 'react-dom';

function handleSubmit() {
  flushSync(() => {
    setSubmitted(true); // renders synchronously NOW
  });
  // DOM is updated here before next line!
  const button = buttonRef.current;
  console.log(button.textContent); // 'Submitted' ✓

  // Without flushSync, state update would be deferred
  // and DOM wouldn't reflect new state yet
}` },
      {
        title: 'Functional updates for correct batching', color: '#a855f7', desc: 'When multiple updates depend on previous state, use functional form to always get latest value.', code: `// ❌ Stale state with batching
function incrementTwice() {
  setCount(count + 1); // both use same count!
  setCount(count + 1); // → count + 1, not count + 2
}

// ✅ Functional update — always uses latest state
function incrementTwice() {
  setCount(c => c + 1); // queued update 1
  setCount(c => c + 1); // queued update 2 (gets updated c)
  // → count + 2 ✓
}` },
    ]} />
    <InlinePoll question="In React 18, you call setLoading(false) and setData(results) inside a Promise.then(). How many re-renders occur?" options={['2 re-renders — one per setState', '1 re-render — React 18 automatic batching groups them', '0 re-renders — async code is ignored', 'It depends on component structure']} correct={1} explanation="React 18 automatic batching applies everywhere including Promise.then(). Both setState calls are batched into one render. In React 17, this would have caused 2 separate renders." />
    <CommonMistake mistake="Using setCount(count + 1) twice expecting count to increment by 2." fix="Both calls read the same stale count value — result is count + 1. Use functional form: setCount(c => c + 1) twice → count + 2. The functional form receives the most recent queued state, not the stale closure value." />
    <DidYouKnow fact="React's automatic batching in React 18 was one of the most impactful performance improvements in React's history — it required no code changes but eliminated thousands of unnecessary re-renders in real apps. Apps with lots of async state updates saw significant performance improvements for free." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'What batching is and why it matters', freq: 80 }, { topic: 'React 17 vs React 18 batching difference', freq: 75 }, { topic: 'flushSync usage', freq: 60 }, { topic: 'Functional updates for correct behavior', freq: 70 }]} />
  </div>
);

export const VirtualizationLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Render Only What's Visible</div>
      <p style={c.prose}>
        Rendering 100,000 list items creates 100,000 DOM nodes. The browser grinds to a halt. Virtualization solves this by <strong style={{ color: '#00ff88' }}>only rendering the items visible in the viewport</strong> — typically 20-30 items — regardless of total list size.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🪟" title="A window in a skyscraper" analogy="You can only see through a window on one floor of a 100-story building. The other 99 floors exist, but you don't see them. As you move up the elevator (scroll), you see different floors. Virtualization works the same — the 'window' (viewport) shows only what's in view." connection="Keep a fixed window of DOM nodes. As the user scrolls, update their content and position. The DOM node count stays constant (~20) regardless of list length (100k)." />
    <StorySteps steps={[
      {
        title: 'The performance problem', color: '#ef4444', desc: '10,000 items = 10,000 DOM nodes. Each has style calculations, layout, paint. The browser can\'t handle it.', code: `// ❌ Renders ALL 10,000 items — crashes browser
function SlowList({ items }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id} style={{ height: 48 }}>
          {item.name}
        </li>
      ))}
    </ul>
  );
  // 10,000 DOM nodes created immediately
  // Initial render: 500ms+
  // Scrolling: janky and slow
}` },
      {
        title: 'How virtualization works', color: '#00ff88', desc: 'Container has total height. Items are absolutely positioned at correct top offset. Only visible items exist in DOM.', code: `// Concept (simplified):
function VirtualList({ items, itemHeight, containerHeight }) {
  const [scrollTop, setScrollTop] = useState(0);

  const startIndex = Math.floor(scrollTop / itemHeight);
  const visibleCount = Math.ceil(containerHeight / itemHeight);
  const endIndex = startIndex + visibleCount + 3; // overscan

  const visibleItems = items.slice(startIndex, endIndex);

  return (
    // Full height scrollbar
    <div style={{ height: containerHeight, overflowY: 'auto' }}
         onScroll={e => setScrollTop(e.target.scrollTop)}>
      {/* Total height spacer */}
      <div style={{ height: items.length * itemHeight, position: 'relative' }}>
        {visibleItems.map((item, i) => (
          <div key={item.id} style={{
            position: 'absolute',
            top: (startIndex + i) * itemHeight, // correct position
            height: itemHeight,
          }}>
            {item.name}
          </div>
        ))}
      </div>
    </div>
  );
}` },
      {
        title: 'TanStack Virtual — production library', color: '#4facfe', desc: 'Handles dynamic heights, horizontal lists, grids, and more. Zero dependencies.', code: `import { useVirtualizer } from '@tanstack/react-virtual';

function VirtualList({ items }) {
  const parentRef = useRef(null);

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 48, // estimated row height
    overscan: 5,            // extra rows above/below
  });

  return (
    <div ref={parentRef} style={{ height: 600, overflowY: 'auto' }}>
      <div style={{ height: virtualizer.getTotalSize() }}>
        {virtualizer.getVirtualItems().map(virtualItem => (
          <div key={virtualItem.key}
            style={{
              position: 'absolute',
              top: virtualItem.start,
              height: virtualItem.size,
            }}
          >
            {items[virtualItem.index].name}
          </div>
        ))}
      </div>
    </div>
  );
}` },
      {
        title: 'When to use virtualization', color: '#eab308', desc: 'Only add virtualization when you actually have performance issues with large lists.', code: `// ✅ Use virtualization when:
// - List has 100+ items
// - Items are complex (images, interactions)
// - Profiling shows scroll jank

// ❌ Don't virtualize when:
// - List has < 50 items
// - Items are simple text
// - No measured performance issue

// Alternatives for medium lists:
// - Pagination (10-20 items per page)
// - Infinite scroll with React Query
// - CSS content-visibility: auto (browser-level)` },
    ]} />
    <InlinePoll question="What is 'overscan' in virtualization?" options={['Rendering extra pixels', 'Rendering a few extra items beyond the visible area to prevent blank flashes during fast scrolling', 'Scanning items before rendering', 'Pre-fetching data for upcoming items']} correct={1} explanation="Overscan renders extra items above and below the visible area. Without it, very fast scrolling can outpace rendering — you'd see blank areas briefly. Typical overscan is 3-5 items in each direction." />
    <CommonMistake mistake="Adding virtualization to every list, even small ones with 20 items." fix="Virtualization adds complexity and can cause issues (accessibility, find-in-page, print). Only add it when profiling shows actual performance problems. For lists under 100 items, simple rendering with React.memo on list items is usually sufficient." />
    <DidYouKnow fact="Twitter's feed was one of the first major implementations of list virtualization on the web in 2012. Before virtualization, Twitter's timeline would get progressively slower as you scrolled — each new tweet added a DOM node that was never removed. Virtualization fixed this." color="#00ff88" />
    <InterviewMeter topics={[{ topic: 'What virtualization is and the problem it solves', freq: 80 }, { topic: 'How DOM node count stays fixed', freq: 65 }, { topic: 'TanStack Virtual or react-window API', freq: 60 }, { topic: 'When to use vs alternatives', freq: 65 }]} />
  </div>
);

export const ConcurrentFeaturesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Prioritizing What Matters Most</div>
      <p style={c.prose}>
        React 18's Concurrent Features let React <strong style={{ color: '#a855f7' }}>prioritize urgent work over non-urgent work</strong>. Typing in a search box is urgent. Filtering 10,000 results is not. Concurrent features keep the UI responsive while heavy work happens in the background.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🎯" title="An emergency room triage system" analogy="An ER doesn't treat patients in arrival order — a broken arm waits while a heart attack gets immediate attention. React's concurrent scheduler works the same way: user typing (high priority) interrupts and pauses ongoing heavy rendering work (low priority) to stay responsive." connection="startTransition marks work as low priority. React can interrupt it for high-priority updates like user input. The deferred work resumes when the main thread is free." />
    <StorySteps steps={[
      {
        title: 'useTransition — defer non-urgent updates', color: '#a855f7', desc: 'Mark state updates as transitions (low priority). React can interrupt them for urgent work.', code: `function SearchPage({ items }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState(items);
  const [isPending, startTransition] = useTransition();

  const handleChange = (e) => {
    setQuery(e.target.value); // URGENT — always immediate

    startTransition(() => {
      // NON-URGENT — can be interrupted
      // React can pause this to handle new keystrokes
      setResults(expensiveFilter(items, e.target.value));
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      {/* Show stale results while filtering */}
      <div style={{ opacity: isPending ? 0.5 : 1 }}>
        {results.map(r => <Result key={r.id} item={r} />)}
      </div>
      {isPending && <span>Updating results...</span>}
    </>
  );
}` },
      {
        title: 'useDeferredValue — defer a value update', color: '#4facfe', desc: 'Returns a lagging version of a value. UI shows stale data while computing fresh data.', code: `function ProductList({ searchQuery, products }) {
  // deferredQuery lags behind searchQuery
  // While typing 'react', deferredQuery still shows old results
  const deferredQuery = useDeferredValue(searchQuery);

  const isStale = deferredQuery !== searchQuery;

  // Only recomputes when deferredQuery changes (low priority)
  const filtered = useMemo(
    () => products.filter(p => p.name.includes(deferredQuery)),
    [products, deferredQuery]
  );

  return (
    <div style={{ opacity: isStale ? 0.6 : 1 }}>
      {filtered.map(p => <Product key={p.id} item={p} />)}
    </div>
  );
}` },
      {
        title: 'useTransition vs useDeferredValue', color: '#eab308', desc: 'useTransition: you control when updates are low priority. useDeferredValue: you receive a value and defer it.', code: `// useTransition — you wrap the setState call
const [isPending, startTransition] = useTransition();
startTransition(() => setExpensiveState(value));
// Use when: you own the state update

// useDeferredValue — you receive a value from outside
const deferredValue = useDeferredValue(propFromParent);
// Use when: you receive a value via props and want to defer it

// Rule of thumb:
// Own the state → useTransition
// Receive as prop → useDeferredValue` },
      {
        title: 'Streaming with Suspense in React 18', color: '#00ff88', desc: 'Server sends HTML in chunks. Each Suspense boundary can stream independently.', code: `// Server sends HTML in chunks as data becomes available:
// 1. Initial HTML arrives (headers, layout)
// 2. UserProfile data arrives — streams UserProfile HTML
// 3. Feed data arrives — streams Feed HTML
// 4. Recommendations arrive — streams Recommendations HTML

function App() {
  return (
    <html>
      <Header /> {/* instant */}
      <Suspense fallback={<ProfileSkeleton />}>
        <UserProfile /> {/* streams when ready */}
      </Suspense>
      <Suspense fallback={<FeedSkeleton />}>
        <Feed />         {/* streams independently */}
      </Suspense>
    </html>
  );
}` },
    ]} />
    <InlinePoll question="What is the key difference between useTransition and useDeferredValue?" options={['useTransition is faster', 'useTransition wraps YOUR setState calls; useDeferredValue defers a value you RECEIVE (from props or state)', 'They are identical', 'useDeferredValue works without React 18']} correct={1} explanation="useTransition: you control state updates — wrap the setState in startTransition. useDeferredValue: you receive a value (from parent props or state) and want to show a deferred version of it. Same goal, different ownership model." />
    <CommonMistake mistake="Wrapping every state update in startTransition thinking it will always improve performance." fix="startTransition only helps when React can actually interrupt and show something useful in the meantime. If the work is so fast it completes before the next frame (under 16ms), startTransition adds overhead without benefit. Use it for genuinely expensive updates that take 50ms+." />
    <DidYouKnow fact="React's Concurrent Mode was in development for 4 years before shipping in React 18. The team called it 'the most significant change to React since its launch'. It required a complete rewrite of the reconciler and scheduler to support priority-based rendering and interruptible work." color="#a855f7" />
    <InterviewMeter topics={[{ topic: 'useTransition — mark updates as low priority', freq: 75 }, { topic: 'isPending state for loading indicators', freq: 65 }, { topic: 'useTransition vs useDeferredValue', freq: 70 }, { topic: 'How Concurrent Mode enables this', freq: 60 }]} />
  </div>
);

export const HydrationLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Waking Up Server-Rendered HTML</div>
      <p style={c.prose}>
        When a server renders React, the browser receives static HTML. Hydration is the process of React <strong style={{ color: '#06b6d4' }}>attaching event listeners and state</strong> to that existing HTML — "waking it up" without rebuilding the DOM from scratch.
      </p>
    </RevealCard>
    <AnalogyCard emoji="💧" title="Freeze-dried coffee vs fresh brew" analogy="Freeze-dried coffee is pre-made and ready instantly (server HTML). Add water (JavaScript hydration) and it becomes a real drink with full functionality. The shape was already there — hydration just adds the missing ingredient that makes it interactive." connection="Server sends HTML (structure visible immediately). React hydrates (attaches events, state). The DOM doesn't change — React just takes control of the existing nodes." />
    <StorySteps steps={[
      {
        title: 'Hydration vs client-side rendering', color: '#06b6d4', desc: 'CSR builds the DOM from scratch. Hydration reuses server HTML and only adds interactivity.', code: `// CSR — React builds everything from empty div
ReactDOM.createRoot(document.getElementById('root')).render(<App />);
// DOM is empty until JS loads + executes

// SSR Hydration — React takes over existing HTML
ReactDOM.hydrateRoot(document.getElementById('root'), <App />);
// DOM already has content from server!
// React attaches events to existing nodes
// Users see content before JS loads` },
      {
        title: 'Hydration mismatch — the most common SSR bug', color: '#ef4444', desc: 'Server and client render different HTML. React warns and rebuilds — slow and can cause visual flash.', code: `// ❌ Common mismatch causes:

// 1. Date/time — different on server vs client
function Timestamp() {
  return <time>{new Date().toLocaleString()}</time>;
  // Server: "Jan 1, 2024 10:00:00 AM" (server time)
  // Client: "Jan 1, 2024 10:00:01 AM" (client time) → MISMATCH
}

// 2. Random values
<div>{Math.random()}</div> // different every render

// 3. Browser-only APIs
<div>{window.innerWidth}px wide</div> // window undefined on server

// 4. User-specific data without proper SSR setup
<div>Hello {localStorage.getItem('name')}</div>` },
      {
        title: 'Fixing hydration mismatches', color: '#00ff88', desc: 'Use useEffect for browser-only code. suppressHydrationWarning for intentionally different content.', code: `// ✅ Fix 1: useEffect for browser-only values
function ClientOnlyComponent() {
  const [width, setWidth] = useState(0); // 0 on server
  useEffect(() => {
    setWidth(window.innerWidth); // only runs on client
  }, []);
  return <div>{width || 'Loading...'}px wide</div>;
}

// ✅ Fix 2: Next.js dynamic with ssr:false
const BrowserOnlyMap = dynamic(() => import('./Map'), { ssr: false });

// ✅ Fix 3: suppressHydrationWarning for expected differences
<time suppressHydrationWarning>
  {new Date().toLocaleString()}
</time>` },
      {
        title: 'React 18 selective hydration', color: '#a855f7', desc: 'React 18 hydrates components as they become visible and prioritizes user-interacted components.', code: `// React 18: hydrate in priority order
// 1. Components the user clicks/hovers hydrate first
//    (urgent — user is interacting)
// 2. Components above the fold next
// 3. Off-screen components last

// With Suspense streaming:
<Suspense fallback={<Skeleton />}>
  <Header />    {/* hydrates first — critical */}
</Suspense>
<Suspense fallback={<Skeleton />}>
  <Feed />      {/* hydrates when scrolled into view */}
</Suspense>
// Each Suspense boundary hydrates independently!` },
    ]} />
    <InlinePoll question="What causes a React hydration mismatch error?" options={['Using useState in SSR', 'Server-rendered HTML doesn\'t match what React would render on the client — different content, Date.now(), window checks', 'Network errors during SSR', 'Missing CSS classes']} correct={1} explanation="Hydration mismatch: server renders one thing, client renders something different. Common causes: Date.now() (different times), Math.random(), window/localStorage access (undefined on server), or conditional rendering based on device/browser." />
    <CommonMistake mistake="Using suppressHydrationWarning everywhere to silence all hydration warnings." fix="suppressHydrationWarning hides the warning but doesn't fix the underlying issue. Use it only for genuinely expected differences (timestamps, user-specific data). For most cases, fix the root cause: use useEffect for browser-only code, or ensure server and client render the same initial content." />
    <DidYouKnow fact="React 18's selective hydration was a major breakthrough. Previously, React had to hydrate the entire tree before any part became interactive. Now React can start hydrating immediately, prioritize what the user is clicking, and let the rest hydrate lazily — making SSR apps feel much more responsive." color="#06b6d4" />
    <InterviewMeter topics={[{ topic: 'What hydration is vs CSR', freq: 80 }, { topic: 'Common causes of hydration mismatches', freq: 75 }, { topic: 'Fixing mismatches with useEffect', freq: 70 }, { topic: 'React 18 selective hydration', freq: 55 }]} />
  </div>
);

export const AppRouterLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#e2e8f040' delay={0}>
      <div style={c.title('#e2e8f0')}>🎬 A New Mental Model for Next.js</div>
      <p style={c.prose}>
        The App Router isn't just a new file structure — it's a fundamentally different mental model. <strong style={{ color: '#e2e8f0' }}>Server Components by default</strong>, persistent layouts, and streaming change how you think about data fetching and rendering.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🏛️" title="A new building vs renovating an old one" analogy="Pages Router is like a renovated older building — familiar layout, works well, but some modern features are retrofitted awkwardly. App Router is a new building designed from scratch with modern architecture — server components, layouts, and streaming are first-class citizens, not add-ons." connection="Pages Router: client components by default, data fetching via getServerSideProps. App Router: server components by default, data fetching via async components, layouts persist across navigation." />
    <StorySteps steps={[
      {
        title: 'Server Components by default', color: '#e2e8f0', desc: 'Every component in App Router is a Server Component unless you add "use client". Zero JS shipped for server components.', code: `// app/page.tsx — Server Component by default
// No "use client" = runs on server only
async function Page() {
  // Direct database access — no API needed!
  const users = await db.query('SELECT * FROM users');

  // No JS shipped to browser for this component
  // Data fetching is colocated with the component
  return <UserList users={users} />;
}

// Need interactivity? Add "use client"
'use client';
function LikeButton({ postId }) {
  const [liked, setLiked] = useState(false);
  return <button onClick={() => setLiked(!liked)}>{liked ? '❤️' : '🤍'}</button>;
}` },
      {
        title: 'Layouts persist across navigation', color: '#4facfe', desc: 'layout.tsx wraps routes and persists — state is preserved when navigating between child routes.', code: `// app/dashboard/layout.tsx
// This component persists across all /dashboard/* routes
export default function DashboardLayout({ children }) {
  return (
    <div className="dashboard">
      <Sidebar />      {/* persists — state preserved */}
      <Header />       {/* persists — no re-mount */}
      <main>{children}</main> {/* only this changes */}
    </div>
  );
}

// app/dashboard/page.tsx        → shows DashboardLayout + Dashboard
// app/dashboard/settings/page.tsx → shows SAME layout + Settings
// Sidebar scroll position preserved! State preserved!` },
      {
        title: 'File-based routing conventions', color: '#a855f7', desc: 'Special files define different aspects of a route — page, layout, loading, error, not-found.', code: `app/
  layout.tsx       // root layout (always rendered)
  page.tsx         // / route
  loading.tsx      // Suspense fallback for this route
  error.tsx        // Error boundary for this route
  not-found.tsx    // 404 for this route
  dashboard/
    layout.tsx     // dashboard layout
    page.tsx       // /dashboard route
    loading.tsx    // dashboard-specific loading
    [id]/
      page.tsx     // /dashboard/[id] dynamic route` },
      {
        title: 'Data fetching in Server Components', color: '#00ff88', desc: 'fetch() is extended with caching. No more getServerSideProps — just async components.', code: `// ✅ App Router — colocated data fetching
async function ProductPage({ params }) {
  // Cached by default — deduplicated across components
  const product = await fetch(\`/api/products/\${params.id}\`, {
    next: { revalidate: 60 } // ISR — revalidate every 60s
  }).then(r => r.json());

  // No more props drilling from getServerSideProps!
  return <Product data={product} />;
}

// ❌ Pages Router — separate data fetching function
export async function getServerSideProps({ params }) {
  const product = await fetchProduct(params.id);
  return { props: { product } };
}
export default function Page({ product }) { /* ... */ }` },
    ]} />
    <InlinePoll question="What is the default rendering model for components in Next.js App Router?" options={['Client-side rendering — same as React default', 'Server Components — render on server, zero JS shipped unless you add "use client"', 'Static generation — all pages pre-rendered at build time', 'Edge rendering — runs at CDN edge nodes']} correct={1} explanation="App Router defaults to Server Components — they render on the server, can access databases and secrets directly, and ship zero JavaScript to the client. Add 'use client' at the top of a file to make it a Client Component." />
    <CommonMistake mistake="Adding 'use client' to every component because you're used to the Pages Router mental model." fix="Start with Server Components (no directive). Only add 'use client' when you actually need: useState, useEffect, onClick/onChange, browser APIs, or third-party hooks. The goal is to push 'use client' as deep into the tree as possible — maximize server components." />
    <DidYouKnow fact="The App Router was inspired directly by React Server Components, which were developed by the React core team and first deployed at Facebook. Next.js and Vercel worked closely with the React team to build the App Router around RSC — it's the reference implementation of React's vision for full-stack components." color="#e2e8f0" />
    <InterviewMeter topics={[{ topic: 'Server Components by default', freq: 85 }, { topic: 'When to add "use client"', freq: 80 }, { topic: 'Layouts and navigation persistence', freq: 70 }, { topic: 'Data fetching without getServerSideProps', freq: 75 }]} />
  </div>
);

export const RSCLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Components That Live on the Server</div>
      <p style={c.prose}>
        React Server Components render <strong style={{ color: '#4facfe' }}>exclusively on the server</strong>. They have direct access to databases, filesystems, and secrets. They ship <strong style={{ color: '#4facfe' }}>zero JavaScript</strong> to the browser — only HTML output.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🏭" title="A factory vs a retail store" analogy="A factory (Server Component) does all the heavy work — processes raw materials, runs machinery, uses expensive equipment. It ships you the finished product. The retail store (Client Component) displays it and lets you interact with it. You don't see the factory's internal machinery." connection="Server Component: database access, file system, secrets, heavy computation — all on the server. Client receives only the rendered HTML. Zero factory machinery ships to the store." />
    <StorySteps steps={[
      {
        title: 'What Server Components can do', color: '#4facfe', desc: 'Direct server resource access without API routes. Zero client bundle impact.', code: `// ✅ Server Component superpowers
async function Dashboard() {
  // Direct database access
  const users = await prisma.user.findMany();

  // Read environment secrets
  const apiKey = process.env.INTERNAL_API_KEY;

  // File system access
  const content = await fs.readFile('./data.json', 'utf-8');

  // Heavy computation — doesn't affect client perf
  const report = generateComplexReport(users);

  // ALL of the above never ships to the browser!
  return <ReportView data={report} />;
}` },
      {
        title: 'What Server Components CANNOT do', color: '#ef4444', desc: 'No client-side state, no effects, no browser APIs. Use Client Components for these.', code: `// ❌ Server Components cannot use:
'use client'; // ← needed for all of these

function Interactive() {
  const [count, setCount] = useState(0);        // ❌ state
  const ref = useRef(null);                     // ❌ refs
  useEffect(() => { /* ... */ }, []);           // ❌ effects
  window.innerWidth;                            // ❌ browser APIs
  localStorage.getItem('key');                  // ❌ storage
  document.getElementById('el');               // ❌ DOM
  // onClick, onChange, onSubmit handlers       // ❌ events

  // These REQUIRE "use client"
}` },
      {
        title: 'Composing Server and Client Components', color: '#00ff88', desc: 'Server Components can render Client Components. The boundary is one-way.', code: `// Server Component — can render Client Component ✓
async function ProductPage({ id }) {
  const product = await db.getProduct(id); // server-only

  return (
    <div>
      <ProductInfo product={product} /> {/* Server Component */}
      <AddToCart productId={id} />      {/* Client Component */}
      <Reviews productId={id} />        {/* Server Component */}
    </div>
  );
}

// Client Component — CANNOT import Server Component ❌
'use client';
function AddToCart({ productId }) {
  // ❌ Cannot import ServerOnlyComponent here
  // import ServerComp from './ServerComp'; // error!
  const [inCart, setInCart] = useState(false);
  return <button onClick={() => setInCart(true)}>Add</button>;
}` },
      {
        title: 'The "use server" directive — Server Actions', color: '#a855f7', desc: 'Functions marked with "use server" run on the server when called from Client Components.', code: `// Server Action — runs on server, callable from client
'use server';
async function submitForm(formData: FormData) {
  const name = formData.get('name') as string;
  await db.users.create({ name });
  revalidatePath('/users'); // refresh cached data
}

// Client Component uses Server Action
'use client';
function UserForm() {
  return (
    <form action={submitForm}> {/* Server Action as form action */}
      <input name="name" />
      <button type="submit">Create User</button>
    </form>
  );
  // No API route needed!
  // Form submits to server function directly
}` },
    ]} />
    <InlinePoll question="Can a Client Component import and render a Server Component?" options={['Yes — components can be mixed freely', 'No — Client Components cannot import Server Components. Server Components can render Client Components, not vice versa', 'Only with "use server" directive', 'Only in Next.js 14+']} correct={1} explanation="The boundary is one-way: Server Components can render Client Components. But Client Components cannot import Server Components — that would include server-only code (database access, secrets) in the client bundle. Pass Server Component output as props/children to Client Components instead." />
    <CommonMistake mistake="Trying to use async/await directly in Client Components the way you do in Server Components." fix="Client Components can't be async (no async function MyComponent). Use data fetching hooks (React Query, SWR, useEffect + fetch) in Client Components. Server Components are where you do async data fetching directly." />
    <DidYouKnow fact="React Server Components were secretly deployed at Facebook scale before being announced publicly in 2020. The Facebook.com news feed was one of the first major uses — server components eliminated large amounts of JavaScript that was previously needed to render static content." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'What Server Components are and their benefits', freq: 85 }, { topic: 'What Server Components cannot do', freq: 80 }, { topic: 'Composing Server and Client Components', freq: 75 }, { topic: 'Server Actions with "use server"', freq: 65 }]} />
  </div>
);

export const NextjsCachingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#e2e8f040' delay={0}>
      <div style={c.title('#e2e8f0')}>🎬 Four Layers of Caching</div>
      <p style={c.prose}>
        Next.js App Router has <strong style={{ color: '#e2e8f0' }}>four distinct caching layers</strong> that work together to make apps fast. Understanding each one prevents bugs where you wonder why your data isn't updating.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🗄️" title="A library's book system" analogy="A library has: your personal notes (memory), the local branch's collection (full route cache), the library network's shared catalog (data cache), and your personal lookup shortcuts (router cache). Each layer serves different purposes and has different lifetimes." connection="Request Memoization → Data Cache → Full Route Cache → Router Cache. Each reduces work at a different level. Knowing which to invalidate fixes your stale data problem." />
    <StorySteps steps={[
      {
        title: 'Layer 1 — Request Memoization (per-render)', color: '#4facfe', desc: 'Deduplicates identical fetch() calls within a single render tree. No config needed.', code: `// Two components, same data — only ONE network request
async function Header() {
  const user = await getUser(); // fetch('/api/user')
  return <div>{user.name}</div>;
}

async function Sidebar() {
  const user = await getUser(); // fetch('/api/user') — SAME REQUEST
  return <div>{user.avatar}</div>;
}
// React deduplicates — 1 network call, not 2
// Resets on every server request (per-render only)` },
      {
        title: 'Layer 2 — Data Cache (persistent)', color: '#a855f7', desc: 'Persists fetch() results across requests and deployments. Like a server-side cache.', code: `// Default: cached indefinitely
const data = await fetch('/api/products');

// Revalidate every 60 seconds (ISR behavior)
const data = await fetch('/api/products', {
  next: { revalidate: 60 }
});

// No cache — fetch fresh on every request (SSR behavior)
const data = await fetch('/api/products', {
  cache: 'no-store'
});

// Revalidate by tag — invalidate on demand
const data = await fetch('/api/products', {
  next: { tags: ['products'] }
});
// Later: revalidateTag('products') invalidates this cache` },
      {
        title: 'Layer 3 — Full Route Cache (build-time)', color: '#eab308', desc: 'Stores rendered HTML + RSC payload at build time for static routes. Served from CDN.', code: `// Static routes cached at build time:
// app/about/page.tsx    → about.html (forever)
// app/blog/[slug]/page.tsx → blog-slug.html (if no dynamic data)

// Make a route dynamic (opt out of full route cache):
export const dynamic = 'force-dynamic'; // SSR every request
export const revalidate = 60;           // ISR every 60s

// Or use dynamic functions:
import { cookies } from 'next/headers';
export default async function Page() {
  const session = cookies().get('session'); // opts out!
  // Any dynamic function use = dynamic route
}` },
      {
        title: 'Layer 4 — Router Cache (client-side)', color: '#00ff88', desc: 'Browser-side cache of RSC payloads. Makes back/forward navigation instant.', code: `// Router Cache behavior:
// - Navigating to /dashboard: payload cached in memory
// - Navigating back to /dashboard: served from cache instantly
// - Duration: 30s for dynamic, 5min for static routes
// - Invalidated on: router.refresh(), server action, revalidatePath

// Force refresh client cache:
import { useRouter } from 'next/navigation';
const router = useRouter();
router.refresh(); // clears router cache, re-fetches from server

// Server Actions automatically invalidate relevant routes:
'use server';
async function updateUser(data) {
  await db.update(data);
  revalidatePath('/profile'); // clears all cache layers for /profile
}` },
    ]} />
    <InlinePoll question="You update data in the database but the page still shows old data. Which cache layer is most likely causing the stale data?" options={['Request Memoization', 'Data Cache — fetch results are cached and not yet revalidated', 'Full Route Cache', 'Router Cache']} correct={1} explanation="The Data Cache persists fetch() results across requests. If you updated the database but didn't invalidate the Data Cache (via revalidateTag, revalidatePath, or cache: 'no-store'), the old data is served from cache. Call revalidateTag('your-tag') after mutation." />
    <CommonMistake mistake="Adding cache: 'no-store' to every fetch to 'ensure fresh data' — defeating all Next.js caching benefits." fix="Use targeted cache invalidation instead: tag your fetches with next: { tags: ['products'] }, then call revalidateTag('products') after mutations. This gives you fresh data when needed while still getting CDN performance for everything else." />
    <DidYouKnow fact="Next.js caching is so aggressive by default that several developers were surprised to find their apps serving stale data after database updates. This led to the Next.js team adding more documentation and making cache: 'no-store' easier to use. The trade-off between performance and freshness is one of the most discussed aspects of App Router." color="#e2e8f0" />
    <InterviewMeter topics={[{ topic: 'Four caching layers and their purposes', freq: 70 }, { topic: 'revalidate and cache: no-store options', freq: 75 }, { topic: 'revalidateTag and revalidatePath for invalidation', freq: 65 }, { topic: 'When data becomes stale and why', freq: 70 }]} />
  </div>
);

export const ServerActionsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Server Functions You Call From the Client</div>
      <p style={c.prose}>
        Server Actions are async functions that run on the server but can be called directly from Client Components. <strong style={{ color: '#00ff88' }}>No API routes needed</strong> for mutations — just call the function.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📞" title="A direct phone line to the office" analogy="Before Server Actions, calling server logic was like sending a letter (HTTP request) to a post office (API route) which forwards it to the right department. Server Actions are a direct phone line — you call the function, it runs on the server, results come back immediately." connection="'use server' marks a function as a Server Action. Client calls it like a normal function. Next.js handles the HTTP plumbing automatically." />
    <StorySteps steps={[
      {
        title: 'Basic Server Action', color: '#00ff88', desc: 'Mark an async function with "use server". Call it from Client Components.', code: `// actions.ts
'use server';

export async function createUser(formData: FormData) {
  const name = formData.get('name') as string;
  const email = formData.get('email') as string;

  // Direct database access — no API route needed!
  await db.users.create({ data: { name, email } });

  // Revalidate cached data
  revalidatePath('/users');
}

// In a Client Component:
'use client';
import { createUser } from './actions';

function CreateUserForm() {
  return (
    <form action={createUser}>  {/* Server Action as form action */}
      <input name="name" placeholder="Name" />
      <input name="email" placeholder="Email" />
      <button type="submit">Create User</button>
    </form>
  );
}` },
      {
        title: 'Using with useTransition for pending state', color: '#4facfe', desc: 'Track loading state during Server Action execution.', code: `'use client';
import { useTransition } from 'react';
import { deleteUser } from './actions';

function UserActions({ userId }) {
  const [isPending, startTransition] = useTransition();

  const handleDelete = () => {
    startTransition(async () => {
      await deleteUser(userId);
    });
  };

  return (
    <button
      onClick={handleDelete}
      disabled={isPending}
    >
      {isPending ? 'Deleting...' : 'Delete User'}
    </button>
  );
}` },
      {
        title: 'Optimistic updates with useOptimistic', color: '#a855f7', desc: 'Update UI instantly while Server Action runs in background. Roll back if it fails.', code: `'use client';
import { useOptimistic } from 'react';
import { toggleLike } from './actions';

function LikeButton({ post }) {
  const [optimisticPost, setOptimisticPost] = useOptimistic(
    post,
    (current, optimisticValue) => ({ ...current, ...optimisticValue })
  );

  const handleLike = async () => {
    setOptimisticPost({ liked: !post.liked }); // instant update
    await toggleLike(post.id); // actual server mutation
    // If server action fails, React rolls back optimistic state
  };

  return (
    <button onClick={handleLike}>
      {optimisticPost.liked ? '❤️' : '🤍'}
    </button>
  );
}` },
      {
        title: 'Security — always validate server-side', color: '#ef4444', desc: 'Server Actions are public HTTP endpoints. Treat them like API routes — validate and authenticate.', code: `'use server';

export async function deletePost(postId: string) {
  // ❌ Never trust client input blindly!

  // ✅ Always authenticate
  const session = await getServerSession(authOptions);
  if (!session) throw new Error('Unauthorized');

  // ✅ Always authorize
  const post = await db.post.findUnique({ where: { id: postId } });
  if (post.authorId !== session.user.id) throw new Error('Forbidden');

  // ✅ Always validate input
  if (!z.string().uuid().safeParse(postId).success) {
    throw new Error('Invalid post ID');
  }

  await db.post.delete({ where: { id: postId } });
  revalidatePath('/posts');
}` },
    ]} />
    <InlinePoll question="Are Server Actions secure by default?" options={['Yes — they run on the server so clients can\'t access them', 'No — they are public HTTP endpoints that anyone can call. Always validate auth and input', 'Yes — Next.js automatically adds authentication', 'Only if you use TypeScript']} correct={1} explanation="Server Actions compile to HTTP POST endpoints. Anyone with the URL can call them — including attackers. Always: verify authentication (is user logged in?), check authorization (can this user do this?), and validate input. Treat them exactly like API route handlers." />
    <CommonMistake mistake="Putting sensitive business logic in Server Actions without authentication checks — thinking they're 'hidden' from clients." fix="Server Actions are HTTP endpoints. The only thing protecting them is your own authentication and authorization code. Always use getServerSession() or equivalent to verify the user, check their permissions, and validate all input before performing any database operations." />
    <DidYouKnow fact="Server Actions use HTTP POST under the hood with a special content type. Next.js generates a unique ID for each Server Action that becomes the endpoint. This means they can be called via fetch() directly from anywhere — which is why proper authentication is critical." color="#00ff88" />
    <InterviewMeter topics={[{ topic: 'What Server Actions are and basic usage', freq: 75 }, { topic: 'Security — always validate auth', freq: 80 }, { topic: 'useTransition for pending state', freq: 65 }, { topic: 'useOptimistic for instant UI updates', freq: 55 }]} />
  </div>
);

export const ImageOptimizationLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Images Are the Biggest Performance Problem</div>
      <p style={c.prose}>
        Images account for <strong style={{ color: '#4facfe' }}>50%+ of page weight</strong> on most websites. Unoptimized images are the single biggest cause of slow LCP scores. next/image solves this automatically.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📷" title="A professional photo lab" analogy="A professional photo lab takes your original high-resolution film and produces prints in exactly the right size, format, and quality for each purpose — wallet photos, posters, digital displays. next/image does the same: one source image, automatically optimized for each device and screen size." connection="You provide one high-quality image. next/image generates WebP/AVIF format, correct size for each viewport, lazy loading, blur placeholder — automatically." />
    <StorySteps steps={[
      {
        title: 'What next/image does automatically', color: '#4facfe', desc: 'Automatic format conversion, resizing, lazy loading, and blur placeholder.', code: `import Image from 'next/image';

// ✅ next/image — all optimizations automatic
<Image
  src="/hero.jpg"
  alt="Hero image"
  width={1200}
  height={600}
  priority   // LCP image — disable lazy loading!
/>

// What next/image does for you:
// ✓ Converts to WebP/AVIF (40-60% smaller)
// ✓ Generates responsive sizes for each device
// ✓ Lazy loads by default (except priority images)
// ✓ Prevents Cumulative Layout Shift (requires dimensions)
// ✓ Blur placeholder while loading
// ✓ Serves from CDN edge cache` },
      {
        title: 'LCP image — always use priority', color: '#ef4444', desc: 'The largest image above the fold is the LCP element. Never lazy-load it.', code: `// ❌ Kills LCP — hero image lazy loaded
<Image src="/hero.jpg" width={1200} height={600} />
// Default is lazy — delays LCP by seconds!

// ✅ Priority = no lazy, high fetchpriority, preload link
<Image
  src="/hero.jpg"
  width={1200}
  height={600}
  priority         // ← critical for LCP!
  alt="Our product"
/>

// What priority does:
// - Removes loading="lazy"
// - Adds fetchpriority="high"
// - Adds <link rel="preload"> in <head>
// Result: LCP image starts loading immediately` },
      {
        title: 'Responsive images with sizes', color: '#00ff88', desc: 'Tell the browser how large the image will be at each breakpoint for optimal selection.', code: `// sizes prop tells browser which source to select
<Image
  src="/product.jpg"
  alt="Product"
  fill
  sizes="(max-width: 768px) 100vw,
         (max-width: 1200px) 50vw,
         33vw"
  // Mobile: full width → download mobile-sized image
  // Tablet: half width → download medium image
  // Desktop: third width → download smaller image
  // Without sizes: always downloads largest version!
/>` },
      {
        title: 'Blur placeholder for perceived performance', color: '#a855f7', desc: 'Show a blurred version while the full image loads. Dramatically improves perceived performance.', code: `// Static images: blur placeholder automatic
import heroImg from './hero.jpg'; // static import
<Image src={heroImg} alt="Hero" placeholder="blur" />
// Next.js generates the blur data URL at build time!

// Remote images: provide blurDataURL
<Image
  src="https://cdn.example.com/photo.jpg"
  alt="Photo"
  placeholder="blur"
  blurDataURL="data:image/png;base64,..."
  // Use next-placeholder to generate blur hash
/>` },
    ]} />
    <InlinePoll question="Why should you never add loading='lazy' (or omit the priority prop) to the hero/LCP image?" options={['It looks worse', 'Lazy loading defers image loading until near-viewport — the LCP element delays loading, directly hurting LCP score', 'Lazy loading breaks the image', 'LCP images must be loaded in a specific order']} correct={1} explanation="Lazy loading tells the browser to not start loading the image until it's near the viewport. For the LCP image (hero, above the fold), this means delaying what should be the most important image on the page. Always use priority={true} on your LCP image to start loading it immediately." />
    <CommonMistake mistake="Using next/image's fill layout without specifying sizes prop." fix="Without sizes, the browser doesn't know how large the image will appear and downloads the largest source. Always provide sizes: sizes='(max-width: 768px) 100vw, 50vw' tells the browser the rendered width at each breakpoint, allowing it to download the correctly-sized source." />
    <DidYouKnow fact="WebP images are 25-35% smaller than JPEG at equivalent quality. AVIF (used in newer browsers) is 50% smaller than JPEG. next/image automatically serves WebP to Chrome/Firefox/Edge and AVIF where supported — all from the same source JPEG. This alone can cut image payload in half with no code changes." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'What next/image optimizes automatically', freq: 75 }, { topic: 'priority prop for LCP images', freq: 80 }, { topic: 'sizes prop for responsive images', freq: 65 }, { topic: 'blur placeholder for perceived performance', freq: 60 }]} />
  </div>
);

export const EdgeFunctionsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Code That Runs at the Network Edge</div>
      <p style={c.prose}>
        Edge Functions run in <strong style={{ color: '#f97316' }}>data centers closest to users</strong> — not in one central server. A user in Tokyo gets a response from Tokyo, not from a server in Virginia. Latency drops from 200ms to 20ms.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🌍" title="Local stores vs one central warehouse" analogy="Amazon could ship everything from one warehouse in Ohio, but instead they have fulfillment centers in every major city. Your order ships from the nearest one — same product, dramatically faster delivery. Edge Functions are fulfillment centers for code." connection="Edge runtime runs your middleware/functions from 100+ global PoPs (Points of Presence). Users get responses from the nearest location — milliseconds instead of hundreds of milliseconds." />
    <StorySteps steps={[
      {
        title: 'Next.js Middleware', color: '#f97316', desc: 'Runs before every request — perfect for auth checks, redirects, A/B testing, geolocation.', code: `// middleware.ts — runs on every request at the edge
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Auth check — redirect to login if no session
  const session = request.cookies.get('session');
  if (!session && pathname.startsWith('/dashboard')) {
    return NextResponse.redirect(new URL('/login', request.url));
  }

  // A/B testing
  const bucket = Math.random() < 0.5 ? 'A' : 'B';
  const response = NextResponse.next();
  response.headers.set('x-variant', bucket);
  return response;
}

export const config = {
  matcher: ['/dashboard/:path*', '/api/:path*'],
};` },
      {
        title: 'Edge Runtime limitations', color: '#ef4444', desc: 'Edge runtime is NOT Node.js. It\'s V8-only — no fs, no native modules, no full Node APIs.', code: `// ❌ NOT available in Edge Runtime:
import fs from 'fs';                // no file system
import { createConnection } from 'mysql2'; // no native modules
import crypto from 'crypto';        // limited (use Web Crypto)

// ✅ Available in Edge Runtime:
fetch('/api/data');                  // fetch API ✓
new TextEncoder().encode('hello');  // Web APIs ✓
crypto.subtle.digest('SHA-256', data); // Web Crypto ✓
request.cookies.get('session');     // Cookies ✓
request.geo?.country;               // Geolocation ✓

// Use Node.js runtime for: database connections,
// file system, native modules
export const runtime = 'nodejs'; // opts out of edge` },
      {
        title: 'Geolocation and personalization', color: '#00ff88', desc: 'Edge functions have access to request geolocation — personalize content without a round trip.', code: `// middleware.ts
export function middleware(request: NextRequest) {
  const country = request.geo?.country || 'US';
  const city = request.geo?.city || 'Unknown';

  // Redirect to country-specific version
  if (country !== 'US' && !request.nextUrl.pathname.startsWith('/intl')) {
    return NextResponse.redirect(
      new URL(\`/intl/\${country.toLowerCase()}\${request.nextUrl.pathname}\`, request.url)
    );
  }

  // Set country header for downstream use
  const response = NextResponse.next();
  response.headers.set('x-user-country', country);
  return response;
}` },
      {
        title: 'Edge API Routes', color: '#4facfe', desc: 'API routes can opt into edge runtime for lower latency.', code: `// app/api/fast-response/route.ts
export const runtime = 'edge'; // run at edge, not Node.js

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const name = searchParams.get('name');

  // Runs in 100+ global edge locations
  // Typical cold start: <1ms vs 100ms+ for serverless
  return Response.json({
    message: \`Hello \${name}!\`,
    location: 'edge',
  });
}` },
    ]} />
    <InlinePoll question="What is the primary advantage of Edge Functions over traditional serverless functions?" options={['They are cheaper to run', 'They run in data centers closest to users — dramatically lower latency (20ms vs 200ms)', 'They have more memory available', 'They support more languages']} correct={1} explanation="Edge Functions run at global Points of Presence (PoPs) close to users. Instead of every request going to one central server, requests are handled by the nearest edge location. This reduces latency from 100-200ms to under 20ms for most users." />
    <CommonMistake mistake="Trying to use database connections or native Node.js modules in Edge middleware." fix="Edge runtime is V8-only — no Node.js APIs. You can't use Prisma, native modules, or file system. For database access at the edge, use edge-compatible clients (Neon serverless driver, PlanetScale HTTP driver) or move that logic to an API route with Node.js runtime." />
    <DidYouKnow fact="Cloudflare Workers (which inspired Edge Functions) run in 300+ data centers worldwide. They start in under 1 millisecond because they don't spin up a new process — they run in a V8 isolate that's always warm. Traditional Lambda functions can take 100-3000ms to cold start." color="#f97316" />
    <InterviewMeter topics={[{ topic: 'What edge functions are and latency benefit', freq: 70 }, { topic: 'Middleware use cases (auth, redirects, A/B)', freq: 75 }, { topic: 'Edge runtime limitations vs Node.js runtime', freq: 65 }, { topic: 'Geolocation for personalization', freq: 55 }]} />
  </div>
);

export const MemoizationLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Cache the Result, Not the Computation</div>
      <p style={c.prose}>
        Memoization stores the results of expensive function calls and returns the cached result when the same inputs occur again. <strong style={{ color: '#a855f7' }}>Same inputs → same output</strong> — so why compute it twice?
      </p>
    </RevealCard>
    <AnalogyCard emoji="📖" title="A math textbook with an answer key" analogy="A math student solving 15 × 17 for the first time works it out. The second time, they check the answer key — instant result. The third time, they've memorized it — even faster. Memoization builds this answer key automatically." connection="First call: compute and cache. Subsequent calls: look up in cache. Cache key is the stringified input. Only works for pure functions — same input must always produce same output." />
    <StorySteps steps={[
      {
        title: 'Basic memoization', color: '#a855f7', desc: 'Cache function results in a Map. Return cached result if inputs seen before.', code: `function memoize(fn) {
  const cache = new Map();

  return function(...args) {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key); // cache hit!
    }

    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

// Usage
const expensiveFib = memoize(function fib(n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2);
});

expensiveFib(40); // computed (slow)
expensiveFib(40); // from cache (instant!)` },
      {
        title: 'React useMemo — memoize during render', color: '#4facfe', desc: 'Cache expensive computations between renders. Only recompute when deps change.', code: `function ProductList({ products, category, sortBy }) {
  // ❌ Runs on every render
  const processed = products
    .filter(p => p.category === category)
    .sort((a, b) => a[sortBy] > b[sortBy] ? 1 : -1);

  // ✅ Only when products, category, or sortBy changes
  const processed = useMemo(() => {
    return products
      .filter(p => p.category === category)
      .sort((a, b) => a[sortBy] > b[sortBy] ? 1 : -1);
  }, [products, category, sortBy]);

  return processed.map(p => <Product key={p.id} item={p} />);
}` },
      {
        title: 'LRU cache — bounded memoization', color: '#00ff88', desc: 'Limit cache size to prevent memory leaks. Evict least recently used entries.', code: `function memoizeWithLRU(fn, maxSize = 100) {
  const cache = new Map(); // Map preserves insertion order

  return function(...args) {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      // Move to end (most recently used)
      const value = cache.get(key);
      cache.delete(key);
      cache.set(key, value);
      return value;
    }

    const result = fn.apply(this, args);

    // Evict oldest (first entry) if at capacity
    if (cache.size >= maxSize) {
      cache.delete(cache.keys().next().value);
    }

    cache.set(key, result);
    return result;
  };
}` },
      {
        title: 'When memoization helps vs hurts', color: '#eab308', desc: 'Memoization has overhead. Only worth it for expensive pure functions.', code: `// ✅ Worth memoizing:
const sortedUsers = useMemo(
  () => [...users].sort((a,b) => a.name.localeCompare(b.name)),
  [users]
); // O(n log n) sort — expensive

// ❌ Not worth memoizing — overhead > benefit:
const doubled = useMemo(() => count * 2, [count]);
// Single multiplication is nanoseconds
// useMemo overhead: closure creation, dep comparison

// ❌ Doesn't work on impure functions:
const timestamp = useMemo(() => Date.now(), []); // stale!
const random    = useMemo(() => Math.random(), []); // fixed forever
// Pure function requirement: same inputs = same outputs ALWAYS` },
    ]} />
    <InlinePoll question="What is the key requirement for a function to be safely memoizable?" options={['It must be async', 'It must be pure — same inputs always produce the same output with no side effects', 'It must use arrow syntax', 'It must return an object']} correct={1} explanation="Memoization only works correctly for pure functions. If a function reads from Date.now(), Math.random(), external state, or has side effects, memoizing it returns stale or incorrect results. Always verify the function is pure before memoizing." />
    <CommonMistake mistake="Using useMemo for simple calculations: const doubled = useMemo(() => count * 2, [count])" fix="useMemo has overhead: dep array comparison, closure allocation, cache storage. For trivial calculations (multiply, add, string concatenation), this overhead exceeds the savings. Only useMemo when the calculation takes >1ms or when reference stability matters (objects/arrays passed to memoized children)." />
    <DidYouKnow fact="The word 'memoization' was coined by Donald Michie in 1968 — it's derived from 'memo' (Latin: 'to be remembered'). It's intentionally NOT 'memorization' — the distinction matters. Dynamic programming (used in coding interviews) is essentially memoization applied to recursive algorithms." color="#a855f7" />
    <InterviewMeter topics={[{ topic: 'What memoization is and when to use it', freq: 80 }, { topic: 'Pure function requirement', freq: 75 }, { topic: 'useMemo vs manual memoization', freq: 70 }, { topic: 'LRU cache for bounded memoization', freq: 55 }]} />
  </div>
);

export const CachingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 The Fastest Request Is One That Never Happens</div>
      <p style={c.prose}>
        Caching stores responses so they can be reused. A cached response is served <strong style={{ color: '#06b6d4' }}>instantly from memory or disk</strong> instead of going to the server. The right caching strategy can make an app feel 10x faster.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🍕" title="A pizza place with pre-made vs made-to-order" analogy="A pizza place pre-makes popular pizzas (cache). When someone orders a Margherita, it's ready in 30 seconds (cache hit). A custom order takes 20 minutes (cache miss). The key is knowing which pizzas to pre-make — popular items (public content), not custom orders (personalized data)." connection="Cache responses that are the same for all users (public data). Don't cache personalized responses. Set expiry based on how often data changes." />
    <StorySteps steps={[
      {
        title: 'HTTP Cache-Control headers', color: '#06b6d4', desc: 'Tell the browser and CDN how to cache responses.', code: `// Immutable static assets (hashed filenames)
Cache-Control: public, max-age=31536000, immutable
// main.a3f9c2.js — filename changes when content changes
// Cache forever — same URL = always same content

// Frequently updated content
Cache-Control: public, max-age=60
// Fresh for 60s, then revalidate

// Never cache (user-specific data)
Cache-Control: private, no-store
// Each user gets their own response, never cached

// Stale-while-revalidate (best UX)
Cache-Control: public, max-age=60, stale-while-revalidate=300
// Serve immediately (even if stale), revalidate in background` },
      {
        title: 'ETags and conditional requests', color: '#a855f7', desc: 'Check if content changed before downloading again.', code: `// 1. First request: server sends ETag
HTTP/1.1 200 OK
ETag: "abc123"
Content-Length: 50000
{ big response body }

// 2. Second request: browser sends ETag back
GET /api/products
If-None-Match: "abc123"

// 3a. Content unchanged: server sends 304 (no body!)
HTTP/1.1 304 Not Modified
// Browser uses cached version — zero bandwidth!

// 3b. Content changed: server sends new response
HTTP/1.1 200 OK
ETag: "def456"
{ new response body }` },
      {
        title: 'React Query caching strategies', color: '#00ff88', desc: 'React Query provides stale-while-revalidate caching for all API calls.', code: `const { data } = useQuery({
  queryKey: ['products', category],
  queryFn: () => fetchProducts(category),

  staleTime: 60 * 1000,     // fresh for 60s — no refetch
  gcTime: 5 * 60 * 1000,    // keep in memory 5min after unused

  // stale-while-revalidate behavior:
  // 1. Return cached data immediately (fast!)
  // 2. Refetch in background if stale
  // 3. Update UI when fresh data arrives

  refetchOnWindowFocus: true,  // refetch when tab regains focus
  refetchInterval: 30000,      // poll every 30s for live data
});` },
      {
        title: 'Service Worker cache for offline', color: '#eab308', desc: 'Intercept network requests and serve from cache when offline.', code: `// service-worker.js — cache-first strategy
self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request).then(cached => {
      if (cached) return cached; // serve from cache!

      // Not cached — fetch and cache for next time
      return fetch(event.request).then(response => {
        const clone = response.clone();
        caches.open('v1').then(cache => {
          cache.put(event.request, clone);
        });
        return response;
      });
    }).catch(() => {
      // Network error AND not cached — show offline page
      return caches.match('/offline.html');
    })
  );
});` },
    ]} />
    <InlinePoll question="What does stale-while-revalidate mean in caching?" options={['Serve only fresh content', 'Serve cached content immediately (even if stale) while fetching fresh content in the background', 'Block until fresh content is available', 'Only serve content when explicitly revalidated']} correct={1} explanation="stale-while-revalidate serves the cached (possibly stale) response immediately for fast UX, then revalidates in the background. When fresh data arrives, it's cached for the next request. Users see instant responses while content stays eventually fresh." />
    <CommonMistake mistake="Setting max-age=0 on all responses to 'ensure users always get fresh data' — defeating all caching benefits." fix="Use targeted caching: long max-age for immutable assets (hashed filenames), moderate for public content that changes occasionally, no-cache for personalized data. Combine with ETag for efficient revalidation — 304 responses use zero bandwidth." />
    <DidYouKnow fact="The stale-while-revalidate HTTP cache directive was proposed in 2010 but not widely supported until 2019. Before that, developers implemented it manually in service workers. Now it's a standard header supported by all modern browsers and CDNs." color="#06b6d4" />
    <InterviewMeter topics={[{ topic: 'Cache-Control headers and their values', freq: 80 }, { topic: 'stale-while-revalidate strategy', freq: 75 }, { topic: 'ETags for conditional requests', freq: 65 }, { topic: 'React Query caching configuration', freq: 70 }]} />
  </div>
);

export const WebSocketsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 HTTP vs Real-Time Communication</div>
      <p style={c.prose}>
        HTTP is request-response: client asks, server answers. But what about <strong style={{ color: '#00ff88' }}>live updates</strong> — chat messages, stock prices, collaborative editing? The server needs to push data without the client asking. That's what WebSockets and SSE solve.
      </p>
    </RevealCard>
    <AnalogyCard emoji="📡" title="Letter vs walkie-talkie vs radio broadcast" analogy="HTTP is like letters — you write (request), wait for reply, receive response. WebSocket is like a walkie-talkie — persistent connection, both sides talk freely anytime. SSE is like a radio broadcast — server transmits continuously, client just listens." connection="HTTP: request/response. WebSocket: bidirectional persistent connection. SSE: server-to-client stream over HTTP. Each has different use cases." />
    <StorySteps steps={[
      {
        title: 'WebSocket — bidirectional persistent connection', color: '#00ff88', desc: 'Upgrades HTTP to a persistent TCP connection. Both sides send messages anytime.', code: `// Client
const ws = new WebSocket('wss://chat.example.com/room/123');

ws.onopen = () => {
  ws.send(JSON.stringify({ type: 'join', user: 'Alice' }));
};

ws.onmessage = (event) => {
  const message = JSON.parse(event.data);
  appendMessage(message);
};

ws.onclose = () => console.log('Disconnected');
ws.onerror = (error) => console.error('WS Error:', error);

// Send a message:
ws.send(JSON.stringify({ type: 'message', text: 'Hello!' }));

// Cleanup:
ws.close();` },
      {
        title: 'WebSocket in React with cleanup', color: '#4facfe', desc: 'Always clean up WebSocket connections in useEffect to prevent memory leaks.', code: `function ChatRoom({ roomId }) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    const ws = new WebSocket(\`wss://chat.app/rooms/\${roomId}\`);

    ws.onmessage = (event) => {
      const msg = JSON.parse(event.data);
      setMessages(prev => [...prev, msg]);
    };

    // Reconnect on error
    ws.onerror = () => {
      setTimeout(() => reconnect(roomId), 1000);
    };

    return () => {
      ws.close(); // cleanup on unmount or roomId change!
    };
  }, [roomId]); // reconnect when room changes

  return <MessageList messages={messages} />;
}` },
      {
        title: 'Server-Sent Events — simpler one-way streaming', color: '#a855f7', desc: 'Server pushes events over a regular HTTP connection. Auto-reconnects. No special server needed.', code: `// Client — SSE
const eventSource = new EventSource('/api/live-feed');

eventSource.onmessage = (event) => {
  const data = JSON.parse(event.data);
  updateFeed(data);
};

// Handle specific event types
eventSource.addEventListener('notification', (event) => {
  showNotification(JSON.parse(event.data));
});

// Auto-reconnects if connection drops!
// Headers the browser sends: Accept: text/event-stream

eventSource.close(); // stop listening

// Server response format:
// data: {"type": "message", "text": "Hello"}
//
// event: notification
// data: {"title": "New comment"}` },
      {
        title: 'WebSocket vs SSE — when to use each', color: '#eab308', desc: 'Choose based on whether the client also sends data or just receives it.', code: `// Use WebSocket when:
// - Client sends frequent data back (chat, games, collaboration)
// - You need binary data (file transfer, video)
// - Ultra-low latency required

// Use SSE when:
// - Server pushes only (notifications, live feeds, progress)
// - Simple to implement (plain HTTP, no upgrade)
// - Auto-reconnect is important
// - Works through HTTP/2 multiplexing

// Use Long Polling when:
// - WebSocket/SSE not available (rare)
// - Simple implementation needed

// Never use regular polling for real-time:
// setInterval(() => fetch('/api/updates'), 1000); // ❌ wasteful` },
    ]} />
    <InlinePoll question="What is the main difference between WebSocket and Server-Sent Events (SSE)?" options={['WebSocket is faster', 'WebSocket is bidirectional; SSE is server-to-client only but simpler, uses HTTP, and auto-reconnects', 'They are identical', 'SSE requires special server software']} correct={1} explanation="SSE is one-directional (server → client) over regular HTTP. Simpler to implement, auto-reconnects, works through HTTP/2 multiplexing. WebSocket is bidirectional — client can also send data. Use SSE for feeds/notifications, WebSocket when client sends frequent data." />
    <CommonMistake mistake="Not cleaning up WebSocket connections in useEffect — causing memory leaks and multiple active connections." fix="Always close the WebSocket in the useEffect cleanup function: return () => ws.close(). Without cleanup, navigating away and back creates a new WebSocket while the old one stays open — multiple connections, event handlers firing multiple times." />
    <DidYouKnow fact="WebSocket was standardized in 2011 but wasn't widely adopted until 2013-2014 when browser support became universal. Before WebSocket, developers used 'Comet' techniques — long polling, forever frames, and chunked transfer encoding — to simulate real-time communication over HTTP." color="#00ff88" />
    <InterviewMeter topics={[{ topic: 'WebSocket vs SSE vs polling differences', freq: 80 }, { topic: 'WebSocket cleanup in React useEffect', freq: 75 }, { topic: 'When to use each technology', freq: 70 }, { topic: 'SSE auto-reconnect behavior', freq: 55 }]} />
  </div>
);

export const CSRFLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#ef444440' delay={0}>
      <div style={c.title('#ef4444')}>🎬 Tricking You Into Making Requests</div>
      <p style={c.prose}>
        CSRF (Cross-Site Request Forgery) attacks trick authenticated users into <strong style={{ color: '#ef4444' }}>unknowingly making requests to your server</strong>. The browser automatically includes cookies — the attacker doesn't need to steal them.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🎣" title="A phishing letter that looks like a bank form" analogy="You get a letter that looks like it's from your bank, asking you to fill out a form to 'verify your account'. You sign it and mail it back — but it was actually a fraudulent transfer request in disguise. You authenticated it with your signature without realizing." connection="Attacker creates a form on evil.com that submits to bank.com. Your browser automatically sends your bank.com cookies. The bank sees a legitimate authenticated request — from you, without your knowledge." />
    <StorySteps steps={[
      {
        title: 'How CSRF works', color: '#ef4444', desc: 'Attacker exploits the fact that browsers automatically send cookies with cross-origin requests.', code: `<!-- evil.com/attack.html -->
<!-- This form auto-submits when you visit the page -->
<form action="https://bank.com/transfer" method="POST" id="evil">
  <input type="hidden" name="to" value="attacker-account" />
  <input type="hidden" name="amount" value="10000" />
</form>
<script>document.getElementById('evil').submit();</script>

<!-- Browser sends: POST bank.com/transfer + your session cookie -->
<!-- Bank sees authenticated request — processes transfer! -->
<!-- You never knew it happened` },
      {
        title: 'SameSite cookies — simplest fix', color: '#00ff88', desc: 'SameSite=Strict prevents cookies from being sent on cross-site requests entirely.', code: `// Server sets cookie with SameSite
res.cookie('session', token, {
  httpOnly: true,
  secure: true,
  sameSite: 'strict',  // ← CSRF protection!
  // 'strict': never sent cross-site
  // 'lax': sent on top-level navigation (link clicks)
  // 'none': always sent (requires Secure)
});

// With SameSite=Strict:
// evil.com's form submits to bank.com
// → browser does NOT include session cookie
// → bank.com sees unauthenticated request → rejects ✓` },
      {
        title: 'CSRF tokens — double submit pattern', color: '#4facfe', desc: 'Server generates a token, sends in cookie AND expects it in request header. Attacker can\'t read cookies from another domain.', code: `// Server: set CSRF token in readable cookie
const csrfToken = crypto.randomBytes(32).toString('hex');
res.cookie('csrf', csrfToken, {
  httpOnly: false, // JS must read this
  sameSite: 'strict',
  secure: true,
});

// Client: read cookie, include in header
const csrf = document.cookie.match(/csrf=([^;]+)/)?.[1];
fetch('/api/transfer', {
  method: 'POST',
  headers: {
    'X-CSRF-Token': csrf, // attacker can't set this!
  },
  body: JSON.stringify(data),
});

// Server: validate header matches cookie
if (req.headers['x-csrf-token'] !== req.cookies.csrf) {
  return res.status(403).json({ error: 'CSRF validation failed' });
}` },
      {
        title: 'Same-Origin Policy — the underlying protection', color: '#a855f7', desc: 'SOP prevents scripts from reading responses from different origins — but not from sending requests.', code: `// Same-Origin Policy:
// Origin = protocol + hostname + port
// https://app.com ≠ https://api.app.com (different subdomain)
// https://app.com ≠ http://app.com (different protocol)

// SOP prevents: reading responses from other origins
// SOP does NOT prevent: sending requests to other origins

// This is why CSRF is possible:
// evil.com CAN send POST to bank.com (SOP allows sending)
// evil.com CANNOT read bank.com's response (SOP blocks reading)
// But the damage is done on the POST — reading wasn't needed!

// CORS (Cross-Origin Resource Sharing):
// Explicitly whitelist trusted origins for reading responses
// 'Access-Control-Allow-Origin: https://trusted.com'` },
    ]} />
    <InlinePoll question="Why does SameSite=Strict prevent CSRF attacks?" options={['It encrypts the cookie', 'The browser refuses to send the cookie on cross-site requests — the attacker\'s fake form has no authentication token', 'It validates the cookie signature on each request', 'It limits which domains can set cookies']} correct={1} explanation="SameSite=Strict tells the browser: don't send this cookie on cross-site requests. The attacker's form on evil.com POST-ing to bank.com won't include your session cookie. The bank server sees an unauthenticated request and rejects it." />
    <CommonMistake mistake="Thinking CORS protection prevents CSRF — they're completely different problems." fix="CORS prevents cross-origin reads (JavaScript reading another domain's response). CSRF exploits cross-origin writes (forms/fetches sending requests). CORS headers don't help against CSRF because the attack doesn't need to read the response — just trigger the action. Use SameSite cookies and CSRF tokens." />
    <DidYouKnow fact="CSRF was one of the OWASP Top 10 vulnerabilities for years but was removed from the 2021 list because SameSite cookies (now default in most browsers) make it much harder to exploit. However, older browsers and certain OAuth flows still require explicit CSRF protection." color="#ef4444" />
    <InterviewMeter topics={[{ topic: 'How CSRF attacks work', freq: 80 }, { topic: 'SameSite cookie attribute', freq: 85 }, { topic: 'CSRF tokens — double submit pattern', freq: 70 }, { topic: 'CORS vs CSRF — they are different', freq: 75 }]} />
  </div>
);

export const BrowserRenderingLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 From HTML to Pixels</div>
      <p style={c.prose}>
        The browser receives bytes from the network and produces pixels on screen. This <strong style={{ color: '#4facfe' }}>Critical Rendering Path</strong> determines how fast users see your content. Optimizing it is the key to fast first paints.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🏗️" title="Building a house from blueprints" analogy="An architect receives a blueprint (HTML), translates it to structural plans (DOM), gets material specs (CSS → CSSOM), combines them into a construction plan (Render Tree), surveys the land (Layout), assigns contractors (Paint), and the house is built (Composite). Each step must complete before the next." connection="HTML → DOM → CSSOM → Render Tree → Layout → Paint → Composite. Blocking resources at any step delay everything after." />
    <StorySteps steps={[
      {
        title: 'Parsing HTML — building the DOM', color: '#4facfe', desc: 'HTML parser reads bytes, tokenizes, builds the DOM tree incrementally. Script tags block parsing.', code: `<!-- HTML parsing — incremental -->
<!DOCTYPE html>
<html>
  <head>
    <!-- ❌ Parser blocks here until script downloads + runs -->
    <script src="app.js"></script>

    <!-- ✅ Defer — downloads parallel, runs after parse -->
    <script src="app.js" defer></script>

    <!-- ✅ Async — downloads parallel, runs immediately when ready -->
    <script src="analytics.js" async></script>
  </head>
  <!-- Parser continues here with defer/async -->
</html>` },
      {
        title: 'CSSOM + Render Tree', color: '#a855f7', desc: 'CSS is parsed into CSSOM. Combined with DOM to create Render Tree — only visible elements.', code: `/* CSS blocks rendering — browser must have all CSS before rendering */
/* Critical CSS: inline above-the-fold styles */
<style>
  /* Minimal styles for initial viewport */
  .hero { color: #333; font-size: 24px; }
</style>

/* Non-critical CSS: load asynchronously */
<link rel="preload" href="non-critical.css" as="style"
  onload="this.onload=null;this.rel='stylesheet'">

/* Render Tree only includes visible elements */
/* display:none → NOT in render tree */
/* visibility:hidden → IN render tree (takes space) */` },
      {
        title: 'Layout (Reflow) and Paint', color: '#eab308', desc: 'Layout calculates position/size of every element. Paint fills in pixels. Reflow is expensive.', code: `// ❌ Layout thrashing — read then write in a loop
for (const el of elements) {
  const width = el.offsetWidth; // forces layout READ
  el.style.width = (width + 10) + 'px'; // layout WRITE
  // Each iteration: forced synchronous reflow!
}

// ✅ Batch reads then writes
const widths = elements.map(el => el.offsetWidth); // all reads
elements.forEach((el, i) => {
  el.style.width = (widths[i] + 10) + 'px'; // all writes
});

// ✅ Use transform/opacity — compositor only, no reflow/repaint
element.style.transform = 'translateX(10px)'; // GPU ✓
element.style.left = '10px'; // triggers reflow ❌` },
      {
        title: 'Compositing — GPU layers', color: '#00ff88', desc: 'Compositor thread assembles layers into final frame. GPU handles transform/opacity changes.', code: `/* will-change promotes element to own GPU layer */
.animated-element {
  will-change: transform; /* hint: this will animate */
}

/* transform/opacity: compositor only (60fps smooth) */
.slide-in {
  animation: slideIn 0.3s ease;
}
@keyframes slideIn {
  from { transform: translateX(-100px); } /* GPU ✓ */
  to   { transform: translateX(0); }
}

/* Avoid animating: width, height, top, left, padding */
/* These trigger layout → paint → composite (slow) */
/* Use: transform (translate, scale) and opacity (fast) */` },
    ]} />
    <InlinePoll question="What is 'layout thrashing'?" options={['CSS animations that conflict', 'Reading layout properties (offsetWidth) and then writing styles in a loop — forcing multiple synchronous reflows', 'Too many DOM nodes causing slow layout', 'CSS grid and flexbox conflicting']} correct={1} explanation="Layout thrashing: reading a layout property (offsetWidth, getBoundingClientRect) forces the browser to flush pending style changes and calculate layout. If you then write a style change and read again in a loop, you force N synchronous reflows instead of 1. Batch reads, then writes." />
    <CommonMistake mistake="Animating position with 'top' and 'left' properties for smooth animations." fix="top/left changes trigger Layout → Paint → Composite (the full pipeline, expensive). Use transform: translateX/Y instead — these only require Composite (GPU handles it). This is why 60fps animations always use transform and opacity, never width/height/top/left." />
    <DidYouKnow fact="The rendering pipeline is why React's Virtual DOM was so revolutionary — it minimized DOM operations by batching updates. But a single expensive CSS property change (like box-shadow) on scroll can still cause major performance issues. Knowing the rendering pipeline explains why some 'simple' CSS changes are expensive." color="#4facfe" />
    <InterviewMeter topics={[{ topic: 'Critical Rendering Path steps', freq: 85 }, { topic: 'Layout thrashing and how to fix it', freq: 80 }, { topic: 'transform/opacity vs layout-triggering properties', freq: 75 }, { topic: 'async vs defer for scripts', freq: 70 }]} />
  </div>
);

export const StorageLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Where to Store Data in the Browser</div>
      <p style={c.prose}>
        The browser offers multiple storage options, each with different <strong style={{ color: '#eab308' }}>scope, persistence, security, and capacity</strong>. Choosing the wrong one is a security vulnerability or UX bug waiting to happen.
      </p>
    </RevealCard>
    <AnalogyCard emoji="🗄️" title="Different types of storage at work" analogy="Your desk (localStorage) — always there when you return. Whiteboard (sessionStorage) — erased when you leave for the day. Filing cabinet (IndexedDB) — organized, large capacity, searchable. Company mail system (cookies) — goes back and forth with every external communication." connection="localStorage: persists forever. sessionStorage: cleared on tab close. Cookies: sent with HTTP requests. IndexedDB: large structured data. Choose based on who needs to see it and for how long." />
    <StorySteps steps={[
      {
        title: 'localStorage vs sessionStorage', color: '#eab308', desc: 'Both are synchronous key-value stores. Differ only in persistence.', code: `// localStorage — persists across sessions
localStorage.setItem('theme', 'dark');
localStorage.getItem('theme'); // 'dark' (even after browser restart)
localStorage.removeItem('theme');

// sessionStorage — cleared on tab close
sessionStorage.setItem('draft', formData);
sessionStorage.getItem('draft'); // gone when tab closes

// Both:
// ✓ String values only (use JSON.stringify for objects)
// ✓ ~5-10MB limit per origin
// ✗ Synchronous — blocks main thread
// ✗ Accessible by ANY JS on the page (XSS risk)
// ✗ Not sent with HTTP requests

JSON.parse(localStorage.getItem('user') || 'null');` },
      {
        title: 'Cookies — sent with every request', color: '#4facfe', desc: 'Automatically sent to server. Supports httpOnly (no JS access), Secure, SameSite flags.', code: `// Client-side cookie
document.cookie = 'theme=dark; max-age=2592000; SameSite=Strict';

// Reading cookies in JS
const cookies = Object.fromEntries(
  document.cookie.split('; ').map(c => c.split('='))
);

// Server-side secure cookie (Express)
res.cookie('session', token, {
  httpOnly: true,   // ← no JS access (XSS-safe!)
  secure: true,     // ← HTTPS only
  sameSite: 'strict', // ← no CSRF
  maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
});

// httpOnly cookies are invisible to document.cookie
// Perfect for auth tokens — XSS can't steal them` },
      {
        title: 'IndexedDB — for large structured data', color: '#a855f7', desc: 'Async, transactional, supports complex queries. For large datasets, offline apps, binary data.', code: `// IndexedDB — async, large data (GBs)
const request = indexedDB.open('myDB', 1);

request.onupgradeneeded = (e) => {
  const db = e.target.result;
  const store = db.createObjectStore('users', { keyPath: 'id' });
  store.createIndex('email', 'email', { unique: true });
};

request.onsuccess = (e) => {
  const db = e.target.result;
  const tx = db.transaction('users', 'readwrite');
  const store = tx.objectStore('users');
  store.add({ id: 1, name: 'Alice', email: 'alice@example.com' });
};

// In practice, use a library:
// Dexie.js, idb, localForage — much simpler API` },
      {
        title: 'Security — what NOT to store where', color: '#ef4444', desc: 'Wrong storage choice creates security vulnerabilities.', code: `// ❌ NEVER store in localStorage:
localStorage.setItem('accessToken', jwt); // XSS steals it!
localStorage.setItem('password', pass);   // Never!

// ✅ Auth tokens:
// Access token → in-memory JS variable (not persistent)
// Refresh token → httpOnly cookie (XSS-safe)

// ❌ NEVER store sensitive data client-side at all:
// SSNs, credit cards, medical data
// These belong server-side only

// ✅ localStorage is fine for:
// User preferences (theme, language)
// Non-sensitive UI state
// App configuration that isn't sensitive` },
    ]} />
    <InlinePoll question="Where should you store a JWT refresh token for maximum security?" options={['localStorage — easy JS access', 'sessionStorage — cleared on close', 'httpOnly cookie — inaccessible to JavaScript', 'Global JS variable']} correct={2} explanation="httpOnly cookies are inaccessible to JavaScript — XSS attacks can't steal what they can't read. localStorage and sessionStorage are vulnerable to any XSS on your page. In-memory variables are secure from XSS but lost on page refresh. httpOnly cookie is the best balance for auth tokens." />
    <CommonMistake mistake="Storing JWT access tokens in localStorage 'because it's easier to read in JavaScript'." fix="localStorage is readable by any JavaScript on your page — XSS vulnerabilities steal it instantly. Store access tokens in memory (JS variable), refresh tokens in httpOnly cookies. Memory tokens are lost on refresh — that's fine, just get a new one from the refresh token." />
    <DidYouKnow fact="The Web Storage API (localStorage/sessionStorage) was designed to replace cookies for non-sensitive client-side storage. The irony is that many developers use it for auth tokens — the opposite of what it was designed for. Cookies with httpOnly were always meant for sensitive data like session tokens." color="#eab308" />
    <InterviewMeter topics={[{ topic: 'localStorage vs sessionStorage vs cookies differences', freq: 85 }, { topic: 'httpOnly cookies for auth tokens', freq: 85 }, { topic: 'When to use IndexedDB', freq: 65 }, { topic: 'What NOT to store in localStorage', freq: 80 }]} />
  </div>
);

// ── CSS ARCHITECTURE ─────────────────────────────────────────────────

export const CSSSpecificityLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Why Does My CSS Not Apply?</div>
      <p style={c.prose}>The #1 CSS frustration: you write a rule and it does nothing. Another rule is winning. The cascade has a strict priority system — understanding it means <strong style={{ color: '#818cf8' }}>you always know which rule will win and why</strong>.</p>
    </RevealCard>
    <AnalogyCard emoji="⚖️" title="A court hierarchy" analogy="A local court ruling can be overturned by a state court, which can be overturned by a supreme court. CSS specificity works the same way — inline styles beat IDs, IDs beat classes, classes beat elements. Higher court always wins, regardless of how many lower-court rulings exist." connection="0 inline > 0 IDs > 0 classes > 0 elements. (0,1,0,0) always beats (0,0,99,0) — one ID beats 99 classes." />
    <StorySteps steps={[
      {
        title: 'Calculating specificity', color: '#818cf8', desc: 'Count selectors in four buckets: (inline, IDs, classes/pseudo-classes/attributes, elements)', code: `/* (0, 0, 0, 1) — element */
p { color: black; }

/* (0, 0, 1, 0) — class */
.text { color: blue; }  /* wins over p */

/* (0, 0, 1, 1) — class + element */
p.text { color: green; } /* wins over .text */

/* (0, 1, 0, 0) — ID */
#header { color: red; }  /* wins over all above */

/* (1, 0, 0, 0) — inline */
<p style="color: pink"> /* wins over everything */` },
      {
        title: 'The cascade order', color: '#4facfe', desc: 'When specificity is equal, later rules win.', code: `/* Same specificity (0,0,1,0) — last wins */
.button { background: blue; }
.button { background: green; } /* ← wins (later in file) */

/* Important: specificity doesn't matter */
.button { background: blue !important; } /* wins */
#id    { background: red; } /* loses to !important */` },
      {
        title: '@layer — modern cascade control', color: '#00ff88', desc: 'Define explicit cascade layers. Later layers always win over earlier ones, regardless of specificity.', code: `@layer base, components, utilities;

@layer base {
  .button { color: blue; } /* (0,0,1,0) */
}
@layer utilities {
  .text-red { color: red; } /* (0,0,1,0) — same specificity */
  /* But utilities layer > base layer → wins! */
}` },
      {
        title: 'Inheritance — not all properties cascade', color: '#eab308', desc: 'Some properties inherit from parent (color, font), others don\'t (border, padding).', code: `/* Inherited: color, font-*, text-*, line-height */
body { color: #333; }
p { /* inherits color: #333 from body */ }

/* Not inherited: border, background, padding, margin */
div { border: 1px solid red; }
span { /* does NOT get the border */ }

/* Force inheritance */
span { border: inherit; } /* now inherits parent's border */` },
    ]} />
    <InlinePoll question="Which selector wins: '#nav .link' or '.nav-container .nav-item a.link.active'?" options={['#nav .link wins', '.nav-container .nav-item a.link.active wins', 'They are equal', 'Depends on source order']} correct={0} explanation="#nav .link has specificity (0,1,1,0). The class chain has (0,0,3,1). One ID (0,1,0,0) beats any number of classes (0,0,N,0). #nav .link wins despite the other selector being longer." />
    <CommonMistake mistake="Adding !important to fix specificity issues — creating a specificity arms race." fix="!important should be used sparingly (utility classes, accessibility overrides). The real fix is lower specificity architecture: use classes instead of IDs, BEM instead of nested selectors, or CSS Modules for automatic scoping." />
    <DidYouKnow fact="CSS specificity was deliberately designed to be non-intuitive in one way: 11 classes (0,0,11,0) do NOT beat 1 ID (0,1,0,0). The buckets don't overflow into each other. This surprises many developers." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'Specificity calculation', freq: 80 }, { topic: '!important usage and problems', freq: 75 }, { topic: '@layer for cascade management', freq: 55 }, { topic: 'Inheritance — which properties inherit', freq: 65 }]} />
  </div>
);

export const CSSLayoutLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Flexbox vs Grid — Choose the Right Tool</div>
      <p style={c.prose}>Flexbox and Grid solve different problems. Using the wrong one creates unnecessary complexity. <strong style={{ color: '#818cf8' }}>Flexbox is one-dimensional. Grid is two-dimensional.</strong> That single distinction tells you which to use.</p>
    </RevealCard>
    <AnalogyCard emoji="📐" title="A train vs a city grid" analogy="A train track (Flexbox) goes in one direction — items line up along the track, and you control spacing between them. A city grid (CSS Grid) has both streets and avenues — items can be placed at exact intersections of rows and columns." connection="Flexbox: control items in a row OR a column. Grid: control items across rows AND columns simultaneously." />
    <StorySteps steps={[
      {
        title: 'Flexbox — one-dimensional layout', color: '#4facfe', desc: 'Controls items along a single axis. Perfect for navigation bars, button groups, centering.', code: `/* Flexbox basics */
.container {
  display: flex;
  flex-direction: row;         /* main axis: horizontal */
  justify-content: space-between; /* main axis alignment */
  align-items: center;         /* cross axis alignment */
  gap: 16px;
}

/* Flex item grows to fill space */
.item { flex: 1; } /* equal width items */
.item--wide { flex: 2; } /* twice as wide */` },
      {
        title: 'CSS Grid — two-dimensional layout', color: '#a855f7', desc: 'Controls both rows and columns. Perfect for page layouts, card grids, complex UIs.', code: `/* Grid basics */
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr); /* 3 equal columns */
  grid-template-rows: auto;
  gap: 24px;
}

/* Responsive grid — no media queries! */
.auto-grid {
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  /* Creates as many 250px+ columns as fit */
}

/* Span multiple cells */
.featured { grid-column: 1 / 3; grid-row: 1 / 3; }` },
      {
        title: 'When to use each', color: '#00ff88', desc: 'The decision framework.', code: `/* Use FLEXBOX for: */
/* - Navigation bars (1D row of links) */
/* - Button groups */
/* - Centering a single item */
/* - Variable-length content in a line */

/* Use GRID for: */
/* - Page layouts */
/* - Card grids */
/* - Any 2D alignment (items align across rows AND columns) */
/* - When you need items to span multiple tracks */

/* Often combined: Grid for layout, Flex inside cells */` },
      {
        title: 'Subgrid — align nested content', color: '#eab308', desc: 'Subgrid lets children participate in the parent grid\'s tracks.', code: `/* Card grid where all card contents align */
.card-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: auto 1fr auto; /* header, body, footer */
}

.card {
  display: grid;
  grid-row: span 3;
  grid-template-rows: subgrid; /* use parent's row tracks! */
}
/* Now all card titles, bodies, footers align across cards */` },
    ]} />
    <InlinePoll question="When should you use CSS Grid instead of Flexbox?" options={['Grid is always better', 'For two-dimensional layouts where items must align in both rows AND columns', 'Only for image galleries', 'When you need more than 3 columns']} correct={1} explanation="The key question: do you need to control one axis or two? A navigation bar (one row of items) → Flexbox. A card grid (items must align in rows AND columns) → Grid. When both axes matter, Grid is the right choice." />
    <CommonMistake mistake="Using Flexbox for a 2D grid layout by nesting multiple flex containers." fix="Nested flex rows to create a grid is fragile — items in different rows can't align with each other. CSS Grid handles true 2D alignment natively. Use Grid when you need items in different rows to line up vertically." />
    <DidYouKnow fact="CSS Grid was designed specifically to replace all the CSS layout hacks (floats for layout, table-based layouts, positioning tricks). The spec was developed by Microsoft in 2011 and shipped in all major browsers in 2017 in a coordinated release — all browsers added support within weeks of each other." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'Flexbox vs Grid — when to use each', freq: 85 }, { topic: 'justify-content vs align-items', freq: 80 }, { topic: 'fr unit and auto-fit/auto-fill', freq: 70 }, { topic: 'Subgrid for nested alignment', freq: 50 }]} />
  </div>
);

export const CSSBEMLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Naming Things Is Hard — BEM Makes It Easy</div>
      <p style={c.prose}>Without a naming convention, CSS becomes a mess of <code>.btn2</code>, <code>.new-header</code>, <code>.fix-margin</code>. BEM gives every class a <strong style={{ color: '#818cf8' }}>predictable, self-documenting name</strong> that tells you exactly what it styles and where it belongs.</p>
    </RevealCard>
    <AnalogyCard emoji="🏷️" title="A parts catalog" analogy="A car parts catalog has structured names: Toyota_Camry__Engine--V6. You immediately know: brand (Toyota), model (Camry), part (Engine), variant (V6). BEM works the same: Block__Element--Modifier. .card__header--highlighted tells you: card component, header element, highlighted variant." connection=".block__element--modifier — three parts, each with a specific meaning. Block = component. Element = part of component. Modifier = variation." />
    <StorySteps steps={[
      {
        title: 'Block — the component', color: '#818cf8', desc: 'A standalone reusable component. Should make sense on its own.', code: `/* Block — standalone component */
.card { background: white; border-radius: 8px; }
.button { padding: 8px 16px; border-radius: 4px; }
.nav { display: flex; gap: 16px; }

/* Blocks are independent — can live anywhere */` },
      {
        title: 'Element — part of a block', color: '#4facfe', desc: 'A part that only makes sense inside its block. Double underscore (__)', code: `/* Elements — parts of .card */
.card__header { font-size: 18px; font-weight: bold; }
.card__body   { padding: 16px; }
.card__footer { border-top: 1px solid #eee; }
.card__image  { width: 100%; aspect-ratio: 16/9; }

/* ❌ Never nest BEM: .card__header__title — wrong! */
/* ✅ Use .card__title instead — flat structure */` },
      {
        title: 'Modifier — variation or state', color: '#a855f7', desc: 'A variation of a block or element. Double hyphen (--)', code: `/* Block modifiers */
.button--primary  { background: blue; color: white; }
.button--danger   { background: red; color: white; }
.button--disabled { opacity: 0.5; cursor: not-allowed; }

/* Element modifiers */
.card__image--rounded { border-radius: 50%; }
.card--featured .card__header { font-size: 24px; }

/* Combine block + modifier in HTML */` },
      {
        title: 'BEM in practice', color: '#00ff88', desc: 'Real HTML using BEM naming.', code: `<div class="card card--featured">
  <img class="card__image" src="..." alt="">
  <div class="card__body">
    <h2 class="card__title">Title</h2>
    <p class="card__description">...</p>
  </div>
  <div class="card__footer">
    <button class="button button--primary">
      Read More
    </button>
  </div>
</div>` },
    ]} />
    <InlinePoll question="In BEM, how do you name a navigation link that is currently active?" options={['.nav-link-active', '.nav__link--active', '.nav-active__link', '#nav .link.active']} correct={1} explanation=".nav__link--active: nav is the Block, link is the Element (double underscore), active is the Modifier (double hyphen). This communicates: 'an active link inside the nav component'. Perfectly self-documenting." />
    <CommonMistake mistake="Deeply nesting BEM: .card__body__section__title" fix="BEM elements are always flat — they reference the Block, not other elements. Instead of .card__body__section__title, use .card__section-title. The element name should describe what it is, not where it is in the DOM structure." />
    <DidYouKnow fact="BEM was developed at Yandex (Russia's largest search engine) in 2009 to manage CSS at massive scale — Yandex had hundreds of developers writing CSS. The methodology became public in 2010 and influenced virtually every subsequent CSS naming convention." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'BEM naming convention — Block__Element--Modifier', freq: 75 }, { topic: 'When to use BEM vs CSS Modules', freq: 65 }, { topic: 'Common BEM mistakes (deep nesting)', freq: 60 }]} />
  </div>
);

export const CSSVariablesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 CSS Variables — Runtime Theming Power</div>
      <p style={c.prose}>CSS custom properties (variables) are different from Sass variables — they're <strong style={{ color: '#818cf8' }}>live in the browser</strong>, changeable at runtime with JavaScript, and can cascade through the DOM tree.</p>
    </RevealCard>
    <AnalogyCard emoji="🎨" title="A paint store with custom mixing" analogy="Sass variables are like pre-mixed paint cans — the color is fixed when manufactured. CSS variables are like a paint store's formula system — the base formula is stored, and you can change the color at any time by updating the formula. Every surface using that formula updates instantly." connection="Sass variables compile away at build time. CSS variables exist at runtime — change them with JavaScript and every component using them updates instantly." />
    <StorySteps steps={[
      {
        title: 'Defining and using custom properties', color: '#818cf8', desc: 'Define with -- prefix. Access with var(). Define on :root for global scope.', code: `/* Define on :root for global access */
:root {
  --color-primary: #3b82f6;
  --color-bg: #ffffff;
  --spacing-4: 16px;
  --font-sans: 'Inter', sans-serif;
  --shadow-md: 0 4px 6px rgba(0,0,0,0.1);
}

/* Use with var() */
.button {
  background: var(--color-primary);
  padding: var(--spacing-4);
  font-family: var(--font-sans);
}` },
      {
        title: 'Fallback values', color: '#4facfe', desc: 'var() accepts a fallback for when the variable isn\'t defined.', code: `/* Fallback syntax: var(--name, fallback) */
.card {
  background: var(--card-bg, white);
  color: var(--card-text, #333);
  /* If --card-bg isn't defined, uses white */
}

/* Chain fallbacks */
color: var(--primary, var(--accent, blue));
/* Tries --primary, then --accent, then blue */` },
      {
        title: 'Dynamic theming with JavaScript', color: '#00ff88', desc: 'Change variables at runtime — instant theme switching.', code: `// Change a single variable → all components update
document.documentElement.style.setProperty(
  '--color-primary', '#ef4444'
);

// Dark mode toggle
function toggleDarkMode(isDark) {
  const root = document.documentElement;
  root.style.setProperty('--color-bg', isDark ? '#0d1117' : '#fff');
  root.style.setProperty('--color-text', isDark ? '#e2e8f0' : '#111');
}

// Read a variable
getComputedStyle(document.documentElement)
  .getPropertyValue('--color-primary'); // '#3b82f6'` },
      {
        title: 'Scoped variables', color: '#eab308', desc: 'Variables can be scoped to components, not just :root.', code: `/* Global default */
:root { --button-bg: #3b82f6; }

/* Scoped override — only affects buttons in .dark-section */
.dark-section {
  --button-bg: #1e40af;
}

/* Component uses the variable — gets scoped value in dark-section */
.button {
  background: var(--button-bg);
}` },
    ]} />
    <InlinePoll question="What is the key advantage of CSS custom properties over Sass variables?" options={['CSS variables are faster', 'CSS variables are runtime — changeable with JavaScript and respond to media queries. Sass variables are compiled away at build time', 'Sass variables are deprecated', 'CSS variables have better browser support']} correct={1} explanation="Sass variables are processed at build time — they don't exist in the browser. CSS custom properties live in the cascade and can be: changed by JavaScript for dynamic theming, overridden in media queries, scoped to components, and inherited through the DOM." />
    <CommonMistake mistake="Using CSS variables like Sass variables — only for static color tokens with no dynamic behavior." fix="CSS variables' superpower is runtime mutability. Use them for: dark mode (toggle one CSS variable, entire theme changes), component variants (scope a variable to change child appearance), user-configurable settings (font size, contrast), and animation state (update via JS for dynamic animations)." />
    <DidYouKnow fact="CSS custom properties are inherited — they follow the cascade like any other property. A variable defined on a parent element is available to all descendants. This is why defining on :root makes variables globally available. You can override variables at any level of the DOM tree." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'CSS variables vs Sass variables difference', freq: 80 }, { topic: 'var() syntax and fallbacks', freq: 75 }, { topic: 'Runtime theming with setProperty()', freq: 70 }, { topic: 'Scoped variables for component theming', freq: 65 }]} />
  </div>
);

export const CSSInJSLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Styles and Components — Together or Separate?</div>
      <p style={c.prose}>CSS-in-JS, CSS Modules, and Tailwind represent fundamentally different philosophies about where styles should live. Each has real trade-offs — <strong style={{ color: '#818cf8' }}>there's no universal winner</strong>.</p>
    </RevealCard>
    <AnalogyCard emoji="🍽️" title="Dining styles — à la carte vs buffet vs set menu" analogy="Runtime CSS-in-JS (styled-components) is à la carte — maximum flexibility, each item prepared fresh. CSS Modules is a set menu — predictable, efficient, no surprises. Tailwind is a buffet — everything available instantly, you assemble what you need. Different contexts call for different approaches." connection="CSS Modules: auto-scoping at build time. Styled-components: dynamic styles at runtime. Tailwind: utility classes in HTML. Choose based on project needs." />
    <StorySteps steps={[
      {
        title: 'CSS Modules — best default choice', color: '#00ff88', desc: 'Auto-scoped class names at build time. Zero runtime overhead. Works with any CSS syntax.', code: `/* Button.module.css */
.button { padding: 8px 16px; border-radius: 4px; }
.primary { background: #3b82f6; color: white; }
.danger  { background: #ef4444; color: white; }

/* Button.jsx */
import styles from './Button.module.css';
import { clsx } from 'clsx';

function Button({ variant = 'primary', children }) {
  return (
    <button className={clsx(styles.button, styles[variant])}>
      {children}
    </button>
  );
}` },
      {
        title: 'styled-components — runtime CSS-in-JS', color: '#a855f7', desc: 'Styles defined in JavaScript. Dynamic based on props. Generates and injects CSS at runtime.', code: `import styled from 'styled-components';

const Button = styled.button\`
  padding: 8px 16px;
  background: \${props => props.variant === 'danger'
    ? '#ef4444' : '#3b82f6'};
  color: white;
  /* Dynamic styles based on props! */
\`;

<Button variant="danger">Delete</Button>

/* Downsides: runtime CSS generation, SSR complexity,
   style recalculation, serialization cost */` },
      {
        title: 'Tailwind — utility-first', color: '#4facfe', desc: 'Pre-defined utility classes composed in HTML. No custom CSS files needed.', code: `/* Tailwind — compose styles in JSX */
<button className="
  px-4 py-2 rounded
  bg-blue-500 hover:bg-blue-600
  text-white font-medium
  transition-colors duration-200
  disabled:opacity-50
">
  Submit
</button>

/* Pros: no CSS files, always fresh (no dead code),
   design constraints, great for prototyping */
/* Cons: long class strings, harder to read, theming limits */` },
      {
        title: 'Zero-runtime CSS-in-JS — best of both worlds', color: '#eab308', desc: 'Write CSS-in-JS syntax but extract to static CSS at build time.', code: `// vanilla-extract — TypeScript + build-time extraction
import { style } from '@vanilla-extract/css';

export const button = style({
  padding: '8px 16px',
  borderRadius: 4,
  selectors: {
    '&:hover': { opacity: 0.9 },
  },
});
// Becomes: .button_button__abc123 { ... } (static CSS!)
// Type-safe + no runtime overhead` },
    ]} />
    <InlinePoll question="What is the main performance concern with styled-components/Emotion (runtime CSS-in-JS)?" options={['Large bundle size', 'Styles generated and injected at runtime — adds JS execution cost, can cause FOUC in SSR, and creates style recalculations', 'Poor browser support', 'No TypeScript support']} correct={1} explanation="Runtime CSS-in-JS generates style tags in the browser during render. This means: JS must run before styles apply (risk of unstyled content), adds CPU cost for template literal parsing, can cause hydration mismatches in SSR. Zero-runtime alternatives (vanilla-extract, Linaria) give the DX without the runtime cost." />
    <CommonMistake mistake="Choosing runtime CSS-in-JS because 'everyone uses styled-components' without considering the performance implications." fix="For most new projects, CSS Modules or Tailwind are better defaults — zero runtime overhead. Use styled-components/Emotion if you specifically need: dynamic prop-based styles that change frequently, or you're maintaining an existing codebase built on them. Consider vanilla-extract for type-safe zero-runtime alternative." />
    <DidYouKnow fact="The CSS-in-JS debate has been ongoing since 2014. In 2022, the React team began discouraging runtime CSS-in-JS for React Server Components (they can't inject styles in server-rendered HTML). This accelerated adoption of zero-runtime alternatives like vanilla-extract and Tailwind in the React ecosystem." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'CSS Modules vs styled-components trade-offs', freq: 75 }, { topic: 'Runtime vs zero-runtime CSS-in-JS', freq: 65 }, { topic: 'Tailwind utility-first approach', freq: 70 }, { topic: 'Choosing the right approach for a project', freq: 70 }]} />
  </div>
);

export const CSSContainerLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Modern CSS: The Features That Change Everything</div>
      <p style={c.prose}>Container queries, :has(), @layer, and cascade layers represent the biggest leap in CSS capabilities since Flexbox. These features solve problems developers have worked around for a decade.</p>
    </RevealCard>
    <AnalogyCard emoji="📦" title="A responsive component vs a responsive page" analogy="Media queries ask 'how wide is the window?' Container queries ask 'how wide is MY box?' A card component in a sidebar (narrow) should look different from the same card in a main content area (wide) — but both are on the same page, same viewport width. Container queries make this possible." connection="@container queries respond to the containing element's size, not the viewport. The same component adapts to wherever it's placed." />
    <StorySteps steps={[
      {
        title: 'Container queries — responsive components', color: '#818cf8', desc: 'Components adapt to their container size, not the viewport.', code: `/* Define containment context on parent */
.card-container {
  container-type: inline-size;
  container-name: card; /* optional name */
}

/* Query the container */
@container card (min-width: 400px) {
  .card {
    display: flex;
    flex-direction: row;
  }
}

@container (max-width: 300px) {
  .card__image { display: none; }
}` },
      {
        title: ':has() — the parent selector', color: '#4facfe', desc: 'Style a parent based on its children. Previously impossible in CSS.', code: `/* Style form when it contains an invalid input */
form:has(:invalid) {
  border: 2px solid red;
}

/* Style card when it contains an image */
.card:has(img) {
  padding: 0;
}

/* Style nav when it has a checked checkbox (hamburger menu) */
nav:has(input[type="checkbox"]:checked) {
  background: rgba(0,0,0,0.5);
}

/* Complex: 3-column grid when exactly 3 items */
.grid:has(:nth-child(3):last-child) {
  grid-template-columns: repeat(3, 1fr);
}` },
      {
        title: '@layer — cascade management', color: '#00ff88', desc: 'Define explicit cascade layers. Solves specificity wars with third-party CSS.', code: `/* Define layer order — later layers win */
@layer reset, base, components, utilities;

@layer reset {
  * { margin: 0; box-sizing: border-box; }
}
@layer base {
  a { color: blue; text-decoration: underline; }
}
@layer components {
  .button { color: white; } /* beats base.a even with same spec */
}
@layer utilities {
  .text-red { color: red; } /* always wins in utilities layer */
}

/* Unlayered styles beat ALL layers */
.override { color: green; } /* beats utilities layer */` },
      {
        title: 'logical properties', color: '#eab308', desc: 'Writing-mode independent properties for international layouts.', code: `/* Physical → Logical */
margin-left:   → margin-inline-start
margin-right:  → margin-inline-end
margin-top:    → margin-block-start
padding-left:  → padding-inline-start
width:         → inline-size
height:        → block-size

/* Benefits: RTL (Arabic, Hebrew) works automatically */
.card {
  margin-inline: auto;  /* centered in any writing direction */
  padding-block: 16px;  /* top/bottom padding */
  border-inline-start: 4px solid blue; /* left in LTR, right in RTL */
}` },
    ]} />
    <InlinePoll question="What problem do container queries solve that media queries cannot?" options={['Container queries are faster', 'A component adapting to its container size, not the viewport — the same component renders differently in a sidebar vs main content area', 'Container queries work without JavaScript', 'Container queries support all browsers']} correct={1} explanation="Media queries check viewport width — a card always looks the same at 1200px viewport regardless of whether it's in a 200px sidebar or 800px main content. Container queries check the parent element's size — the card adapts to WHERE it is, not just how big the screen is." />
    <CommonMistake mistake="Not defining container-type on the parent before using @container queries." fix="container-type: inline-size (or size) must be set on the parent element to establish a containment context. Without it, @container rules have no element to query. Also: adding container-type creates a new stacking context — can affect z-index behavior." />
    <DidYouKnow fact=":has() was called 'the holy grail of CSS selectors' for over a decade because it seemed impossible to implement without causing performance issues (scanning the whole DOM for parent matching). Safari shipped it first in 2022, then Chrome and Firefox followed. It's now available in all modern browsers." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'Container queries vs media queries', freq: 70 }, { topic: ':has() selector use cases', freq: 65 }, { topic: '@layer for cascade control', freq: 55 }, { topic: 'Logical properties for internationalization', freq: 45 }]} />
  </div>
);

export const CSSPerfLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 CSS Is Not Free — It Blocks Rendering</div>
      <p style={c.prose}>External CSS files are <strong style={{ color: '#ef4444' }}>render-blocking</strong>. The browser won't show anything until all CSS is downloaded and parsed. Optimizing CSS delivery is one of the highest-impact performance improvements.</p>
    </RevealCard>
    <AnalogyCard emoji="🚦" title="A traffic light that can't turn green until all supply trucks arrive" analogy="The browser can't paint pixels (green light) until it has all the CSS (supply trucks). If you have one slow CSS file, the entire page waits. Critical CSS inlines the minimum needed to show the first screen — the green light turns on immediately, and remaining CSS loads while the user reads." connection="Inline critical CSS in <head> → first paint immediately. Load non-critical CSS asynchronously. Users see content before full CSS loads." />
    <StorySteps steps={[
      {
        title: 'Critical CSS — inline above-the-fold', color: '#818cf8', desc: 'Extract and inline only the CSS needed for the initial viewport.', code: `<!-- ❌ Render-blocking external CSS -->
<link rel="stylesheet" href="all-styles.css">
<!-- Browser waits for 200KB CSS before painting! -->

<!-- ✅ Critical CSS inlined, rest async -->
<style>
  /* ~5KB of above-the-fold styles */
  .hero { font-size: 2rem; color: #333; }
  .nav { display: flex; gap: 16px; }
</style>
<!-- Non-critical: load after initial render -->
<link rel="preload" href="rest.css" as="style"
  onload="this.rel='stylesheet'">` },
      {
        title: 'content-visibility — skip off-screen rendering', color: '#4facfe', desc: 'Browser skips rendering off-screen elements entirely.', code: `/* Skip rendering for off-screen sections */
.section {
  content-visibility: auto;
  contain-intrinsic-size: 0 500px; /* estimated size */
}

/* Browser: "This section is off-screen,
   I'll skip layout/paint until it's near viewport"

   Long pages with many sections: 4-5x rendering speedup!
   The browser-native alternative to JS virtualization */` },
      {
        title: 'will-change — GPU layer hints', color: '#a855f7', desc: 'Pre-promote animated elements to compositor layers.', code: `/* ✅ Only use when animation is imminent */
.modal {
  will-change: transform, opacity;
  /* Creates GPU layer before animation starts */
}

/* ✅ Remove after animation to free GPU memory */
.modal--closed {
  will-change: auto;
}

/* ❌ Never do this — wastes GPU memory */
* { will-change: transform; }` },
      {
        title: 'CSS containment', color: '#00ff88', desc: 'contain property tells browser this element is independent — optimizes rendering.', code: `/* Layout containment — changes inside don't affect outside */
.widget {
  contain: layout; /* internal layout changes don't reflow parent */
}

/* Strict containment — most isolation */
.isolated {
  contain: strict;
  /* Equivalent to: layout style paint size */
  /* Browser can skip rendering if off-screen */
}

/* content-visibility uses this internally */` },
    ]} />
    <InlinePoll question="What is 'Critical CSS' and why does it improve performance?" options={['Minified CSS', 'CSS inlined in <head> containing only above-the-fold styles — eliminates the render-blocking CSS request for initial paint', 'CSS with !important rules', 'Compressed CSS files']} correct={1} explanation="Critical CSS: extract styles for the initial viewport (~5KB), inline them in <head>. The browser can paint immediately without waiting for an external CSS file. Load the full CSS async after. Tools like Critical, Critters (webpack), or Next.js do this automatically." />
    <CommonMistake mistake="Using content-visibility: auto on everything including small elements." fix="content-visibility: auto has overhead — calculating element bounds and watching for viewport intersection. It only helps for substantial off-screen content (long page sections, complex components). For small elements, the overhead exceeds the benefit. Use it for major page sections." />
    <DidYouKnow fact="Google found that adding content-visibility: auto to long Wikipedia-style articles reduced initial render time by ~7x. For a 6000px tall article, the browser only needs to render the first screen instead of the entire page. The rest renders progressively as the user scrolls." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'Critical CSS and render-blocking', freq: 80 }, { topic: 'content-visibility for off-screen performance', freq: 60 }, { topic: 'will-change usage and caveats', freq: 65 }, { topic: 'CSS containment property', freq: 50 }]} />
  </div>
);

export const CSSDarkModeLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#818cf840' delay={0}>
      <div style={c.title('#818cf8')}>🎬 Dark Mode Without the Headache</div>
      <p style={c.prose}>Dark mode done wrong means duplicating every CSS rule. Done right — with CSS custom properties and a single source of truth — <strong style={{ color: '#818cf8' }}>changing the theme is updating one set of variables</strong>.</p>
    </RevealCard>
    <AnalogyCard emoji="🌙" title="A painting vs a digital display" analogy="A painting can only look one way — changing it means repainting everything. A digital display uses color profiles — switch the profile and all colors adapt instantly, no individual element changes needed. CSS variables are your color profile for dark mode." connection="Define semantic tokens (--bg, --text, --border). Override them for dark mode. Every component using the tokens adapts automatically." />
    <StorySteps steps={[
      {
        title: 'CSS variable strategy', color: '#818cf8', desc: 'Semantic tokens + one override block for dark mode.', code: `/* Light mode defaults on :root */
:root {
  --color-bg:      #ffffff;
  --color-surface: #f8f9fa;
  --color-text:    #111827;
  --color-muted:   #6b7280;
  --color-border:  #e5e7eb;
  --color-primary: #3b82f6;
}

/* System dark mode */
@media (prefers-color-scheme: dark) {
  :root {
    --color-bg:      #0d1117;
    --color-surface: #161b22;
    --color-text:    #e2e8f0;
    --color-muted:   #8b949e;
    --color-border:  #21262d;
  }
}

/* Every component just uses var() — zero changes needed */
.card { background: var(--color-surface); color: var(--color-text); }` },
      {
        title: 'Manual toggle + system preference', color: '#4facfe', desc: 'Support both: follow system preference, allow manual override.', code: `/* CSS: data-theme attribute overrides media query */
[data-theme='dark'] {
  --color-bg: #0d1117;
  --color-text: #e2e8f0;
}
[data-theme='light'] {
  --color-bg: #ffffff;
  --color-text: #111827;
}

// JS: toggle with localStorage persistence
function setTheme(theme) {
  document.documentElement.setAttribute('data-theme', theme);
  localStorage.setItem('theme', theme);
}

// Initialize: use saved preference or system
const saved = localStorage.getItem('theme');
const system = window.matchMedia('(prefers-color-scheme: dark)').matches
  ? 'dark' : 'light';
setTheme(saved || system);` },
      {
        title: 'color-scheme property', color: '#00ff88', desc: 'Tell the browser which color scheme to use for native UI elements.', code: `/* Tell browser to use dark native UI elements */
:root { color-scheme: light dark; }
/* OR specifically: */
[data-theme='dark'] { color-scheme: dark; }

/* What this affects:
   - Form inputs (dark background on dark mode)
   - Scrollbars (dark on macOS)
   - Native select dropdowns
   - Browser default link colors
   Without this, native elements stay light even in dark mode! */` },
      {
        title: 'Image handling in dark mode', color: '#eab308', desc: 'Dimming and inverting images for dark mode.', code: `/* Dim bright images in dark mode */
@media (prefers-color-scheme: dark) {
  img:not([src*='.svg']) {
    filter: brightness(0.85) contrast(1.1);
  }
}

/* Different image per theme with picture element */
<picture>
  <source srcset="logo-dark.svg"
    media="(prefers-color-scheme: dark)" />
  <img src="logo-light.svg" alt="Logo" />
</picture>

/* CSS invert for icons */
[data-theme='dark'] .icon { filter: invert(1); }` },
    ]} />
    <InlinePoll question="What does the color-scheme CSS property do for dark mode?" options={['Changes all element colors', 'Tells the browser to use dark/light native UI elements (scrollbars, form inputs, selects) matching the theme', 'Only affects background color', 'Required for dark mode to work']} correct={1} explanation="Without color-scheme: dark, form inputs, scrollbars, and native controls stay light-themed even when your CSS is dark. Setting color-scheme: dark on the root tells the browser to apply its dark-mode native styling to these browser-controlled elements." />
    <CommonMistake mistake="Using separate CSS classes (.light and .dark) on every component to implement dark mode." fix="Don't duplicate rules. Define semantic CSS variables (--bg, --text, --border) and override them once in @media (prefers-color-scheme: dark) or [data-theme='dark']. Components just use var(--bg) — zero component changes needed when switching themes." />
    <DidYouKnow fact="prefers-color-scheme was proposed in 2017 and shipped in all major browsers by 2019. Before OS-level dark mode APIs, websites detected dark mode preference via user accounts or manual toggles. Now the OS preference is directly queryable — making automatic dark mode respect a user's system setting." color="#818cf8" />
    <InterviewMeter topics={[{ topic: 'CSS custom properties for theming', freq: 80 }, { topic: 'prefers-color-scheme media query', freq: 75 }, { topic: 'Manual toggle with data-theme attribute', freq: 70 }, { topic: 'color-scheme property for native elements', freq: 55 }]} />
  </div>
);

