export const AsyncDeferLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Scripts That Don't Block Your Page</div>
      <p style={c.prose}>
        A plain <code>&lt;script&gt;</code> tag stops everything — HTML parsing freezes until the script downloads AND executes. <strong style={{ color: '#f97316' }}>async and defer</strong> let scripts load without blocking, but they behave very differently from each other.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🚧"
      title="A road crew blocking one lane vs working at night"
      analogy="A plain script is like a road crew blocking all traffic to fix a pothole — everything stops. async is like fixing the pothole while traffic flows around it — done when done, no schedule. defer is like scheduling the repair for after rush hour — work starts in parallel but traffic isn't affected until the road is clear."
      connection="Plain: blocks parsing. async: downloads in parallel, executes immediately when done (may interrupt parsing). defer: downloads in parallel, executes after parsing completes (in order)."
    />
    <StorySteps steps={[
      {
        title: 'Plain <script> — render blocking',
        color: '#ef4444',
        desc: 'HTML parsing stops. Script downloads. Script executes. Then parsing resumes. Everything waits.',
        code: `<!-- ❌ Render blocking — avoid for non-critical scripts -->
<head>
  <script src="app.js"></script>
  <!-- HTML parsing PAUSES here:
       1. Browser discovers <script>
       2. Downloads app.js (could be 500ms)
       3. Executes app.js (could be 200ms)
       4. Resumes parsing HTML
       Result: user sees blank page for 700ms! -->
</head>`,
      },
      {
        title: 'async — download parallel, execute immediately',
        color: '#eab308',
        desc: 'Script downloads while HTML parses. Executes AS SOON as download finishes — may interrupt HTML parsing. Order not guaranteed.',
        code: `<head>
  <!-- Downloads while HTML parses -->
  <!-- Executes ASAP after download — may pause parsing -->
  <!-- Order NOT guaranteed — race condition if multiple -->
  <script src="analytics.js" async></script>
  <script src="ads.js" async></script>
  <!-- Which executes first? Whoever downloads first! -->
</head>

<!-- ✅ Best for: independent scripts with no dependencies -->
<!-- Analytics, ads, social widgets — they don't depend on each other -->
<!-- ❌ Bad for: scripts that depend on each other or the DOM -->`,
      },
      {
        title: 'defer — download parallel, execute after parse',
        color: '#00ff88',
        desc: 'Script downloads while HTML parses. Executes AFTER HTML is fully parsed. Order guaranteed. Before DOMContentLoaded.',
        code: `<head>
  <!-- Downloads while HTML parses -->
  <!-- Executes after HTML fully parsed, in document order -->
  <!-- Before DOMContentLoaded fires -->
  <script src="react.js" defer></script>
  <script src="app.js" defer></script>
  <!-- react.js always executes before app.js ✓ -->
</head>

<!-- ✅ Best for: your main app scripts -->
<!-- They need DOM to be ready, order matters -->
<!-- Same as putting <script> before </body> but downloads earlier -->`,
      },
      {
        title: 'Comparison and when to use each',
        color: '#a855f7',
        desc: 'The decision chart.',
        code: `<!-- Summary: -->
<!-- Plain:  blocks parsing, blocks rendering, in order -->
<!-- async:  parallel download, runs ASAP, no order guarantee -->
<!-- defer:  parallel download, runs after parse, in order -->

<!-- Use plain: for critical inline scripts only -->
<script>/* tiny critical inline script */</script>

<!-- Use async: independent scripts (no DOM, no dependencies) -->
<script src="analytics.js" async></script>

<!-- Use defer: everything else (main bundle, libraries, app code) -->
<script src="vendor.js" defer></script>
<script src="app.js" defer></script>

<!-- Modern modules are deferred by default! -->
<script type="module" src="app.js"></script>
<!-- type="module" is always deferred, never blocks -->`,
      },
    ]} />
    <InlinePoll
      question="You have jQuery and a plugin that depends on jQuery. Which attribute should you use?"
      options={['async on both', 'defer on both — executes in document order after parsing', 'async on jQuery, defer on plugin', 'Plain script tags']}
      correct={1}
      explanation="async doesn't guarantee order — the plugin might execute before jQuery loads. defer guarantees order: jQuery executes first, plugin executes second, both execute after HTML is parsed. For dependent scripts, defer is always the right choice."
    />
    <CommonMistake
      mistake="Putting defer scripts at the bottom of <body> instead of in <head>."
      fix="The benefit of defer is that the browser discovers and starts downloading the script early — even while parsing <head>. If you put deferred scripts at the bottom, they start downloading later. Put defer scripts in <head> for maximum benefit: early discovery + no render blocking."
    />
    <DidYouKnow
      fact="ES Module scripts (<script type='module'>) are deferred by default — you don't need the defer attribute. They also have strict mode automatically, their own scope, and support import/export. Modern bundlers output module scripts, which is why the 'put scripts at bottom of body' rule is outdated for modern web apps."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'async vs defer behavior difference', freq: 90 },
      { topic: 'When to use each', freq: 85 },
      { topic: 'type="module" is deferred by default', freq: 65 },
      { topic: 'DOMContentLoaded and defer execution timing', freq: 70 },
    ]} />
  </div>
);

export const CriticalRenderingPathLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 From Bytes to Pixels</div>
      <p style={c.prose}>
        The Critical Rendering Path is the sequence of steps a browser takes to convert HTML, CSS, and JavaScript into pixels on screen. <strong style={{ color: '#f97316' }}>Every step is a potential bottleneck.</strong> Understanding it lets you optimize for the fastest possible first paint.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏭"
      title="An assembly line"
      analogy="A car factory has a fixed assembly sequence — chassis first, then engine, then body, then paint. You can't paint before the body is attached. The Critical Rendering Path is an assembly line: HTML must be parsed before DOM is built, CSS must be parsed before styles apply, both must combine before layout can run."
      connection="HTML → DOM → CSSOM → Render Tree → Layout → Paint → Composite. Each step feeds the next. Blocking resources at step 1 or 2 delay everything that follows."
    />
    <StorySteps steps={[
      {
        title: 'Step 1 & 2: HTML and CSS parsing',
        color: '#f97316',
        desc: 'HTML is parsed into the DOM. CSS is parsed into the CSSOM. Both are required before rendering can begin.',
        code: `<!-- HTML parsing: incremental, browser can start immediately -->
<!-- CSS parsing: render-blocking — browser needs full CSSOM -->
<!-- before it can render anything -->

<!-- ❌ Render-blocking CSS -->
<link rel="stylesheet" href="styles.css">
<!-- Browser downloads ALL CSS, parses ALL CSS,
     then starts rendering. Large CSS = slow first paint. -->

<!-- ✅ Inline critical CSS — no network request needed -->
<style>
  /* Only above-the-fold styles — ~3-5KB */
  body { margin: 0; font-family: sans-serif; }
  .hero { font-size: 2rem; color: #333; }
  .nav { display: flex; gap: 1rem; }
</style>

<!-- Load non-critical CSS asynchronously -->
<link rel="preload" href="full-styles.css" as="style"
  onload="this.rel='stylesheet'">`,
      },
      {
        title: 'Step 3: Render Tree',
        color: '#4facfe',
        desc: 'DOM + CSSOM combine into the Render Tree — only visible elements included.',
        code: `/* Render Tree = DOM nodes with their computed styles */
/* Only visible elements included: */

/* NOT in Render Tree: */
/* - <head>, <script>, <meta> (not rendered) */
/* - display: none elements (removed completely) */
/* - Hidden elements outside viewport */

/* IS in Render Tree: */
/* - All visible elements with computed styles */
/* - visibility: hidden elements (take space, no paint) */

/* Why it matters: */
/* display: none → removed from Render Tree → no layout cost */
/* visibility: hidden → in Render Tree → still takes space */`,
      },
      {
        title: 'Step 4 & 5: Layout and Paint',
        color: '#a855f7',
        desc: 'Layout calculates geometry. Paint fills in pixels. Both are expensive — minimize triggering them.',
        code: `/* Layout (Reflow): calculates position + size of every element */
/* Triggered by: width, height, margin, padding, font-size changes */
/* Most expensive step — avoid during animation! */

/* Paint: fills pixels with color */
/* Triggered by: color, background, box-shadow changes */
/* Less expensive than layout, but still avoid during animation */

/* ❌ Layout thrashing — read then write in loop */
for (const el of elements) {
  const w = el.offsetWidth;   // read (forces layout sync)
  el.style.width = w + 10;    // write (invalidates layout)
}

/* ✅ Batch reads then writes */
const widths = [...elements].map(el => el.offsetWidth); // all reads
elements.forEach((el, i) => { el.style.width = widths[i] + 10; }); // all writes`,
      },
      {
        title: 'Step 6: Compositing + Optimization',
        color: '#00ff88',
        desc: 'GPU combines layers into the final frame. Shortcut the pipeline with transform/opacity.',
        code: `/* Pipeline shortcuts: */
/* Full pipeline: JS → Style → Layout → Paint → Composite */
/* transform/opacity: only Composite (GPU) — 60fps! */
/* color/bg-color: skips Layout → Paint + Composite */
/* width/height/top/left: full pipeline (slow) */

/* Preload critical resources */
<link rel="preload" href="hero.jpg" as="image" fetchpriority="high">
<link rel="preload" href="font.woff2" as="font" crossorigin>

/* Preconnect to third-party origins */
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://cdn.example.com">

/* Measure with: */
/* Chrome DevTools → Performance panel → record */
/* Lighthouse → Performance audit */
/* web-vitals library in production */`,
      },
    ]} />
    <InlinePoll
      question="What is the correct order of the Critical Rendering Path?"
      options={[
        'Paint → Layout → DOM → CSSOM',
        'HTML parsing → DOM + CSSOM → Render Tree → Layout → Paint → Composite',
        'JavaScript → CSS → HTML → Layout',
        'DOM → Paint → CSSOM → Composite',
      ]}
      correct={1}
      explanation="HTML is parsed to DOM, CSS is parsed to CSSOM simultaneously. DOM + CSSOM combine into the Render Tree. Layout calculates geometry. Paint fills pixels. Compositor combines layers. Each step requires the previous one to complete."
    />
    <CommonMistake
      mistake="Placing all CSS in one large external stylesheet and loading it in <head>."
      fix="Every byte of CSS blocks rendering. Extract critical (above-the-fold) CSS and inline it in <head>. Load the full stylesheet async with preload. Tools like Critters (webpack), Critical (Node.js), or Next.js built-in CSS optimization do this automatically."
    />
    <DidYouKnow
      fact="The Critical Rendering Path was coined by Google's Ilya Grigorik in his book 'High Performance Browser Networking'. His research showed that most web pages spend over 50% of load time on the CRP, not network latency. Optimizing the CRP is often more impactful than faster servers."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'CRP steps in correct order', freq: 85 },
      { topic: 'Render-blocking resources and how to fix', freq: 80 },
      { topic: 'Critical CSS concept', freq: 75 },
      { topic: 'Layout thrashing and batch DOM reads/writes', freq: 70 },
    ]} />
  </div>
);

export const WebComponentsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Framework-Independent Custom Elements</div>
      <p style={c.prose}>
        Web Components are a set of browser APIs that let you create <strong style={{ color: '#f97316' }}>reusable custom HTML elements</strong> — framework-agnostic, encapsulated, and first-class HTML citizens. A component built once works in React, Vue, Angular, or plain HTML.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🔌"
      title="USB-C — one standard, all devices"
      analogy="Before USB-C, every device needed a different cable (React component, Vue component, Angular component). USB-C is one universal standard that works everywhere. Web Components are the USB-C of the web — define once, use in any framework or no framework."
      connection="Custom Elements define new HTML tags. Shadow DOM encapsulates styles and DOM. HTML Templates define reusable markup. Together: <my-button>, <app-modal>, <color-picker> that work anywhere."
    />
    <StorySteps steps={[
      {
        title: 'Custom Elements — define new HTML tags',
        color: '#f97316',
        desc: 'Extend HTMLElement to create custom elements with their own behavior.',
        code: `class MyButton extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: 'open' }); // Shadow DOM
  }

  connectedCallback() {
    // Called when element is added to DOM
    this.shadowRoot.innerHTML = \`
      <style>
        button { background: #3b82f6; color: white; padding: 8px 16px; }
        button:hover { background: #1d4ed8; }
      </style>
      <button><slot></slot></button>
    \`;
    // <slot> = content projection (like React children)
  }

  disconnectedCallback() { /* cleanup */ }
  attributeChangedCallback(name, old, newVal) { /* attr changed */ }

  static get observedAttributes() { return ['disabled', 'variant']; }
}

// Register the custom element
customElements.define('my-button', MyButton);`,
      },
      {
        title: 'Using Custom Elements in HTML',
        color: '#4facfe',
        desc: 'Once defined, custom elements work like native HTML elements.',
        code: `<!-- Works in plain HTML -->
<my-button>Click me</my-button>
<my-button disabled variant="danger">Delete</my-button>

<!-- Works in React -->
function App() {
  return <my-button onClick={handleClick}>Click</my-button>;
}

<!-- Works in Vue -->
<template>
  <my-button @click="handleClick">Click</my-button>
</template>

<!-- Works in Angular -->
<my-button (click)="handleClick()">Click</my-button>

<!-- The custom element is registered globally — -->
<!-- available in any framework or plain HTML on the page -->`,
      },
      {
        title: 'HTML Templates — reusable markup',
        color: '#00ff88',
        desc: '<template> content is inert — not rendered until cloned and inserted.',
        code: `<!-- <template> — not rendered, but parseable and clonable -->
<template id="card-template">
  <div class="card">
    <h2 class="card__title"></h2>
    <p class="card__body"></p>
  </div>
</template>

<script>
  const template = document.getElementById('card-template');

  function createCard(title, body) {
    // Clone the template content
    const clone = template.content.cloneNode(true);
    clone.querySelector('.card__title').textContent = title;
    clone.querySelector('.card__body').textContent = body;
    document.body.appendChild(clone);
  }

  createCard('Hello', 'World');
</script>`,
      },
      {
        title: 'Web Components vs React Components',
        color: '#a855f7',
        desc: 'Different problems, different solutions — they can coexist.',
        code: `/* Web Components: */
/* ✓ Framework-agnostic — works anywhere */
/* ✓ Native browser support — no build step */
/* ✓ True encapsulation via Shadow DOM */
/* ✗ Verbose to write (class syntax, lifecycle methods) */
/* ✗ Less ecosystem/tooling than React */
/* ✗ React event system doesn't work great with Shadow DOM */

/* React Components: */
/* ✓ Rich ecosystem, great DX, easier to write */
/* ✓ React state, hooks, concurrent features */
/* ✗ Only works in React apps */
/* ✗ No real style encapsulation (CSS leaks) */

/* Best use case for Web Components: */
/* Design system tokens and base components */
/* that need to work in React, Vue, AND Angular */
/* across a large organization */`,
      },
    ]} />
    <InlinePoll
      question="What is the main advantage of Web Components over React components?"
      options={[
        'Web Components are faster',
        'Framework-agnostic — a Web Component works in React, Vue, Angular, and plain HTML without any changes',
        'Web Components have better state management',
        'Web Components are easier to write',
      ]}
      correct={1}
      explanation="Web Components are defined using browser APIs — not tied to any framework. A <ui-button> custom element built once can be dropped into a React app, a Vue app, an Angular app, or plain HTML. This is valuable for design systems used across multiple tech stacks."
    />
    <CommonMistake
      mistake="Using Web Components for every component in a React app instead of React components."
      fix="Web Components solve the cross-framework reuse problem. If your whole app is React, use React components — they're much more ergonomic. Use Web Components for design system primitives that must work across different frameworks (different teams using different frameworks in a large org)."
    />
    <DidYouKnow
      fact="YouTube, GitHub, and Twitter/X use Web Components in production. GitHub's entire design system (Primer) is built on Web Components. Google's Material Design 3 (MWC — Material Web Components) is a full Web Component design system. The technology is mature and production-ready, but adoption varies by team preference."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'What Web Components are and their three APIs', freq: 65 },
      { topic: 'Framework-agnostic advantage', freq: 70 },
      { topic: 'Custom Elements lifecycle callbacks', freq: 55 },
      { topic: 'Web Components vs framework components', freq: 65 },
    ]} />
  </div>
);

export const ShadowDOMLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Encapsulation at the Browser Level</div>
      <p style={c.prose}>
        The regular DOM has no style encapsulation — a global CSS rule can accidentally style anything. Shadow DOM creates an <strong style={{ color: '#f97316' }}>isolated DOM subtree</strong> with its own scope. Styles inside don't leak out. Global styles don't leak in.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏠"
      title="A private gated community"
      analogy="A regular neighborhood: anyone can walk in, city rules apply everywhere. A gated community: private rules inside, outsiders can't enter, inside rules don't affect the city. Shadow DOM is a gated community for your component — its CSS and DOM are private by default."
      connection="Shadow root creates a boundary. Styles defined inside the shadow root only apply inside. Global page styles don't penetrate the shadow boundary (unless CSS custom properties)."
    />
    <StorySteps steps={[
      {
        title: 'Shadow DOM vs regular DOM',
        color: '#f97316',
        desc: 'Shadow DOM attaches a separate DOM tree to any element. It\'s isolated from the main document.',
        code: `// Create Shadow DOM
const host = document.getElementById('my-widget');
const shadow = host.attachShadow({ mode: 'open' });
// mode: 'open'   → accessible via element.shadowRoot
// mode: 'closed' → element.shadowRoot returns null

// Shadow DOM has its own document
shadow.innerHTML = \`
  <style>
    p { color: red; } /* only affects shadow DOM! */
    /* Global p { color: blue } doesn't apply here */
  </style>
  <p>This text is red, even if page has p { color: blue }</p>
\`;

// The host element in light DOM:
// <div id="my-widget">
//   ↳ shadow-root (isolated)
//      ↳ <style>...</style>
//      ↳ <p>...</p>
// </div>`,
      },
      {
        title: 'Style encapsulation boundaries',
        color: '#4facfe',
        desc: 'Styles don\'t cross the shadow boundary by default.',
        code: `/* Light DOM (regular page styles): */
p { color: blue; }   /* does NOT affect shadow DOM */
.button { background: red; } /* does NOT affect shadow */

/* Shadow DOM styles: */
shadow.innerHTML = \`
  <style>
    p { color: green; }  /* only inside this shadow root */
    /* Does not affect light DOM paragraphs */
  </style>
  <p>Green text (shadow DOM)</p>
\`;

/* Page's <p> elements stay blue */
/* Shadow <p> elements are green */
/* Zero collision! */

/* Exception: CSS custom properties DO pierce shadow DOM */
/* :root { --primary: #3b82f6 } → available inside shadow */
p { color: var(--primary); } /* works across shadow boundary */`,
      },
      {
        title: '<slot> — content projection',
        color: '#00ff88',
        desc: 'Slots let the shadow DOM consume content from the light DOM (like React children).',
        code: `class MyCard extends HTMLElement {
  connectedCallback() {
    this.attachShadow({ mode: 'open' }).innerHTML = \`
      <style>
        .card { border: 1px solid #ddd; padding: 16px; }
        .card__header { font-weight: bold; font-size: 1.2rem; }
      </style>
      <div class="card">
        <div class="card__header">
          <slot name="header">Default title</slot>
        </div>
        <slot></slot>  <!-- default slot for remaining content -->
      </div>
    \`;
  }
}
customElements.define('my-card', MyCard);

<!-- Usage: -->
<my-card>
  <span slot="header">Custom Title</span>
  <p>Card body content (goes into default slot)</p>
</my-card>`,
      },
      {
        title: 'Shadow DOM in the browser today',
        color: '#a855f7',
        desc: 'You interact with Shadow DOM every day — browser built-ins use it.',
        code: `/* These HTML elements use Shadow DOM internally: */
<input type="date">    /* date picker widget */
<input type="range">   /* slider handle */
<video controls>       /* play/pause/progress controls */
<details>/<summary>    /* disclosure widget */
<select>               /* dropdown on some platforms */

/* See them in DevTools: */
/* Settings → Show user agent shadow DOM */
/* Reveals the internal structure of native elements */

/* This is why you CAN'T easily style these: */
input[type="range"]::-webkit-slider-thumb { ... }
/* ::-webkit-slider-thumb is a shadow pseudo-element */
/* Browsers expose limited styling hooks via pseudo-elements */`,
      },
    ]} />
    <InlinePoll
      question="What is the key difference between open and closed Shadow DOM?"
      options={[
        'Open is public, closed is private from all code',
        'Open: element.shadowRoot returns the shadow root (accessible to JS). Closed: element.shadowRoot returns null — inaccessible from outside',
        'Open has better performance',
        'Closed Shadow DOM is deprecated',
      ]}
      correct={1}
      explanation="attachShadow({ mode: 'open' }): element.shadowRoot returns the shadow root — external JavaScript can access it. mode: 'closed': element.shadowRoot is null — the shadow root is completely inaccessible from outside. Closed mode is rarely used — even browsers' own built-in components use open mode."
    />
    <CommonMistake
      mistake="Trying to style Web Components from external CSS without CSS custom properties."
      fix="Shadow DOM blocks external styles by design. The intended styling API is CSS custom properties — they pierce shadow boundaries. Define --component-bg, --component-color in your component and expose them as the styling API. External code sets these variables to customize the component."
    />
    <DidYouKnow
      fact="Every <video controls> element you've ever seen uses Shadow DOM internally. The play button, progress bar, volume control — all of it is built with Shadow DOM. This is why you can't simply style video controls with CSS selectors; they live in an isolated shadow tree. You need browser-specific pseudo-elements like ::-webkit-media-controls-panel."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'Shadow DOM style encapsulation', freq: 70 },
      { topic: 'Open vs closed Shadow DOM', freq: 60 },
      { topic: 'Slots for content projection', freq: 55 },
      { topic: 'CSS custom properties crossing shadow boundary', freq: 60 },
    ]} />
  </div>
);

export const MetaPerformanceLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Resource Hints — Tell the Browser What's Coming</div>
      <p style={c.prose}>
        Browsers don't know what resources your page will need until they parse the HTML. Resource hints let you <strong style={{ color: '#f97316' }}>tell the browser in advance</strong> — it can start DNS lookups, establish connections, and download resources before they're needed.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🔭"
      title="A weather forecast vs a weather surprise"
      analogy="Without resource hints, the browser is like a chef who doesn't know what dishes will be ordered — waits for the order, then starts prepping. Resource hints are like giving the chef advance notice of the menu — they can prep ingredients before orders arrive. Same resources, dramatically less wait time."
      connection="preload: prep for current page. prefetch: prep for next page. preconnect: establish connection to known origins. dns-prefetch: just resolve the DNS (cheaper)."
    />
    <StorySteps steps={[
      {
        title: 'preload — critical resources for THIS page',
        color: '#f97316',
        desc: 'High-priority fetch for resources the current page needs soon. Starts download immediately.',
        code: `<!-- preload: fetch at HIGH priority, needed soon -->

<!-- LCP image: preload so it starts loading immediately -->
<link rel="preload" href="/hero.jpg" as="image"
      fetchpriority="high">

<!-- Critical font: preload to prevent FOUT -->
<link rel="preload" href="/fonts/Inter.woff2" as="font"
      type="font/woff2" crossorigin>

<!-- Critical CSS file (if not inlined) -->
<link rel="preload" href="/critical.css" as="style">

<!-- JavaScript for above-the-fold interactivity -->
<link rel="preload" href="/main.js" as="script">

<!-- as attribute is required — tells browser resource type -->
<!-- as="image" | "font" | "style" | "script" | "fetch" -->`,
      },
      {
        title: 'prefetch — resources for NEXT page',
        color: '#4facfe',
        desc: 'Low-priority fetch for resources the user might need next. Doesn\'t compete with current page.',
        code: `<!-- prefetch: fetch at LOW priority, for future navigation -->

<!-- User is on search results — prefetch likely next pages -->
<link rel="prefetch" href="/product/1.html">

<!-- Prefetch common next-page JavaScript -->
<link rel="prefetch" href="/checkout.js" as="script">

<!-- Prefetch on hover — start before user clicks -->
<a href="/dashboard"
   onmouseenter="document.head.insertAdjacentHTML(
     'beforeend',
     '<link rel=prefetch href=/dashboard.js>'
   )">
  Dashboard
</a>

<!-- Next.js <Link> prefetches automatically on hover/visibility -->
<!-- React Router has similar prefetch capabilities -->`,
      },
      {
        title: 'preconnect — establish early connections',
        color: '#00ff88',
        desc: 'Do DNS lookup + TCP handshake + TLS for a known origin. Saves 100-300ms when resources are actually requested.',
        code: `<!-- preconnect: do DNS + TCP + TLS early -->
<!-- Use for: CDN, API origins, font providers, analytics -->

<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<!-- crossorigin required for fonts (cross-origin requests) -->

<link rel="preconnect" href="https://cdn.mysite.com">
<link rel="preconnect" href="https://api.mysite.com">

<!-- Without preconnect: -->
<!-- Request → DNS lookup (20-60ms) + TCP (50-150ms) + TLS (50-150ms) = 300ms overhead -->
<!-- With preconnect: connection is already established → 0ms overhead -->

<!-- Don't use on too many origins — each uses resources -->
<!-- Limit to 2-4 most critical third-party origins -->`,
      },
      {
        title: 'dns-prefetch — just the DNS lookup',
        color: '#a855f7',
        desc: 'Only resolves DNS — cheaper than preconnect. Good for less-critical origins.',
        code: `<!-- dns-prefetch: DNS only (20-60ms saving) -->
<!-- Cheaper than preconnect (no TCP/TLS) -->
<!-- Good for: origins you're less sure about using -->

<link rel="dns-prefetch" href="https://analytics.example.com">
<link rel="dns-prefetch" href="https://cdn.widgets.example.com">

<!-- preconnect vs dns-prefetch: -->
<!-- preconnect: DNS + TCP + TLS (~300ms saving) — use for critical origins -->
<!-- dns-prefetch: DNS only (~50ms saving) — use as fallback / less critical -->

<!-- Common pattern: both for critical, prefetch-only for others -->
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="dns-prefetch" href="https://analytics.example.com">

/* fetchpriority attribute for fine-grained control */
<img src="lcp-image.jpg" fetchpriority="high">   /* boost */
<img src="below-fold.jpg" fetchpriority="low">    /* reduce */`,
      },
    ]} />
    <InlinePoll
      question="What is the difference between preload and prefetch?"
      options={[
        'They are identical',
        'preload: high-priority fetch for current page resources needed soon. prefetch: low-priority fetch for resources needed on future pages',
        'prefetch is faster than preload',
        'preload is for scripts, prefetch is for images',
      ]}
      correct={1}
      explanation="preload competes with other high-priority resources for bandwidth — use only for truly critical current-page resources (LCP image, critical font, critical JS). prefetch uses idle bandwidth and doesn't compete — safe to use more liberally for next-page resources."
    />
    <CommonMistake
      mistake="Adding preload for every resource on the page to 'make everything faster'."
      fix="preload competes with other critical resources. Preloading 10 resources means all 10 compete for bandwidth, potentially delaying your actual LCP image. Preload only 2-3 most critical resources: the LCP image, critical fonts, and the above-the-fold JavaScript chunk."
    />
    <DidYouKnow
      fact="Google found that adding rel='preconnect' for Google Fonts (both googleapis.com and gstatic.com) reduces font load time by 100-200ms on average. Google Fonts themselves recommend this in their documentation. It's one of the highest-impact, lowest-effort performance improvements available."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'preload vs prefetch difference', freq: 80 },
      { topic: 'preconnect for third-party origins', freq: 75 },
      { topic: 'fetchpriority for LCP images', freq: 65 },
      { topic: 'dns-prefetch as cheaper alternative', freq: 60 },
    ]} />
  </div>
);

export const ScalableComponentLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Components That Scale With Your Team</div>
      <p style={c.prose}>
        A component that works for one developer breaks when ten developers use it. Scalable component design means writing components that are <strong style={{ color: '#06b6d4' }}>easy to use correctly and hard to use incorrectly</strong> — with predictable APIs, clear boundaries, and zero surprise side effects.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏗️"
      title="LEGO vs custom sculptures"
      analogy="LEGO pieces have a standardized interface — any piece connects to any other piece. You don't need to know how a brick was made to use it. Custom sculptures look unique but can't be recombined. Scalable components are LEGO: consistent interfaces, composable, interchangeable."
      connection="Consistent prop naming, single responsibility, clear composition patterns. A team of 50 can all use Button without reading its source code."
    />
    <StorySteps steps={[
      {
        title: 'Single Responsibility — one job per component',
        color: '#06b6d4',
        desc: 'A component that does too much is impossible to reuse and hard to test.',
        code: `// ❌ Does too much — fetching, formatting, rendering, error handling
function UserDashboard() {
  const [user, setUser] = useState(null);
  const [posts, setPosts] = useState([]);
  // ... 200 lines of mixed concerns
}

// ✅ Each component has one job
function UserDashboard() {
  return (
    <ErrorBoundary>
      <UserProfile />      // owns user display
      <UserPosts />        // owns posts display
      <UserActivity />     // owns activity display
    </ErrorBoundary>
  );
}

// Each child fetches its own data, renders its own states
// Broken UserPosts doesn't break UserProfile`,
      },
      {
        title: 'Prop API design — explicit over implicit',
        color: '#4facfe',
        desc: 'Design props the way you\'d design a public API. Explicit, predictable, typed.',
        code: `// ❌ Implicit / boolean soup
<Button primary large loading leftIcon="send" />
// What happens with primary + secondary both true?

// ✅ Explicit union types — only one valid state
interface ButtonProps {
  variant: 'primary' | 'secondary' | 'ghost' | 'danger';
  size: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
  leftIcon?: React.ReactNode;
  // Not: disabled AND loading AND primary AND secondary
}

// ✅ Composition over configuration
<Button variant="primary" size="lg" isLoading>
  <SendIcon />
  Submit
</Button>`,
      },
      {
        title: 'Inversion of control — let callers decide',
        color: '#00ff88',
        desc: 'Don\'t hard-code logic inside components. Let the parent control behavior.',
        code: `// ❌ Hard-coded behavior — impossible to customize
function Select({ options, onSelect }) {
  const [filtered, setFiltered] = useState(options);
  const search = (q) => {
    setFiltered(options.filter(o => o.label.includes(q))); // fixed!
  };
  return <div>...</div>;
}

// ✅ Inversion of control — caller controls filtering
function Select({ options, filterFn, onSelect }) {
  const [query, setQuery] = useState('');
  const filtered = filterFn
    ? filterFn(options, query)
    : options.filter(o => o.label.includes(query));
  return <div>...</div>;
}

// Caller can: async search, fuzzy match, server-side filter
<Select
  options={options}
  filterFn={(opts, q) => fuse.search(q).map(r => r.item)}
  onSelect={handleSelect}
/>`,
      },
      {
        title: 'Composition patterns — open for extension',
        color: '#a855f7',
        desc: 'Design components to be composed, not configured with infinite props.',
        code: `// ❌ God component — 47 props
<DataTable
  columns={...}
  data={...}
  sortable
  filterable
  paginated
  selectable
  expandable
  headerRenderer={...}
  rowRenderer={...}
  footerRenderer={...}
  // 40 more props...
/>

// ✅ Compound components — composable
<DataTable data={data}>
  <DataTable.Header>
    <DataTable.Column key="name" sortable>Name</DataTable.Column>
    <DataTable.Column key="email">Email</DataTable.Column>
  </DataTable.Header>
  <DataTable.Body rowKey="id" />
  <DataTable.Footer>
    <DataTable.Pagination pageSize={10} />
    <DataTable.Export format="csv" />
  </DataTable.Footer>
</DataTable>
// Each sub-component can be swapped or omitted`,
      },
    ]} />
    <InlinePoll
      question="What is 'inversion of control' in component design?"
      options={[
        'Using useReducer instead of useState',
        'Letting the caller pass in behavior (callbacks, render props, function props) instead of hard-coding logic inside the component',
        'Inverting the component tree',
        'Using context instead of props',
      ]}
      correct={1}
      explanation="Inversion of control means the component doesn't hard-code decisions — it exposes hooks (callbacks, render props, state reducers) for the caller to customize. A Select component shouldn't hard-code its filter logic. Pass filterFn as a prop and the caller controls how filtering works."
    />
    <CommonMistake
      mistake="Adding a new prop every time a consumer needs slightly different behavior."
      fix="After 5-6 customization props, consider inversion of control instead. Instead of onRenderItem, onFilterItem, onSortItem — expose a single renderItem render prop and let consumers do what they need. Fewer props, infinite flexibility."
    />
    <DidYouKnow
      fact="Kent C. Dodds coined the term 'inversion of control' for React components in his 2018 article. He showed that React's own hooks API is built on this principle — instead of React deciding how state works, you control it with useState/useReducer. The pattern scales from small utilities to entire design systems."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Single responsibility in components', freq: 80 },
      { topic: 'Prop API design — explicit union types', freq: 75 },
      { topic: 'Inversion of control pattern', freq: 65 },
      { topic: 'Compound components for extensibility', freq: 65 },
    ]} />
  </div>
);

export const MicrofrontendsLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Microservices for the Frontend</div>
      <p style={c.prose}>
        Micro-frontends apply microservice principles to the UI: <strong style={{ color: '#a855f7' }}>split a large frontend into independently deployable pieces</strong>, each owned by a different team. Different teams can use different frameworks, deploy independently, and scale separately.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏢"
      title="A mall vs a department store"
      analogy="A department store (monolith) is one business — one team manages everything, one deployment, one release cycle. A mall (micro-frontends) has independent stores — each tenant owns their space, deploys their own signage, and operates independently. The mall provides shared infrastructure (parking, utilities, common areas)."
      connection="Each micro-frontend is an independently deployable slice of the UI. Teams own their domain end-to-end: backend, API, and frontend. A deployment in one domain doesn't require redeploying others."
    />
    <StorySteps steps={[
      {
        title: 'Why micro-frontends — the scaling problem',
        color: '#a855f7',
        desc: 'When multiple teams work on one frontend, coordination becomes the bottleneck.',
        code: `// ❌ Monolithic frontend at scale:
// - 50 developers in one codebase
// - One team blocks another's deployment
// - Merge conflicts every day
// - Full regression test for every change
// - 4-hour build times
// - Can't experiment with new tech in one area

// ✅ Micro-frontends:
// App Shell loads:
//   → /checkout  → Team A's React app
//   → /catalog   → Team B's Vue app
//   → /account   → Team C's Angular app
//   → /support   → Team D's React app

// Each team:
// - Deploys independently
// - Chooses their own tech stack
// - Owns their domain end to end
// - Has their own CI/CD pipeline`,
      },
      {
        title: 'Module Federation — Webpack 5 approach',
        color: '#4facfe',
        desc: 'Share live code between separately deployed applications at runtime.',
        code: `// webpack.config.js — Host app (shell)
new ModuleFederationPlugin({
  name: 'shell',
  remotes: {
    // Load checkout micro-frontend at runtime
    checkout: 'checkout@https://checkout.myapp.com/remoteEntry.js',
    catalog:  'catalog@https://catalog.myapp.com/remoteEntry.js',
  },
  shared: {
    react: { singleton: true, requiredVersion: '^18.0.0' },
    'react-dom': { singleton: true },
    // Shared deps — only one copy of React loaded!
  },
});

// webpack.config.js — Checkout micro-frontend
new ModuleFederationPlugin({
  name: 'checkout',
  filename: 'remoteEntry.js', // ← manifest file
  exposes: {
    './CheckoutApp': './src/CheckoutApp', // what we expose
  },
});

// Host app uses checkout like any import:
const CheckoutApp = React.lazy(() => import('checkout/CheckoutApp'));`,
      },
      {
        title: 'Communication between micro-frontends',
        color: '#00ff88',
        desc: 'Apps must communicate without tight coupling. Events and shared state are the options.',
        code: `// ❌ Direct coupling — breaks independence
import { useCartStore } from 'checkout/store'; // tight coupling!

// ✅ Custom events — loose coupling
// Catalog app dispatches:
window.dispatchEvent(new CustomEvent('cart:add', {
  detail: { productId: '123', quantity: 1 },
  bubbles: true,
}));

// Checkout app listens:
window.addEventListener('cart:add', (e) => {
  addToCart(e.detail.productId, e.detail.quantity);
});

// ✅ Shared event bus (pub/sub)
const eventBus = window.__APP_EVENT_BUS__ ||= new EventTarget();
eventBus.dispatchEvent(new CustomEvent('user:login', { detail: { userId } }));
eventBus.addEventListener('user:login', handleUserLogin);

// ✅ URL/routing as shared state
// Each app reads URL params instead of shared state`,
      },
      {
        title: 'Trade-offs — when NOT to use micro-frontends',
        color: '#eab308',
        desc: 'Micro-frontends add real complexity. Only justified at a certain scale.',
        code: `// ✅ Use micro-frontends when:
// - Multiple teams (5+) working on same frontend
// - Teams need independent deployment cadences
// - Different parts of app have different tech needs
// - Org structure maps to product domains

// ❌ Don't use micro-frontends when:
// - Small team (< 3-4 teams)
// - You just want code organization (use modules/packages)
// - Performance is critical (bundle duplication)
// - Teams are tightly coupled anyway

// Real costs:
// - Operational complexity (N build pipelines)
// - Bundle duplication (each app ships React?)
// - Consistent UX is harder across apps
// - Local dev environment complexity
// - Testing across app boundaries is hard

// Alternative: monorepo with independent packages
// (Next.js, Turborepo) — 80% of the benefit, 20% of the cost`,
      },
    ]} />
    <InlinePoll
      question="What problem does Webpack Module Federation's 'singleton: true' for React solve?"
      options={[
        'Makes React load faster',
        'Ensures only one copy of React is loaded — without it, each micro-frontend would bundle its own React causing version conflicts and wasted bytes',
        'Enables React Server Components',
        'Prevents React from being tree-shaken',
      ]}
      correct={1}
      explanation="Without singleton shared deps, each micro-frontend bundles its own copy of React — multiple React instances on one page cause 'hooks can only be called inside function component' errors and ~140KB duplication per micro-frontend. singleton: true makes all MFEs share one React instance."
    />
    <CommonMistake
      mistake="Using micro-frontends as a code organization strategy for a single team."
      fix="Micro-frontends are a people-scaling strategy, not a code organization strategy. The complexity (independent deployments, cross-app communication, shared dependency management) is only justified when you have multiple teams that need deployment independence. For one team, monorepo with shared packages achieves the same organization benefits without the operational overhead."
    />
    <DidYouKnow
      fact="IKEA, Spotify, Zalando, and DAZN are famous micro-frontend adopters. Zalando was one of the pioneers — they called their approach 'Project Mosaic' in 2016. Spotify famously uses 'independent squads' where each squad owns their UI slice. The architecture follows Conway's Law: system architecture mirrors organizational communication structure."
      color="#a855f7"
    />
    <InterviewMeter topics={[
      { topic: 'What micro-frontends are and why', freq: 70 },
      { topic: 'Module Federation basics', freq: 65 },
      { topic: 'Cross-app communication patterns', freq: 65 },
      { topic: 'When NOT to use micro-frontends', freq: 70 },
    ]} />
  </div>
);

export const DesignSystemLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 One Source of Truth for Your UI</div>
      <p style={c.prose}>
        A design system is more than a component library — it's the <strong style={{ color: '#eab308' }}>shared language between design and engineering</strong>. Design tokens, component APIs, documentation, and usage guidelines that ensure consistent UI across every product and team.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📐"
      title="An architect's standard specifications"
      analogy="When building a skyscraper, every architect uses the same standard specifications for door widths, outlet heights, and staircase dimensions. Nobody debates these on each floor. A design system is the standard specs for your UI — every team builds to the same spec without debating button sizes on every project."
      connection="Design tokens define the constants (colors, spacing, typography). Components implement the tokens. Documentation ensures consistent usage. The system removes repeated decisions."
    />
    <StorySteps steps={[
      {
        title: 'Design tokens — the foundation',
        color: '#eab308',
        desc: 'Named values for every visual decision. The single source of truth for design.',
        code: `// tokens.ts — single source of truth
export const tokens = {
  // Primitive tokens — raw values
  colors: {
    blue400: '#60a5fa',
    blue500: '#3b82f6',
    blue600: '#2563eb',
    gray100: '#f3f4f6',
    gray900: '#111827',
  },
  spacing: {
    1: '4px',  2: '8px',  3: '12px',
    4: '16px', 6: '24px', 8: '32px',
  },
  // Semantic tokens — reference primitives
  semantic: {
    colorPrimary:    'var(--color-blue500)',
    colorBackground: 'var(--color-gray100)',
    colorText:       'var(--color-gray900)',
    spacingComponent: 'var(--spacing-4)',
  },
};
// CSS custom properties generated from tokens
// Figma variables map 1:1 to token names
// Design and code always in sync`,
      },
      {
        title: 'Component API consistency',
        color: '#4facfe',
        desc: 'Consistent prop patterns across every component. Zero surprises for consumers.',
        code: `// ✅ Consistent patterns across ALL components:

// Variants always called 'variant'
<Button variant="primary" />
<Badge variant="success" />
<Alert variant="warning" />

// Sizes always called 'size'
<Button size="sm" />
<Avatar size="lg" />
<Input size="md" />

// Loading state always 'isLoading'
<Button isLoading />
<Select isLoading />
<Table isLoading />

// Disabled always 'disabled' (HTML standard)
<Button disabled />
<Input disabled />

// ❌ Inconsistent — developer has to check docs every time
<Button loading />      // or isLoading or showLoader?
<Select isFetching />   // different name!
<Table dataLoading />   // yet another name!`,
      },
      {
        title: 'Documentation and Storybook',
        color: '#00ff88',
        desc: 'Components without documentation don\'t get used correctly. Storybook is the standard.',
        code: `// Button.stories.tsx
import type { Meta, StoryObj } from '@storybook/react';
import { Button } from './Button';

const meta: Meta<typeof Button> = {
  title: 'Components/Button',
  component: Button,
  argTypes: {
    variant: {
      control: 'select',
      options: ['primary', 'secondary', 'ghost', 'danger'],
      description: 'Visual style of the button',
    },
    size: { control: 'radio', options: ['sm', 'md', 'lg'] },
    isLoading: { control: 'boolean' },
  },
};
export default meta;

export const Primary: StoryObj = {
  args: { variant: 'primary', children: 'Click me' },
};
export const AllVariants: StoryObj = {
  render: () => (
    <div style={{ display: 'flex', gap: 8 }}>
      {['primary','secondary','ghost','danger'].map(v => (
        <Button key={v} variant={v}>{v}</Button>
      ))}
    </div>
  ),
};`,
      },
      {
        title: 'Versioning and distribution',
        color: '#a855f7',
        desc: 'A design system is a product. It needs versioning, changelogs, and a distribution strategy.',
        code: `// package.json of your design system
{
  "name": "@company/ui",
  "version": "2.4.1",  // semantic versioning!
  "main": "dist/index.js",
  "exports": {
    ".": "./dist/index.js",
    "./tokens": "./dist/tokens.js",
    "./styles": "./dist/styles.css"
  }
}

// Consumers install a specific version:
// npm install @company/ui@2.4.1

// Semantic versioning:
// PATCH 2.4.0 → 2.4.1: bug fix, safe to update
// MINOR 2.4.0 → 2.5.0: new components, backward compat
// MAJOR 2.4.0 → 3.0.0: breaking changes, migration needed

// Changelogger + conventional commits:
// feat(Button): add 'ghost' variant  → MINOR
// fix(Input): fix focus ring color    → PATCH
// BREAKING: rename isLoading to loading → MAJOR

// Tooling: Changesets (Atlassian), auto, semantic-release`,
      },
    ]} />
    <InlinePoll
      question="What is the difference between primitive tokens and semantic tokens?"
      options={[
        'They are identical',
        'Primitive tokens are raw values (blue-500: #3b82f6). Semantic tokens describe purpose (color-primary: blue-500) — components use semantic tokens so themes can change without touching components',
        'Semantic tokens are only for colors',
        'Primitive tokens are deprecated in modern design systems',
      ]}
      correct={1}
      explanation="Primitive tokens: raw values (blue-500, spacing-4). Semantic tokens: named by purpose (color-primary references blue-500, color-danger references red-500). Components use semantic tokens. To rebrand or create a dark mode: change semantic token mappings only. Components update automatically without any changes."
    />
    <CommonMistake
      mistake="Building a component library without design tokens — hard-coding #3b82f6 in every component."
      fix="Hard-coded values create a maintenance nightmare — rebrand means finding and replacing values in hundreds of files. Use semantic tokens everywhere: color: var(--color-primary). Change the token value once and every component that uses it updates automatically. This also enables themes and dark mode trivially."
    />
    <DidYouKnow
      fact="Airbnb's design system (DLS) is estimated to have saved over 300 engineer-weeks of work in its first two years by eliminating repeated UI decisions. Atlassian's Atlaskit, Shopify's Polaris, and IBM's Carbon Design System are all public examples. The ROI of a mature design system compounds — every new product built on it starts further ahead."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Design tokens — primitive vs semantic', freq: 75 },
      { topic: 'Consistent prop API patterns', freq: 70 },
      { topic: 'Storybook for documentation', freq: 70 },
      { topic: 'Versioning and distribution strategy', freq: 65 },
    ]} />
  </div>
);

export const SingletonLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 One Instance to Rule Them All</div>
      <p style={c.prose}>
        Singleton ensures a class has <strong style={{ color: '#06b6d4' }}>exactly one instance</strong> throughout the application. Any code that asks for it gets the same object. In JavaScript, ES modules are naturally singletons — you get this for free.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🌍"
      title="The Earth — only one exists"
      analogy="There's only one Earth. Every person who refers to 'the Earth' is referring to the same planet. You can't create a second Earth. Singleton works the same way — no matter how many times you call getInstance(), you always get the same object back."
      connection="const store = createStore(reducer) — Redux creates one store. Every useSelector, useDispatch, and connect() call in your entire app references that single store instance."
    />
    <StorySteps steps={[
      {
        title: 'Class-based Singleton',
        color: '#06b6d4',
        desc: 'Store the instance on the class. Return it on every subsequent call.',
        code: `class ConfigManager {
  static #instance = null;
  #config = {};

  static getInstance() {
    if (!ConfigManager.#instance) {
      ConfigManager.#instance = new ConfigManager();
    }
    return ConfigManager.#instance;
  }

  set(key, value) { this.#config[key] = value; }
  get(key) { return this.#config[key]; }
}

const config1 = ConfigManager.getInstance();
const config2 = ConfigManager.getInstance();
console.log(config1 === config2); // true — same object!

config1.set('theme', 'dark');
console.log(config2.get('theme')); // 'dark' — same instance`,
      },
      {
        title: 'Module-level Singleton — idiomatic JavaScript',
        color: '#00ff88',
        desc: 'ES modules are evaluated once and cached. Module-level exports ARE singletons.',
        code: `// logger.js — this IS a singleton automatically
const logs = [];

export const logger = {
  log(msg) {
    const entry = { msg, time: Date.now() };
    logs.push(entry);
    console.log(\`[\${new Date().toISOString()}] \${msg}\`);
  },
  getLogs: () => [...logs],
  clear:   () => { logs.length = 0; },
};

// Any file that imports this gets the SAME logger:
import { logger } from './logger';
logger.log('App started'); // same instance everywhere`,
      },
      {
        title: 'When Singleton creates problems',
        color: '#ef4444',
        desc: 'Global state makes tests order-dependent and code hard to reason about.',
        code: `// ❌ Singleton makes tests fragile
test('test A', () => {
  ConfigManager.getInstance().set('feature', true);
  // ... test passes
});

test('test B', () => {
  // singleton still has feature=true from test A!
  // Tests pass/fail depending on execution order
});

// ✅ Dependency injection — testable alternative
class App {
  constructor(config) { // inject the dependency
    this.config = config;
  }
}

// In production: new App(realConfig)
// In tests: new App(mockConfig) — no shared state!`,
      },
      {
        title: 'Real Singletons in JavaScript',
        color: '#a855f7',
        desc: 'You use Singletons every day without knowing it.',
        code: `// window object — one per browsing context
window.myGlobal = 'shared';

// Redux store — explicitly a singleton
const store = configureStore({ reducer });
// Entire app uses this one store

// React Query client — singleton
const queryClient = new QueryClient();
// Shared cache across all useQuery calls

// Module-level cache
const cache = new Map(); // created once per module
export function memoize(fn) {
  return (key) => {
    if (!cache.has(key)) cache.set(key, fn(key));
    return cache.get(key);
  };
}`,
      },
    ]} />
    <InlinePoll
      question="Why are ES modules considered singletons?"
      options={[
        'They use the singleton keyword',
        'Modules are evaluated once and cached — every import of the same module gets the same cached instance, not a fresh evaluation',
        'Modules can only export one value',
        'Modules run in strict mode',
      ]}
      correct={1}
      explanation="When you import a module, JavaScript evaluates it once and caches the result. Every subsequent import of that module (anywhere in the app) gets the cached module object. Module-level variables (like a logger object) are created once and shared — that's Singleton behavior for free."
    />
    <CommonMistake
      mistake="Using Singleton for dependencies that should be injectable — making unit tests impossible."
      fix="If a class creates its own singleton dependency internally, tests can't replace it with a mock. Pass dependencies as constructor arguments (dependency injection) instead. In tests, pass a mock. In production, pass the real singleton. Best of both worlds."
    />
    <DidYouKnow
      fact="The Singleton pattern is often listed as an anti-pattern in modern software design because it creates hidden global state and makes testing difficult. The Gang of Four (who defined the original 23 design patterns in 1994) themselves cautioned against overuse. Dependency injection containers manage object lifetime and are preferred in large codebases."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'What Singleton is and a JS implementation', freq: 75 },
      { topic: 'Why modules are naturally singletons', freq: 70 },
      { topic: 'Problems with Singleton — testing', freq: 75 },
      { topic: 'Dependency injection as the alternative', freq: 65 },
    ]} />
  </div>
);

export const ObserverPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 React to Changes Without Tight Coupling</div>
      <p style={c.prose}>
        The Observer pattern lets multiple parts of your app <strong style={{ color: '#06b6d4' }}>react to the same event</strong> without the event source knowing who's listening. It's the backbone of every event system — DOM events, Node.js EventEmitter, RxJS, React state.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📰"
      title="A newspaper subscription"
      analogy="The newspaper (Subject) doesn't know who its subscribers are individually. It just prints and delivers to everyone who subscribed. You can subscribe or unsubscribe anytime. The newspaper doesn't change based on who's reading it."
      connection="Subject.notify() loops through all registered observers and calls their update(). Observers register via subscribe() and deregister via unsubscribe(). Subject doesn't import or reference observer classes directly."
    />
    <StorySteps steps={[
      {
        title: 'Building an Observable from scratch',
        color: '#06b6d4',
        desc: 'Subject maintains a subscriber list, notifies all on change.',
        code: `class Observable {
  #observers = new Set();

  subscribe(observer) {
    this.#observers.add(observer);
    return () => this.#observers.delete(observer); // unsubscribe fn
  }

  notify(data) {
    this.#observers.forEach(observer => observer(data));
  }
}

// Usage
const cartStore = new Observable();

// Multiple observers subscribe
const unsubCart  = cartStore.subscribe(count => updateCartIcon(count));
const unsubBadge = cartStore.subscribe(count => updateBadge(count));
const unsubTitle = cartStore.subscribe(count => updateTabTitle(count));

cartStore.notify(3); // all three observers called

// Cleanup
unsubCart();   // cart icon no longer updates`,
      },
      {
        title: 'DOM Events — Observer in the browser',
        color: '#4facfe',
        desc: 'addEventListener is the Observer pattern built into every HTML element.',
        code: `const button = document.getElementById('submit');

// Subject: button element
// Observers: your event handler functions
const handler1 = () => validateForm();
const handler2 = () => trackAnalytics('submit_clicked');
const handler3 = () => showLoadingSpinner();

button.addEventListener('click', handler1); // subscribe
button.addEventListener('click', handler2); // subscribe
button.addEventListener('click', handler3); // subscribe

// Button doesn't know about any of these handlers
// All three fire when button is clicked

// Cleanup (unsubscribe):
button.removeEventListener('click', handler1);`,
      },
      {
        title: 'Observer in React — useEffect subscriptions',
        color: '#00ff88',
        desc: 'Always unsubscribe in useEffect cleanup — the most common memory leak.',
        code: `function LivePriceDisplay({ symbol }) {
  const [price, setPrice] = useState(null);

  useEffect(() => {
    // Subscribe to price updates
    const unsubscribe = priceService.subscribe(symbol, (newPrice) => {
      setPrice(newPrice);
    });

    // Cleanup — unsubscribe on unmount or symbol change
    return () => unsubscribe();
    // Without cleanup: component unmounts but priceService
    // still holds a reference -> memory leak!
  }, [symbol]);

  return <div>{symbol}: {price ?? 'Loading...'}</div>;
}`,
      },
      {
        title: 'Custom EventEmitter — full implementation',
        color: '#eab308',
        desc: 'A production-ready EventEmitter with all edge cases handled.',
        code: `class EventEmitter {
  #events = new Map();

  on(event, listener) {
    if (!this.#events.has(event)) this.#events.set(event, new Set());
    this.#events.get(event).add(listener);
    return this; // chainable
  }

  off(event, listener) {
    this.#events.get(event)?.delete(listener);
    return this;
  }

  once(event, listener) {
    const wrapper = (data) => {
      listener(data);
      this.off(event, wrapper); // auto-unsubscribe after one call
    };
    return this.on(event, wrapper);
  }

  emit(event, data) {
    this.#events.get(event)?.forEach(listener => listener(data));
    return this;
  }
}

const emitter = new EventEmitter();
emitter.on('data', console.log).emit('data', 42); // chainable`,
      },
    ]} />
    <InlinePoll
      question="What is the most common bug when using the Observer pattern in React?"
      options={[
        'Subscribing too many observers',
        'Forgetting to unsubscribe in useEffect cleanup — the subject holds a reference preventing garbage collection, and setState gets called on unmounted components',
        'Notifying too frequently',
        'Using wrong event names',
      ]}
      correct={1}
      explanation="Without cleanup, the subject holds your observer callback forever. Even after the component unmounts, the callback is still registered and gets called on updates — setting state on an unmounted component and preventing garbage collection. Always return an unsubscribe function from useEffect."
    />
    <CommonMistake
      mistake="Calling observer functions synchronously in a loop without error handling."
      fix="If one observer throws, it breaks notification for all subsequent observers. Wrap each notification in try/catch, or use async notification to isolate observer failures. Production EventEmitters should be resilient to individual observer errors."
    />
    <DidYouKnow
      fact="The Observer pattern is one of the most used patterns in JavaScript — virtually every async API uses it. Node.js EventEmitter is its canonical implementation. RxJS Observable is a more powerful variant that adds lazy evaluation, backpressure, and operator composition. React's state system is essentially an Observable that triggers re-renders."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Observer pattern implementation', freq: 80 },
      { topic: 'Memory leak from not unsubscribing', freq: 85 },
      { topic: 'DOM addEventListener as Observer', freq: 75 },
      { topic: 'Observer vs Pub/Sub difference', freq: 65 },
    ]} />
  </div>
);

export const FactoryPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Creating Objects Without Knowing Their Type</div>
      <p style={c.prose}>
        Factory decouples <strong style={{ color: '#06b6d4' }}>what you create from how you create it</strong>. Callers say "give me a Button" — not "give me a new PrimaryButton()". The factory decides which class to instantiate. Adding new types doesn't change calling code.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏭"
      title="A car manufacturing plant"
      analogy="You order a 'sedan' or 'SUV' from a car company. You don't go to the factory floor and assemble it yourself. The factory knows how to build each type — you just specify what you want. The factory handles all the complexity of construction."
      connection="createElement('div') — you pass a type string, the factory returns the right DOM element without you knowing or caring which class to instantiate."
    />
    <StorySteps steps={[
      {
        title: 'Simple Factory function',
        color: '#06b6d4',
        desc: 'A function that creates and returns objects based on input.',
        code: `// Simple Factory — function returns different types
function createUser(type, data) {
  const base = {
    id: crypto.randomUUID(),
    createdAt: new Date(),
    ...data,
  };

  switch (type) {
    case 'admin':
      return { ...base, role: 'admin', permissions: ['read','write','delete'] };
    case 'editor':
      return { ...base, role: 'editor', permissions: ['read','write'] };
    case 'viewer':
      return { ...base, role: 'viewer', permissions: ['read'] };
    default:
      throw new Error(\`Unknown user type: \${type}\`);
  }
}

const admin  = createUser('admin',  { name: 'Alice' });
const viewer = createUser('viewer', { name: 'Bob' });`,
      },
      {
        title: 'Factory Method pattern',
        color: '#4facfe',
        desc: 'Define the creation interface in a base class. Subclasses decide what to create.',
        code: `// Base class defines the factory method
class Dialog {
  // Factory method — subclasses override this
  createButton() {
    throw new Error('createButton must be implemented');
  }

  render() {
    const button = this.createButton(); // uses factory method
    button.render();
  }
}

// Concrete creators — override the factory method
class WindowsDialog extends Dialog {
  createButton() { return new WindowsButton(); }
}

class WebDialog extends Dialog {
  createButton() { return new HTMLButton(); }
}

// Client code — works with any Dialog type
function renderDialog(dialog) {
  dialog.render(); // button created internally
}

renderDialog(new WindowsDialog()); // Windows button
renderDialog(new WebDialog());     // HTML button`,
      },
      {
        title: 'React component factory',
        color: '#00ff88',
        desc: 'Factory pattern appears naturally in React for dynamic component creation.',
        code: `// Component factory — creates components based on type
const componentRegistry = {
  text:     TextWidget,
  chart:    ChartWidget,
  table:    TableWidget,
  calendar: CalendarWidget,
};

function DashboardWidget({ type, config }) {
  const Component = componentRegistry[type];
  if (!Component) {
    console.warn(\`Unknown widget type: \${type}\`);
    return <ErrorWidget />;
  }
  return <Component config={config} />;
}

// Add new widget type without changing DashboardWidget:
componentRegistry['map'] = MapWidget;

// Caller doesn't know which component is created:
<DashboardWidget type="chart" config={chartConfig} />`,
      },
      {
        title: 'Abstract Factory — families of objects',
        color: '#a855f7',
        desc: 'Create families of related objects that work together.',
        code: `// Abstract Factory — theme-based UI factory
const lightTheme = {
  createButton: (props) => <LightButton {...props} />,
  createInput:  (props) => <LightInput {...props} />,
  createModal:  (props) => <LightModal {...props} />,
};

const darkTheme = {
  createButton: (props) => <DarkButton {...props} />,
  createInput:  (props) => <DarkInput {...props} />,
  createModal:  (props) => <DarkModal {...props} />,
};

// Context provides the current factory
const ThemeContext = createContext(lightTheme);

function ThemedLoginForm() {
  const theme = useContext(ThemeContext);
  return (
    <form>
      {theme.createInput({ placeholder: 'Email' })}
      {theme.createInput({ type: 'password' })}
      {theme.createButton({ children: 'Sign In' })}
    </form>
  );
  // Same form, different theme — swap factory to change everything
}`,
      },
    ]} />
    <InlinePoll
      question="What is the key benefit of the Factory pattern over calling 'new ClassName()' directly?"
      options={[
        'Factory is faster',
        'Callers are decoupled from concrete classes — adding new types or changing creation logic doesn\'t require changing calling code',
        'Factory uses less memory',
        'Factory supports async creation',
      ]}
      correct={1}
      explanation="Direct new ClassName() creates tight coupling — callers must know the exact class. With Factory, callers request a type ('admin user', 'chart widget') and the factory decides which class to instantiate. Adding new types or changing the class hierarchy only affects the factory, not all callers."
    />
    <CommonMistake
      mistake="Using a Factory when a simple object literal or direct instantiation is clearer."
      fix="Factory adds indirection — only justified when you need: multiple variants of an object, to defer the decision of which class to create, or to abstract away complex instantiation logic. Don't use Factory just because it sounds architectural."
    />
    <DidYouKnow
      fact="React.createElement() is a factory function — it's what JSX compiles to. <Button variant='primary'> compiles to React.createElement(Button, { variant: 'primary' }). The factory creates a React element (a plain object description), not an actual component instance. Component instantiation happens separately during reconciliation."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Factory pattern and decoupling benefit', freq: 75 },
      { topic: 'Simple factory vs factory method', freq: 65 },
      { topic: 'Component registry as factory in React', freq: 65 },
      { topic: 'document.createElement as real-world factory', freq: 70 },
    ]} />
  </div>
);

export const StrategyPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Swap Algorithms at Runtime</div>
      <p style={c.prose}>
        Strategy replaces if/else chains with <strong style={{ color: '#06b6d4' }}>interchangeable algorithm objects</strong>. The context delegates to whatever strategy is currently set. In JavaScript, functions are first-class — strategies are often just callback functions.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🗺️"
      title="A GPS with different routing modes"
      analogy="A GPS has one destination but multiple routing strategies: fastest route, avoid highways, avoid tolls, cycling mode. You switch the strategy without rebuilding the GPS. Each strategy takes the same input (start, end) and produces the same output type (route) but via different algorithms."
      connection="The GPS is the Context. Routing algorithms are Strategies. context.setStrategy(avoidHighways) swaps the algorithm. The context calls strategy.execute(start, end) without knowing how it works internally."
    />
    <StorySteps steps={[
      {
        title: 'Strategy with classes',
        color: '#06b6d4',
        desc: 'Each strategy is a class with an execute() method. Context delegates to the current strategy.',
        code: `// Strategies — same interface, different algorithms
class BubbleSort {
  sort(data) { return [...data].sort((a, b) => a - b); }
}
class QuickSort {
  sort(data) {
    if (data.length <= 1) return data;
    const pivot = data[0];
    const left  = data.slice(1).filter(x => x <= pivot);
    const right = data.slice(1).filter(x => x > pivot);
    return [...this.sort(left), pivot, ...this.sort(right)];
  }
}

// Context — delegates to current strategy
class Sorter {
  constructor(strategy) { this.strategy = strategy; }
  sort(data) { return this.strategy.sort(data); }
  setStrategy(strategy) { this.strategy = strategy; }
}

const sorter = new Sorter(new QuickSort());
sorter.sort([3, 1, 4, 1, 5, 9]);
sorter.setStrategy(new BubbleSort()); // swap at runtime!`,
      },
      {
        title: 'Functional Strategy — idiomatic JavaScript',
        color: '#4facfe',
        desc: 'Functions are first-class in JavaScript. Strategies are often just callbacks.',
        code: `// Strategies as plain functions
const strategies = {
  creditCard: (amount) => chargeCreditCard(amount),
  paypal:     (amount) => chargePaypal(amount),
  crypto:     (amount) => chargeCrypto(amount),
};

// Context accepts strategy as parameter
function processPayment(amount, strategyName) {
  const strategy = strategies[strategyName];
  if (!strategy) throw new Error('Unknown payment method');
  return strategy(amount);
}

processPayment(100, 'creditCard');
processPayment(50,  'paypal');

// Add new strategy without changing processPayment:
strategies.applePay = (amount) => chargeApplePay(amount);`,
      },
      {
        title: 'Strategy in React — render and behavior props',
        color: '#00ff88',
        desc: 'Passing functions as props IS the Strategy pattern in React.',
        code: `// List component with pluggable strategies
function List({ items, renderItem, filterFn, sortFn }) {
  const processed = items
    .filter(filterFn || (() => true))
    .sort(sortFn || (() => 0));

  return <ul>{processed.map(renderItem)}</ul>;
}

// Different strategies for same component:
<List
  items={users}
  renderItem={user => <UserCard key={user.id} user={user} />}
  filterFn={user => user.active}
  sortFn={(a, b) => a.name.localeCompare(b.name)}
/>

// Swap rendering strategy — different look, same data:
<List
  items={users}
  renderItem={user => <UserRow key={user.id} user={user} />}
  filterFn={user => user.role === 'admin'}
/>`,
      },
      {
        title: 'Validation strategy — real-world example',
        color: '#eab308',
        desc: 'Different validation rules as swappable strategies.',
        code: `// Validation strategies
const validators = {
  required:  (val) => val?.length > 0 || 'This field is required',
  email:     (val) => /\S+@\S+\.\S+/.test(val) || 'Invalid email',
  minLength: (min) => (val) => val.length >= min || \`Min \${min} chars\`,
  maxLength: (max) => (val) => val.length <= max || \`Max \${max} chars\`,
};

// Form field with pluggable validation strategy
function FormField({ name, rules }) {
  const [value, setValue] = useState('');
  const [errors, setErrors] = useState([]);

  const validate = (v) => {
    const errs = rules
      .map(rule => rule(v))
      .filter(result => result !== true);
    setErrors(errs);
  };

  return (
    <>
      <input value={value}
             onChange={e => { setValue(e.target.value); validate(e.target.value); }} />
      {errors.map((err, i) => <span key={i}>{err}</span>)}
    </>
  );
}

<FormField
  name="email"
  rules={[validators.required, validators.email]}
/>`,
      },
    ]} />
    <InlinePoll
      question="A component has 5 different if/else branches for rendering different types of cards. How would Strategy pattern improve this?"
      options={[
        'Move all branches to a parent component',
        'Extract each branch into its own render function (strategy). Accept a renderCard prop. The component calls renderCard(item) — no internal if/else',
        'Use switch instead of if/else',
        'Create 5 separate components',
      ]}
      correct={1}
      explanation="Replace the if/else with a renderCard strategy prop. Each 'branch' becomes a separate render function passed by the caller. Adding a new card type = adding a new render function, zero changes to the component. This is exactly how React data grids work — renderCell/renderHeader are strategy props."
    />
    <CommonMistake
      mistake="Over-engineering Strategy for simple one-off conditionals."
      fix="Strategy earns its complexity when you have 3+ interchangeable algorithms that grow over time. For a simple if/else between two options, Strategy is overkill. Apply it when you find yourself adding the 3rd or 4th algorithm variation."
    />
    <DidYouKnow
      fact="The Strategy pattern is the foundation of most payment processing systems. Stripe, PayPal, Apple Pay, and Google Pay are all payment strategies implementing the same interface. Checkout systems like Shopify use Strategy to add new payment methods without changing the checkout flow code."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Strategy pattern definition and example', freq: 80 },
      { topic: 'Functions as strategies in JavaScript', freq: 75 },
      { topic: 'React props as Strategy pattern', freq: 70 },
      { topic: 'When to apply Strategy vs if/else', freq: 65 },
    ]} />
  </div>
);

export const DecoratorPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Add Behavior Without Changing the Original</div>
      <p style={c.prose}>
        Decorator wraps an object to add new behavior <strong style={{ color: '#06b6d4' }}>without modifying the original class</strong>. Stack multiple decorators to add multiple behaviors. HOCs in React, middleware in Express, and Python's @decorator are all Decorator pattern.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🎂"
      title="A plain cake getting layers of decoration"
      analogy="Start with a plain cake (base component). Add frosting (logging decorator). Add sprinkles (caching decorator). Add a topper (auth decorator). Each decoration layer wraps the previous one. The cake itself never changed — each decorator adds something on top."
      connection="withAuth(withLogging(withCache(Component))) — each HOC is a decorator layer. The inner Component is unchanged. Each decorator adds behavior around it."
    />
    <StorySteps steps={[
      {
        title: 'Classic object Decorator',
        color: '#06b6d4',
        desc: 'Wrapper object implements the same interface as the wrapped object.',
        code: `// Base interface: { request() }
class WebService {
  request(url) {
    return fetch(url).then(r => r.json());
  }
}

// Logging decorator — adds logging around request
class LoggingDecorator {
  constructor(service) { this.service = service; }
  async request(url) {
    console.log(\`Requesting: \${url}\`);
    const start = Date.now();
    const result = await this.service.request(url);
    console.log(\`Done in \${Date.now() - start}ms\`);
    return result;
  }
}

// Caching decorator — adds caching around request
class CachingDecorator {
  #cache = new Map();
  constructor(service) { this.service = service; }
  async request(url) {
    if (this.#cache.has(url)) return this.#cache.get(url);
    const result = await this.service.request(url);
    this.#cache.set(url, result);
    return result;
  }
}

// Stack decorators:
const service = new CachingDecorator(
  new LoggingDecorator(
    new WebService()
  )
);`,
      },
      {
        title: 'HOC — Decorator in React',
        color: '#4facfe',
        desc: 'Higher-Order Components are the Decorator pattern for React components.',
        code: `// withAuth HOC — decorator that adds auth checking
function withAuth(WrappedComponent) {
  return function AuthenticatedComponent(props) {
    const { user } = useAuth();
    if (!user) return <Navigate to="/login" />;
    return <WrappedComponent {...props} user={user} />;
  };
}

// withLoading HOC — decorator that adds loading state
function withLoading(WrappedComponent) {
  return function LoadingComponent({ isLoading, ...props }) {
    if (isLoading) return <Spinner />;
    return <WrappedComponent {...props} />;
  };
}

// Stack decorators:
const ProtectedUserList = withAuth(withLoading(UserList));
// UserList is unchanged. Each HOC decorates around it.`,
      },
      {
        title: 'Function decorator — wrap any function',
        color: '#00ff88',
        desc: 'Wrap functions to add cross-cutting concerns like logging, timing, error handling.',
        code: `// Function decorators
function withTiming(fn) {
  return async function(...args) {
    const start = performance.now();
    const result = await fn(...args);
    console.log(\`\${fn.name} took \${performance.now() - start}ms\`);
    return result;
  };
}

function withRetry(fn, maxRetries = 3) {
  return async function(...args) {
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await fn(...args);
      } catch (err) {
        if (attempt === maxRetries) throw err;
        await new Promise(r => setTimeout(r, attempt * 1000));
      }
    }
  };
}

// Compose decorators on any function:
const robustFetch = withTiming(withRetry(fetchUser, 3));
await robustFetch(userId);`,
      },
      {
        title: 'TypeScript @decorators',
        color: '#a855f7',
        desc: 'TypeScript/JavaScript decorator syntax adds metadata and behavior to classes.',
        code: `// TypeScript decorator syntax (Stage 3 proposal)
function log(target, key, descriptor) {
  const original = descriptor.value;
  descriptor.value = function(...args) {
    console.log(\`Calling \${key} with\`, args);
    const result = original.apply(this, args);
    console.log(\`\${key} returned\`, result);
    return result;
  };
  return descriptor;
}

class UserService {
  @log  // decorates the method
  getUser(id) {
    return this.db.find(id);
  }
}

// Used heavily in: Angular (@Component, @Injectable)
// NestJS (@Controller, @Get, @Injectable)
// TypeORM (@Entity, @Column)`,
      },
    ]} />
    <InlinePoll
      question="What is the key difference between Decorator and inheritance for extending behavior?"
      options={[
        'Inheritance is faster',
        'Decorator extends behavior at runtime by wrapping objects — more flexible than inheritance which is fixed at compile time and creates rigid class hierarchies',
        'Decorator only works with classes',
        'Inheritance is always preferred',
      ]}
      correct={1}
      explanation="Inheritance is static — you define the extended behavior at class definition time. Decorator is dynamic — wrap any object at runtime with any combination of decorators. 3 decorators give you 6 possible combinations. With inheritance you'd need 6 subclasses. Decorator follows 'favor composition over inheritance'."
    />
    <CommonMistake
      mistake="Creating deep HOC chains that make debugging difficult: withA(withB(withC(withD(Component))))"
      fix="Beyond 2-3 HOC layers, use hooks instead. Hooks achieve the same composition without wrapping the component tree. useAuth(), useLogging(), useCache() are cleaner than 4 nested HOCs and much easier to debug in React DevTools."
    />
    <DidYouKnow
      fact="Express.js middleware is the Decorator pattern applied to request handlers. app.use(logger) wraps every route handler with logging. app.use(cors) wraps everything with CORS headers. Each middleware decorates the next — this is why Express middleware has the signature (req, res, next) and calls next() to pass to the next decorator."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Decorator pattern vs inheritance', freq: 75 },
      { topic: 'HOC as Decorator in React', freq: 80 },
      { topic: 'Function decorators for cross-cutting concerns', freq: 70 },
      { topic: 'TypeScript @decorator syntax', freq: 60 },
    ]} />
  </div>
);

export const ProxyPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Intercept and Control Object Access</div>
      <p style={c.prose}>
        Proxy intercepts operations on an object — get, set, function calls — and runs your code before/after/instead. <strong style={{ color: '#06b6d4' }}>Same interface, different behavior.</strong> Vue 3's reactivity, lazy loading, and access control all use this pattern.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🔐"
      title="A receptionist controlling office access"
      analogy="You want to meet the CEO. The receptionist intercepts you first — checks your appointment, logs your visit, lets you through or redirects you. The CEO doesn't know this happened. Proxy is the receptionist — it intercepts access to the real object, adds behavior, and either passes through or handles it itself."
      connection="new Proxy(realObject, handler) — every access to realObject goes through handler first. Vue 3 reactivity: get trap tracks dependencies, set trap triggers re-renders."
    />
    <StorySteps steps={[
      {
        title: 'JavaScript Proxy — the built-in implementation',
        color: '#06b6d4',
        desc: 'JavaScript has Proxy built in — intercept any object operation.',
        code: `const target = { name: 'Alice', age: 30 };

const handler = {
  get(target, key, receiver) {
    console.log(\`Reading: \${key}\`);
    return Reflect.get(target, key, receiver);
  },
  set(target, key, value, receiver) {
    console.log(\`Writing: \${key} = \${value}\`);
    if (key === 'age' && value < 0) {
      throw new RangeError('Age cannot be negative');
    }
    return Reflect.set(target, key, value, receiver);
  },
};

const proxy = new Proxy(target, handler);
proxy.name;      // logs "Reading: name", returns "Alice"
proxy.age = 25;  // logs "Writing: age = 25"
proxy.age = -1;  // throws RangeError`,
      },
      {
        title: 'Caching Proxy — memoize expensive calls',
        color: '#4facfe',
        desc: 'Intercept function calls and return cached results.',
        code: `function createCachingProxy(fn) {
  const cache = new Map();

  return new Proxy(fn, {
    apply(target, thisArg, args) {
      const key = JSON.stringify(args);

      if (cache.has(key)) {
        console.log('Cache hit!');
        return cache.get(key);
      }

      const result = Reflect.apply(target, thisArg, args);
      cache.set(key, result);
      return result;
    },
  });
}

const expensiveCalc = (n) => { /* CPU intensive */ return n * n; };
const cachedCalc = createCachingProxy(expensiveCalc);

cachedCalc(42); // computed
cachedCalc(42); // cache hit!`,
      },
      {
        title: 'Validation Proxy',
        color: '#00ff88',
        desc: 'Intercept property writes to enforce data integrity.',
        code: `function createValidatedObject(schema) {
  return new Proxy({}, {
    set(target, key, value) {
      const validator = schema[key];
      if (validator) {
        const error = validator(value);
        if (error) throw new TypeError(\`\${key}: \${error}\`);
      }
      return Reflect.set(target, key, value);
    },
  });
}

const user = createValidatedObject({
  name:  v => v.length < 2 ? 'Too short' : null,
  email: v => !v.includes('@') ? 'Invalid email' : null,
  age:   v => v < 0 ? 'Must be positive' : null,
});

user.name  = 'Alice';        // ✓
user.email = 'not-an-email'; // TypeError: email: Invalid email
user.age   = -1;             // TypeError: age: Must be positive`,
      },
      {
        title: 'Vue 3 Reactivity — Proxy in production',
        color: '#a855f7',
        desc: 'Vue 3 uses Proxy to power its entire reactivity system.',
        code: `// Simplified Vue 3 reactive() implementation
function reactive(obj) {
  return new Proxy(obj, {
    get(target, key, receiver) {
      // Track: "this component depends on this property"
      track(target, key);
      const value = Reflect.get(target, key, receiver);
      // Recursively make nested objects reactive
      return typeof value === 'object' ? reactive(value) : value;
    },

    set(target, key, value, receiver) {
      const result = Reflect.set(target, key, value, receiver);
      // Trigger: "this property changed, update dependents"
      trigger(target, key);
      return result;
    },
  });
}

const state = reactive({ count: 0 });
// Any component that reads state.count is tracked
// Changing state.count triggers tracked component re-renders`,
      },
    ]} />
    <InlinePoll
      question="Why should you use Reflect methods inside Proxy traps instead of direct property access?"
      options={[
        'Reflect is faster',
        'Reflect correctly handles prototype chains, getters/setters, and returns the proper boolean — direct access misses edge cases and can break inheritance',
        'Reflect is required by the spec',
        'Direct access doesn\'t work inside traps',
      ]}
      correct={1}
      explanation="target[key] = value in a set trap doesn't trigger inherited setters and always returns undefined (not true/false for success). Reflect.set(target, key, value, receiver) correctly invokes prototype setters, passes the receiver (for correct 'this' binding), and returns true/false. Always use Reflect inside traps."
    />
    <CommonMistake
      mistake="Using Proxy for simple property access logging when console.log in the code would be clearer."
      fix="Proxy adds indirection that makes debugging harder — stepping through code in DevTools shows proxy traps, not direct property access. Use Proxy for genuine cross-cutting concerns (validation, reactivity, access control). For simple debugging, use console.log or a debugger breakpoint."
    />
    <DidYouKnow
      fact="Proxy was a key reason Vue 3 required dropping IE11 support. IE11 has no Proxy support and Proxy can't be polyfilled — it requires native engine support to intercept object operations. Vue 2 used Object.defineProperty() which could be polyfilled but had limitations (couldn't detect new property addition). Proxy enabled Vue 3's superior reactivity system."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'JavaScript Proxy syntax and traps', freq: 75 },
      { topic: 'Use cases: caching, validation, logging', freq: 70 },
      { topic: 'Vue 3 reactivity uses Proxy', freq: 70 },
      { topic: 'Why use Reflect inside traps', freq: 60 },
    ]} />
  </div>
);

export const CommandPatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Requests as First-Class Objects</div>
      <p style={c.prose}>
        Command encapsulates an operation as an object. This means operations can be <strong style={{ color: '#06b6d4' }}>stored, queued, logged, and reversed</strong>. Undo/redo, macro recording, and transactional operations all use Command pattern.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🍽️"
      title="A restaurant order ticket"
      analogy="A waiter takes your order (Command object) and gives the ticket to the kitchen (receiver). The ticket contains all info: what, how, and for whom. Tickets are queued. If you cancel, the ticket is removed. Command pattern: your request is the ticket — fully encapsulated, queueable, cancellable."
      connection="dispatch({ type: 'ADD_ITEM', payload }) is a Command. Redux stores all dispatched commands. DevTools time-travel replays them. undo() would pop the last command."
    />
    <StorySteps steps={[
      {
        title: 'Command with undo/redo',
        color: '#06b6d4',
        desc: 'Each command has execute() and undo(). History stack enables time-travel.',
        code: `class Command {
  execute() { throw new Error('Not implemented'); }
  undo()    { throw new Error('Not implemented'); }
}

class AddTextCommand extends Command {
  constructor(editor, text, position) {
    super();
    this.editor = editor;
    this.text = text;
    this.position = position;
  }
  execute() { this.editor.insert(this.text, this.position); }
  undo()    { this.editor.delete(this.position, this.text.length); }
}

// Command history
class CommandHistory {
  #history = [];
  #redoStack = [];

  execute(command) {
    command.execute();
    this.#history.push(command);
    this.#redoStack = []; // clear redo on new action
  }

  undo() {
    const command = this.#history.pop();
    if (command) { command.undo(); this.#redoStack.push(command); }
  }

  redo() {
    const command = this.#redoStack.pop();
    if (command) { command.execute(); this.#history.push(command); }
  }
}`,
      },
      {
        title: 'Redux actions as Commands',
        color: '#4facfe',
        desc: 'Redux dispatch is the Command pattern — actions are command objects.',
        code: `// Redux action = Command object
const addTodo = (text) => ({
  type: 'todos/add',       // command type
  payload: { id: uuid(), text, done: false }, // command data
});

// dispatch = execute the command
dispatch(addTodo('Buy groceries'));

// Redux Toolkit slice = Command handlers (receivers)
const todosSlice = createSlice({
  name: 'todos',
  initialState: [],
  reducers: {
    add: (state, action) => {  // handles addTodo command
      state.push(action.payload);
    },
    toggle: (state, action) => {
      const todo = state.find(t => t.id === action.payload);
      if (todo) todo.done = !todo.done;
    },
  },
});

// Redux DevTools: all dispatched actions are stored
// Time-travel: replay commands from any point in history`,
      },
      {
        title: 'Command queue — batch execution',
        color: '#00ff88',
        desc: 'Queue commands and execute in batch. Useful for rate limiting, transactions, and offline support.',
        code: `class CommandQueue {
  #queue = [];
  #processing = false;

  enqueue(command) {
    this.#queue.push(command);
    this.processNext();
  }

  async processNext() {
    if (this.#processing || this.#queue.length === 0) return;
    this.#processing = true;
    const command = this.#queue.shift();
    try {
      await command.execute();
    } finally {
      this.#processing = false;
      this.processNext(); // process next in queue
    }
  }
}

// Offline support: queue commands when offline
const queue = new CommandQueue();
queue.enqueue(new SaveDocumentCommand(doc));
queue.enqueue(new SendEmailCommand(email));
// Executes one at a time, in order, handles retries`,
      },
      {
        title: 'Macro commands — composite operations',
        color: '#a855f7',
        desc: 'A command that executes multiple commands as one undoable unit.',
        code: `// MacroCommand — composite command
class MacroCommand extends Command {
  constructor(commands) {
    super();
    this.commands = commands;
  }

  execute() {
    this.commands.forEach(cmd => cmd.execute());
  }

  undo() {
    // Undo in reverse order
    [...this.commands].reverse().forEach(cmd => cmd.undo());
  }
}

// "Format as heading" = multiple commands as one unit
const formatAsHeading = new MacroCommand([
  new SetFontSizeCommand(editor, 24),
  new SetFontWeightCommand(editor, 'bold'),
  new SetColorCommand(editor, '#111'),
]);

history.execute(formatAsHeading);
// One undo reverts all three changes`,
      },
    ]} />
    <InlinePoll
      question="How does the Command pattern enable undo/redo functionality?"
      options={[
        'By using localStorage to save state',
        'Each command object has both execute() and undo() methods. A history stack stores executed commands. Undo pops the last command and calls undo(). Redo re-executes it.',
        'By taking DOM snapshots',
        'By reversing the event loop',
      ]}
      correct={1}
      explanation="Command objects are stored in a history array after execution. Undo: pop the last command, call command.undo() which reverses the operation. Redo: push it back, call command.execute() again. Every undo-able app (text editors, Figma, Photoshop) uses this exact pattern."
    />
    <CommonMistake
      mistake="Putting all command logic in the command object itself instead of delegating to the receiver."
      fix="Command objects should be thin — they know what to do but delegate HOW to do it to the receiver. Command holds the data (what text to insert, where), Receiver performs the actual work (the Editor knows how to insert text). This keeps commands serializable and receivers testable independently."
    />
    <DidYouKnow
      fact="Figma's entire collaborative editing system is built on Command pattern. Every action (move element, resize, change color) is a Command object. These commands are sent over WebSocket to all collaborators who execute them in the same order — giving everyone the same result. CRDT (Conflict-free Replicated Data Types) extends this to handle concurrent conflicting commands."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Command pattern for undo/redo', freq: 80 },
      { topic: 'Redux actions as Command pattern', freq: 75 },
      { topic: 'Command queuing for offline support', freq: 60 },
      { topic: 'execute() and undo() interface', freq: 70 },
    ]} />
  </div>
);

export const FacadePatternLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Simple Interface, Complex System Behind It</div>
      <p style={c.prose}>
        Facade provides a <strong style={{ color: '#06b6d4' }}>simplified interface to a complex subsystem</strong>. Callers use the facade without knowing about the subsystem's complexity. jQuery, SDK wrappers, and service layers are all Facades.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🎛️"
      title="A car's steering wheel vs the engine internals"
      analogy="You turn a steering wheel (facade) without knowing about the rack and pinion gear, tie rods, ball joints, and wheels underneath. The steering system is complex — the facade is simple. You don't need to understand the internals to drive."
      connection="An AnalyticsService.track('click', data) facade hides whether it's calling Segment, Mixpanel, or a custom endpoint. Change the underlying system without changing any calling code."
    />
    <StorySteps steps={[
      {
        title: 'Facade for complex subsystem',
        color: '#06b6d4',
        desc: 'One simple method orchestrates many complex operations.',
        code: `// Complex subsystem — many moving parts
class VideoEncoder { encode(file, format) { /* complex */ } }
class AudioProcessor { normalize(file) { /* complex */ } }
class ThumbnailGenerator { generate(frame) { /* complex */ } }
class StorageUploader { upload(file, bucket) { /* complex */ } }
class CDNInvalidator { invalidate(path) { /* complex */ } }

// ✅ Facade — one method does everything
class VideoUploadService {
  #encoder = new VideoEncoder();
  #audio   = new AudioProcessor();
  #thumbs  = new ThumbnailGenerator();
  #storage = new StorageUploader();
  #cdn     = new CDNInvalidator();

  async uploadVideo(file, options) {
    const encoded   = await this.#encoder.encode(file, 'h264');
    const processed = await this.#audio.normalize(encoded);
    const thumbnail = await this.#thumbs.generate(processed);
    const url       = await this.#storage.upload(processed, 'videos');
    await this.#cdn.invalidate(url);
    return { url, thumbnail };
  }
}

// Caller uses one simple method:
const service = new VideoUploadService();
const { url } = await service.uploadVideo(file); // simple!`,
      },
      {
        title: 'API service facade',
        color: '#4facfe',
        desc: 'Wrap complex HTTP logic behind simple methods.',
        code: `// ❌ Without facade — repeated complexity everywhere
const response = await fetch('/api/users', {
  method: 'GET',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': \`Bearer \${getToken()}\`,
    'X-Request-ID': uuid(),
  },
});
if (!response.ok) throw new Error(\`HTTP \${response.status}\`);
const data = await response.json();

// ✅ Facade — simple consistent API
class ApiClient {
  async get(path) { return this.#request('GET', path); }
  async post(path, body) { return this.#request('POST', path, body); }
  async put(path, body)  { return this.#request('PUT', path, body); }
  async delete(path)     { return this.#request('DELETE', path); }

  async #request(method, path, body) {
    const res = await fetch(\`/api\${path}\`, {
      method,
      headers: this.#getHeaders(),
      body: body ? JSON.stringify(body) : undefined,
    });
    if (!res.ok) throw await this.#handleError(res);
    return res.json();
  }
}

const api = new ApiClient();
const users = await api.get('/users'); // simple!`,
      },
      {
        title: 'React hook as facade',
        color: '#00ff88',
        desc: 'Custom hooks are facades over complex state and effect logic.',
        code: `// ❌ Without facade — complex logic in every component
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    fetch(\`/api/users/\${userId}\`, { signal: controller.signal })
      .then(r => { if (!r.ok) throw new Error(r.status); return r.json(); })
      .then(data => { setUser(data); setLoading(false); })
      .catch(e => { if (e.name !== 'AbortError') { setError(e); setLoading(false); } });
    return () => controller.abort();
  }, [userId]);
  // ... more code
}

// ✅ useUser hook = facade
function useUser(userId) {
  const [state, dispatch] = useReducer(userReducer, initialState);
  useEffect(() => { /* all the complexity */ }, [userId]);
  return state; // { user, loading, error }
}

// Component is simple:
function UserProfile({ userId }) {
  const { user, loading, error } = useUser(userId);
  // ... render
}`,
      },
      {
        title: 'Facade vs Adapter',
        color: '#eab308',
        desc: 'Similar patterns, different intentions.',
        code: `// FACADE: simplifies a complex interface
// Purpose: ease of use
class HomeTheaterFacade {
  watchMovie(movie) {
    this.amp.on(); this.projector.on();
    this.dvd.play(movie); this.lights.dim(10);
    // Simplifies 4 systems into 1 method
  }
}

// ADAPTER: converts one interface to another
// Purpose: compatibility
class LegacyPaymentAdapter {
  constructor(legacySystem) {
    this.legacy = legacySystem;
  }
  // New interface: charge(amount, currency)
  charge(amount, currency) {
    // Converts to old interface: processPayment(cents, code)
    return this.legacy.processPayment(
      amount * 100,          // dollars → cents
      currency.toUpperCase() // normalize currency code
    );
  }
}

// Facade = make it simpler
// Adapter = make it compatible`,
      },
    ]} />
    <InlinePoll
      question="What is the main purpose of the Facade pattern?"
      options={[
        'Adding new features to existing code',
        'Providing a simple interface to a complex subsystem — hiding complexity without changing the subsystem itself',
        'Improving performance',
        'Enforcing access control',
      ]}
      correct={1}
      explanation="Facade doesn't add features or change behavior — it just simplifies the interface. The complex subsystem still exists underneath. Callers use the simple facade API without knowing about the underlying complexity. This reduces coupling between calling code and the subsystem."
    />
    <CommonMistake
      mistake="Turning a Facade into a 'God object' that does everything and has too many responsibilities."
      fix="A Facade should cover a cohesive domain (video processing, payment processing). If your facade grows to 50 methods covering unrelated concerns, split it into multiple focused facades. A good facade is thin — it orchestrates, it doesn't implement."
    />
    <DidYouKnow
      fact="jQuery is one of the most successful Facades ever built. It facades: DOM querying (querySelectorAll with better syntax), event handling (addEventListener with cross-browser fixes), AJAX (XMLHttpRequest with Promise-like API), and animations (requestAnimationFrame with easing). At its peak, 77% of the top 1 million websites used jQuery."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Facade pattern definition and example', freq: 75 },
      { topic: 'Facade vs Adapter difference', freq: 70 },
      { topic: 'React custom hooks as facades', freq: 65 },
      { topic: 'API client as facade', freq: 65 },
    ]} />
  </div>
);

export const PubSubLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Event-Driven Architecture</div>
      <p style={c.prose}>
        Pub/Sub and Observer both handle events, but with a crucial difference: <strong style={{ color: '#06b6d4' }}>Pub/Sub uses a message broker</strong> — publisher and subscriber never reference each other. This extra decoupling enables scalable event-driven architecture.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📻"
      title="Radio broadcasting vs walkie-talkie"
      analogy="Observer is like a walkie-talkie — the sender and receiver know about each other directly. Pub/Sub is like a radio station — the broadcaster (publisher) transmits on a frequency (channel) without knowing who's listening. Listeners (subscribers) tune into a frequency without knowing who's broadcasting."
      connection="Publisher emits to a channel/topic. Subscriber listens to channels. Neither references the other. The message broker routes between them — complete decoupling."
    />
    <StorySteps steps={[
      {
        title: 'Observer vs Pub/Sub — the key difference',
        color: '#06b6d4',
        desc: 'Observer: direct reference. Pub/Sub: decoupled via broker.',
        code: `// OBSERVER — direct coupling
class Button {
  #observers = [];
  subscribe(obs) { this.#observers.push(obs); }
  click() { this.#observers.forEach(obs => obs.update(this)); }
  // Button holds direct references to observers!
}

// PUB/SUB — decoupled via event bus
class EventBus {
  #channels = new Map();
  publish(channel, data) {
    this.#channels.get(channel)?.forEach(fn => fn(data));
  }
  subscribe(channel, fn) {
    if (!this.#channels.has(channel)) this.#channels.set(channel, new Set());
    this.#channels.get(channel).add(fn);
    return () => this.#channels.get(channel).delete(fn); // unsub
  }
}

const bus = new EventBus();
// Publisher doesn't know about subscribers:
bus.publish('cart:updated', { count: 3 });
// Subscriber doesn't know about publisher:
bus.subscribe('cart:updated', ({ count }) => updateBadge(count));`,
      },
      {
        title: 'Event bus for micro-frontend communication',
        color: '#4facfe',
        desc: 'Pub/Sub decouples independently deployed micro-frontends.',
        code: `// Shared event bus across micro-frontends
const eventBus = window.__APP_BUS__ ||= (() => {
  const channels = new Map();
  return {
    publish(channel, data) {
      channels.get(channel)?.forEach(fn => fn(data));
    },
    subscribe(channel, fn) {
      if (!channels.has(channel)) channels.set(channel, new Set());
      channels.get(channel).add(fn);
      return () => channels.get(channel).delete(fn);
    },
  };
})();

// Catalog micro-frontend (React) publishes:
function ProductCard({ product }) {
  const addToCart = () => {
    eventBus.publish('cart:add', { productId: product.id, qty: 1 });
  };
  return <button onClick={addToCart}>Add to Cart</button>;
}

// Checkout micro-frontend (Vue) subscribes:
mounted() {
  this.unsub = eventBus.subscribe('cart:add', ({ productId, qty }) => {
    this.cart.push({ productId, qty });
  });
},
beforeUnmount() { this.unsub(); }`,
      },
      {
        title: 'Topic-based filtering',
        color: '#00ff88',
        desc: 'Hierarchical topics let subscribers filter with wildcards.',
        code: `// Advanced: hierarchical topic routing
class TopicBus {
  #subscriptions = [];

  publish(topic, data) {
    this.#subscriptions
      .filter(({ pattern }) => this.#matches(pattern, topic))
      .forEach(({ fn }) => fn(data, topic));
  }

  subscribe(pattern, fn) {
    this.#subscriptions.push({ pattern, fn });
    return () => {
      this.#subscriptions = this.#subscriptions
        .filter(s => s.fn !== fn);
    };
  }

  #matches(pattern, topic) {
    const regex = new RegExp(
      '^' + pattern.replace('*', '[^.]+').replace('#', '.+') + '$'
    );
    return regex.test(topic);
  }
}

const bus = new TopicBus();
bus.subscribe('user.*', handler);    // user.login, user.logout
bus.subscribe('cart.#', handler);    // cart.add, cart.remove.item
bus.publish('user.login', { id: 1 }); // matches 'user.*'`,
      },
      {
        title: 'When to use Observer vs Pub/Sub',
        color: '#eab308',
        desc: 'Choose based on coupling requirements.',
        code: `// Use OBSERVER when:
// - Components are in the same module/layer
// - Direct reference is acceptable
// - Simple parent-child relationships
// React setState, EventEmitter, DOM events

// Use PUB/SUB when:
// - Components are in different modules/apps
// - Publisher shouldn't know about subscribers
// - Many-to-many relationships
// - Micro-frontends, cross-domain events

// Anti-patterns to avoid:
// ❌ Event bus for parent-child communication
//    (just use props/callbacks)
// ❌ Too many event types (hard to trace)
// ❌ No schema/contract for event payloads
// ❌ Forgetting to unsubscribe (memory leaks)

// Best practice: typed event contracts
interface CartEvent { productId: string; qty: number; }
bus.subscribe('cart:add', (data: CartEvent) => { /* typed! */ });`,
      },
    ]} />
    <InlinePoll
      question="What is the key architectural difference between Observer and Pub/Sub?"
      options={[
        'Pub/Sub is faster',
        'Observer: subject holds direct observer references (coupled). Pub/Sub: publisher emits to a channel, subscribers listen to channels — publisher and subscriber never reference each other (decoupled)',
        'Observer works only in browsers',
        'They are functionally identical',
      ]}
      correct={1}
      explanation="The critical difference is coupling. Observer: Button.subscribe(myHandler) — Button holds a reference to myHandler. Pub/Sub: publisher emits to 'click-channel', subscriber listens to 'click-channel' — neither knows about the other. Pub/Sub's broker adds indirection that enables true decoupling between modules or applications."
    />
    <CommonMistake
      mistake="Using a global event bus for all component communication in a React app."
      fix="Global event buses make data flow unpredictable — you can't trace where events come from or who handles them. For React component communication: use props/callbacks for parent-child, Context for deeply nested, Zustand/Redux for cross-tree. Reserve event bus for genuinely decoupled systems like micro-frontends."
    />
    <DidYouKnow
      fact="Message brokers like Apache Kafka, RabbitMQ, and AWS SNS/SQS are industrial-scale Pub/Sub systems. Kafka handles trillions of events per day at LinkedIn. The pattern scales from a 10-line JavaScript EventBus to distributed systems processing millions of messages per second — same pattern, different scale."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'Observer vs Pub/Sub key difference', freq: 80 },
      { topic: 'Event bus implementation', freq: 70 },
      { topic: 'When to use each pattern', freq: 70 },
      { topic: 'Memory leak from forgotten subscriptions', freq: 75 },
    ]} />
  </div>
);

export const MVCLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Separating What Your App Does From How It Looks</div>
      <p style={c.prose}>
        MVC, MVP, and MVVM are all answers to the same problem: <strong style={{ color: '#06b6d4' }}>business logic and UI logic should not be mixed</strong>. The specific separation varies, but the goal is the same — code that's testable, maintainable, and changeable.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🎭"
      title="A play — script, actors, and director"
      analogy="A theatre play has: the script (Model — the content and rules), the actors (View — what the audience sees), and the director (Controller — orchestrates actors to follow the script). Change the director's interpretation without rewriting the script. Cast new actors without changing the story."
      connection="Model: data and business rules. View: presentation and user input. Controller/Presenter/ViewModel: the glue between them. Separation means you can unit test each part independently."
    />
    <StorySteps steps={[
      {
        title: 'MVC — Model, View, Controller',
        color: '#06b6d4',
        desc: 'Classic pattern. Controller handles input, updates Model, selects View.',
        code: `// MODEL — data and business logic
class TodoModel {
  #todos = [];
  add(text) { this.#todos.push({ id: uuid(), text, done: false }); }
  toggle(id) {
    const todo = this.#todos.find(t => t.id === id);
    if (todo) todo.done = !todo.done;
  }
  getAll() { return [...this.#todos]; }
  getActive() { return this.#todos.filter(t => !t.done); }
}

// CONTROLLER — handles user input, updates model, refreshes view
class TodoController {
  constructor(model, view) {
    this.model = model;
    this.view = view;
    this.view.onAddTodo = (text) => {
      this.model.add(text);
      this.view.render(this.model.getAll());
    };
  }
}

// VIEW — renders data, captures user input
class TodoView {
  render(todos) { /* update DOM */ }
  onAddTodo = null; // callback set by controller
}`,
      },
      {
        title: 'Flux/Redux — unidirectional data flow',
        color: '#4facfe',
        desc: 'Facebook\'s reaction to MVC\'s bidirectional flow issues.',
        code: `// FLUX: Action → Dispatcher → Store → View → Action
// Redux is Flux with a single store and pure reducers

// Action (what happened)
const addTodo = (text) => ({ type: 'ADD_TODO', payload: { text } });

// Reducer (how state changes — pure function)
function todosReducer(state = [], action) {
  switch (action.type) {
    case 'ADD_TODO':
      return [...state, { id: uuid(), text: action.payload.text, done: false }];
    default:
      return state;
  }
}

// Store (single source of truth)
const store = createStore(todosReducer);

// View dispatches actions, reads from store
function TodoApp() {
  const todos = useSelector(state => state.todos);
  const dispatch = useDispatch();
  return (
    <button onClick={() => dispatch(addTodo('New todo'))}>
      Add
    </button>
  );
}
// Strict unidirectional: Action → Reducer → Store → View`,
      },
      {
        title: 'MVVM — data binding',
        color: '#00ff88',
        desc: 'ViewModel exposes data streams. View binds to them. Two-way binding keeps them in sync.',
        code: `// MVVM in Angular — ViewModel = Component class
@Component({
  template: \`
    <input [(ngModel)]="username" />  <!-- two-way binding -->
    <p>Hello {{ username }}</p>       <!-- one-way binding -->
    <button (click)="submit()">Submit</button>
  \`,
})
class LoginComponent {
  username = '';  // ViewModel property — View binds to this
  password = '';

  // ViewModel method — called by View
  submit() {
    this.authService.login(this.username, this.password);
  }
}

// Vue's Options API is also MVVM:
// data() = ViewModel properties
// methods = ViewModel methods
// template = View that binds to ViewModel
// Two-way binding via v-model`,
      },
      {
        title: 'React — where does it fit?',
        color: '#a855f7',
        desc: 'React doesn\'t enforce an architectural pattern — but you can apply them.',
        code: `// React is "just the View layer" — you choose the architecture

// Option 1: Component-level MVC
function TodoApp() {
  // Model (or use custom hook for cleaner separation):
  const [todos, dispatch] = useReducer(todoReducer, []);

  // Controller (event handlers):
  const handleAdd = (text) => dispatch({ type: 'ADD', payload: text });
  const handleToggle = (id) => dispatch({ type: 'TOGGLE', payload: id });

  // View (render):
  return <TodoList todos={todos} onAdd={handleAdd} onToggle={handleToggle} />;
}

// Option 2: Hooks as ViewModels
function useTodoViewModel() {
  const [todos, dispatch] = useReducer(todoReducer, []);
  return {
    todos,
    addTodo: (text) => dispatch({ type: 'ADD', payload: text }),
    toggleTodo: (id) => dispatch({ type: 'TOGGLE', payload: id }),
  };
}
// Component uses ViewModel: const vm = useTodoViewModel();`,
      },
    ]} />
    <InlinePoll
      question="What problem with MVC did Facebook's Flux architecture solve?"
      options={[
        'MVC was too slow',
        'Bidirectional data flow in MVC caused cascading updates — changing a Model could update a View that updates another Model. Flux enforced strict unidirectional flow',
        'MVC didn\'t support React',
        'MVC had no Controller',
      ]}
      correct={1}
      explanation="Facebook found that with many Models and Views, bidirectional MVC created cascading updates that were impossible to debug. 'A changed Model updates a View which updates another Model which updates three Views...' Flux enforced one-way flow: Action → Dispatcher → Store → View. No cycles, fully traceable."
    />
    <CommonMistake
      mistake="Putting business logic in React components because 'that's how React works'."
      fix="React is the View layer. Complex business rules (validation, calculations, data transformation) belong in: custom hooks (useCartTotal), utility functions (calculateDiscount), or a state management layer (Redux reducer). Pure functions are easily testable without rendering components."
    />
    <DidYouKnow
      fact="The original MVC pattern was invented by Trygve Reenskaug at Xerox PARC in 1979 for Smalltalk. It predates the web by over a decade. The web community adopted and adapted it extensively — resulting in dozens of variations (MVP, MVVM, MVRC, MVI). The core insight — separate data from presentation — remains universally valid."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'MVC — roles of each part', freq: 85 },
      { topic: 'Flux/Redux unidirectional flow', freq: 80 },
      { topic: 'MVVM two-way binding (Angular/Vue)', freq: 70 },
      { topic: 'Where React fits architecturally', freq: 75 },
    ]} />
  </div>
);

export const ZustandVsReduxLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#a855f740' delay={0}>
      <div style={c.title('#a855f7')}>🎬 Choosing the Right State Tool</div>
      <p style={c.prose}>
        Redux and Zustand solve the same problem — shared client state — but with radically different philosophies. <strong style={{ color: '#a855f7' }}>Redux: explicit, verbose, powerful DevTools. Zustand: minimal, flexible, zero boilerplate.</strong> The right choice depends on team size, app complexity, and debugging needs.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏦"
      title="A central bank vs a local credit union"
      analogy="Redux is like a central bank — strict rules, full audit trail, every transaction logged, highly regulated. Zustand is like a local credit union — fewer rules, faster to open an account, less paperwork, same core banking functions. Both keep your money safe. Different overhead."
      connection="Redux: strict unidirectional flow, action creators, reducers, selectors. Zustand: create a store with state and actions together, use it anywhere. Same result, opposite DX."
    />
    <StorySteps steps={[
      {
        title: 'Redux — explicit, traceable, verbose',
        color: '#a855f7',
        desc: 'Every state change is an explicit action. Full DevTools support with time-travel debugging.',
        code: `// Redux Toolkit — modern Redux
import { createSlice, configureStore } from '@reduxjs/toolkit';

const cartSlice = createSlice({
  name: 'cart',
  initialState: { items: [], total: 0 },
  reducers: {
    addItem: (state, action) => {
      state.items.push(action.payload);
      state.total += action.payload.price;
    },
    removeItem: (state, action) => {
      const index = state.items.findIndex(i => i.id === action.payload);
      if (index !== -1) {
        state.total -= state.items[index].price;
        state.items.splice(index, 1);
      }
    },
    clearCart: (state) => {
      state.items = [];
      state.total = 0;
    },
  },
});

export const { addItem, removeItem, clearCart } = cartSlice.actions;
const store = configureStore({ reducer: { cart: cartSlice.reducer } });

// In component:
const items = useSelector(state => state.cart.items);
const dispatch = useDispatch();
dispatch(addItem({ id: 1, name: 'Book', price: 29 }));`,
      },
      {
        title: 'Zustand — minimal, flexible, fast',
        color: '#4facfe',
        desc: 'Define state and actions together. No providers, no boilerplate.',
        code: `import { create } from 'zustand';

// State + actions in one place
const useCartStore = create((set, get) => ({
  items: [],
  total: 0,

  addItem: (item) => set(state => ({
    items: [...state.items, item],
    total: state.total + item.price,
  })),

  removeItem: (id) => set(state => {
    const item = state.items.find(i => i.id === id);
    return {
      items: state.items.filter(i => i.id !== id),
      total: state.total - (item?.price || 0),
    };
  }),

  clearCart: () => set({ items: [], total: 0 }),

  // Can access other state via get():
  getItemCount: () => get().items.length,
}));

// In component — no Provider needed!
const { items, addItem } = useCartStore();
// Selective subscription — only re-renders when items changes:
const items = useCartStore(state => state.items);`,
      },
      {
        title: 'Side-by-side comparison',
        color: '#00ff88',
        desc: 'Same feature, different approaches.',
        code: `// REDUX — async with createAsyncThunk
export const fetchUser = createAsyncThunk(
  'users/fetch',
  async (id) => {
    const res = await fetch(\`/api/users/\${id}\`);
    return res.json();
  }
);
// Generates: users/fetch/pending, /fulfilled, /rejected

// ZUSTAND — async directly in action
const useUserStore = create((set) => ({
  user: null,
  loading: false,
  error: null,

  fetchUser: async (id) => {
    set({ loading: true, error: null });
    try {
      const res = await fetch(\`/api/users/\${id}\`);
      const user = await res.json();
      set({ user, loading: false });
    } catch (err) {
      set({ error: err.message, loading: false });
    }
  },
}));

// Zustand: 10 lines. Redux: 30+ lines for same feature.`,
      },
      {
        title: 'When to use each',
        color: '#eab308',
        desc: 'Neither is universally better — context determines the right choice.',
        code: `// USE REDUX WHEN:
// ✓ Large team (5+ devs) — enforced patterns prevent chaos
// ✓ Complex state interactions across many features
// ✓ DevTools time-travel debugging is critical
// ✓ Already using Redux — migration cost not worth it
// ✓ Need strict code review enforcement of patterns

// USE ZUSTAND WHEN:
// ✓ Small-medium team — move fast, less ceremony
// ✓ Simple-moderate shared state needs
// ✓ New project — start lean, scale if needed
// ✓ Performance matters — granular subscriptions built in
// ✓ Tired of Redux boilerplate

// BOTH support:
// ✓ Middleware (devtools, persistence, immer)
// ✓ TypeScript
// ✓ Async operations
// ✓ Computed/derived state
// ✓ React DevTools integration

// NEITHER is right for:
// ✗ Server state (use React Query)
// ✗ Form state (use React Hook Form)
// ✗ URL state (use router)`,
      },
    ]} />
    <InlinePoll
      question="What is Zustand's key performance advantage over React Context?"
      options={[
        'Zustand uses Web Workers',
        'Components subscribe to specific state slices — only re-render when their specific slice changes, not when any part of the store changes',
        'Zustand batches all updates',
        'Zustand uses requestIdleCallback',
      ]}
      correct={1}
      explanation="useCartStore(state => state.items) subscribes only to items. If user changes in the same store, this component doesn't re-render. Context re-renders ALL consumers when ANY value changes. Zustand's selector-based subscriptions give you fine-grained reactivity at zero extra cost."
    />
    <CommonMistake
      mistake="Putting server data (API responses) in Zustand or Redux store."
      fix="Redux and Zustand are for client state — UI state, user preferences, session data. API data has different needs: caching, deduplication, background revalidation, stale handling. Use React Query or SWR for server state. The stores become much simpler when you remove all the loading/error/data patterns."
    />
    <DidYouKnow
      fact="Zustand was created by Poimandres (the team behind react-spring and react-three-fiber) in 2019. The name means 'state' in German. Despite being tiny (~1KB), it's used in production by major companies. As of 2024, Zustand has more weekly npm downloads than Redux Toolkit — a remarkable shift in the React ecosystem."
      color="#a855f7"
    />
    <InterviewMeter topics={[
      { topic: 'Zustand vs Redux API differences', freq: 80 },
      { topic: 'When to choose each', freq: 75 },
      { topic: 'Zustand selective subscriptions', freq: 70 },
      { topic: 'Neither for server state — use React Query', freq: 75 },
    ]} />
  </div>
);

export const ReactQueryVsReduxLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Server State Is a Different Problem</div>
      <p style={c.prose}>
        The biggest mistake in React state management: <strong style={{ color: '#ef4444' }}>putting API data in Redux</strong>. Server state and client state are fundamentally different problems. React Query is built specifically for server state — caching, revalidation, deduplication, background updates.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📡"
      title="A live satellite feed vs a local whiteboard"
      analogy="A whiteboard (Redux) is for your own notes — stable, you control every change. A satellite feed (React Query) streams real-world data that changes remotely — you need caching (don't re-request every second), staleness detection (how old is this?), and background sync. Same data model, very different management needs."
      connection="Redux/Zustand: client state you own and control. React Query: server state that lives on a server, can change any time, needs cache invalidation and background refetching."
    />
    <StorySteps steps={[
      {
        title: 'The problem with server state in Redux',
        color: '#ef4444',
        desc: 'Managing API data in Redux requires enormous amounts of boilerplate for basic functionality.',
        code: `// ❌ Server state in Redux — all this for one endpoint!
const usersSlice = createSlice({
  name: 'users',
  initialState: { data: [], loading: false, error: null },
  extraReducers: (builder) => {
    builder
      .addCase(fetchUsers.pending,   s => { s.loading = true; s.error = null; })
      .addCase(fetchUsers.fulfilled, (s, a) => { s.loading = false; s.data = a.payload; })
      .addCase(fetchUsers.rejected,  (s, a) => { s.loading = false; s.error = a.error.message; });
  },
});
// And you still don't have:
// ✗ Automatic refetch on window focus
// ✗ Cache invalidation
// ✗ Deduplication of simultaneous requests
// ✗ Background revalidation
// ✗ Stale data handling
// ✗ Retry on failure`,
      },
      {
        title: 'React Query — server state done right',
        color: '#00ff88',
        desc: 'All the server state infrastructure for free.',
        code: `import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

// GET — all loading/error/caching handled automatically
function UserList() {
  const { data: users, isLoading, error } = useQuery({
    queryKey: ['users'],
    queryFn: () => fetch('/api/users').then(r => r.json()),
    staleTime:  5 * 60 * 1000, // fresh for 5 minutes
    gcTime:    10 * 60 * 1000, // keep in cache 10 minutes
    refetchOnWindowFocus: true, // refetch when tab regains focus
    retry: 3,                  // retry failed requests 3 times
  });

  if (isLoading) return <Spinner />;
  if (error)     return <ErrorMessage error={error} />;
  return <ul>{users.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}
// 6 lines of config replaces 50+ lines of Redux code`,
      },
      {
        title: 'Mutations and cache invalidation',
        color: '#4facfe',
        desc: 'After a mutation, invalidate related queries so they refetch fresh data.',
        code: `function CreateUser() {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: (newUser) =>
      fetch('/api/users', {
        method: 'POST',
        body: JSON.stringify(newUser),
      }).then(r => r.json()),

    onSuccess: () => {
      // Invalidate users list — will refetch automatically
      queryClient.invalidateQueries({ queryKey: ['users'] });
    },

    onError: (error) => {
      toast.error(\`Failed: \${error.message}\`);
    },
  });

  return (
    <button
      onClick={() => mutation.mutate({ name: 'Alice', email: 'a@a.com' })}
      disabled={mutation.isPending}
    >
      {mutation.isPending ? 'Creating...' : 'Create User'}
    </button>
  );
}`,
      },
      {
        title: 'What each tool is for',
        color: '#eab308',
        desc: 'Use both together — they solve different problems.',
        code: `// REACT QUERY handles:
// ✓ API data fetching and caching
// ✓ Loading / error states
// ✓ Background revalidation
// ✓ Pagination and infinite scroll
// ✓ Optimistic updates
// ✓ Request deduplication

// REDUX / ZUSTAND handles:
// ✓ Auth state (current user, token)
// ✓ UI state (modal open, sidebar collapsed)
// ✓ User preferences (theme, language)
// ✓ Shopping cart (before checkout)
// ✓ Multi-step form progress

// USING BOTH TOGETHER:
function App() {
  const { user } = useAuthStore(); // Zustand — client state
  const { data } = useQuery({      // React Query — server state
    queryKey: ['posts', user?.id],
    queryFn: () => fetchPosts(user.id),
    enabled: !!user, // only fetch when user exists
  });
}`,
      },
    ]} />
    <InlinePoll
      question="Five components all call useQuery(['users'], fetchUsers) simultaneously. How many HTTP requests fire?"
      options={[
        '5 requests — one per component',
        '1 request — React Query deduplicates identical in-flight requests and shares the cached result',
        '0 requests — React Query always uses cache',
        'Depends on staleTime configuration',
      ]}
      correct={1}
      explanation="React Query deduplicates requests with the same query key. If 5 components mount simultaneously and all call useQuery(['users']), only ONE network request fires. When it resolves, all 5 components receive the data. This is one of React Query's most valuable features — impossible to replicate easily with Redux."
    />
    <CommonMistake
      mistake="Storing React Query data in Redux to 'have one source of truth'."
      fix="React Query IS the source of truth for server data — its cache IS the store. Copying React Query data into Redux creates two sources of truth that can get out of sync. Use queryClient.getQueryData(['users']) anywhere you need the cached server data. Only put truly client-side state in Redux/Zustand."
    />
    <DidYouKnow
      fact="Tanner Linsley created React Query after building the same data-fetching infrastructure 5 times at different companies. He realized every team was solving the same problems (caching, loading states, revalidation) manually in Redux. React Query's thesis: server state deserves its own dedicated tool. As of 2024, it has over 8 million weekly downloads."
      color="#00ff88"
    />
    <InterviewMeter topics={[
      { topic: 'Server state vs client state distinction', freq: 90 },
      { topic: 'React Query features vs Redux for API data', freq: 85 },
      { topic: 'invalidateQueries after mutations', freq: 75 },
      { topic: 'Using React Query + Zustand together', freq: 70 },
    ]} />
  </div>
);

export const OptimisticUpdatesLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#4facfe40' delay={0}>
      <div style={c.title('#4facfe')}>🎬 Update the UI Before the Server Responds</div>
      <p style={c.prose}>
        Optimistic updates assume a mutation will succeed and <strong style={{ color: '#4facfe' }}>update the UI immediately</strong> — before the server confirms. If the server fails, roll back. The result: instant-feeling interactions even on slow connections.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="✅"
      title="A bank ATM showing your balance before the server confirms"
      analogy="When you deposit cash at an ATM, your balance updates on screen immediately — the bank assumes success. If something fails in the background, they reconcile later. Optimistic UI works the same way: show success immediately, handle rare failures gracefully."
      connection="setLiked(true) immediately. Send the API request. If it fails: setLiked(false) + show error. Users see instant response 99% of the time. The 1% failure is handled gracefully."
    />
    <StorySteps steps={[
      {
        title: 'Basic optimistic update pattern',
        color: '#4facfe',
        desc: 'Update state immediately, send request, rollback on failure.',
        code: `function LikeButton({ postId, initialLiked, initialCount }) {
  const [liked, setLiked] = useState(initialLiked);
  const [count, setCount] = useState(initialCount);

  const handleLike = async () => {
    // 1. Optimistic update — immediate
    const wasLiked = liked;
    const prevCount = count;
    setLiked(!liked);
    setCount(liked ? count - 1 : count + 1);

    try {
      // 2. Send to server
      await toggleLike(postId);
      // 3. Success — UI already correct, nothing to do
    } catch (error) {
      // 4. Failure — rollback to previous state
      setLiked(wasLiked);
      setCount(prevCount);
      toast.error('Failed to update like');
    }
  };

  return (
    <button onClick={handleLike}>
      {liked ? '❤️' : '🤍'} {count}
    </button>
  );
}`,
      },
      {
        title: 'React Query optimistic updates',
        color: '#00ff88',
        desc: 'React Query has built-in optimistic update support with automatic rollback.',
        code: `function useLikeMutation(postId) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: () => toggleLike(postId),

    onMutate: async () => {
      // Cancel any outgoing refetches
      await queryClient.cancelQueries({ queryKey: ['post', postId] });

      // Snapshot current value for rollback
      const previous = queryClient.getQueryData(['post', postId]);

      // Optimistically update the cache
      queryClient.setQueryData(['post', postId], (old) => ({
        ...old,
        liked: !old.liked,
        likeCount: old.liked ? old.likeCount - 1 : old.likeCount + 1,
      }));

      return { previous }; // context for onError
    },

    onError: (err, vars, context) => {
      // Rollback to snapshot on error
      queryClient.setQueryData(['post', postId], context.previous);
      toast.error('Failed to update');
    },

    onSettled: () => {
      // Always refetch to ensure sync with server
      queryClient.invalidateQueries({ queryKey: ['post', postId] });
    },
  });
}`,
      },
      {
        title: 'useOptimistic — React 19 built-in',
        color: '#a855f7',
        desc: 'React 19 adds a hook specifically for optimistic updates.',
        code: `import { useOptimistic } from 'react';

function LikeButton({ post }) {
  const [optimisticPost, addOptimistic] = useOptimistic(
    post,
    // Updater: receives current state + optimistic value
    (currentPost, optimisticValue) => ({
      ...currentPost,
      ...optimisticValue,
    })
  );

  const handleLike = async () => {
    // Apply optimistic update immediately
    addOptimistic({
      liked: !post.liked,
      likeCount: post.liked ? post.likeCount - 1 : post.likeCount + 1,
    });

    // Server action — if it fails, React auto-rolls back
    await toggleLikeAction(post.id);
  };

  return (
    <button onClick={handleLike}>
      {optimisticPost.liked ? '❤️' : '🤍'} {optimisticPost.likeCount}
    </button>
  );
  // No manual rollback needed — React handles it!
}`,
      },
      {
        title: 'When optimistic updates are appropriate',
        color: '#eab308',
        desc: 'Not every mutation should be optimistic.',
        code: `// ✅ GOOD candidates for optimistic updates:
// - Like / bookmark / follow actions (low stakes)
// - Reordering items in a list
// - Marking todos complete
// - Archiving items
// - Updating profile preferences
// All: reversible, low failure rate, immediate feedback matters

// ❌ BAD candidates for optimistic updates:
// - Payment processing (stakes too high, must confirm)
// - Sending emails (can't unsend)
// - Deleting account (catastrophic if wrong)
// - File uploads (can't show progress without actual upload)
// - Complex operations with unknown server-side effects

// Key question: "If this fails and we showed success,
// how bad is the user experience?"
// Low impact → optimistic is great
// High impact → wait for server confirmation`,
      },
    ]} />
    <InlinePoll
      question="What must you always save before applying an optimistic update?"
      options={[
        'The user\'s session token',
        'A snapshot of the previous state — so you can rollback if the server request fails',
        'The mutation function reference',
        'The component render count',
      ]}
      correct={1}
      explanation="Before optimistically updating, capture the current state. If the API call fails, restore from the snapshot. Without the snapshot, you have no way to rollback — the user sees a success state that doesn't match server reality. React Query's onMutate returns context specifically for this purpose."
    />
    <CommonMistake
      mistake="Not handling the error case — applying the optimistic update but forgetting to rollback on failure."
      fix="Every optimistic update needs a try/catch (or React Query's onError) that restores the previous state. Test your error handling by mocking API failures. The optimistic UI is only good UX if failures are handled gracefully — silent failures that leave the UI in wrong state are worse than pessimistic updates."
    />
    <DidYouKnow
      fact="Facebook pioneered optimistic UI extensively — the Like button was one of the first widely-used optimistic interactions on the web. They found that users perceive pages as significantly faster when interactions respond immediately. Studies show that UI latency under 100ms feels instant, 100-300ms feels responsive, over 1000ms breaks the flow of thought."
      color="#4facfe"
    />
    <InterviewMeter topics={[
      { topic: 'What optimistic updates are and why', freq: 85 },
      { topic: 'Snapshot and rollback pattern', freq: 80 },
      { topic: 'React Query onMutate / onError pattern', freq: 70 },
      { topic: 'When not to use optimistic updates', freq: 65 },
    ]} />
  </div>
);

export const NormalizedStateLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Organizing Data Like a Database</div>
      <p style={c.prose}>
        Normalized state stores each entity <strong style={{ color: '#eab308' }}>once, by ID</strong>. No duplicates, no inconsistency. References use IDs instead of nested objects. Updates touch one place — no hunting through arrays.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📚"
      title="A library catalog vs piles of books"
      analogy="A disorganized library has duplicate books scattered everywhere — update one and others are stale. A catalog system gives every book a unique ID and stores it in one location. References point to the ID. Normalization is the catalog system for your app state."
      connection="{ users: { byId: { '1': {...} }, allIds: ['1','2'] } } — each user stored once by ID. Posts reference users by ID. Update user once, all posts see the change."
    />
    <StorySteps steps={[
      {
        title: 'The problem — nested/duplicated data',
        color: '#ef4444',
        desc: 'Nested data creates duplicates. Update one copy and others go stale.',
        code: `// ❌ Unnormalized — user duplicated in every post
const state = {
  posts: [
    {
      id: 1,
      title: 'Hello World',
      author: { id: 'u1', name: 'Alice', avatar: 'alice.jpg' },
      // ↑ Author object embedded in post
    },
    {
      id: 2,
      title: 'Second Post',
      author: { id: 'u1', name: 'Alice', avatar: 'alice.jpg' },
      // ↑ Same author DUPLICATED — 2 copies of Alice
    },
  ],
};

// Problem: Alice changes her avatar
// Must update EVERY post that contains Alice's data
// Easy to miss one → inconsistent UI`,
      },
      {
        title: 'Normalized shape — each entity once',
        color: '#eab308',
        desc: 'Store entities by ID. Use IDs for references. Single source of truth.',
        code: `// ✅ Normalized — each entity stored once
const state = {
  // Entities stored by ID (like a database table)
  users: {
    byId: {
      'u1': { id: 'u1', name: 'Alice', avatar: 'alice.jpg' },
      'u2': { id: 'u2', name: 'Bob',   avatar: 'bob.jpg' },
    },
    allIds: ['u1', 'u2'],
  },
  posts: {
    byId: {
      1: { id: 1, title: 'Hello World', authorId: 'u1' },
      2: { id: 2, title: 'Second Post', authorId: 'u1' },
      // ↑ Reference by ID — not embedded object
    },
    allIds: [1, 2],
  },
};

// Update Alice once:
state.users.byId['u1'].avatar = 'new-alice.jpg';
// Both posts now show the updated avatar automatically ✓`,
      },
      {
        title: 'Redux Toolkit createEntityAdapter',
        color: '#4facfe',
        desc: 'RTK\'s built-in tool for normalized state management.',
        code: `import { createEntityAdapter, createSlice } from '@reduxjs/toolkit';

// EntityAdapter provides normalized CRUD operations
const usersAdapter = createEntityAdapter({
  selectId: (user) => user.id,
  sortComparer: (a, b) => a.name.localeCompare(b.name),
});

const usersSlice = createSlice({
  name: 'users',
  initialState: usersAdapter.getInitialState(),
  // initialState = { ids: [], entities: {} }
  reducers: {
    // Adapter gives you these for free:
    addUser:     usersAdapter.addOne,
    addUsers:    usersAdapter.addMany,
    updateUser:  usersAdapter.updateOne,
    removeUser:  usersAdapter.removeOne,
    upsertUsers: usersAdapter.upsertMany, // add or update
  },
});

// Generated selectors:
const { selectAll, selectById, selectIds } =
  usersAdapter.getSelectors(state => state.users);

const allUsers = useSelector(selectAll);        // array
const alice    = useSelector(s => selectById(s, 'u1'));`,
      },
      {
        title: 'Denormalization at read time',
        color: '#00ff88',
        desc: 'Join entities when displaying — like a database JOIN.',
        code: `// Selector that joins posts with their authors
const selectPostsWithAuthors = createSelector(
  state => state.posts.byId,
  state => state.users.byId,
  state => state.posts.allIds,
  (postsById, usersById, allPostIds) =>
    allPostIds.map(id => ({
      ...postsById[id],
      // JOIN: resolve authorId to full user object
      author: usersById[postsById[id].authorId],
    }))
);

// Component gets joined data:
const postsWithAuthors = useSelector(selectPostsWithAuthors);
// [{ id: 1, title: '...', author: { name: 'Alice', avatar: '...' } }]

// Updates are still normalized — one place to change
// Reading is denormalized — convenient for components`,
      },
    ]} />
    <InlinePoll
      question="A post object embeds the full author object. The user updates their avatar. What's the problem?"
      options={[
        'The update is too fast',
        'Every post that embeds that user has a stale copy — must find and update all of them or different posts show different avatars',
        'Redux can\'t handle nested objects',
        'Avatars should be stored in localStorage',
      ]}
      correct={1}
      explanation="Embedded/duplicated data creates update inconsistency. Update the user's avatar but miss even one post — that post shows old avatar. With normalization, each user exists once (in users.byId). All posts reference by ID. Update the user once and all posts reflect it immediately."
    />
    <CommonMistake
      mistake="Normalizing everything including data that genuinely belongs nested."
      fix="Normalize when entities are shared across multiple places. Don't normalize when data is truly nested by nature (a form's field validation errors, a comment's reactions if reactions are never shown independently). Over-normalization creates excessive complexity. Normalize shared entities, keep local data nested."
    />
    <DidYouKnow
      fact="Redux's normalization recommendations were heavily influenced by database normalization theory (1NF, 2NF, 3NF). The Normalizr library (created by Dan Abramov's collaborator Paul Armstrong in 2015) popularized the pattern before Redux Toolkit's EntityAdapter made it built-in. GraphQL clients like Apollo and Relay normalize responses automatically."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Why normalize — avoiding duplicate data', freq: 80 },
      { topic: 'byId + allIds normalized shape', freq: 75 },
      { topic: 'createEntityAdapter in Redux Toolkit', freq: 65 },
      { topic: 'Selectors for denormalization at read time', freq: 65 },
    ]} />
  </div>
);

export const StaleWhileRevalidateLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#06b6d440' delay={0}>
      <div style={c.title('#06b6d4')}>🎬 Show Old Data Instantly, Fetch New Data Silently</div>
      <p style={c.prose}>
        Stale-While-Revalidate (SWR) is a caching strategy: <strong style={{ color: '#06b6d4' }}>serve cached data immediately</strong> even if it might be stale, then fetch fresh data in the background and update when it arrives. Zero loading spinners for cached data.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📰"
      title="A newspaper vs a live news ticker"
      analogy="When you open a newspaper app, you immediately see yesterday's news (stale cache) while today's news downloads in the background. The ticker updates to today's news the moment it's ready. You never stare at a loading spinner — you always have something to read. That's stale-while-revalidate."
      connection="On mount: serve from cache immediately (fast). Simultaneously: fetch fresh data in background. When fresh data arrives: update the UI silently. No spinner, no blank state, always responsive."
    />
    <StorySteps steps={[
      {
        title: 'The three states of cached data',
        color: '#06b6d4',
        desc: 'Fresh, stale, and gone. SWR serves stale data while fetching fresh.',
        code: `// React Query cache states:
const { data, isLoading, isFetching, isStale } = useQuery({
  queryKey: ['users'],
  queryFn: fetchUsers,

  staleTime: 60 * 1000,  // FRESH for 60 seconds — no refetch
  gcTime:    5 * 60 * 1000, // STALE but cached for 5 minutes

  // After staleTime: data is STALE
  // → Still served from cache immediately
  // → Refetch happens in background (isFetching=true)
  // → UI updates silently when fresh data arrives

  // After gcTime: data is GONE from cache
  // → isLoading=true, shows loading state
  // → Must wait for fresh fetch
});

// isLoading: true only when no cached data exists
// isFetching: true when fetching (even if cache hit)
// isStale: true when data is older than staleTime`,
      },
      {
        title: 'Background refetch triggers',
        color: '#4facfe',
        desc: 'React Query revalidates stale data on multiple triggers.',
        code: `const { data } = useQuery({
  queryKey: ['dashboard'],
  queryFn: fetchDashboard,
  staleTime: 30 * 1000,

  // When stale data is in cache, refetch on:
  refetchOnWindowFocus:    true,  // tab regains focus
  refetchOnReconnect:      true,  // internet reconnects
  refetchOnMount:          true,  // component mounts
  refetchInterval:         60000, // every 60s (polling)
  refetchIntervalInBackground: false, // only when tab active
});

// The magic: user sees INSTANT data on window focus
// (from cache) while fresh data loads silently in background
// When fresh data arrives → UI updates without any flash`,
      },
      {
        title: 'HTTP Cache-Control: stale-while-revalidate',
        color: '#00ff88',
        desc: 'The browser-level HTTP equivalent of the same pattern.',
        code: `// HTTP header — works at network level
// No JavaScript needed!
Cache-Control: public, max-age=60, stale-while-revalidate=300

// max-age=60: FRESH for 60 seconds — serve from cache
// stale-while-revalidate=300: for next 5 minutes:
//   → Serve stale cache immediately (fast!)
//   → Revalidate in background
//   → Next request gets fresh data

// Timeline:
// 0s:   Request 1 → MISS → fetch from server → cache
// 30s:  Request 2 → FRESH → serve from cache (no fetch)
// 90s:  Request 3 → STALE → serve from cache + bg fetch
// 120s: Request 4 → FRESH (bg fetch completed) → serve from cache
// 400s: Request 5 → EXPIRED → must fetch from server`,
      },
      {
        title: 'Placeholder and previous data patterns',
        color: '#a855f7',
        desc: 'Show previous data while fetching to avoid loading flashes.',
        code: `// placeholderData — show previous results while fetching new ones
function SearchResults({ query }) {
  const { data, isPlaceholderData } = useQuery({
    queryKey: ['search', query],
    queryFn: () => searchAPI(query),

    // While query changes and new results load,
    // show PREVIOUS results instead of spinner:
    placeholderData: keepPreviousData,
  });

  return (
    <div style={{ opacity: isPlaceholderData ? 0.5 : 1 }}>
      {data?.results.map(r => <Result key={r.id} item={r} />)}
      {isPlaceholderData && <span>Updating...</span>}
    </div>
  );
  // User sees results immediately on query change
  // Results fade slightly while new ones load
  // No blank state, no full spinner
}`,
      },
    ]} />
    <InlinePoll
      question="What is the difference between isLoading and isFetching in React Query?"
      options={[
        'They are identical',
        'isLoading: true only when there is NO cached data (first load). isFetching: true whenever a request is in flight — including background revalidation of stale cached data',
        'isFetching is deprecated in React Query v5',
        'isLoading is for mutations, isFetching is for queries',
      ]}
      correct={1}
      explanation="isLoading combines isFetching with no cached data. If you have stale cached data and React Query is refetching in the background: isFetching=true, isLoading=false. Show a subtle 'refreshing' indicator for isFetching, show a full loading spinner only for isLoading. This distinction enables the SWR pattern."
    />
    <CommonMistake
      mistake="Showing a full loading spinner on every isFetching — including background revalidations."
      fix="Only show a full spinner when isLoading is true (no cached data). For background revalidations (isFetching=true, isLoading=false), show a subtle indicator — a small spinner in the corner, reduced opacity, or 'Last updated: Xs ago'. Full spinners for background revalidation destroy the SWR UX benefit."
    />
    <DidYouKnow
      fact="SWR (stale-while-revalidate) was originally an HTTP RFC (RFC 5861) from 2010, years before React Query popularized it for client-side data. Vercel named their data fetching library 'SWR' after this exact caching strategy. The core insight predates the modern JavaScript ecosystem — it's a fundamental principle of cache design."
      color="#06b6d4"
    />
    <InterviewMeter topics={[
      { topic: 'What stale-while-revalidate means', freq: 85 },
      { topic: 'isLoading vs isFetching distinction', freq: 80 },
      { topic: 'staleTime and gcTime configuration', freq: 75 },
      { topic: 'HTTP Cache-Control SWR header', freq: 60 },
    ]} />
  </div>
);

export const WebpackLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f59e0b40' delay={0}>
      <div style={c.title('#f59e0b')}>🎬 How Webpack Turns Many Files Into One</div>
      <p style={c.prose}>
        Webpack starts at an entry point and follows every import — building a complete dependency graph of your entire application. Then it packages everything into optimized bundles. <strong style={{ color: '#f59e0b' }}>Understanding this graph is the key to understanding Webpack.</strong>
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🕸️"
      title="A spider building a web"
      analogy="A spider starts at one anchor point and follows threads outward, connecting everything into a complete web. Webpack starts at your entry file and follows every import statement — pulling in React, your components, CSS, images — until it has mapped your entire application."
      connection="Entry → follows imports → builds dependency graph → applies loaders to transform files → plugins modify the compilation → outputs optimized bundles."
    />
    <StorySteps steps={[
      {
        title: 'Entry, output and the dependency graph',
        color: '#f59e0b',
        desc: 'Webpack starts at entry and follows every import recursively.',
        code: `// webpack.config.js
const path = require('path');

module.exports = {
  // Start here — Webpack follows all imports from this file
  entry: './src/index.tsx',

  output: {
    path: path.resolve(__dirname, 'dist'),
    // [contenthash] changes when file content changes
    // → perfect for long-term browser caching
    filename: '[name].[contenthash:8].js',
    clean: true, // clean dist/ before each build
  },

  // Webpack resolves these extensions automatically
  resolve: {
    extensions: ['.tsx', '.ts', '.js'],
    alias: { '@': path.resolve(__dirname, 'src') },
  },
};`,
      },
      {
        title: 'Loaders — transform non-JS files',
        color: '#4facfe',
        desc: 'Loaders are applied right-to-left. Each loader transforms the file and passes to the next.',
        code: `module.exports = {
  module: {
    rules: [
      // TypeScript and JSX → JavaScript
      {
        test: /\\.tsx?$/,
        use: 'babel-loader',
        exclude: /node_modules/,
      },
      // CSS → JavaScript module (dev: injected, prod: extracted)
      {
        test: /\\.css$/,
        use: [
          'style-loader',  // 2nd: injects CSS into DOM
          'css-loader',    // 1st: resolves @import and url()
          'postcss-loader', // 0th: applies PostCSS transforms
        ], // right-to-left execution!
      },
      // Images → asset modules (Webpack 5 built-in)
      {
        test: /\\.(png|jpg|svg)$/,
        type: 'asset/resource',
      },
    ],
  },
};`,
      },
      {
        title: 'Plugins — extend the build process',
        color: '#00ff88',
        desc: 'Plugins hook into the entire compilation lifecycle — not just individual file transforms.',
        code: `const HtmlWebpackPlugin      = require('html-webpack-plugin');
const MiniCssExtractPlugin   = require('mini-css-extract-plugin');
const { BundleAnalyzerPlugin } = require('webpack-bundle-analyzer');

module.exports = {
  plugins: [
    // Generates index.html with correct bundle script tags
    new HtmlWebpackPlugin({
      template: './public/index.html',
      favicon: './public/favicon.ico',
    }),

    // Extracts CSS into separate files (production)
    new MiniCssExtractPlugin({
      filename: '[name].[contenthash:8].css',
    }),

    // Visualize bundle — only when ANALYZE=true
    process.env.ANALYZE && new BundleAnalyzerPlugin(),
  ].filter(Boolean),
};`,
      },
      {
        title: 'Code splitting and optimization',
        color: '#a855f7',
        desc: 'Split vendor code from app code. Lazy load routes. Maximize caching.',
        code: `module.exports = {
  mode: 'production',

  optimization: {
    // Split chunks automatically
    splitChunks: {
      chunks: 'all',
      cacheGroups: {
        // Vendor bundle — rarely changes, long cache
        vendor: {
          test: /[\\\\/]node_modules[\\\\/]/,
          name: 'vendor',
          chunks: 'all',
        },
      },
    },
    // Separate runtime — keeps vendor hash stable
    runtimeChunk: 'single',
  },
};

// In your React app — dynamic import creates a split point
const Dashboard = React.lazy(() => import('./pages/Dashboard'));
// → Dashboard becomes its own chunk, loads on demand`,
      },
    ]} />
    <InlinePoll
      question="What is the difference between a Webpack loader and a plugin?"
      options={[
        'They are the same',
        'Loader: transforms individual file types (CSS → JS, TS → JS). Plugin: hooks into the entire compilation — HTML generation, CSS extraction, bundle analysis, env variables',
        'Plugins are faster than loaders',
        'Loaders run in production only',
      ]}
      correct={1}
      explanation="Loaders operate on individual files during the module transformation step. Plugins hook into Webpack's event system and can operate on the entire compilation — before bundling starts, after chunks are created, when assets are emitted. They solve different problems."
    />
    <CommonMistake
      mistake="Using import _ from 'lodash' and being surprised that the entire 70KB library is in the bundle."
      fix="Named imports enable tree shaking: import { debounce } from 'lodash' still imports all of lodash because lodash uses CommonJS. Use lodash-es for ES module version: import { debounce } from 'lodash-es'. Or import the specific function directly: import debounce from 'lodash/debounce'."
    />
    <DidYouKnow
      fact="Webpack was created by Tobias Koppers in 2012. He started it as a side project to add code splitting to an existing bundler (Browserify) and ended up building something entirely new. At its peak Webpack had ~25 million weekly downloads. Despite competition from Vite and esbuild, Webpack 5 is still the most used bundler in production due to its maturity and ecosystem."
      color="#f59e0b"
    />
    <InterviewMeter topics={[
      { topic: 'Entry, output, loaders, plugins — what each does', freq: 85 },
      { topic: 'Code splitting and lazy loading', freq: 80 },
      { topic: 'Tree shaking requirements', freq: 75 },
      { topic: 'contenthash for caching strategy', freq: 65 },
    ]} />
  </div>
);

export const ViteLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f59e0b40' delay={0}>
      <div style={c.title('#f59e0b')}>🎬 Why Your Dev Server Starts in 300ms</div>
      <p style={c.prose}>
        Webpack bundles everything before serving. A 5000-module app waits 30+ seconds. Vite's insight: <strong style={{ color: '#f59e0b' }}>don't bundle in development at all.</strong> Serve native ES modules directly. The browser requests only what it needs.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="⚡"
      title="A library with instant card catalog vs reindexing all books"
      analogy="Webpack dev server reindexes every book before you can search — you wait for the full index to rebuild on every start. Vite is a card catalog that already knows where every book is — you request a specific book and it fetches just that one instantly. Adding new books doesn't require reindexing."
      connection="Vite dev server starts instantly by serving files as-is. Browser requests index.js → Vite transforms it → browser sees its imports → requests those → Vite transforms them. Only requested files are ever processed."
    />
    <StorySteps steps={[
      {
        title: 'The architecture difference',
        color: '#f59e0b',
        desc: 'Webpack bundles before serving. Vite serves then transforms on request.',
        code: `// WEBPACK DEV SERVER:
// 1. Start dev server command
// 2. Bundle ALL 5000 modules (30 seconds)
// 3. Only now: browser can load the page
// 4. Change one file → re-bundle affected modules (5+ seconds)

// VITE DEV SERVER:
// 1. Start dev server command
// 2. Pre-bundle node_modules only (ESBuild, ~2 seconds, cached)
// 3. Immediately: browser can load the page
// 4. Browser requests src/main.tsx
//    → Vite transforms just that file (~5ms)
//    → Browser sees its imports, requests those
//    → Vite transforms each on demand
// 5. Change one file → only that file transforms (~5ms)
// Scale doesn't matter — 100 or 10,000 modules: same speed`,
      },
      {
        title: 'Vite config — simple and powerful',
        color: '#4facfe',
        desc: 'Vite config is minimal by design. Most things work out of the box.',
        code: `// vite.config.ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [
    react(), // HMR, JSX transform, React Refresh
  ],

  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
      '@components': path.resolve(__dirname, './src/components'),
    },
  },

  server: {
    port: 3000,
    // Proxy API calls to backend in development
    proxy: {
      '/api': {
        target: 'http://localhost:8080',
        changeOrigin: true,
      },
    },
  },

  build: {
    sourcemap: true,
    rollupOptions: {
      output: {
        // Manual chunk splitting
        manualChunks: {
          'react-vendor': ['react', 'react-dom'],
          'router': ['react-router-dom'],
        },
      },
    },
  },
});`,
      },
      {
        title: 'HMR — instant feedback loop',
        color: '#00ff88',
        desc: 'Vite HMR updates only the changed module. State is preserved.',
        code: `// How Vite HMR works:
// 1. You save Button.tsx
// 2. Vite detects the file change
// 3. Sends a WebSocket message to the browser:
//    "Button.tsx changed, here's the new module"
// 4. Browser re-executes only Button.tsx
// 5. React Fast Refresh updates the component in place
//    — React state, scroll position preserved!

// Webpack HMR: re-bundles the entire module graph
// for the changed file's ancestors
// → Gets slower as app grows

// Vite HMR: re-transforms ONE file
// → Speed stays constant regardless of app size

// In your React component — this works with HMR:
export function Counter() {
  const [count, setCount] = useState(0);
  // Changing the JSX below preserves count value ✓
  return <button onClick={() => setCount(c => c + 1)}>
    Clicked {count} times
  </button>;
}`,
      },
      {
        title: 'Production build — Rollup under the hood',
        color: '#a855f7',
        desc: 'Vite uses Rollup for production — excellent tree shaking and code splitting.',
        code: `// npm run build → Rollup production build

// Output analysis:
// dist/
//   assets/
//     index-[hash].js          (your app code)
//     react-vendor-[hash].js   (react + react-dom)
//     router-[hash].js         (react-router)
//     Dashboard-[hash].js      (lazy loaded route)

// What Rollup gives you:
// ✓ Excellent tree shaking (ES module native)
// ✓ Automatic code splitting
// ✓ CSS code splitting
// ✓ Content-hash filenames (cache busting)
// ✓ Minification via ESBuild (faster than Terser)
// ✓ Source maps

// Always test production build before deploying:
npm run build && npm run preview
// preview serves the built dist/ locally`,
      },
    ]} />
    <InlinePoll
      question="Why does Vite's dev server start instantly regardless of project size?"
      options={[
        'Vite uses more memory to pre-cache everything',
        'Vite serves native ES modules without bundling — files are transformed on demand when the browser requests them, not all upfront',
        'Vite skips TypeScript checking',
        'Vite only supports small projects',
      ]}
      correct={1}
      explanation="Webpack must bundle the entire dependency graph before any page can load. Vite bypasses this by serving unbundled files — the browser requests files as needed and Vite transforms each one on demand using ESBuild (~5ms per file). Starting the server requires no upfront work beyond pre-bundling node_modules (done once, cached)."
    />
    <CommonMistake
      mistake="Assuming Vite's dev behavior matches production — testing only in dev mode."
      fix="Vite's dev server (native ESM, no bundling) and production build (Rollup) can behave differently. CommonJS packages that work in dev via pre-bundling might behave differently in production. Always run npm run build && npm run preview before deploying. Test the production build in CI."
    />
    <DidYouKnow
      fact="Vite was created by Evan You (Vue.js creator) in 2020 during lockdown. The name means 'fast' in French. It took less than a year to become the most-starred build tool on GitHub. The framework-agnostic design (works with React, Vue, Svelte, vanilla JS) and dramatically better DX fueled explosive adoption. As of 2024, Vite has over 22 million weekly downloads."
      color="#f59e0b"
    />
    <InterviewMeter topics={[
      { topic: 'Why Vite is faster in development', freq: 85 },
      { topic: 'Vite dev (ESBuild) vs production (Rollup)', freq: 75 },
      { topic: 'HMR and why it stays fast at scale', freq: 70 },
      { topic: 'Vite config — plugins, proxy, aliases', freq: 65 },
    ]} />
  </div>
);

export const RollupLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f59e0b40' delay={0}>
      <div style={c.title('#f59e0b')}>🎬 The Bundler Libraries Choose</div>
      <p style={c.prose}>
        React, Vue, Lodash, and most major npm packages are bundled with Rollup. It produces <strong style={{ color: '#f59e0b' }}>clean, minimal output</strong> without Webpack's module runtime boilerplate — perfect for libraries that will be bundled again by their consumers.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="✂️"
      title="A tailor vs a factory"
      analogy="A factory produces clothes with standard components that work for everyone. A tailor (Rollup) takes exact measurements and produces precisely what's needed — no excess material. For libraries, precision matters more than universality. Rollup's output is minimal, clean, and perfectly sized."
      connection="Rollup produces ES module output (.mjs) that other bundlers can tree-shake. Webpack's module system wrapping prevents downstream tree shaking. Libraries need Rollup's clean output."
    />
    <StorySteps steps={[
      {
        title: 'Why libraries use Rollup',
        color: '#f59e0b',
        desc: 'Rollup output is clean ES modules. Webpack output has a runtime module system — unnecessary in libraries.',
        code: `// INPUT: your library code
export function add(a, b) { return a + b; }
export function multiply(a, b) { return a * b; }

// ROLLUP OUTPUT (clean, consumer can tree-shake):
export { add, multiply };
// Consumer: import { add } from 'mylib'
// → multiply is tree-shaken away ✓

// WEBPACK OUTPUT (wrapped in runtime):
(function(modules) { // ← runtime module system
  var installedModules = {};
  function __webpack_require__(moduleId) { /* ... */ }
  return __webpack_require__(0);
})([function(module, exports) {
  exports.add = function(a, b) { return a + b; };
  exports.multiply = function(a, b) { return a * b; };
}]);
// Consumer can't easily tree-shake this ✗`,
      },
      {
        title: 'Rollup config for library output',
        color: '#4facfe',
        desc: 'Output multiple formats — ESM for modern bundlers, CJS for Node.js.',
        code: `// rollup.config.js
import typescript from '@rollup/plugin-typescript';
import { nodeResolve } from '@rollup/plugin-node-resolve';
import dts from 'rollup-plugin-dts';

export default [
  {
    input: 'src/index.ts',
    external: ['react', 'react-dom'], // don't bundle peer deps!
    plugins: [nodeResolve(), typescript()],
    output: [
      // ES modules — for modern bundlers (Webpack, Vite, Rollup)
      { file: 'dist/index.esm.js', format: 'esm', sourcemap: true },
      // CommonJS — for Node.js and older bundlers
      { file: 'dist/index.cjs.js', format: 'cjs', sourcemap: true },
    ],
  },
  // Type definitions bundle
  {
    input: 'src/index.ts',
    plugins: [dts()],
    output: { file: 'dist/index.d.ts', format: 'es' },
  },
];`,
      },
      {
        title: 'Tree shaking deep dive',
        color: '#00ff88',
        desc: 'How tree shaking works and why ES modules are required.',
        code: `// Tree shaking requires STATIC imports (ES modules)
// ✅ Static — can be analyzed at build time
import { add } from './math';
// Bundler knows: only 'add' is needed, remove 'multiply'

// ❌ Dynamic — can't be analyzed
const fn = require('./math')[someVariable]; // runtime decision
// Bundler can't know which exports are used → includes all

// Side effects matter for tree shaking:
// package.json
{
  "sideEffects": false // tell bundlers: safe to tree-shake
  // OR list files with side effects:
  "sideEffects": ["./src/polyfills.js", "*.css"]
}

// Without sideEffects: false, bundlers keep ALL imports
// even if nothing from them is explicitly used
// (CSS imports, polyfill files have side effects — include them)`,
      },
      {
        title: 'Scope hoisting — smaller and faster output',
        color: '#a855f7',
        desc: 'Rollup merges all modules into one scope — no function wrapper overhead.',
        code: `// BEFORE scope hoisting (each module in its own scope):
var module1 = (function() {
  var PI = 3.14159;
  return { area: function(r) { return PI * r * r; } };
})();

var module2 = (function() {
  return { volume: function(r) { return (4/3) * module1.area(r); } };
})();

// AFTER scope hoisting (flat, single scope):
var PI = 3.14159;
function area(r) { return PI * r * r; }
function volume(r) { return (4/3) * area(r); }

// Benefits:
// ✓ Smaller bundle (no IIFE wrappers)
// ✓ Faster execution (no closure overhead)
// ✓ Better minification (variable names can be shortened)`,
      },
    ]} />
    <InlinePoll
      question="Why must a library mark peerDependencies as 'external' in Rollup config?"
      options={[
        'To make the build faster',
        'So React/Vue are not bundled into the library — consumers already have React. Bundling it would cause two React instances on the page, breaking hooks',
        'External dependencies load faster',
        'Peer dependencies are automatically external',
      ]}
      correct={1}
      explanation="If a component library bundles React into its output, the consuming app has two React instances — the app's React and the library's React. React hooks require a single React instance. Always mark react and react-dom as external in library Rollup configs — they're peerDependencies that consumers provide."
    />
    <CommonMistake
      mistake="Forgetting to set sideEffects: false in package.json for a library with pure functions."
      fix="Without sideEffects: false, consumers' bundlers can't tree-shake your library. They must include every export 'just in case' it has side effects. Set sideEffects: false for pure libraries. List CSS files and polyfills explicitly: sideEffects: ['*.css', './src/polyfills.js']."
    />
    <DidYouKnow
      fact="Rollup was created by Rich Harris (creator of Svelte) in 2015. The scope hoisting innovation — inlining all modules into a single flat scope — inspired Webpack to add its own version (Module Concatenation Plugin / Scope Hoisting) in Webpack 3. Rich Harris coined the term 'tree shaking' for the technique of removing unused exports."
      color="#f59e0b"
    />
    <InterviewMeter topics={[
      { topic: 'Why libraries use Rollup over Webpack', freq: 75 },
      { topic: 'Tree shaking and ES module requirement', freq: 80 },
      { topic: 'sideEffects in package.json', freq: 65 },
      { topic: 'Scope hoisting benefits', freq: 60 },
    ]} />
  </div>
);

export const BabelLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f59e0b40' delay={0}>
      <div style={c.title('#f59e0b')}>🎬 Running Tomorrow's JavaScript Today</div>
      <p style={c.prose}>
        Babel lets you write modern JavaScript (ES2024, JSX, TypeScript) and run it in browsers that don't support it yet. It <strong style={{ color: '#f59e0b' }}>transforms syntax</strong> and optionally polyfills missing APIs — the translation layer between what you write and what browsers understand.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🌍"
      title="A universal translator"
      analogy="A UN translator lets a French diplomat speak to a Japanese diplomat — same message, different language. Babel is the universal translator between modern JavaScript and older browser dialects. You speak ES2024 with optional chaining and nullish coalescing. Babel translates it to ES5 that IE11 understands."
      connection="arrow functions → function expressions. const/let → var. JSX → React.createElement(). Optional chaining → if/else chains. Babel handles all of these transformations."
    />
    <StorySteps steps={[
      {
        title: 'How Babel works — the pipeline',
        color: '#f59e0b',
        desc: 'Parse → transform → generate. Plugins operate on the AST.',
        code: `// Your code:
const greet = (name) => \`Hello, \${name}!\`;

// Babel pipeline:
// 1. PARSE → Abstract Syntax Tree (AST)
// {
//   type: "VariableDeclaration",
//   kind: "const",
//   declarations: [{
//     type: "VariableDeclarator",
//     id: { type: "Identifier", name: "greet" },
//     init: {
//       type: "ArrowFunctionExpression",
//       ...
//     }
//   }]
// }

// 2. TRANSFORM → plugins modify the AST

// 3. GENERATE → output code from modified AST
// var greet = function(name) { return "Hello, " + name + "!"; };`,
      },
      {
        title: 'Presets — bundled plugin collections',
        color: '#4facfe',
        desc: '@babel/preset-env is the most important. It automatically determines which transforms to apply.',
        code: `// babel.config.json
{
  "presets": [
    // Smart browser targeting:
    ["@babel/preset-env", {
      "targets": "> 0.25%, not dead",
      // Only transforms syntax unsupported by target browsers
      // Modern browsers: very few transforms needed
      // IE11: many transforms needed

      // Polyfills via core-js:
      "useBuiltIns": "usage", // only polyfills you actually use
      "corejs": 3
    }],

    // JSX transformation:
    ["@babel/preset-react", {
      "runtime": "automatic" // no need to import React in every file
    }],

    // TypeScript (strips types only — no type checking!):
    "@babel/preset-typescript"
  ]
}`,
      },
      {
        title: 'Transpilation vs polyfilling',
        color: '#00ff88',
        desc: 'Two different problems — syntax and missing APIs.',
        code: `// TRANSPILATION — syntax transformation (Babel does this)
// Optional chaining (syntax)
const name = user?.profile?.name;
// → Babel transforms to:
const name = user === null ? void 0
  : user.profile === null ? void 0
  : user.profile.name;

// POLYFILLING — adding missing built-ins (core-js does this)
// Promise doesn't exist in IE11
// → core-js adds it:
if (!window.Promise) {
  window.Promise = PromisePolyfill;
}

// Array.prototype.flat doesn't exist in older Safari
// → core-js adds it:
if (!Array.prototype.flat) {
  Array.prototype.flat = function() { /* implementation */ };
}

// babel-polyfill (deprecated) → core-js 3 + regenerator-runtime`,
      },
      {
        title: 'Modern alternatives — SWC and ESBuild',
        color: '#a855f7',
        desc: 'Babel is being replaced in many projects by faster compiled alternatives.',
        code: `// BABEL: JavaScript → slow at scale
// Average transform time: ~200ms per file
// Large project (5000 files): minutes

// SWC (Rust): used by Next.js 13+, Parcel 2
// 17x faster than Babel (Next.js benchmark)
// Drop-in replacement for babel-jest in Jest

// ESBuild (Go): used by Vite, esbuild
// 100x faster than Babel
// But: less extensible, fewer plugins

// Migrate Jest to SWC:
// jest.config.js
module.exports = {
  transform: {
    '^.+\\.(t|j)sx?$': ['@swc/jest'],
    // Replaces: '^.+\\.(t|j)sx?$': ['babel-jest']
  },
};

// next.config.js (Next.js uses SWC by default since v12):
module.exports = {
  swcMinify: true, // SWC minifier instead of Terser
};`,
      },
    ]} />
    <InlinePoll
      question="What is the difference between Babel transpilation and polyfilling?"
      options={[
        'They are the same process',
        'Transpilation converts new syntax to old syntax (arrow functions → function). Polyfilling adds missing built-in APIs (Promise, Array.flat) to environments that lack them',
        'Polyfilling is faster than transpilation',
        'Babel only does polyfilling',
      ]}
      correct={1}
      explanation="Transpilation is syntax transformation — @babel/preset-env converts optional chaining and arrow functions to equivalent ES5 code. Polyfilling adds missing runtime APIs — core-js adds Promise, fetch, Array.prototype.flat to browsers that don't have them. Babel handles transpilation. core-js (via preset-env's useBuiltIns) handles polyfills."
    />
    <CommonMistake
      mistake="Using @babel/preset-typescript and thinking TypeScript errors will be caught."
      fix="Babel strips TypeScript types without type checking — it ignores all type errors and just removes the annotations. For actual type safety, run tsc --noEmit separately in your CI pipeline. Many projects use Babel for fast transformation and tsc only for type checking — best of both worlds."
    />
    <DidYouKnow
      fact="Babel was created by Sebastian McKenzie as a high school student in Australia in 2014 (originally called 6to5). He wrote it during school holidays. It was later renamed Babel after the biblical Tower of Babel — a structure where people spoke different languages. The project is now maintained by a team and used by virtually every React project."
      color="#f59e0b"
    />
    <InterviewMeter topics={[
      { topic: 'Babel pipeline: parse, transform, generate', freq: 70 },
      { topic: 'Transpilation vs polyfilling difference', freq: 80 },
      { topic: '@babel/preset-env browser targeting', freq: 75 },
      { topic: 'SWC and ESBuild as faster alternatives', freq: 70 },
    ]} />
  </div>
);

export const TsconfigLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f59e0b40' delay={0}>
      <div style={c.title('#f59e0b')}>🎬 Configuring TypeScript to Catch More Bugs</div>
      <p style={c.prose}>
        tsconfig.json is more than a settings file — it determines <strong style={{ color: '#f59e0b' }}>how strictly TypeScript checks your code</strong>. The right configuration catches bugs before they reach runtime. The wrong configuration gives you TypeScript in name only.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🔬"
      title="A microscope with adjustable magnification"
      analogy="A microscope at low magnification misses details — you see the big picture but not the bacteria. High magnification reveals everything. TypeScript's strict settings are the magnification — low strictness misses type errors, high strictness catches them all. Most teams set it to maximum."
      connection="strict: true enables all strict checks. Each check catches a different class of bug. noImplicitAny catches untyped values. strictNullChecks catches null dereferences. Together they eliminate entire bug categories."
    />
    <StorySteps steps={[
      {
        title: 'The essential compiler options',
        color: '#f59e0b',
        desc: 'The options every TypeScript project should configure.',
        code: `{
  "compilerOptions": {
    // STRICTNESS — always enable
    "strict": true,                    // enables all strict flags
    // strict: true is shorthand for:
    //   strictNullChecks: true        (null/undefined must be handled)
    //   noImplicitAny: true           (all values must have types)
    //   strictFunctionTypes: true     (function parameter contravariance)
    //   strictPropertyInitialization: true
    //   noImplicitThis: true
    //   alwaysStrict: true            (use strict in output)

    // OUTPUT — what JS to produce
    "target": "ES2020",               // output syntax
    "module": "ESNext",               // module system
    "moduleResolution": "bundler",    // for Vite/Webpack (TS 5+)
    "lib": ["ES2020", "DOM", "DOM.Iterable"],

    // REACT
    "jsx": "react-jsx",               // new JSX transform
    "noEmit": true,                   // type check only, bundler emits

    // QUALITY
    "noUnusedLocals": true,           // unused variable error
    "noUnusedParameters": true,       // unused param error
    "noFallthroughCasesInSwitch": true,
    "exactOptionalPropertyTypes": true
  }
}`,
      },
      {
        title: 'Path aliases — clean imports',
        color: '#4facfe',
        desc: 'Configure once in tsconfig, then match in your bundler.',
        code: `// tsconfig.json
{
  "compilerOptions": {
    "baseUrl": ".",
    "paths": {
      "@/*":            ["src/*"],
      "@components/*": ["src/components/*"],
      "@hooks/*":       ["src/hooks/*"],
      "@utils/*":       ["src/utils/*"]
    }
  }
}

// Now use clean imports:
import { Button } from '@/components/Button';
// Instead of:
import { Button } from '../../../components/Button';

// IMPORTANT: tsconfig paths are for type checking ONLY
// Must also configure in bundler:

// vite.config.ts:
resolve: { alias: { '@': path.resolve(__dirname, './src') } }

// webpack.config.js:
resolve: { alias: { '@': path.resolve(__dirname, 'src') } }`,
      },
      {
        title: 'Project references — monorepo optimization',
        color: '#00ff88',
        desc: 'composite: true enables incremental compilation for monorepos.',
        code: `// packages/ui/tsconfig.json
{
  "compilerOptions": {
    "composite": true,           // enables project references
    "declaration": true,         // emit .d.ts files
    "declarationMap": true       // source maps for .d.ts
  }
}

// apps/web/tsconfig.json
{
  "compilerOptions": { "strict": true },
  "references": [
    { "path": "../../packages/ui" },   // depends on ui package
    { "path": "../../packages/utils" } // depends on utils package
  ]
}

// Build with:
// tsc --build (or tsc -b)
// Only rebuilds changed packages and their dependents
// 10-package monorepo: from 60s full build → 2s incremental`,
      },
      {
        title: 'Strict mode catches — examples',
        color: '#a855f7',
        desc: 'What each strict flag actually prevents.',
        code: `// strictNullChecks: prevents null dereference
function getLength(str: string | null) {
  return str.length; // ❌ Error: str might be null
  return str?.length ?? 0; // ✓ handled
}

// noImplicitAny: forces explicit types
function process(data) { // ❌ Error: data has implicit 'any'
  return data.value;
}
function process(data: { value: string }) { return data.value; } // ✓

// exactOptionalPropertyTypes: distinguishes undefined vs missing
interface Config {
  timeout?: number; // optional
}
const config: Config = { timeout: undefined }; // ❌ with exactOptional
const config: Config = {};                      // ✓ (property absent)
const config: Config = { timeout: 5000 };       // ✓ (property present)`,
      },
    ]} />
    <InlinePoll
      question="tsconfig.json paths are configured correctly but imports still fail at runtime. Why?"
      options={[
        'TypeScript paths don\'t work with modern projects',
        'tsconfig paths are for type checking only — they don\'t affect the actual module resolution at runtime. The bundler (Vite/Webpack) must also have matching alias configuration',
        'Paths require TypeScript 5+',
        'The paths syntax is wrong',
      ]}
      correct={1}
      explanation="TypeScript paths tell the type checker where to find types — but TypeScript with noEmit: true doesn't transform the imports. The bundler sees the original @/ path and can't resolve it. Configure matching aliases in vite.config.ts (resolve.alias) or webpack.config.js (resolve.alias) separately."
    />
    <CommonMistake
      mistake="Not enabling strict: true and being surprised by null dereference errors in production."
      fix="Without strictNullChecks (part of strict: true), TypeScript allows null/undefined anywhere without checking. You get the appearance of TypeScript with none of the protection. Always start with strict: true. If migrating a JS project, enable strict gradually per file using // @ts-strict-ignore or ts-migrate."
    />
    <DidYouKnow
      fact="TypeScript was created by Anders Hejlsberg at Microsoft — the same person who designed C# and Turbo Pascal. It was announced in 2012 and became open source immediately. The strict mode flags were added gradually over TypeScript versions. TypeScript 5.0 (2023) introduced the 'bundler' moduleResolution mode specifically for Vite and modern bundlers."
      color="#f59e0b"
    />
    <InterviewMeter topics={[
      { topic: 'strict: true and what it enables', freq: 85 },
      { topic: 'target vs module options', freq: 75 },
      { topic: 'Paths aliases and bundler config', freq: 70 },
      { topic: 'noEmit: true for type-check-only', freq: 65 },
    ]} />
  </div>
);

