        title: 'Code splitting strategy',
        color: '#00ff88',
        desc: 'Split by route and by heavy features. Never split small components.',
        code: `// ROUTE-BASED SPLITTING — the minimum you should do
const Home      = lazy(() => import('./pages/Home'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Settings  = lazy(() => import('./pages/Settings'));
// Each route is a separate chunk — users download only what they visit

// FEATURE-BASED SPLITTING — heavy features
const RichTextEditor = lazy(() => import('./components/Editor'));
const DataGrid       = lazy(() => import('./components/DataGrid'));
const VideoPlayer    = lazy(() => import('./components/VideoPlayer'));
// These are large — only load when actually needed

// PREFETCH ON HOVER — zero wait time on navigation
function NavLink({ to, chunk, children }) {
  const prefetch = () => import(\`./pages/\${chunk}\`); // start download
  return (
    <Link to={to} onMouseEnter={prefetch}>
      {children}
    </Link>
  );
}
// By the time user clicks, chunk is already downloaded

// DON'T split:
// - Small components (network request > savings)
// - Components used on initial load
// - Things that load in < 50ms anyway`,
