export const MCRBACLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#00ff8840' delay={0}>
      <div style={c.title('#00ff88')}>🎬 Role-Based Access Control in React</div>
      <p style={c.prose}>
        RBAC in React is a <strong style={{ color: '#00ff88' }}>two-layer problem</strong>: frontend hides UI elements (UX) and backend enforces permissions (security). The senior answer implements both and never trusts the client alone.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏢"
      title="An office building"
      analogy="A receptionist checks your badge (authentication). Different floors have keycard readers that check your clearance level (authorization/RBAC). A visitor badge lets you in the lobby but not the server room. The keycard system (backend) is real security — the receptionist greeting (frontend) is just UX."
      connection="Frontend RBAC = receptionist. Backend RBAC = keycard readers. Never rely on just the receptionist."
    />
    <StorySteps steps={[
      {
        title: 'Auth context with permissions',
        color: '#00ff88',
        desc: 'Store user, roles, and permissions. Expose helper functions.',
        code: `// auth-context.tsx
const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);

  const login = async (credentials) => {
    const { user, accessToken } = await api.login(credentials);
    // Decode JWT to get roles (client-side, for UI only)
    const { roles, permissions } = jwtDecode(accessToken);
    setUser({ ...user, roles, permissions });
  };

  const hasRole = useCallback((role) => {
    return user?.roles?.includes(role) ?? false;
  }, [user]);

  const can = useCallback((permission) => {
    return user?.permissions?.includes(permission) ?? false;
  }, [user]);

  return (
    <AuthContext.Provider value={{ user, login, hasRole, can }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);

// Usage anywhere:
const { can, hasRole } = useAuth();
can('delete_user')     // true/false
hasRole('admin')       // true/false`,
      },
      {
        title: 'Route guards',
        color: '#4facfe',
        desc: 'ProtectedRoute wraps react-router routes. Redirects to login or 403.',
        code: `function ProtectedRoute({ requiredPermission, requiredRole, children }) {
  const { user, can, hasRole } = useAuth();

  // Not logged in → redirect to login
  if (!user) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  // Logged in but wrong role/permission → 403
  if (requiredRole && !hasRole(requiredRole)) {
    return <Navigate to="/403" replace />;
  }
  if (requiredPermission && !can(requiredPermission)) {
    return <Navigate to="/403" replace />;
  }

  return children;
}

// Usage in router:
<Routes>
  <Route path="/"      element={<Home />} />
  <Route path="/admin" element={
    <ProtectedRoute requiredRole="admin">
      <AdminDashboard />
    </ProtectedRoute>
  } />
  <Route path="/settings" element={
    <ProtectedRoute requiredPermission="edit_settings">
      <Settings />
    </ProtectedRoute>
  } />
  <Route path="/403" element={<Forbidden />} />
</Routes>`,
      },
      {
        title: 'Component-level permission gates',
        color: '#a855f7',
        desc: 'Can component hides UI elements. Never rely on this for security.',
        code: `// Permission gate component
function Can({ permission, role, fallback = null, children }) {
  const { can, hasRole } = useAuth();

  const allowed =
    (permission && can(permission)) ||
    (role && hasRole(role)) ||
    (!permission && !role); // no restriction specified

  return allowed ? children : fallback;
}

// Usage throughout the app:
function UserTable({ users }) {
  return (
    <table>
      {users.map(user => (
        <tr key={user.id}>
          <td>{user.name}</td>
          <td>
            {/* Edit button — only editors and admins see this */}
            <Can permission="edit_user">
              <button onClick={() => editUser(user.id)}>Edit</button>
            </Can>

            {/* Delete button — only admins see this */}
            <Can role="admin" fallback={<span title="Admin only">🔒</span>}>
              <button onClick={() => deleteUser(user.id)}>Delete</button>
            </Can>
          </td>
        </tr>
      ))}
    </table>
  );
}

// ⚠️ IMPORTANT: These are cosmetic only!
// A user can open DevTools and remove these components.
// The DELETE /api/users/:id endpoint MUST also check permissions server-side.`,
      },
    ]} />
    <InlinePoll
      question="A user with role='viewer' opens DevTools and removes the Can component wrapping a Delete button. They click Delete. What happens?"
      options={['Nothing — React prevents it', 'The API call fires but the server rejects it with 403 if backend RBAC is implemented correctly', 'The user is deleted — frontend RBAC is real security', 'The browser blocks the request']}
      correct={1}
      explanation="Frontend RBAC is cosmetic UX, not security. Any user can manipulate the DOM or call APIs directly. The backend API endpoint must check the JWT claims server-side on every request. Frontend checks = good UX. Backend checks = actual security."
    />
    <CommonMistake
      mistake="Only implementing frontend RBAC — hiding buttons without protecting the API endpoints."
      fix="Every sensitive API endpoint must verify: 1) Valid JWT signature, 2) Token not expired, 3) User has required permission/role for this specific operation. Express middleware: checkPermission('delete_user') before the route handler."
    />
    <DidYouKnow
      fact="The concept of Role-Based Access Control was formalized by NIST (National Institute of Standards and Technology) in 1992. Before RBAC, systems used ACLs (Access Control Lists) which assigned permissions directly to users. RBAC assigns permissions to roles, roles to users — much more manageable at scale. Today, most enterprise software (AWS IAM, Google Cloud, GitHub) uses RBAC as the foundation."
      color="#00ff88"
    />
    <InterviewMeter topics={[
      { topic: 'Auth context with roles and permissions', freq: 85 },
      { topic: 'ProtectedRoute component for route guards', freq: 90 },
      { topic: 'Component-level Can permission gate', freq: 80 },
      { topic: 'Frontend RBAC is UX, backend RBAC is security', freq: 90 },
      { topic: 'JWT role claims and server-side verification', freq: 80 },
    ]} />
  </div>
);

export const DBReactRendersLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Hunting Down Unnecessary Re-renders</div>
      <p style={c.prose}>
        Unnecessary re-renders are the most common React performance issue. The process is always the same: <strong style={{ color: '#eab308' }}>profile first, find the exact cause, apply the minimal fix</strong>. Never guess and add memo everywhere.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🔬"
      title="A doctor diagnosing a symptom"
      analogy="A good doctor doesn't prescribe medicine before running tests. They profile the patient (React DevTools), identify the specific pathogen (which prop changed), then prescribe targeted treatment (useCallback/useMemo). Prescribing randomly wastes everyone's time."
      connection="Profile first (DevTools Profiler) → identify cause ('Why did this render?') → fix specifically (useMemo/useCallback/split context). Never add React.memo blindly."
    />
    <StorySteps steps={[
      {
        title: 'React DevTools Profiler — the primary tool',
        color: '#eab308',
        desc: 'Record an interaction, find the components that rendered, click one to see exactly why.',
        code: `// WORKFLOW:
// 1. Open React DevTools → Profiler tab
// 2. Click the Record button (circle icon)
// 3. Interact with the slow part of your app
// 4. Click Stop
// 5. See the flame chart — each colored bar = a render
// 6. Click any rendered component
// 7. Look at "Why did this render?" panel:
//    - "Prop 'onClick' changed"
//    - "State 'count' changed"
//    - "Context value changed"
//    - "This is the first time the component rendered"

// 8. Gray bars = component DIDN'T re-render (good)
//    Colored bars = component DID re-render (investigate)

// KEY INSIGHT: React DevTools shows the EXACT prop name
// that changed — no guesswork needed.`,
      },
      {
        title: 'why-did-you-render — console-based debugging',
        color: '#4facfe',
        desc: 'Logs re-renders to console with deep diffs. Catches "same value, different reference" instantly.',
        code: `// Install: npm i @welldone-software/why-did-you-render

// src/wdyr.ts (import before React)
import React from 'react';
if (process.env.NODE_ENV === 'development') {
  const whyDidYouRender = require('@welldone-software/why-did-you-render');
  whyDidYouRender(React, { trackAllPureComponents: false });
}

// Enable on specific components:
MyComponent.whyDidYouRender = true;

// OR with extra info:
MyComponent.whyDidYouRender = {
  logOnDifferentValues: true,  // log even when values look the same
  customName: 'MyComponent',
};

// Console output:
// [why-did-you-render] MyComponent re-rendered
// because of prop changes:
//   {config: {color: "red"}} !== {config: {color: "red"}}
//   (same value, different reference!)
// Fix: memoize config with useMemo`,
      },
      {
        title: 'The three most common causes and their fixes',
        color: '#00ff88',
        desc: 'Inline objects/functions and unstable context are the culprits 90% of the time.',
        code: `// CAUSE 1: Inline object prop
// ❌ New {} on every render
<Child config={{ theme: 'dark', size: 'lg' }} />

// ✅ Stable reference
const config = useMemo(() => ({ theme: 'dark', size: 'lg' }), []);
<Child config={config} />

// CAUSE 2: Inline function prop
// ❌ New function on every render
<Child onClick={() => handleClick(id)} />

// ✅ Stable reference
const handleClickMemo = useCallback(() => handleClick(id), [id]);
<Child onClick={handleClickMemo} />

// CAUSE 3: Context value not memoized
// ❌ New object on every provider render
<ThemeContext.Provider value={{ theme, setTheme }}>

// ✅ Stable value
const value = useMemo(() => ({ theme, setTheme }), [theme]);
<ThemeContext.Provider value={value}>`,
      },
      {
        title: 'Children-as-props — the no-memo trick',
        color: '#a855f7',
        desc: 'Pass expensive components as children to a stateful parent. The owner never re-renders, so children are stable.',
        code: `// PROBLEM: ExpensiveList re-renders when count changes
function Parent() {
  const [count, setCount] = useState(0);
  return (
    <>
      <button onClick={() => setCount(c => c+1)}>{count}</button>
      <ExpensiveList items={items} /> {/* re-renders on count change */}
    </>
  );
}

// SOLUTION: Children as props — no memo needed
function App() {
  return (
    <Counter>
      <ExpensiveList items={items} />  {/* App doesn't re-render */}
    </Counter>
  );
}

function Counter({ children }) {
  const [count, setCount] = useState(0);
  return (
    <>
      <button onClick={() => setCount(c => c+1)}>{count}</button>
      {children}  {/* same JSX element reference from App → no re-render */}
    </>
  );
}
// Works because: Counter re-renders, but App (ExpensiveList's owner) doesn't.
// React sees the same children element reference → skips re-rendering it.`,
      },
    ]} />
    <InlinePoll
      question="React DevTools Profiler shows: 'Component re-rendered because prop onClick changed.' But the function logic hasn't changed. What is the fix?"
      options={['Add React.memo to the component', 'Wrap the onClick handler in useCallback in the parent — each render creates a new function reference without useCallback', 'Remove the onClick prop', 'Use Redux instead']}
      correct={1}
      explanation="() => handleSubmit(id) creates a brand new function on every parent render. React.memo does reference comparison — new function = different prop = re-render. useCallback(fn, [id]) returns the same function reference when id hasn't changed."
    />
    <CommonMistake
      mistake="Adding React.memo, useMemo, and useCallback everywhere as a 'best practice' without profiling first."
      fix="Memoization has real overhead: comparison cost, closure allocation, cognitive complexity. Profile first. Apply only where DevTools shows actual unnecessary renders. The React Compiler (React Forget) aims to automate this — until then, profile before you optimize."
    />
    <DidYouKnow
      fact="The React DevTools Profiler was added in React 16.5 (2018) and completely changed how teams debug performance. Before it, developers used console.log in render methods or added timing around components manually. The 'Why did this render?' feature was specifically requested by the community — it was added after React DevTools v4.0 in 2019."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'React DevTools Profiler workflow', freq: 90 },
      { topic: 'Why did this render? — identifying exact cause', freq: 85 },
      { topic: 'Inline objects/functions as root cause', freq: 85 },
      { topic: 'Children-as-props optimization', freq: 70 },
    ]} />
  </div>
);

export const DBMemoryLeakLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Finding and Fixing Memory Leaks</div>
      <p style={c.prose}>
        Memory leaks cause apps to slow down over time and eventually crash. The toolkit: <strong style={{ color: '#eab308' }}>Chrome Memory panel for heap snapshots, Performance Monitor for leak detection, and systematic cleanup patterns</strong>.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🚰"
      title="A water pipe with a slow drip"
      analogy="A memory leak is like a pipe dripping into a bucket. The bucket (heap) slowly fills. The app doesn't crash immediately — it just gets heavier and slower over time until it overflows (out-of-memory crash). Finding the leak: watch the bucket, trace the drip, seal the pipe."
      connection="Performance Monitor watches heap size (the bucket). Heap snapshots find what's growing (the drip). useEffect cleanup seals the pipe."
    />
    <StorySteps steps={[
      {
        title: 'Detecting leaks with Performance Monitor',
        color: '#eab308',
        desc: 'Watch JS heap size over time. Continuous growth = leak.',
        code: `// DETECTION WORKFLOW:
// 1. Open Chrome DevTools
// 2. More Tools → Performance monitor
// 3. Watch: JS heap size, DOM Nodes, Event Listeners
//
// HEALTHY pattern (sawtooth):
//    heap: ████▁████▁████▁ (grows then drops on GC)
//
// LEAKING pattern (upward slope):
//    heap: ████████████████ (never fully drops)
//
// 4. Navigate to the suspected page/feature
// 5. Interact repeatedly (open modal 10 times, navigate back/forth)
// 6. Watch if heap size resets or keeps growing
//
// DOM Nodes growing = detached DOM nodes
// Event Listeners growing = forgotten removeEventListener
// JS Heap growing = closures holding large objects`,
      },
      {
        title: 'Heap snapshots — finding what leaked',
        color: '#4facfe',
        desc: 'Compare two snapshots to find objects that grew between them.',
        code: `// HEAP SNAPSHOT WORKFLOW:
// 1. DevTools → Memory → Heap snapshot
// 2. Take Snapshot 1 (baseline)
// 3. Interact with the leaking feature (e.g., navigate back/forth 10x)
// 4. Take Snapshot 2
// 5. In Snapshot 2, select "Comparison" view
// 6. Sort by "#Delta" (count added - removed)
// 7. Look for:
//    - Your component names (e.g., +10 UserProfile instances)
//    - "(closure)" entries with large retained sizes
//    - "Detached HTMLElement" entries
//
// READING THE TABLE:
// Constructor  | #New | #Deleted | #Delta | Alloc Size
// UserProfile  |  10  |    0     |  +10   |  2.4 MB
// ↑ 10 instances created, none garbage collected = LEAK
//
// Click the leak to see its retainer chain:
// who is holding a reference preventing GC?`,
      },
      {
        title: 'The three most common React memory leaks',
        color: '#00ff88',
        desc: 'Event listeners, subscriptions, and async callbacks — all need cleanup.',
        code: `// LEAK 1: Event listener without cleanup
// ❌
useEffect(() => {
  window.addEventListener('resize', handleResize);
  // Forgot cleanup! handler holds component reference.
}, []);

// ✅
useEffect(() => {
  window.addEventListener('resize', handleResize);
  return () => window.removeEventListener('resize', handleResize);
}, []);

// LEAK 2: WebSocket / subscription without cleanup
// ❌
useEffect(() => {
  const ws = new WebSocket('wss://...');
  ws.onmessage = (e) => setData(JSON.parse(e.data));
  // ws never closed!
}, []);

// ✅
useEffect(() => {
  const ws = new WebSocket('wss://...');
  ws.onmessage = (e) => setData(JSON.parse(e.data));
  return () => ws.close();
}, []);

// LEAK 3: async callback after unmount
// ❌
useEffect(() => {
  fetchData().then(data => setData(data)); // setState after unmount
}, []);

// ✅
useEffect(() => {
  let cancelled = false;
  fetchData().then(data => { if (!cancelled) setData(data); });
  return () => { cancelled = true; };
}, []);`,
      },
      {
        title: 'Detached DOM nodes — the invisible leak',
        color: '#a855f7',
        desc: 'DOM elements removed from the page but still referenced by JS.',
        code: `// HOW IT HAPPENS:
function App() {
  const [items, setItems] = useState([]);
  const refs = useRef({}); // keeps DOM refs of items

  function addItem(id) {
    const el = document.createElement('div');
    document.body.appendChild(el);
    refs.current[id] = el; // stored reference
  }

  function removeItem(id) {
    const el = refs.current[id];
    el.remove(); // removed from DOM
    // ❌ refs.current[id] still exists → detached node → LEAK
    // ✅ delete refs.current[id]; // release the reference
  }
}

// DETECTING IN DEVTOOLS:
// Heap snapshot → search "Detached"
// Will show: "Detached HTMLDivElement", "Detached HTMLButtonElement"
// Retainer shows WHICH JS object holds the reference

// COMMON CAUSES:
// - caching DOM nodes in arrays/objects without cleanup
// - React refs on unmounted components (less common in modern React)
// - Third-party libraries that cache DOM elements`,
      },
    ]} />
    <InlinePoll
      question="After opening and closing a modal 20 times, JS heap size has grown from 15MB to 45MB and never drops. What tool do you use next?"
      options={['React DevTools Profiler', 'Chrome Memory panel → Heap snapshot comparison between before and after the interactions — find what grew by #Delta', 'Network tab', 'Performance Monitor (you\'re already using it)']}
      correct={1}
      explanation="Performance Monitor confirmed the leak (heap growing). Now use Heap Snapshots to find WHAT is leaking. Take snapshot before → interact 20 times → snapshot after → Comparison view → sort by #Delta → find Modal component instances or event listeners that weren't cleaned up."
    />
    <CommonMistake
      mistake="Adding cleanup to useEffect only when React shows a warning about updating unmounted components."
      fix="React 18 removed that warning, but leaks still happen. Add cleanup for ALL effects that set up external subscriptions, event listeners, timers, or async operations. The rule: if you 'turn something on' in useEffect, turn it off in the cleanup."
    />
    <DidYouKnow
      fact="Gmail has historically had severe memory leak issues — power users who keep it open for weeks see it consume 2GB+ of RAM. Google's Chrome team built the Memory DevTools specifically to help debug these issues. The heap snapshot comparison feature was inspired by V8 engineers debugging Node.js production servers where memory leaks are immediately dangerous."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Performance Monitor to detect leak', freq: 80 },
      { topic: 'Heap snapshot comparison workflow', freq: 85 },
      { topic: 'useEffect cleanup for event listeners', freq: 90 },
      { topic: 'Detached DOM nodes', freq: 75 },
    ]} />
  </div>
);

export const DBNetworkLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Reading the Network Waterfall</div>
      <p style={c.prose}>
        The Network waterfall tells the complete story of page load. <strong style={{ color: '#eab308' }}>Every colored bar, every stacked request, every timing number</strong> is a clue. Senior engineers can diagnose most performance issues from the waterfall alone.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🏗️"
      title="A construction project timeline"
      analogy="A Gantt chart shows which construction tasks run in parallel and which are blocked waiting for prerequisites. The network waterfall is identical — each bar is a resource, horizontal position is time, gaps show waiting, parallel bars are concurrent requests."
      connection="Long bars = slow resources. Stacked (serial) bars = blocked by previous resource. Wide yellow bar = server slow. Wide blue bar = large file."
    />
    <StorySteps steps={[
      {
        title: 'Reading timing breakdown',
        color: '#eab308',
        desc: 'Each request has phases. Each phase tells a different story.',
        code: `// WATERFALL BAR COLORS (hover any request → Timing tab):

// 🔵 Queued/Stalled (light gray):
//   HTTP/1.1 browser limit: max 6 parallel connections per host
//   Fix: HTTP/2 (multiplexing), CDN, fewer requests

// 🟡 DNS Lookup (gray):
//   Resolving hostname to IP address
//   Usually <20ms. High = no DNS prefetch
//   Fix: <link rel="dns-prefetch" href="//api.example.com">

// 🟠 Initial connection + SSL:
//   TCP handshake + TLS negotiation
//   Usually 50-200ms. High = far server, no keepalive
//   Fix: <link rel="preconnect" href="//api.example.com">

// 🟡 Waiting (TTFB - Time to First Byte):
//   Server processing time — the most important metric
//   Good: <200ms. Concern: >600ms. Problem: >1500ms
//   Fix: faster server, caching, CDN, database optimization

// 🔵 Content Download (blue):
//   Transferring bytes over the network
//   Proportional to file size × connection speed
//   Fix: compression, code splitting, image optimization`,
      },
      {
        title: 'Identifying the critical rendering path',
        color: '#4facfe',
        desc: 'Find the chain that blocks your first render.',
        code: `// WHAT TO LOOK FOR:

// 1. RENDER-BLOCKING RESOURCES (red triangle icon):
//    CSS and sync scripts block rendering
//    They appear early in waterfall — everything waits for them
//    Fix: defer/async scripts, inline critical CSS

// 2. LONG WATERFALL CHAINS:
//    HTML → discovers CSS → CSS downloads
//    HTML → discovers font URL in CSS → font downloads
//    Each requires the previous to complete
//    Fix: preload fonts: <link rel="preload" as="font" href="font.woff2">

// 3. REQUEST QUEUING (stacked bars at same time):
//    HTTP/1.1: see groups of 6 requests, then next group
//    HTTP/2: all requests start immediately (no stacking)
//    Check Response Headers for HTTP version:
//    "HTTP/2 200" = good, "HTTP/1.1 200" = upgrade needed

// 4. LARGE vs SLOW:
//    Long blue bar (download) = large file → compress/split
//    Long yellow bar (TTFB)   = slow server → cache/CDN
//    Understanding this prevents fixing the wrong thing!`,
      },
      {
        title: 'Key Network panel features',
        color: '#00ff88',
        desc: 'Filter, throttle, and measure to diagnose precisely.',
        code: `// USEFUL NETWORK PANEL TRICKS:

// 1. THROTTLING — simulate slow connections
//    Network panel → throttle dropdown → "Slow 3G"
//    See what mobile users on poor connections experience
//    Most critical for: LCP, TTFB, render-blocking CSS

// 2. FILTER by type
//    Buttons: All | Fetch/XHR | JS | CSS | Img | Media | Font | Doc | WS
//    XHR/Fetch: find slow API calls
//    Font: find render-blocking font requests

// 3. SIZE vs TRANSFERRED columns
//    Size: uncompressed (what browser parses, what CPU processes)
//    Transferred: compressed (what travels over network)
//    If equal: compression NOT enabled on server → missed optimization
//    Good JS: Size 400KB, Transferred 120KB (70% compression)

// 4. INITIATOR column
//    Shows which file/line caused this request
//    Click to jump to source
//    Find: which component is making too many API calls

// 5. WATERFALL column
//    Right-click header → add "Priority" column
//    "Highest" = render-blocking. "Low" = lazy loaded.
//    Everything "Highest" that doesn't need to be = fix priority`,
      },
    ]} />
    <InlinePoll
      question="Network panel shows 20 requests all starting at the same time with no queuing. TTFB is 50ms for each but the page still loads slowly. What is the bottleneck?"
      options={['Server is slow (high TTFB)', 'Files are large — 20 × large files downloading in parallel still takes time. Check the download (blue bar) width and file sizes.', 'DNS resolution', 'Browser limit reached']}
      correct={1}
      explanation="No queuing = HTTP/2 working. Low TTFB (50ms) = server is fast. The bottleneck is file SIZE — large JavaScript/CSS bundles take time to download even in parallel. Solution: code splitting, compression, lazy loading, smaller dependencies."
    />
    <CommonMistake
      mistake="Assuming a slow page means a slow server — looking only at TTFB and ignoring download time and render-blocking resources."
      fix="Check ALL phases: TTFB tells you about server speed. Blue bar width tells you about file size. Stacked requests tell you about HTTP version. Red triangles tell you about render blocking. Each diagnosis has a different fix."
    />
    <DidYouKnow
      fact="HTTP/2 multiplexing, which eliminated the 6-connection limit, was based on Google's SPDY protocol developed in 2009. The switch from HTTP/1.1 to HTTP/2 was one of the biggest automatic performance improvements in web history — sites loading 20+ resources saw 30-50% faster load times with no code changes. HTTP/3 (QUIC) further improves this with UDP instead of TCP."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'TTFB vs download time distinction', freq: 85 },
      { topic: 'Render-blocking resources identification', freq: 80 },
      { topic: 'HTTP/1.1 queuing vs HTTP/2 multiplexing', freq: 75 },
      { topic: 'Size vs Transferred (compression)', freq: 75 },
    ]} />
  </div>
);

export const DBPerformanceLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Tracing Performance Bottlenecks</div>
      <p style={c.prose}>
        The Performance panel flame chart is the most powerful debugging tool in Chrome DevTools. <strong style={{ color: '#eab308' }}>Every millisecond is accounted for</strong> — you can find exactly what code ran during a jank, a slow click, or a dropped frame.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🎵"
      title="A music conductor reading a score"
      analogy="A music score shows every instrument on every beat — the conductor sees exactly which instrument played at each moment in time. The flame chart is identical: every function call, every layout, every paint is shown on a timeline. Find the note that doesn't belong (the long red task)."
      connection="Flame chart = music score. Each track = call stack level. Width = time. Find the widest note in the wrong instrument (unexpected function taking too long)."
    />
    <StorySteps steps={[
      {
        title: 'Reading the flame chart',
        color: '#eab308',
        desc: 'Width = time. Bottom = actual executing code. Red = long tasks.',
        code: `// FLAME CHART ANATOMY:

// TOP ROW: Frames (FPS indicator)
//   Green bars = 60fps ✓
//   Yellow bars = below 60fps ⚠️
//   Red bars = very slow frame (jank) ❌

// BELOW: Main thread timeline
//   Each horizontal layer = one level of the call stack
//   Width = time spent
//   Click any block to see function name and duration

// READING IT:
//   handleClick (50ms total)
//   └── processData (45ms)  ← MOST TIME HERE
//       └── expensiveCalc (44ms)  ← THE ACTUAL BOTTLENECK
//           └── JSON.parse (40ms)  ← ROOT CAUSE

// The WIDEST block at the DEEPEST level = root cause
// Everything above it is just the call chain leading to it

// PURPLE = Layout (reflow)
// GREEN  = Paint
// YELLOW = Scripting (JavaScript)
// GRAY   = System/Browser work`,
      },
      {
        title: 'Finding long tasks',
        color: '#ef4444',
        desc: 'Long tasks (>50ms) block user input. Chrome marks them in red.',
        code: `// FINDING LONG TASKS:
// Performance panel → record → interact → stop
// In the Main thread track: look for RED flags on top of tasks
// These are "Long Tasks" (>50ms) — browser can't respond to input
// while these run

// BREAKING UP LONG TASKS:
// ❌ One 300ms task = 300ms where user input is ignored
function processAllItems(items) {
  items.forEach(item => heavyProcess(item)); // blocks for 300ms
}

// ✅ Yield between chunks = browser handles input between chunks
async function processAllItemsAsync(items) {
  const CHUNK_SIZE = 50;
  for (let i = 0; i < items.length; i += CHUNK_SIZE) {
    const chunk = items.slice(i, i + CHUNK_SIZE);
    chunk.forEach(item => heavyProcess(item));
    // Yield to browser — handles any pending input events
    await scheduler.yield(); // modern browsers
    // OR: await new Promise(r => setTimeout(r, 0)); // fallback
  }
}

// MEASURING IMPACT:
// Before: one red 300ms block
// After: six green 50ms blocks with gaps for input handling`,
      },
      {
        title: 'Detecting layout thrashing',
        color: '#a855f7',
        desc: 'Alternating read/write cycles cause forced synchronous layouts. Purple spikes everywhere.',
        code: `// LAYOUT THRASHING in DevTools:
// Performance panel → Main thread
// Look for: alternating YELLOW (JS) → PURPLE (Layout) → YELLOW → PURPLE
// Tooltip on purple block: "Forced reflow is a likely performance bottleneck"

// THE CAUSE:
// ❌ Read layout property after write = forces synchronous layout
function badAnimation() {
  elements.forEach(el => {
    const width = el.offsetWidth;    // READ  → forces layout (purple)
    el.style.width = width + 1 + 'px'; // WRITE → invalidates layout
    // Next iteration: READ again → forces ANOTHER layout!
  });
  // 100 elements = 100 synchronous reflows!
}

// ✅ Batch reads then writes:
function goodAnimation() {
  // All reads first:
  const widths = elements.map(el => el.offsetWidth);
  // All writes after:
  elements.forEach((el, i) => { el.style.width = widths[i] + 1 + 'px'; });
  // Only 1 reflow at the end!
}

// ✅ Or use requestAnimationFrame:
function rafAnimation() {
  requestAnimationFrame(() => {
    const width = el.offsetWidth;  // read
    el.style.width = width + 1 + 'px'; // write
    // Safe because RAF runs at frame boundary when layout is stable
  });
}`,
      },
    ]} />
    <InlinePoll
      question="Flame chart shows a 200ms yellow block. You expand it and find: handleClick → sortItems → compareFunction. compareFunction is 190ms wide. What is the fix?"
      options={['Memoize handleClick with useCallback', 'Optimize compareFunction — it\'s the actual bottleneck. Consider a faster sorting algorithm, pre-processing data, or moving the sort to a Web Worker', 'Debounce the click handler', 'Use React.memo on the component']}
      correct={1}
      explanation="The flame chart points at compareFunction as the bottleneck — it's 190ms of the 200ms task. Memoizing handleClick or using React.memo won't help because the JavaScript execution itself is slow. Fix the algorithm or move to a Web Worker."
    />
    <CommonMistake
      mistake="Recording the Performance panel without interacting — getting a timeline with no useful data."
      fix="Always record AROUND the specific interaction that's slow. Click Record → immediately do the slow thing (click button, scroll, type) → click Stop. The recording should be 1-5 seconds. Long recordings have too much data to analyze."
    />
    <DidYouKnow
      fact="Chrome's Performance panel is built on the Trace Event Format — the same format used by Google's internal profiling tools for Chrome itself. The concept of 'flame graphs' was invented by Brendan Gregg at Netflix in 2011 to profile Linux kernel performance. He noticed the folded call stack format looked like flames when visualized — the name stuck."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Reading flame chart — width = time, bottom = bottleneck', freq: 85 },
      { topic: 'Long tasks identification (>50ms)', freq: 80 },
      { topic: 'Layout thrashing detection and fix', freq: 80 },
      { topic: 'Breaking up long tasks with yield', freq: 70 },
    ]} />
  </div>
);

export const DBHydrationLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Debugging Hydration Errors</div>
      <p style={c.prose}>
        Hydration errors are some of the most confusing React errors. They mean the <strong style={{ color: '#eab308' }}>server-rendered HTML doesn't match what React would render on the client</strong>. Understanding why they happen makes them trivial to fix.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🖨️"
      title="A printed document vs a live document"
      analogy="Hydration is like comparing a printed snapshot of a document (server HTML) to the live version (React's render). If the live version says 'Monday' but the print says 'Sunday' (Date.now() ran at different times), React sees a mismatch and complains."
      connection="Server HTML = printed at request time. Client React = rendered at hydration time. Any dynamic value (dates, random numbers, window size) will differ between the two."
    />
    <StorySteps steps={[
      {
        title: 'Reading the hydration error',
        color: '#eab308',
        desc: 'React 18 shows exactly what element mismatched and what both sides expected.',
        code: `// React 18 hydration error message:
// "Error: Hydration failed because the initial UI does not match
//  what was rendered on the server."
//
// "Warning: Text content did not match.
//  Server: "Monday, January 1"  ← what server rendered
//  Client: "Tuesday, January 2" ← what React renders now"
//
// The component path shows WHERE:
// at span
// at DateDisplay (DateDisplay.tsx:12)
// at Header (Header.tsx:34)
// at App (App.tsx:8)

// HOW TO READ IT:
// 1. Find the innermost component in the path (DateDisplay)
// 2. Look at line 12 in DateDisplay.tsx
// 3. It probably has: new Date().toLocaleDateString()
// 4. Server ran this at request time (date A)
// 5. Client runs it at hydration time (date B)
// 6. They differ → mismatch`,
      },
      {
        title: 'The most common causes and fixes',
        color: '#4facfe',
        desc: 'Date.now(), window/document, Math.random() — all differ between server and client.',
        code: `// CAUSE 1: Dynamic dates/times
// ❌ Different value on server vs client
<time>{new Date().toLocaleDateString()}</time>

// ✅ Defer to client only
function ClientDate() {
  const [date, setDate] = useState('');
  useEffect(() => setDate(new Date().toLocaleDateString()), []);
  return <time>{date}</time>; // server: empty string. client: date
}

// CAUSE 2: Browser-only APIs (window, document, navigator)
// ❌ window doesn't exist on server
const width = window.innerWidth;

// ✅ Guard with typeof
const width = typeof window !== 'undefined' ? window.innerWidth : 0;
// OR: read in useEffect (runs client-only)

// CAUSE 3: Math.random() or crypto
// ❌ Different random value each render
<div id={\`item-\${Math.random()}\`}>

// ✅ Generate in useEffect or use a stable ID
const id = useId(); // React 18 — same on server and client!

// CAUSE 4: Browser extension injecting DOM
// Not fixable in code — suppress on the extension-injected element
<html suppressHydrationWarning>`,
      },
      {
        title: 'Next.js dynamic() for browser-only components',
        color: '#00ff88',
        desc: 'Skip SSR for components that fundamentally can\'t match.',
        code: `// Some components simply can't hydrate correctly:
// - Canvas animations
// - WebGL
// - window.innerWidth layout
// - Local timezone-dependent UI

// Next.js dynamic() with ssr: false:
import dynamic from 'next/dynamic';

const Map = dynamic(() => import('./MapComponent'), {
  ssr: false,
  loading: () => <div style={{ height: 400 }}>Loading map...</div>,
});

// Server renders: <div style={{height:400}}>Loading map...</div>
// Client renders: <MapComponent /> after mount
// No comparison needed → no mismatch

// WHEN TO USE ssr: false:
// ✓ Components using window/document in render
// ✓ Canvas/WebGL/Three.js
// ✓ Libraries that aren't SSR-compatible
// ✗ Normal data-fetching components (use async/await instead)`,
      },
      {
        title: 'suppressHydrationWarning — when it\'s appropriate',
        color: '#a855f7',
        desc: 'A last resort for intentionally different content. Narrow scope.',
        code: `// suppressHydrationWarning: skip comparison for this element only
// React still hydrates children normally

// ✅ APPROPRIATE: timestamps that will differ
<time
  dateTime={serverTime}
  suppressHydrationWarning
>
  {new Date().toLocaleTimeString()}  {/* will differ */}
</time>

// ✅ APPROPRIATE: browser extension adds attributes to html
<html lang="en" suppressHydrationWarning>

// ❌ INAPPROPRIATE: hiding real bugs
<div suppressHydrationWarning>
  {user.name}  {/* if this mismatches, it's a real bug! */}
</div>

// RULE: suppressHydrationWarning is for KNOWN, HARMLESS mismatches
// (timestamps, locale-specific formatting, browser extensions)
// NOT for silencing bugs you don't understand yet`,
      },
    ]} />
    <InlinePoll
      question="Server renders 'Hello, Alice'. Client renders 'Hello, Bob'. This is a hydration mismatch. What is the most likely cause?"
      options={['A network error', 'User state read during render (user object differs between SSR and client hydration — user wasn\'t loaded during SSR)', 'Date.now() mismatch', 'A browser extension']}
      correct={1}
      explanation="Classic auth hydration bug: server renders without auth context (user = null or anonymous), client has user 'Bob' from localStorage. Fix: either include user context in SSR, or defer user-specific content to client-only rendering with useEffect."
    />
    <CommonMistake
      mistake="Adding suppressHydrationWarning to everything to silence the errors without understanding the cause."
      fix="Each suppressHydrationWarning should be justified. Find the root cause first. Most hydration errors reveal real bugs (wrong user showing, incorrect data). suppressHydrationWarning is correct only for intentionally dynamic values like timestamps."
    />
    <DidYouKnow
      fact="React 18 dramatically improved hydration error messages compared to React 17. In React 17, you'd just see 'Warning: Expected server HTML to contain a matching <div>.' — unhelpful. The React team spent significant engineering time on React 18's error messages, adding the server/client diff view. They were inspired by TypeScript's error messages which show both the expected and actual types."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Why hydration mismatches happen', freq: 90 },
      { topic: 'Reading hydration error messages', freq: 80 },
      { topic: 'Fixing Date.now()/window causes', freq: 85 },
      { topic: 'suppressHydrationWarning — appropriate use', freq: 75 },
    ]} />
  </div>
);

export const DBProductionLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 Debugging Production-Only Bugs</div>
      <p style={c.prose}>
        Production bugs are the hardest — you can't reproduce them locally, the code is minified, and users are affected. The toolkit: <strong style={{ color: '#eab308' }}>source maps, error monitoring, feature flags, and systematic hypothesis testing</strong>.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="🕵️"
      title="A detective at a crime scene"
      analogy="A detective can't recreate the crime — they work from evidence. Source maps translate minified code to readable source (evidence translation). Error monitoring captures the exact state when it happened (crime scene photos). Feature flags enable the bug for investigation (controlled reconstruction)."
      connection="Source maps = crime scene translator. Sentry = crime scene photographer. Feature flags = controlled reproduction. Systematic hypothesis = detective's reasoning."
    />
    <StorySteps steps={[
      {
        title: 'Source maps — readable production stack traces',
        color: '#eab308',
        desc: 'Map minified bundle positions back to original source files.',
        code: `// WITHOUT source maps — useless stack trace:
// TypeError: Cannot read properties of undefined (reading 'name')
//   at e (bundle.min.js:1:45823)
//   at t (bundle.min.js:1:46012)

// WITH source maps — actionable:
// TypeError: Cannot read properties of undefined (reading 'name')
//   at UserProfile.render (src/components/UserProfile.tsx:47:22)
//   at formatUserData (src/utils/format.ts:12:8)

// SETUP (Vite):
// vite.config.ts
build: { sourcemap: true }
// Generates: bundle.js + bundle.js.map

// SETUP (Webpack):
// webpack.config.js
devtool: 'source-map', // production
// devtool: 'eval-source-map', // development (fast)

// SENTRY — upload source maps (keep private!):
// Use @sentry/vite-plugin — source maps uploaded to Sentry
// NOT served to users. Errors symbolicated server-side.
// sentry.io/settings → Source Maps shows upload status`,
      },
      {
        title: 'Error monitoring — capture context at failure time',
        color: '#4facfe',
        desc: 'Sentry captures the exact state, user, and breadcrumbs when an error occurs.',
        code: `// sentry.client.config.ts
Sentry.init({
  dsn: process.env.NEXT_PUBLIC_SENTRY_DSN,
  release: process.env.NEXT_PUBLIC_COMMIT_SHA, // link to deploy
  environment: process.env.NODE_ENV,

  beforeSend(event) {
    // Scrub PII before sending
    delete event.request?.headers?.['Authorization'];
    return event;
  },
});

// Add user context after login:
Sentry.setUser({ id: user.id, email: user.email });

// Add custom breadcrumbs:
Sentry.addBreadcrumb({
  category: 'checkout',
  message: 'User clicked "Place Order"',
  data: { cartId, itemCount, total },
  level: 'info',
});

// WHAT SENTRY CAPTURES AUTOMATICALLY:
// - Full stack trace (symbolicated with source maps)
// - User agent, OS, browser version
// - URL, referrer, cookies (configurable)
// - Redux/Zustand state snapshot (with plugin)
// - All console.error calls
// - Network request failures (XHR/Fetch)`,
      },
      {
        title: 'Feature flags for controlled reproduction',
        color: '#00ff88',
        desc: 'Enable debug mode or the buggy feature for specific users without deploying.',
        code: `// Scenario: bug only affects users created before 2023-01-01
// Normal users can't reproduce. Affected users can't debug.

// Feature flag approach (LaunchDarkly/Unleash/custom):
const showVerboseLogging = useFeatureFlag('verbose-logging', {
  userId: user.id,
});

useEffect(() => {
  if (showVerboseLogging) {
    window.DEBUG_CHECKOUT = true; // enable extra logging
  }
}, [showVerboseLogging]);

// WORKFLOW:
// 1. Sentry shows error with userId=12345
// 2. Enable 'verbose-logging' flag for userId=12345
// 3. User interacts → detailed logs captured
// 4. OR: enable flag for your own account with userId=12345's data
//    (staging environment with prod data copy)
// 5. Reproduce → fix → turn off flag → deploy

// PRODUCTION DEBUG WITHOUT DEPLOY:
// localStorage.setItem('DEBUG', 'true')
// Code checks: if (localStorage.getItem('DEBUG')) console.debug(...)
// No deploy needed, no other users affected`,
      },
      {
        title: 'Systematic hypothesis testing',
        color: '#a855f7',
        desc: 'When you can\'t reproduce locally, narrow down systematically.',
        code: `// PRODUCTION-ONLY BUG CHECKLIST:

// 1. ENVIRONMENT DIFFERENCES
//    Local .env != .env.production?
//    console.log(process.env.NEXT_PUBLIC_API_URL) in prod
//    Missing env vars often cause silent failures

// 2. BUILD DIFFERENCES
//    Minification: fn.name is empty in production
//    if (MyComponent.name === 'MyComponent') // breaks in production!
//    Tree-shaking: export you use somewhere isn't being included

// 3. DATA DIFFERENCES
//    Specific user data triggers edge case
//    Sentry → user context → reproduce with that user ID in staging

// 4. TIMING DIFFERENCES
//    Race conditions masked by local dev server speed
//    Production has slower/different latency patterns

// 5. BROWSER/OS DIFFERENCES
//    Error only on iOS Safari, Windows Chrome, etc.
//    Sentry tags → filter by browser → confirm pattern

// BINARY SEARCH APPROACH:
// Deploy with: if (userId % 2 === 0) { new code } else { old code }
// 50% of users get new code. If only new-code users error → confirmed.
// Halve the search space each time.`,
      },
    ]} />
    <InlinePoll
      question="Sentry shows: 'TypeError at bundle.min.js:1:456823'. How do you get a readable stack trace?"
      options={['Add console.log statements and redeploy', 'Upload source maps to Sentry using @sentry/vite-plugin — Sentry symbolicates the error server-side and shows original file names and line numbers', 'Use the browser debugger on the minified bundle', 'Add // @ts-nocheck comments']}
      correct={1}
      explanation="Source maps map minified positions back to original source. Upload them to Sentry (never serve them publicly). Sentry symbolicates errors server-side — you see 'UserProfile.tsx:47' instead of 'bundle.min.js:1:456823'. The @sentry/vite-plugin automates the upload on each build."
    />
    <CommonMistake
      mistake="Deploying console.log statements to production to debug — logs are visible to users and waste bandwidth."
      fix="Use Sentry breadcrumbs for structured logging. Use feature flags to enable verbose logging for specific users. Use sampling (5% of users log details). Never deploy permanent console.log to production — it's a security risk and performance issue."
    />
    <DidYouKnow
      fact="Sentry was founded in 2012 by David Cramer after he got tired of finding out about bugs from angry users instead of automated systems. The name references the idea of a sentinel — a guard that watches for problems. As of 2024, Sentry processes over 10 billion events per month. GitHub, Cloudflare, and Notion all use Sentry for error monitoring."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Source maps setup and why they\'re needed', freq: 85 },
      { topic: 'Sentry error context and breadcrumbs', freq: 80 },
      { topic: 'Feature flags for controlled reproduction', freq: 75 },
      { topic: 'Systematic hypothesis testing approach', freq: 75 },
    ]} />
  </div>
);

export const DBStaleClosureLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#eab30840' delay={0}>
      <div style={c.title('#eab308')}>🎬 The Stale Closure — React's Most Subtle Bug</div>
      <p style={c.prose}>
        Stale closures are behind the most confusing React bugs. A component renders, a function captures a value, renders again with new values — <strong style={{ color: '#eab308' }}>but the old function still sees the old values</strong>. Diagnosing and fixing this separates senior developers.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="📸"
      title="A photograph vs a live video"
      analogy="A closure is like a photograph taken at render time — it captures the values as they were. The page may change (new renders, new state) but the photograph still shows the old values. A ref is like a live video feed — it always shows the current state."
      connection="Closure = photograph (stale). Ref = live feed (current). Functional updater = asking for the current value without a photograph."
    />
    <StorySteps steps={[
      {
        title: 'The classic stale closure — setInterval',
        color: '#eab308',
        desc: 'Effect runs once. count captured as 0. Never updates.',
        code: `// ❌ STALE CLOSURE
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    // This runs once (empty deps [])
    // count is CAPTURED as 0 — a photograph
    const id = setInterval(() => {
      console.log(count);      // always logs 0!
      setCount(count + 1);     // always sets to 1!
    }, 1000);
    return () => clearInterval(id);
  }, []); // ← empty deps means the closure is never refreshed

  return <div>{count}</div>; // UI shows 1 forever
}

// WHY: the setInterval callback is created once (render 1).
// count in that callback = 0 (render 1's value).
// Even after 10 renders where count is 5,7,9...
// the interval still reads count = 0.`,
      },
      {
        title: 'Three fixes, each for different situations',
        color: '#4facfe',
        desc: 'Functional updater for state, ref for external values, fresh effect for subscriptions.',
        code: `// FIX 1: Functional updater (best for state)
// setCount receives the LATEST state, not the closure value
useEffect(() => {
  const id = setInterval(() => {
    setCount(c => c + 1); // c = current state, always fresh
  }, 1000);
  return () => clearInterval(id);
}, []); // ✓ deps still empty — we don't need count in closure

// FIX 2: useRef (best for non-state values)
function useInterval(callback, delay) {
  const callbackRef = useRef(callback);

  // Keep ref current on every render
  useEffect(() => { callbackRef.current = callback; }, [callback]);

  useEffect(() => {
    const id = setInterval(() => callbackRef.current(), delay);
    return () => clearInterval(id);
  }, [delay]); // ✓ callback always fresh via ref
}

// FIX 3: Add to deps (refreshes the closure)
useEffect(() => {
  const id = setInterval(() => {
    console.log(count); // ✓ fresh — effect re-creates on count change
  }, 1000);
  return () => clearInterval(id);
}, [count]); // ← effect re-runs when count changes
// Trade-off: interval resets on every count change`,
      },
      {
        title: 'Diagnosing stale closures with React DevTools',
        color: '#00ff88',
        desc: 'Symptoms, breakpoints, and the exhaustive-deps ESLint rule.',
        code: `// SYMPTOMS OF STALE CLOSURE:
// 1. State doesn't update as expected in async code
// 2. Event handler sees old state/props
// 3. useEffect shows warnings about missing deps
// 4. Console.log shows old values inside callbacks

// DIAGNOSIS WITH BREAKPOINTS:
// 1. Add debugger; inside the suspect callback
// 2. When it pauses, hover over the variable
// 3. Compare: is the value what you expect?
//    If paused inside setInterval and count shows 0 when UI shows 8 → stale

// THE EXHAUSTIVE-DEPS ESLINT RULE (your best friend):
// Install: eslint-plugin-react-hooks
// .eslintrc: "react-hooks/exhaustive-deps": "warn"

// It will warn on:
useEffect(() => {
  fetchUser(userId); // ← userId used but not in deps
}, []); // ESLint: "React Hook useEffect has a missing dependency: 'userId'"

// The rule catches stale closures BEFORE they become bugs.
// When it warns about a dep you "don't need":
// - Add it to deps and handle the re-run (often correct)
// - Use functional updater (for state)
// - Use useRef (for values that shouldn't trigger re-runs)
// - NEVER use // eslint-disable-next-line without understanding why`,
      },
      {
        title: 'Stale closures in event handlers',
        color: '#a855f7',
        desc: 'Button click handlers can also go stale — less obvious but same cause.',
        code: `// STALE IN EVENT HANDLER:
function SearchBar() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  // This handler is created on first render
  // query captured as '' forever
  const handleSubmit = () => {
    console.log(query); // always '' ← STALE
    fetchResults(query);
  };

  useEffect(() => {
    // Adding click listener in useEffect with [] = stale handler!
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') handleSubmit(); // handleSubmit is stale!
    });
  }, []); // ← handleSubmit never refreshes

  return <input value={query} onChange={e => setQuery(e.target.value)} />;
}

// ✅ FIX: Don't add event handlers in useEffect for DOM elements
// Use React's onClick directly — React always uses latest handler
return (
  <input
    value={query}
    onChange={e => setQuery(e.target.value)}
    onKeyDown={e => e.key === 'Enter' && handleSubmit()} // always fresh!
  />
);

// OR: put handleSubmit in useCallback with proper deps
const handleSubmit = useCallback(() => {
  fetchResults(query); // query is in the deps
}, [query]); // refreshes when query changes`,
      },
    ]} />
    <InlinePoll
      question="setInterval logs 0 every second even though count updates in the UI. What is the ONE-LINE fix that doesn't require adding count to deps?"
      options={['Add count to the useEffect deps array', "Change setCount(count + 1) to setCount(c => c + 1) — functional updater receives current state, bypasses the stale closure entirely", 'Use useRef to store count', 'Add useCallback around the interval']}
      correct={1}
      explanation="setCount(c => c + 1): React passes the most recent state as c — not the closed-over count. This is the idiomatic fix for state updates in async callbacks. The closure doesn't need to 'see' count because you're never reading it."
    />
    <CommonMistake
      mistake="Disabling exhaustive-deps ESLint warnings with // eslint-disable-next-line because 'the effect runs too many times with the dependency'."
      fix="The 'too many times' problem means the dependency reference is unstable (new object/function on every render). Fix the instability (useMemo/useCallback) rather than suppressing the warning. The warning exists to prevent stale closures — disabling it just hides the bug."
    />
    <DidYouKnow
      fact="Dan Abramov wrote a seminal blog post in 2019 called 'A Complete Guide to useEffect' specifically to explain stale closures and the mental model for thinking about effects as synchronization (not lifecycle). It's still required reading for React developers in 2024. He invented the functional updater pattern (setState(s => s + 1)) partially to solve this class of bugs."
      color="#eab308"
    />
    <InterviewMeter topics={[
      { topic: 'Identify stale closure from symptoms', freq: 90 },
      { topic: 'Functional updater pattern', freq: 90 },
      { topic: 'useRef for always-current values', freq: 80 },
      { topic: 'exhaustive-deps rule and what it prevents', freq: 85 },
    ]} />
  </div>
);
