export const PIBundleLearn = () => (
  <div style={c.wrap}>
    <RevealCard color='#f9731640' delay={0}>
      <div style={c.title('#f97316')}>🎬 Bundle Size Optimization</div>
      <p style={c.prose}>
        Every kilobyte of JavaScript has a cost: download time, parse time, compile time, execution time. <strong style={{ color: '#f97316' }}>Reducing bundle size is the highest ROI performance optimization</strong> — it benefits every user on every device, forever.
      </p>
    </RevealCard>
    <AnalogyCard
      emoji="✈️"
      title="Packing a suitcase for a flight"
      analogy="Every item you pack has weight — the more you pack, the longer security takes (parse time) and the harder it is to carry (execution time). Smart travelers pack only what they need for THIS trip (code splitting), use compression bags (Brotli), and leave rarely-used items at home (tree shaking)."
      connection="Bundle size = suitcase weight. Tree shaking = removing clothes you won't wear. Code splitting = separate carry-on for each destination. Bundle analyzer = the scale showing you what's heavy."
    />
    <StorySteps steps={[
      {
        title: 'Bundle analysis — find before you fix',
        color: '#f97316',
        desc: 'See exactly what\'s in your bundle before optimizing anything.',
        code: `// SETUP BUNDLE ANALYZER:

// Vite:
import { visualizer } from 'rollup-plugin-visualizer';
// vite.config.ts
plugins: [
  visualizer({
    open: true,        // opens in browser after build
    gzipSize: true,    // shows gzipped sizes
    brotliSize: true,  // shows brotli sizes
  })
]
// Run: npm run build → treemap opens automatically

// Webpack:
const { BundleAnalyzerPlugin } = require('webpack-bundle-analyzer');
plugins: [new BundleAnalyzerPlugin()]

// WHAT TO LOOK FOR:
// 1. Largest rectangles — biggest contributors
// 2. Unexpected packages (moment.js for one date format)
// 3. Duplicate packages (two versions of React)
// 4. Full icon libraries (importing all 1000 icons for 3)
// 5. Dev-only packages in production bundle

// QUICK CHECK — before installing any package:
// bundlephobia.com → search package name
// Shows: size, gzipped size, tree-shakeable, alternatives`,
      },
      {
        title: 'Tree shaking — eliminate dead exports',
        color: '#4facfe',
        desc: 'Static analysis removes exports nobody imports. Requires ES modules.',
        code: `// TREE SHAKING REQUIREMENTS:
// 1. ES module syntax (import/export) — NOT require/module.exports
// 2. No side effects on import (or mark in package.json)
// 3. Named exports (not default export of entire namespace)

// ❌ Prevents tree shaking:
import _ from 'lodash';          // CJS, imports everything: 70KB
import * as utils from './utils'; // namespace import: pulls everything

// ✅ Enables tree shaking:
import { debounce } from 'lodash-es'; // ESM lodash: only debounce
import { debounce } from './utils';   // named import: only debounce

// ICON LIBRARIES — common culprit:
// ❌ Imports entire icon library (500KB+)
import { icons } from 'lucide-react';

// ✅ Named import — only this icon:
import { Search } from 'lucide-react'; // ~2KB

// DATE LIBRARIES:
// ❌ moment.js — not tree-shakeable, 67KB always
import moment from 'moment';

// ✅ date-fns — fully tree-shakeable
import { format, addDays } from 'date-fns'; // ~2KB for these two

// VERIFY TREE SHAKING WORKS:
// package.json of the library should have:
// "sideEffects": false  — safe to tree shake
// "module": "dist/index.esm.js"  — ESM entry point`,
      },
      {
        title: 'Code splitting — load on demand',
        color: '#00ff88',
        desc: 'Split at route and component boundaries. Load only what the current page needs.',
        code: `// ROUTE-BASED SPLITTING (highest ROI):
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Admin     = lazy(() => import('./pages/Admin'));
const Settings  = lazy(() => import('./pages/Settings'));

// Each route = separate chunk
// /dashboard loads Dashboard chunk only
// /admin loads Admin chunk only (users who never visit → never download)

function App() {
  return (
    <Suspense fallback={<PageSkeleton />}>
      <Routes>
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/admin"     element={<Admin />} />
      </Routes>
    </Suspense>
  );
}

// COMPONENT-BASED SPLITTING (for heavy components):
// ❌ Chart library (500KB) loads even for users who never see chart
import HeavyChart from 'recharts';

// ✅ Only loads when ShowChart becomes true
const HeavyChart = lazy(() => import('./HeavyChart'));
function Page() {
  const [show, setShow] = useState(false);
  return (
    <>
      <button onClick={() => setShow(true)}>Show Chart</button>
      {show && <Suspense fallback={<Spinner />}><HeavyChart /></Suspense>}
    </>
  );
}

// PREFETCH on hover — eliminate perceived loading:
const prefetchChart = () => import('./HeavyChart');
<button onMouseEnter={prefetchChart} onClick={() => setShow(true)}>
  Show Chart  // by click time, chunk already downloaded
</button>`,
      },
    ]} />
    <InlinePoll
      question="Bundle analyzer shows moment.js taking 67KB gzipped. You only use moment for formatting dates. What is the correct fix?"
      options={['Compress moment.js', 'Replace with date-fns: import { format } from "date-fns" — tree-shakeable, adds ~2KB vs moment\'s always-67KB. Or use native Intl.DateTimeFormat for simple cases.', 'Lazy-load moment.js', 'Import only the locale you need from moment']}
      correct={1}
      explanation="moment.js is a CommonJS bundle — not tree-shakeable. Even importing one function includes the entire 67KB. date-fns is a collection of ESM modules — each function is a separate file. import { format } from 'date-fns' adds only ~2KB. Migrating from moment to date-fns is one of the highest-ROI bundle optimizations."
    />
    <CommonMistake
      mistake="Lazy loading everything including small components — creating hundreds of tiny chunks that each require a network request."
      fix="Only split at meaningful boundaries: routes (always), and components >30KB that aren't immediately visible. Very small chunks add HTTP overhead that exceeds the savings. The sweet spot is chunks >20KB that users may never need."
    />
    <DidYouKnow
      fact="The average web page JavaScript payload has grown from 100KB in 2012 to over 500KB in 2024. Addy Osmani (Chrome team) found that 1MB of JavaScript takes 8-10 seconds to parse on a median mobile device — far longer than download time. This is why bundle size matters even on fast connections: parsing and compilation cost scales with bytes regardless of network speed."
      color="#f97316"
    />
    <InterviewMeter topics={[
      { topic: 'Bundle analyzer workflow', freq: 90 },
      { topic: 'Tree shaking requirements (ESM, named imports)', freq: 90 },
      { topic: 'Route-based code splitting', freq: 85 },
      { topic: 'Common bundle bloat causes (moment, icons, lodash)', freq: 85 },
    ]} />
  </div>
);

